/**
 * AgentHealthGrid
 *
 * Real-time grid view of agent health status with Apple-style design.
 * Displays agents as cards with live status indicators and key metrics.
 */

import React, { useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { slideUpVariants, staggerContainerVariants } from '../ui/animationVariants';
import { SentinelAgent } from '../../types/agent';
import {
    Monitor, Apple, Server, Cpu, HardDrive,
    Activity, Shield, Clock, MoreVertical,
    Eye, Settings, Trash2, RefreshCw
} from '../ui/Icons';
import { Badge } from '../ui/Badge';
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger,
    DropdownMenuSeparator,
} from '../ui/dropdown-menu';
import { cn } from '../../lib/utils';

interface AgentHealthGridProps {
    agents: SentinelAgent[];
    onAgentClick?: (agent: SentinelAgent) => void;
    onAgentAction?: (agent: SentinelAgent, action: 'view' | 'configure' | 'refresh' | 'delete') => void;
    viewMode?: 'grid' | 'compact';
}

// OS Icon component
const OSIcon: React.FC<{ os: SentinelAgent['os']; className?: string }> = ({ os, className }) => {
    switch (os) {
        case 'darwin':
            return <Apple className={className} />;
        case 'windows':
            return <Monitor className={className} />;
        case 'linux':
        default:
            return <Server className={className} />;
    }
};

// Format bytes to human readable
const formatBytes = (bytes: number | undefined): string => {
    if (!bytes) return '-';
    const gb = bytes / (1024 * 1024 * 1024);
    if (gb >= 1) return `${gb.toFixed(1)} GB`;
    const mb = bytes / (1024 * 1024);
    return `${mb.toFixed(0)} MB`;
};

// Format last seen time
const formatLastSeen = (dateStr: string): string => {
    const date = new Date(dateStr);
    const now = new Date();
    const diff = now.getTime() - date.getTime();
    const seconds = Math.floor(diff / 1000);
    const minutes = Math.floor(diff / 60000);
    const hours = Math.floor(diff / 3600000);
    const days = Math.floor(diff / 86400000);

    if (seconds < 60) return 'À l\'instant';
    if (minutes < 60) return `${minutes}m`;
    if (hours < 24) return `${hours}h`;
    if (days < 7) return `${days}j`;
    return date.toLocaleDateString('fr-FR', { day: '2-digit', month: 'short' });
};

// Score color based on value
const getScoreColor = (score: number | null | undefined): string => {
    if (score === null || score === undefined) return 'text-muted-foreground';
    if (score >= 80) return 'text-success';
    if (score >= 60) return 'text-warning';
    return 'text-destructive';
};

// Agent Health Card Component
interface AgentHealthCardProps {
    agent: SentinelAgent;
    onClick?: () => void;
    onAction?: (action: 'view' | 'configure' | 'refresh' | 'delete') => void;
    compact?: boolean;
}

const AgentHealthCard: React.FC<AgentHealthCardProps> = ({
    agent,
    onClick,
    onAction,
    compact = false
}) => {
    const isActive = agent.status === 'active';
    const hasMetrics = agent.cpuPercent !== undefined || agent.memoryBytes !== undefined;

    if (compact) {
        // Compact row view
        return (
            <motion.div
                variants={slideUpVariants}
                onClick={onClick}
                onKeyDown={(e) => {
                    if (onClick && (e.key === 'Enter' || e.key === ' ')) {
                        e.preventDefault();
                        onClick();
                    }
                }}
                role={onClick ? "button" : undefined}
                tabIndex={onClick ? 0 : undefined}
                className={cn(
                    'group flex items-center gap-3 p-3 rounded-xl border border-border/50',
                    'bg-card/50 backdrop-blur-sm hover:bg-card hover:border-border',
                    'transition-all duration-200 cursor-pointer hover:shadow-apple-sm focus-visible:ring-2 focus-visible:ring-brand-500 focus-visible:outline-none'
                )}
            >
                {/* Status indicator + OS */}
                <div className="relative">
                    <div className={cn(
                        'w-9 h-9 rounded-lg flex items-center justify-center',
                        'bg-muted/50 group-hover:bg-muted transition-colors'
                    )}>
                        <OSIcon os={agent.os} className="w-4 h-4 text-foreground" />
                    </div>
                    <div className={cn(
                        'absolute -bottom-0.5 -right-0.5 w-2.5 h-2.5 rounded-full border-2 border-card',
                        isActive ? 'bg-success animate-pulse' : 'bg-muted-foreground'
                    )} />
                </div>

                {/* Name + hostname */}
                <div className="flex-1 min-w-0">
                    <span className="font-medium text-sm text-foreground truncate block">
                        {agent.name || agent.hostname || agent.id.slice(0, 8)}
                    </span>
                    <span className="text-xs text-muted-foreground truncate block">
                        {agent.ipAddress || agent.hostname}
                    </span>
                </div>

                {/* Metrics (if available) */}
                {hasMetrics && (
                    <div className="hidden sm:flex items-center gap-3 text-xs">
                        {agent.cpuPercent !== undefined && (
                            <div className="flex items-center gap-1 text-muted-foreground">
                                <Cpu className="h-3 w-3" />
                                <span className={cn(
                                    agent.cpuPercent > 80 ? 'text-destructive font-medium' :
                                        agent.cpuPercent > 60 ? 'text-warning' : ''
                                )}>
                                    {agent.cpuPercent.toFixed(0)}%
                                </span>
                            </div>
                        )}
                        {agent.memoryBytes !== undefined && (
                            <div className="flex items-center gap-1 text-muted-foreground">
                                <HardDrive className="h-3 w-3" />
                                <span>{formatBytes(agent.memoryBytes)}</span>
                            </div>
                        )}
                    </div>
                )}

                {/* Score */}
                {agent.complianceScore !== undefined && agent.complianceScore !== null && (
                    <div className={cn('text-sm font-bold', getScoreColor(agent.complianceScore))}>
                        {agent.complianceScore}%
                    </div>
                )}

                {/* Last seen */}
                <div className="text-xs text-muted-foreground hidden md:block">
                    {formatLastSeen(agent.lastHeartbeat)}
                </div>

                {/* Status badge */}
                <Badge
                    status={isActive ? 'success' : 'neutral'}
                    className="hidden lg:inline-flex text-[11px]"
                >
                    {isActive ? 'Actif' : 'Offline'}
                </Badge>
            </motion.div>
        );
    }

    // Grid card view
    return (
        <motion.div
            variants={slideUpVariants}
            className={cn(
                'group relative rounded-2xl border overflow-hidden',
                'bg-card/80 backdrop-blur-sm transition-all duration-300',
                'hover:shadow-apple-md hover:-translate-y-0.5',
                isActive ? 'border-border/50 hover:border-success/30' : 'border-border/30 opacity-80'
            )}
        >
            {/* Header */}
            <div
                onClick={onClick}
                onKeyDown={(e) => {
                    if (onClick && (e.key === 'Enter' || e.key === ' ')) {
                        e.preventDefault();
                        onClick();
                    }
                }}
                role={onClick ? "button" : undefined}
                tabIndex={onClick ? 0 : undefined}
                className="cursor-pointer p-4 pb-3 focus-visible:ring-2 focus-visible:ring-brand-500 focus-visible:outline-none rounded-t-2xl"
            >
                <div className="flex items-start justify-between gap-2">
                    <div className="flex items-center gap-3">
                        {/* OS Icon with status */}
                        <div className="relative">
                            <div className={cn(
                                'w-11 h-11 rounded-xl flex items-center justify-center',
                                'bg-muted/50 group-hover:bg-muted transition-colors'
                            )}>
                                <OSIcon os={agent.os} className="w-5 h-5 text-foreground" />
                            </div>
                            <div className={cn(
                                'absolute -bottom-0.5 -right-0.5 w-3 h-3 rounded-full border-2 border-card',
                                isActive ? 'bg-success' : 'bg-muted-foreground'
                            )}>
                                {isActive && (
                                    <span className="absolute inset-0 rounded-full bg-success animate-ping opacity-75" />
                                )}
                            </div>
                        </div>

                        {/* Name + version */}
                        <div className="min-w-0">
                            <h3 className="font-semibold text-foreground truncate text-sm">
                                {agent.name || agent.hostname || agent.id.slice(0, 8)}
                            </h3>
                            <div className="flex items-center gap-1.5 mt-0.5">
                                <Badge variant="outline" className="text-[11px] px-1.5 py-0 h-4">
                                    v{agent.version}
                                </Badge>
                                <span className="text-[11px] text-muted-foreground">
                                    {agent.osVersion || agent.os}
                                </span>
                            </div>
                        </div>
                    </div>

                    {/* Actions dropdown */}
                    <DropdownMenu>
                        <DropdownMenuTrigger asChild>
                            <button
                                className="h-7 w-7 p-0 rounded-md opacity-0 group-hover:opacity-70 transition-opacity flex items-center justify-center hover:bg-muted"
                                onClick={(e: React.MouseEvent) => e.stopPropagation()}
                            >
                                <MoreVertical className="h-4 w-4" />
                            </button>
                        </DropdownMenuTrigger>
                        <DropdownMenuContent align="end" className="w-40">
                            <DropdownMenuItem onClick={() => onAction?.('view')}>
                                <Eye className="h-4 w-4 mr-2" />
                                Voir détails
                            </DropdownMenuItem>
                            <DropdownMenuItem onClick={() => onAction?.('configure')}>
                                <Settings className="h-4 w-4 mr-2" />
                                Configurer
                            </DropdownMenuItem>
                            <DropdownMenuItem onClick={() => onAction?.('refresh')}>
                                <RefreshCw className="h-4 w-4 mr-2" />
                                Rafraîchir
                            </DropdownMenuItem>
                            <DropdownMenuSeparator />
                            <DropdownMenuItem
                                onClick={() => onAction?.('delete')}
                                className="text-destructive focus:text-destructive"
                            >
                                <Trash2 className="h-4 w-4 mr-2" />
                                Supprimer
                            </DropdownMenuItem>
                        </DropdownMenuContent>
                    </DropdownMenu>
                </div>
            </div>

            {/* Metrics */}
            <div className="px-4 pb-4">
                <div className="grid grid-cols-3 gap-2 text-center">
                    {/* CPU */}
                    <div className="p-2 rounded-lg bg-muted/30">
                        <div className="flex items-center justify-center gap-1 mb-1">
                            <Cpu className="h-3 w-3 text-muted-foreground" />
                        </div>
                        <span className={cn(
                            'text-sm font-bold',
                            agent.cpuPercent !== undefined && agent.cpuPercent > 80 ? 'text-destructive' :
                                agent.cpuPercent !== undefined && agent.cpuPercent > 60 ? 'text-warning' : 'text-foreground'
                        )}>
                            {agent.cpuPercent !== undefined ? `${agent.cpuPercent.toFixed(0)}%` : '-'}
                        </span>
                        <span className="block text-[11px] text-muted-foreground uppercase tracking-wider">CPU</span>
                    </div>

                    {/* Memory */}
                    <div className="p-2 rounded-lg bg-muted/30">
                        <div className="flex items-center justify-center gap-1 mb-1">
                            <HardDrive className="h-3 w-3 text-muted-foreground" />
                        </div>
                        <span className="text-sm font-bold text-foreground">
                            {formatBytes(agent.memoryBytes)}
                        </span>
                        <span className="block text-[11px] text-muted-foreground uppercase tracking-wider">RAM</span>
                    </div>

                    {/* Compliance */}
                    <div className="p-2 rounded-lg bg-muted/30">
                        <div className="flex items-center justify-center gap-1 mb-1">
                            <Shield className="h-3 w-3 text-muted-foreground" />
                        </div>
                        <span className={cn('text-sm font-bold', getScoreColor(agent.complianceScore))}>
                            {agent.complianceScore !== undefined && agent.complianceScore !== null
                                ? `${agent.complianceScore}%`
                                : '-'}
                        </span>
                        <span className="block text-[11px] text-muted-foreground uppercase tracking-wider">Score</span>
                    </div>
                </div>

                {/* Footer */}
                <div className="flex items-center justify-between mt-3 pt-3 border-t border-border/50">
                    <div className="flex items-center gap-1 text-xs text-muted-foreground">
                        <Clock className="h-3 w-3" />
                        <span>{formatLastSeen(agent.lastHeartbeat)}</span>
                    </div>
                    <div className="text-xs text-muted-foreground truncate max-w-[120px]">
                        {agent.ipAddress}
                    </div>
                </div>
            </div>
        </motion.div>
    );
};

// Empty state component
const EmptyState: React.FC = () => (
    <motion.div
        variants={slideUpVariants}
        className="flex flex-col items-center justify-center py-16 text-center"
    >
        <div className="w-20 h-20 rounded-3xl bg-muted/50 flex items-center justify-center mb-4">
            <Activity className="h-10 w-10 text-muted-foreground" />
        </div>
        <h3 className="text-lg font-semibold text-foreground mb-2">
            Aucun agent à afficher
        </h3>
        <p className="text-sm text-muted-foreground max-w-sm">
            Déployez des agents Sentinel sur vos endpoints pour les voir apparaître ici en temps réel.
        </p>
    </motion.div>
);

export const AgentHealthGrid: React.FC<AgentHealthGridProps> = ({
    agents,
    onAgentClick,
    onAgentAction,
    viewMode = 'grid'
}) => {
    // Sort agents: active first, then by last heartbeat
    const sortedAgents = useMemo(() => {
        return [...agents].sort((a, b) => {
            // Active agents first
            if (a.status === 'active' && b.status !== 'active') return -1;
            if (a.status !== 'active' && b.status === 'active') return 1;
            // Then by last heartbeat (most recent first)
            return new Date(b.lastHeartbeat).getTime() - new Date(a.lastHeartbeat).getTime();
        });
    }, [agents]);

    if (agents.length === 0) {
        return <EmptyState />;
    }

    if (viewMode === 'compact') {
        return (
            <motion.div
                variants={staggerContainerVariants}
                initial="initial"
                animate="visible"
                className="flex flex-col gap-2"
            >
                {sortedAgents.map((agent) => (
                    <AgentHealthCard
                        key={agent.id}
                        agent={agent}
                        compact
                        onClick={() => onAgentClick?.(agent)}
                        onAction={(action) => onAgentAction?.(agent, action)}
                    />
                ))}
            </motion.div>
        );
    }

    return (
        <motion.div
            variants={staggerContainerVariants}
            initial="initial"
            animate="visible"
            className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4"
        >
            <AnimatePresence mode="popLayout">
                {sortedAgents.map((agent) => (
                    <AgentHealthCard
                        key={agent.id}
                        agent={agent}
                        onClick={() => onAgentClick?.(agent)}
                        onAction={(action) => onAgentAction?.(agent, action)}
                    />
                ))}
            </AnimatePresence>
        </motion.div>
    );
};

export default AgentHealthGrid;

import React from 'react';
import { InspectorLayout } from '../ui/InspectorLayout';
import { useInspector } from '../../hooks/useInspector';
import { Asset, UserProfile, Supplier, BusinessProcess } from '../../types';
import { AssetFormData } from '../../schemas/assetSchema';
import { AssetForm } from './AssetForm';
import { RelationshipGraph } from '../RelationshipGraph';
import { AssetAIAssistant } from './AssetAIAssistant';
import { DiscussionPanel } from '../collaboration/DiscussionPanel';
import { AssetInspectorSecurity } from './inspector/AssetInspectorSecurity';
import { AssetInspectorLifecycle } from './inspector/AssetInspectorLifecycle';
import { AssetInspectorCompliance } from './inspector/AssetInspectorCompliance';
import { AssetInspectorProjects } from './inspector/AssetInspectorProjects';
import { AssetInspectorAudits } from './inspector/AssetInspectorAudits';
import { AssetInspectorDocuments } from './inspector/AssetInspectorDocuments';
import { AssetInspectorHistory } from './inspector/AssetInspectorHistory';
import { AgentDownloadModal } from './AgentDownloadModal';
import { useAssetDetails } from '../../hooks/assets/useAssetDetails';
import { useAssetSecurity } from '../../hooks/assets/useAssetSecurity';
import { useStore } from '../../store';
import { canDeleteResource } from '../../utils/permissions';
import { Trash2 } from '../ui/Icons';
import {
    ShieldAlert,
    FolderKanban, CheckSquare,
    FileText, History, Plus, Server
} from '../ui/Icons';
import { Tooltip as CustomTooltip } from '../ui/Tooltip';
import { useNavigate } from 'react-router-dom';
import { LayoutDashboard, RefreshCw, Shield, Network, BrainCircuit, MessageSquare } from '../ui/Icons';
import { getUserAvatarUrl } from '../../utils/avatarUtils';

interface AssetInspectorProps {
    isOpen: boolean;
    onClose: () => void;
    selectedAsset?: Asset | null;
    onUpdate: (id: string, data: AssetFormData) => Promise<boolean | string>;
    onCreate: (data: AssetFormData) => Promise<boolean | string>;
    users: UserProfile[];
    suppliers: Supplier[];
    processes: BusinessProcess[];
    canEdit: boolean;
    onDelete: (id: string, name: string) => void;
}

export const AssetInspector: React.FC<AssetInspectorProps> = ({
    isOpen,
    onClose,
    selectedAsset,
    onUpdate,
    onCreate,
    users,
    suppliers,
    processes,
    canEdit,
    onDelete
}) => {
    const { user, t } = useStore();
    const canDelete = React.useMemo(() => {
        if (!user) return false;
        return canDeleteResource(user, 'Asset');
    }, [user]);

    const handleDelete = () => {
        if (selectedAsset && onDelete) {
            onDelete(selectedAsset.id, selectedAsset.name);
        }
    };

    const navigate = useNavigate();

    // Memoize tabs configuration
    const tabs = React.useMemo(() => {
        const baseTabs = [{ id: 'details', label: 'Détails', icon: LayoutDashboard }];
        if (!selectedAsset) return baseTabs;

        return [
            ...baseTabs,
            { id: 'lifecycle', label: 'Cycle de Vie', icon: RefreshCw },
            { id: 'security', label: 'Sécurité', icon: ShieldAlert },
            { id: 'compliance', label: 'Conformité', icon: Shield },
            { id: 'projects', label: 'Projets', icon: FolderKanban },
            { id: 'audits', label: 'Audits', icon: CheckSquare },
            { id: 'documents', label: 'Documents', icon: FileText },
            { id: 'history', label: 'Historique', icon: History },
            { id: 'graph', label: 'Graphe', icon: Network },
            { id: 'intelligence', label: 'Intelligence', icon: BrainCircuit },
            { id: 'comments', label: 'Discussion', icon: MessageSquare }
        ];
    }, [selectedAsset]);

    // Agent Download Modal State
    const [showAgentModal, setShowAgentModal] = React.useState(false);
    const [createdAssetName, setCreatedAssetName] = React.useState<string>('');
    const [isFormDirty, setIsFormDirty] = React.useState(false);
    const [isSubmitting, setIsSubmitting] = React.useState(false);

    // Use standardized Inspector hook
    const {
        activeTab,
        setActiveTab,
        handleUpdate: handleHookUpdate,
        handleCreate: handleHookCreate
    } = useInspector({
        entity: selectedAsset || null,
        tabs,
        moduleName: 'Asset',
        actions: {
            onUpdate: async (id, data) => {
                setIsSubmitting(true);
                try {
                    const result = await onUpdate(id, data as AssetFormData);
                    if (result) setIsFormDirty(false);
                    return result;
                } finally {
                    setIsSubmitting(false);
                }
            },
            onCreate: async (data) => {
                setIsSubmitting(true);
                const formData = data as AssetFormData;
                try {
                    const result = await onCreate(formData);

                    if (result === true || typeof result === 'string') {
                        setIsFormDirty(false);
                        // Check if IT Asset to propose agent
                        // Check if IT Asset to propose agent
                        if (formData.type === 'Matériel') {
                            setCreatedAssetName(formData.name);
                            setShowAgentModal(true);
                            // Do NOT close inspector immediately to allow modal to show
                            // Inspector will be closed when user dismisses modal or downloads
                        } else {
                            onClose();
                        }
                    }
                    return result;
                } finally {
                    setIsSubmitting(false);
                }
            },
            onDelete: async (id, name) => onDelete(id, name)
        },
        getEntityName: (asset) => asset.name
    });

    const handleDownloadAgent = () => {
        // Now handled inside the modal for simulation, but we ensure state is cleared
        setShowAgentModal(false);
        onClose();
    };

    const handleCloseAgentModal = () => {
        setShowAgentModal(false);
        onClose();
    };

    const {
        maintenanceRecords,
        linkedRisks,
        linkedIncidents,
        linkedProjects,
        linkedAudits,
        linkedDocuments,
        linkedControls,
        addMaintenance
    } = useAssetDetails(selectedAsset || null);

    const {
        scanning,
        shodanResult,
        vulnerabilities,
        scanShodan,
        checkCVEs,
        createRiskFromVuln
    } = useAssetSecurity(selectedAsset || null);

    // Optimized subtitle data
    const ownerInfo = React.useMemo(() => {
        if (!selectedAsset) return null;
        const ownerUser = users?.find(u => u.displayName === selectedAsset.owner || u.email === selectedAsset.owner);
        return {
            avatar: getUserAvatarUrl(ownerUser?.photoURL, ownerUser?.role),
            name: selectedAsset.owner
        };
    }, [selectedAsset, users]);

    // Tabs defined above for both hook and render


    return (
        <InspectorLayout
            isOpen={isOpen}
            onClose={onClose}
            title={selectedAsset ? selectedAsset.name : "Nouvel Actif"}
            subtitle={
                selectedAsset && ownerInfo ? (
                    <div className="flex items-center gap-2 mt-1">
                        <span>{selectedAsset.type}</span>
                        <span className="text-muted-foreground">•</span>
                        <div className="flex items-center gap-1.5">
                            <img
                                src={ownerInfo.avatar}
                                alt=""
                                className="w-4 h-4 rounded-full object-cover bg-muted/30"
                                onError={(e) => {
                                    const target = e.target as HTMLImageElement;
                                    target.src = getUserAvatarUrl(null, 'user');
                                }}
                            />
                            <span>{ownerInfo.name}</span>
                        </div>
                    </div>
                ) : "Ajouter un nouvel actif à l'inventaire"
            }
            icon={selectedAsset ? Server : Plus}
            statusBadge={selectedAsset ? (
                <div className="flex gap-2 items-center">
                    <span className={`px-2 py-0.5 rounded text-xs font-bold uppercase tracking-wider ${selectedAsset.lifecycleStatus === 'En service' ? 'bg-success/10 text-success' : 'bg-muted text-muted-foreground'}`}>
                        {selectedAsset.lifecycleStatus || 'Neuf'}
                    </span>
                    {canDelete && selectedAsset && (
                        <CustomTooltip content={t('assets.deleteAssetTooltip')}>
                            <button
                                onClick={(e) => { e.stopPropagation(); handleDelete(); }}
                                className="p-1.5 text-muted-foreground hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-900/30 dark:hover:bg-red-900/20 rounded-lg transition-colors"
                            >
                                <Trash2 className="h-4 w-4" />
                            </button>
                        </CustomTooltip>
                    )}
                </div>
            ) : null}
            tabs={tabs}
            activeTab={activeTab}
            onTabChange={setActiveTab}
            hasUnsavedChanges={isFormDirty}
        >

            <AgentDownloadModal
                isOpen={showAgentModal}
                onClose={handleCloseAgentModal}
                onDownload={handleDownloadAgent}
                assetName={createdAssetName}
            />

            <div className="space-y-8 max-w-7xl mx-auto">
                {activeTab === 'details' && (
                    <div className="space-y-6 sm:space-y-8">
                        <AssetForm
                            initialData={selectedAsset || undefined}
                            onSubmit={async (data) => {
                                if (selectedAsset) {
                                    await handleHookUpdate(data);
                                } else {
                                    await handleHookCreate(data);
                                }
                            }}
                            usersList={users}
                            suppliers={suppliers}
                            isEditing={!!selectedAsset}
                            onCancel={onClose}
                            readOnly={!canEdit}
                            onDirtyChange={setIsFormDirty}
                            isLoading={isSubmitting}
                        />

                    </div>
                )}

                {activeTab === 'lifecycle' && selectedAsset && (
                    <AssetInspectorLifecycle
                        selectedAsset={selectedAsset}
                        maintenanceRecords={maintenanceRecords}
                        addMaintenance={addMaintenance}
                        canEdit={canEdit}
                    />
                )}

                {activeTab === 'security' && selectedAsset && (
                    <AssetInspectorSecurity
                        selectedAsset={selectedAsset}
                        scanning={scanning}
                        shodanResult={shodanResult}
                        vulnerabilities={vulnerabilities}
                        linkedRisks={linkedRisks}
                        linkedIncidents={linkedIncidents}
                        scanShodan={scanShodan}
                        checkCVEs={checkCVEs}
                        createRiskFromVuln={createRiskFromVuln}
                        navigate={navigate}
                    />
                )}

                {activeTab === 'compliance' && selectedAsset && (
                    <AssetInspectorCompliance
                        selectedAsset={selectedAsset}
                        linkedControls={linkedControls}
                        processes={processes}
                    />
                )}

                {activeTab === 'projects' && selectedAsset && (
                    <AssetInspectorProjects
                        selectedAsset={selectedAsset}
                        linkedProjects={linkedProjects}
                    />
                )}

                {activeTab === 'audits' && selectedAsset && (
                    <AssetInspectorAudits
                        linkedAudits={linkedAudits}
                    />
                )}

                {activeTab === 'documents' && selectedAsset && (
                    <AssetInspectorDocuments
                        linkedDocuments={linkedDocuments}
                    />
                )}

                {activeTab === 'history' && selectedAsset && (
                    <AssetInspectorHistory
                        selectedAsset={selectedAsset}
                    />
                )}

                {activeTab === 'graph' && selectedAsset && (
                    <div className="h-[500px]">
                        <RelationshipGraph rootId={selectedAsset.id} rootType="Asset" />
                    </div>
                )}

                {activeTab === 'intelligence' && selectedAsset && (
                    <div className="h-full overflow-y-auto p-6">
                        <AssetAIAssistant
                            asset={selectedAsset}
                            onUpdate={(updates) => handleHookUpdate(updates)}
                        />
                    </div>
                )}

                {activeTab === 'comments' && selectedAsset && (
                    <div className="h-full">
                        <DiscussionPanel
                            collectionName="assets"
                            documentId={selectedAsset.id}
                            title={`Discussion - ${selectedAsset.name}`}
                            enableSearch={true}
                            enableFilters={true}
                            enableExport={true}
                            enableNotifications={true}
                        />
                    </div>
                )}
            </div>
        </InspectorLayout>
    );
};

import React, { useMemo } from 'react';
