/**
 * DashboardEditModeToggle Component
 * Controls for entering/exiting dashboard edit mode and reset to defaults
 *
 * Story 2-6: Configurable Dashboard Widgets
 * Implements Task 4: Edit mode UI (AC: 1, 5)
 */

import { useState } from 'react';
import { cn } from '../../lib/utils';
import { useTranslation } from 'react-i18next';
import { Pencil, Check, RotateCcw, AlertTriangle } from '../ui/Icons';

export interface DashboardEditModeToggleProps {
  /** Current edit mode state */
  isEditing: boolean;
  /** Callback when edit mode changes */
  onEditModeChange: (isEditing: boolean) => void;
  /** Callback when reset is requested */
  onReset: () => void;
  /** Whether the layout is customized (different from defaults) */
  isCustomized?: boolean;
  /** Whether layout is syncing to server */
  isSyncing?: boolean;
  /** Additional CSS classes */
  className?: string;
  /** Size variant */
  size?: 'sm' | 'md';
}

/**
 * Reset confirmation dialog
 */
function ResetConfirmDialog({
  isOpen,
  onConfirm,
  onCancel,
}: {
  isOpen: boolean;
  onConfirm: () => void;
  onCancel: () => void;
}) {
  const { t } = useTranslation();

  if (!isOpen) return null;

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/50"
      role="presentation"
      onClick={onCancel}
    >
      <div
        className="bg-background rounded-xl shadow-2xl p-6 max-w-sm mx-4 border border-muted"
        onClick={(e) => e.stopPropagation()}
        onKeyDown={(e) => {
          if (e.key === 'Escape') onCancel();
        }}
      >
        <div className="flex items-center gap-3 mb-4">
          <div className="p-2 bg-warning/10 rounded-full">
            <AlertTriangle className="w-5 h-5 text-warning" />
          </div>
          <h3
            id="reset-confirm-title"
            className="text-lg font-semibold text-foreground"
          >
            {t('dashboard.resetToDefaults')}
          </h3>
        </div>

        <p className="text-sm text-muted-foreground mb-6">
          {t('dashboard.resetConfirm')}
        </p>

        <div className="flex gap-3 justify-end">
          <button
            type="button"
            onClick={onCancel}
            className={cn(
              'px-4 py-2 rounded-lg text-sm font-medium',
              'text-foreground',
              'bg-muted',
              'hover:bg-muted/80',
              'transition-colors focus:outline-none focus:ring-2 focus:ring-slate-500 focus:ring-offset-2'
            )}
          >
            {t('common.cancel')}
          </button>
          <button
            type="button"
            onClick={onConfirm}
            className={cn(
              'px-4 py-2 rounded-lg text-sm font-medium',
              'text-white bg-warning hover:bg-warning/80',
              'transition-colors focus:outline-none focus:ring-2 focus:ring-orange-500 focus:ring-offset-2'
            )}
          >
            {t('dashboard.resetToDefaults')}
          </button>
        </div>
      </div>
    </div>
  );
}

/**
 * DashboardEditModeToggle - Edit mode controls for configurable dashboard
 *
 * @example
 * ```tsx
 * <DashboardEditModeToggle
 *   isEditing={isEditing}
 *   onEditModeChange={setIsEditing}
 *   onReset={handleReset}
 *   isCustomized={isCustomized}
 * />
 * ```
 */
export function DashboardEditModeToggle({
  isEditing,
  onEditModeChange,
  onReset,
  isCustomized = false,
  isSyncing = false,
  className,
  size = 'md',
}: DashboardEditModeToggleProps) {
  const { t } = useTranslation();
  const [showResetConfirm, setShowResetConfirm] = useState(false);

  const sizeClasses = {
    sm: 'text-xs px-3 py-1.5 gap-1.5',
    md: 'text-sm px-4 py-2 gap-2',
  };

  const iconSize = size === 'sm' ? 'w-3.5 h-3.5' : 'w-4 h-4';

  const handleReset = () => {
    onReset();
    setShowResetConfirm(false);
    onEditModeChange(false);
  };

  return (
    <>
      <div
        className={cn('flex items-center gap-2', className)}
        role="toolbar"
        aria-label={t('dashboard.editMode')}
      >
        {/* Reset button - only show in edit mode and if customized */}
        {isEditing && isCustomized && (
          <button
            type="button"
            onClick={() => setShowResetConfirm(true)}
            className={cn(
              'inline-flex items-center rounded-full font-medium transition-all duration-200',
              'text-slate-500 hover:text-slate-900 hover:bg-slate-100',
              'dark:text-slate-300 dark:hover:text-white dark:hover:bg-white/10',
              'focus:outline-none focus:ring-2 focus:ring-slate-500 focus:ring-offset-2',
              sizeClasses[size]
            )}
            aria-label={t('dashboard.resetToDefaults')}
          >
            <RotateCcw className={cn(iconSize, "transition-transform group-hover:-rotate-180")} aria-hidden="true" />
            <span className="hidden sm:inline">{t('dashboard.resetToDefaults')}</span>
          </button>
        )}

        {/* Sync indicator */}
        {isEditing && isSyncing && (
          <span
            className={cn(
              'flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium',
              'bg-slate-100 text-slate-500',
              'dark:bg-white/5 dark:text-slate-300'
            )}
            aria-live="polite"
          >
            <div className="w-1.5 h-1.5 rounded-full bg-blue-500 animate-pulse" />
            <span className="hidden sm:inline">{t('common.saving')}</span>
          </span>
        )}

        {/* Main toggle button */}
        <button
          type="button"
          onClick={() => onEditModeChange(!isEditing)}
          className={cn(
            'group inline-flex items-center gap-2 rounded-full font-semibold transition-all duration-200 border',
            isEditing
              ? [
                'border-blue-500/20 bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400',
                'dark:border-blue-400/20 dark:bg-blue-400/10 dark:text-blue-400',
                'hover:bg-blue-500/20 dark:hover:bg-blue-400/20',
                'focus:ring-blue-500',
              ]
              : [
                'border-slate-200 bg-white text-slate-700 dark:text-slate-300 shadow-sm',
                'dark:border-white/10 dark:bg-white/5 dark:text-slate-200',
                'hover:bg-slate-50 dark:hover:bg-white/10 hover:border-slate-300 dark:hover:border-white/20',
                'focus:ring-slate-500',
              ],
            'focus:outline-none focus:ring-2 focus:ring-offset-2',
            sizeClasses[size]
          )}
          aria-pressed={isEditing}
          aria-label={
            isEditing ? t('dashboard.doneEditing') : t('dashboard.customize')
          }
        >
          {isEditing ? (
            <>
              <Check className={iconSize} strokeWidth={2.5} aria-hidden="true" />
              <span>{t('dashboard.doneEditing')}</span>
            </>
          ) : (
            <>
              <Pencil className={cn(iconSize, "text-slate-400 group-hover:text-slate-600 dark:text-slate-400 dark:group-hover:text-slate-300 transition-colors")} aria-hidden="true" />
              <span>{t('dashboard.customize')}</span>
            </>
          )}
        </button>
      </div>

      {/* Reset confirmation dialog */}
      <ResetConfirmDialog
        isOpen={showResetConfirm}
        onConfirm={handleReset}
        onCancel={() => setShowResetConfirm(false)}
      />
    </>
  );
}

export default DashboardEditModeToggle;

/**
 * KPICard Component
 * Displays a single KPI with large number, title, trend indicator
 * Implements ADR-004: Dashboard Configurable par Role
 * Per FR7: Uses simple language without ISO jargon
 */

import React, { useMemo } from 'react';
import { cn } from '../../lib/utils';
import type { TrendType } from '../../types/score.types';
import {
  type KPIColorScheme,
  KPI_COLOR_CLASSES,
  getTrendLabel,
} from '../../config/kpiConfig';

/**
 * TrendArrow component for displaying trend direction
 * @param invertColors - When true, UP is red (bad) and DOWN is green (good)
 *                       Use this for metrics where lower is better (e.g., risk count)
 */
function TrendArrow({
  trend,
  className,
  invertColors = false,
}: {
  trend: TrendType;
  className?: string;
  invertColors?: boolean;
}) {
  // Determine colors based on trend and inversion
  // Default: UP = green (good), DOWN = red (bad) - for metrics where higher is better
  // Inverted: UP = red (bad), DOWN = green (good) - for metrics where lower is better
  const upColor = invertColors ? 'text-destructive' : 'text-success';
  const downColor = invertColors ? 'text-success' : 'text-destructive';

  if (trend === 'stable') {
    return (
      <svg
        className={cn('w-5 h-5 text-muted-foreground', className)}
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth={2}
        strokeLinecap="round"
        strokeLinejoin="round"
        aria-hidden="true"
      >
        <path d="M5 12h14" />
      </svg>
    );
  }

  if (trend === 'up') {
    return (
      <svg
        className={cn('w-5 h-5', upColor, className)}
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth={2}
        strokeLinecap="round"
        strokeLinejoin="round"
        aria-hidden="true"
      >
        <path d="M18 15l-6-6-6 6" />
      </svg>
    );
  }

  return (
    <svg
      className={cn('w-5 h-5', downColor, className)}
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth={2}
      strokeLinecap="round"
      strokeLinejoin="round"
      aria-hidden="true"
    >
      <path d="M6 9l6 6 6-6" />
    </svg>
  );
}

export interface KPICardProps {
  /** Simple French label (no jargon) */
  title: string;
  /** Large number display */
  value: number | string;
  /** Additional context text */
  subtitle?: string;
  /** Trend direction */
  trend?: TrendType;
  /** Change percentage for trend */
  trendValue?: number;
  /** Color scheme based on status */
  colorScheme?: KPIColorScheme;
  /** Card size variant */
  size?: 'sm' | 'md' | 'lg';
  /** Additional CSS classes */
  className?: string;
  /** Click handler */
  onClick?: () => void;
  /** Loading state */
  loading?: boolean;
  /** Invert trend colors (use for metrics where lower is better, e.g., risk count) */
  invertTrendColors?: boolean;
}

/**
 * Size configurations for KPICard
 */
const SIZE_CONFIG = {
  sm: {
    value: 'text-xl',
    title: 'text-xs',
    subtitle: 'text-[11px]',
    padding: 'p-3',
    minWidth: 'min-w-[120px]',
  },
  md: {
    value: 'text-2xl',
    title: 'text-sm',
    subtitle: 'text-xs',
    padding: 'p-4',
    minWidth: 'min-w-[160px]',
  },
  lg: {
    value: 'text-3xl',
    title: 'text-base',
    subtitle: 'text-sm',
    padding: 'p-5',
    minWidth: 'min-w-[200px]',
  },
} as const;

/**
 * Gradient overlays by color scheme for visual differentiation
 */
const GRADIENT_BY_SCHEME: Record<KPIColorScheme, string> = {
  success: 'bg-gradient-to-br from-success/5 via-transparent to-transparent',
  warning: 'bg-gradient-to-br from-warning/5 via-transparent to-transparent',
  danger: 'bg-gradient-to-br from-destructive/5 via-transparent to-transparent',
  neutral: 'bg-gradient-to-br from-primary/3 via-transparent to-transparent',
};

/**
 * KPICard - Displays a single KPI metric
 *
 * @example
 * ```tsx
 * <KPICard
 *   title="Sante Conformite"
 *   value={75}
 *   subtitle="Score global"
 *   trend="up"
 *   colorScheme="success"
 * />
 * ```
 */
export const KPICard = React.memo(function KPICard({
  title,
  value,
  subtitle,
  trend,
  trendValue,
  colorScheme = 'neutral',
  size = 'md',
  className,
  onClick,
  loading = false,
  invertTrendColors = false,
}: KPICardProps) {
  const sizeConfig = SIZE_CONFIG[size];
  const colorClasses = KPI_COLOR_CLASSES[colorScheme];

  // Accessible label for trend
  const trendAriaLabel = useMemo(() => {
    if (!trend) return undefined;
    return getTrendLabel(trend, trendValue);
  }, [trend, trendValue]);

  // Loading skeleton
  if (loading) {
    return (
      <div
        className={cn(
          'rounded-2xl border bg-card',
          sizeConfig.padding,
          sizeConfig.minWidth,
          'animate-pulse',
          className
        )}
      >
        <div className="flex flex-col gap-2">
          <div className="h-4 w-4 bg-muted rounded" />
          <div className="h-10 w-20 bg-muted rounded" />
          <div className="h-5 w-24 bg-muted rounded" />
          <div className="h-4 w-32 bg-muted rounded" />
        </div>
      </div>
    );
  }

  const gradientClass = GRADIENT_BY_SCHEME[colorScheme];

  return (
    <div
      className={cn(
        'relative overflow-hidden rounded-2xl border bg-card transition-all duration-200',
        colorClasses.bgLight,
        colorClasses.border,
        sizeConfig.padding,
        sizeConfig.minWidth,
        onClick && 'cursor-pointer hover:shadow-md hover:scale-[1.02] hover:shadow-glow',
        className
      )}
      onClick={onClick}
      role={onClick ? 'button' : undefined}
      tabIndex={onClick ? 0 : undefined}
      onKeyDown={
        onClick
          ? (e) => {
            if (e.key === 'Enter' || e.key === ' ') {
              e.preventDefault();
              onClick();
            }
          }
          : undefined
      }
      aria-label={`${title}: ${value}${subtitle ? `, ${subtitle}` : ''}${trendAriaLabel ? `, ${trendAriaLabel}` : ''}`}
    >
      {/* Gradient overlay for visual differentiation */}
      <div className={cn('absolute inset-0 pointer-events-none', gradientClass)} />

      <div className="relative flex flex-col">
        {/* Trend Arrow */}
        {trend && (
          <div className="flex items-center gap-1 mb-1">
            <TrendArrow trend={trend} invertColors={invertTrendColors} />
            {trendValue !== undefined && (
              <span
                className={cn(
                  'text-xs font-medium',
                  trend === 'up' && (invertTrendColors ? 'text-destructive' : 'text-success'),
                  trend === 'down' && (invertTrendColors ? 'text-success' : 'text-destructive'),
                  trend === 'stable' && 'text-muted-foreground'
                )}
              >
                {trend !== 'stable' && (trend === 'up' ? '+' : '-')}
                {Math.abs(trendValue)}%
              </span>
            )}
            <span className="sr-only">{trendAriaLabel}</span>
          </div>
        )}

        {/* Value - Large and prominent */}
        <div
          className={cn(
            'font-bold tabular-nums',
            sizeConfig.value,
            colorClasses.text
          )}
        >
          {value}
        </div>

        {/* Title - Simple language */}
        <div
          className={cn(
            'font-semibold text-foreground mt-1',
            sizeConfig.title
          )}
        >
          {title}
        </div>

        {/* Subtitle - Additional context */}
        {subtitle && (
          <div
            className={cn(
              'text-muted-foreground mt-0.5',
              sizeConfig.subtitle
            )}
          >
            {subtitle}
          </div>
        )}
      </div>
    </div>
  );
});

