interface PremiumHealthCardProps {
    stats: {
        totalRisks: number;
        highRisks: number;
        criticalRisks: number;
        compliance: number;
        financialRisk: number;
        assetValue: number;
    };
    complianceScore: number;
    activeIncidentsCount: number;
