import React, { useState } from 'react';
import { Document, UserProfile } from '../../types';
import { useDocumentWorkflow } from '../../hooks/useDocumentWorkflow';
import { useStore } from '../../store';
import { CheckCircle2, XCircle, Send, ShieldCheck } from '../ui/Icons';
import { motion } from 'framer-motion';

interface ApprovalFlowProps {
    document: Document;
    users: UserProfile[]; // For selecting reviewers
    onPublish?: () => void;
}

export const ApprovalFlow: React.FC<ApprovalFlowProps> = ({ document, users, onPublish }) => {
    const { user } = useStore();
    const { submitForReview, approveDocument, rejectDocument, publishDocument, loading } = useDocumentWorkflow();

    // Local state for actions
    const [comment, setComment] = useState('');
    const [selectedReviewers, setSelectedReviewers] = useState<string[]>([]);
    const [actionView, setActionView] = useState<'none' | 'submit' | 'reject'>('none');

    // Safe array access
    const safeUsers = users ?? [];

    // Timeline sorting
    const history = [...(document.workflowHistory || [])].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

    const isOwner = user?.uid === document.ownerId || user?.displayName === document.owner; // Fallback to name if ID missing
    const isReviewer = document.reviewers?.includes(user?.uid || '');
    const isDraft = document.status === 'Brouillon';
    const isInReview = document.status === 'En revue';
    const isApproved = document.status === 'Approuvé';

    const handleSubmit = async () => {
        // In a real app, validation of selectedReviewers
        await submitForReview(document, selectedReviewers, comment);
        setActionView('none');
        setComment('');
    };

    const handleReject = async () => {
        if (!comment) return;
        await rejectDocument(document, comment);
        setActionView('none');
        setComment('');
    };

    return (
        <div className="space-y-6">
            {/* Header / Actions Area */}
            <div className="bg-slate-50 dark:bg-slate-900/50 p-4 rounded-xl border border-slate-200 dark:border-slate-800">
                <h3 className="text-sm font-bold text-slate-900 dark:text-white mb-4 flex items-center gap-2">
                    <ShieldCheck className="h-4 w-4 text-brand-500" />
                    Flux de Validation
                </h3>

                {/* ACTION BUTTONS */}
                <div className="flex flex-wrap gap-2 mb-4">
                    {/* SUBMIT (Owner + Draft) */}
                    {isOwner && isDraft && (
                        <button
                            aria-label="Soumettre le document pour revue"
                            onClick={() => setActionView(actionView === 'submit' ? 'none' : 'submit')}
                            className="flex items-center px-3 py-1.5 bg-brand-600 text-white text-xs font-bold rounded-lg hover:bg-brand-700 transition focus:outline-none focus-visible:ring-2 focus-visible:ring-brand-500 focus-visible:ring-offset-2"
                        >
                            <Send className="h-3.5 w-3.5 mr-1.5" />
                            Soumettre pour revue
                        </button>
                    )}

                    {/* REVIEW (Reviewer + In Review) */}
                    {isReviewer && isInReview && (
                        <>
                            <button
                                aria-label="Approuver le document"
                                onClick={() => approveDocument(document)}
                                disabled={loading}
                                className="flex items-center px-3 py-1.5 bg-success-600 text-white text-xs font-bold rounded-lg hover:bg-success-700 transition focus:outline-none focus-visible:ring-2 focus-visible:ring-success-500 focus-visible:ring-offset-2"
                            >
                                <CheckCircle2 className="h-3.5 w-3.5 mr-1.5" />
                                Approuver
                            </button>
                            <button
                                aria-label="Rejeter le document"
                                onClick={() => setActionView(actionView === 'reject' ? 'none' : 'reject')}
                                className="flex items-center px-3 py-1.5 bg-red-600 text-white text-xs font-bold rounded-lg hover:bg-red-700 transition focus:outline-none focus-visible:ring-2 focus-visible:ring-red-500 focus-visible:ring-offset-2"
                            >
                                <XCircle className="h-3.5 w-3.5 mr-1.5" />
                                Rejeter
                            </button>
                        </>
                    )}

                    {/* PUBLISH (Owner + Approved) */}
                    {isOwner && isApproved && (
                        <button
                            aria-label="Publier officiellement le document"
                            onClick={() => onPublish ? onPublish() : publishDocument(document)}
                            disabled={loading}
                            className="flex items-center px-3 py-1.5 bg-blue-600 text-white text-xs font-bold rounded-lg hover:bg-blue-700 transition focus:outline-none focus-visible:ring-2 focus-visible:ring-blue-500 focus-visible:ring-offset-2"
                        >
                            <Send className="h-3.5 w-3.5 mr-1.5" />
                            Publier Officiellement
                        </button>
                    )}
                </div>

                {/* INTERACTIVE FORMS */}
                {actionView === 'submit' && (
                    <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} className="space-y-3 bg-white dark:bg-slate-800 p-3 rounded-lg border border-slate-200 dark:border-slate-700">
                        <div>
                            <label className="text-xs font-medium text-slate-700 dark:text-slate-300 block mb-1">Sélectionner les réviseurs</label>
                            <select
                                aria-label="Sélectionner les réviseurs"
                                multiple
                                className="w-full text-sm bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-md p-2 min-h-[80px] focus:outline-none focus-visible:ring-2 focus-visible:ring-brand-500"
                                onChange={(e) => setSelectedReviewers(Array.from(e.target.selectedOptions, option => option.value))}
                            >
                                {safeUsers.filter(u => u.uid !== user?.uid).map(u => (
                                    <option key={u.uid} value={u.uid}>{u.displayName || u.email}</option>
                                ))}
                            </select>
                            <p className="text-[11px] text-slate-500 dark:text-slate-300 mt-1">Maintenez Ctrl/Cmd pour sélectionner plusieurs.</p>
                        </div>
                        <input value={comment} onChange={(e) => setComment(e.target.value)}
                            aria-label="Message pour les réviseurs"
                            type="text"
                            placeholder="Message pour les réviseurs..."
                            className="w-full text-sm bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-md p-2 focus:outline-none focus-visible:ring-2 focus-visible:ring-brand-500"
                        />
                        <div className="flex justify-end gap-2">
                            <button aria-label="Annuler la soumission" onClick={() => setActionView('none')} className="text-xs text-muted-foreground hover:text-foreground px-2 py-1 focus:outline-none focus-visible:ring-2 focus-visible:ring-slate-500 rounded">Annuler</button>
                            <button aria-label="Confirmer la soumission" onClick={handleSubmit} disabled={loading || selectedReviewers.length === 0} className="px-3 py-1.5 bg-brand-600 text-white text-xs font-bold rounded-lg hover:bg-brand-700 disabled:bg-slate-200 disabled:text-slate-500 dark:disabled:bg-slate-700 dark:disabled:text-slate-400 focus:outline-none focus-visible:ring-2 focus-visible:ring-brand-500 focus-visible:ring-offset-2">Confirmer</button>
                        </div>
                    </motion.div>
                )}

                {actionView === 'reject' && (
                    <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} className="space-y-3 bg-white dark:bg-slate-800 p-3 rounded-lg border border-red-200 dark:border-red-800 dark:border-red-900/30">
                        <textarea
                            aria-label="Raison du rejet"
                            placeholder="Raison du rejet (obligatoire)..."
                            className="w-full text-sm bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-md p-2 focus:outline-none focus-visible:ring-2 focus-visible:ring-red-500"
                            value={comment}
                            onChange={(e) => setComment(e.target.value)}
                        />
                        <div className="flex justify-end gap-2">
                            <button aria-label="Annuler le rejet" onClick={() => setActionView('none')} className="text-xs text-muted-foreground hover:text-foreground px-2 py-1 focus:outline-none focus-visible:ring-2 focus-visible:ring-slate-500 rounded">Annuler</button>
                            <button aria-label="Confirmer le rejet" onClick={handleReject} disabled={loading || !comment} className="px-3 py-1.5 bg-red-600 text-white text-xs font-bold rounded-lg hover:bg-red-700 disabled:bg-slate-200 disabled:text-slate-500 dark:disabled:bg-slate-700 dark:disabled:text-slate-400 focus:outline-none focus-visible:ring-2 focus-visible:ring-red-500 focus-visible:ring-offset-2">Confirmer le Rejet</button>
                        </div>
                    </motion.div>
                )}
            </div>

            {/* TIMELINE */}
            <div className="relative pl-6 border-l-2 border-slate-200 dark:border-slate-800 space-y-6">
                {history.length === 0 && (
                    <div className="text-sm text-slate-500 dark:text-slate-300 italic pl-2">Aucun historique de workflow.</div>
                )}
                {history.map((item) => (
                    <div key={item.id} className="relative">
                        <div className={`absolute -left-[31px] w-4 h-4 rounded-full border-2 border-white dark:border-slate-900 ${item.action === 'approuver' || item.action === 'publier' ? 'bg-success-500' :
                            item.action === 'rejeter' ? 'bg-error-500' : 'bg-brand-500'
                            }`}></div>

                        <div className="flex items-start justify-between">
                            <div>
                                <span className={`text-xs font-bold px-2 py-0.5 rounded-full ${item.action === 'approuver' ? 'bg-success-100 text-success-700 dark:bg-success-900/30 dark:text-success-400' :
                                    item.action === 'publier' ? 'bg-info-100 text-info-700 dark:bg-info-900/30 dark:text-info-400' :
                                        item.action === 'rejeter' ? 'bg-error-100 text-error-700 dark:bg-error-900/30 dark:text-error-400' :
                                            'bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-300'
                                    }`}>
                                    {item.action.toUpperCase()}
                                </span>
                                <div className="mt-1 text-sm text-slate-900 dark:text-white font-medium">
                                    {item.userName}
                                </div>
                                {item.comment && (
                                    <div className="mt-1 text-sm text-slate-600 dark:text-slate-300 bg-slate-50 dark:bg-slate-800/50 p-2 rounded-lg italic">
                                        "{item.comment}"
                                    </div>
                                )}
                            </div>
                            <div className="text-xs text-muted-foreground flex flex-col items-end">
                                <span>{new Date(item.date).toLocaleDateString()}</span>
                                <span>{new Date(item.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                            </div>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

/**
 * Story 27.3 - Document Audit Trail Component
 *
 * Timeline view of document actions with filters, user avatars,
 * action icons, expandable details, and export capabilities.
 */

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import {
  Eye,
  Download,
  Upload,
  Edit,
  Trash2,
  Share2,
  Tag,
  PenTool,
  CheckCircle,
  Lock,
  Unlock,
  XCircle,
  AlertTriangle,
  FileText,
  Activity,
  ChevronDown,
  ChevronUp,
  Filter,
  Calendar,
  // User, // Remove if unused
  RefreshCw,
  FileDown,
  X,
  Loader2,
} from '../ui/Icons';
import { Button } from '../ui/button';
import { VaultAuditService, AuditLogEntry, DocumentAction, AuditFilters } from '@/services/vaultAuditService';
import { getUserAvatarUrl } from '@/utils/avatarUtils';
import { format, formatDistanceToNow } from 'date-fns';
import { fr } from 'date-fns/locale';

interface DocumentAuditTrailProps {
  /** Document ID to show audit trail for (null for organization-wide) */
  documentId?: string | null;
  /** Whether to show organization-wide view (admin only) */
  organizationView?: boolean;
  /** User ID to filter by (optional) */
  userId?: string | null;
  /** Maximum height for scrollable container */
  maxHeight?: string;
  /** Callback when an entry is clicked */
  onEntryClick?: (entry: AuditLogEntry) => void;
  /** Enable real-time updates */
  realtime?: boolean;
  /** Show export buttons */
  showExport?: boolean;
  /** Custom class name */
  className?: string;
}

const iconMap: Record<string, React.ComponentType<{ className?: string }>> = {
  Eye,
  Download,
  Upload,
  Edit,
  Trash2,
  Share2,
  Tag,
  PenTool,
  CheckCircle,
  Lock,
  Unlock,
  XCircle,
  AlertTriangle,
  FileText,
  Activity,
};

export const DocumentAuditTrail: React.FC<DocumentAuditTrailProps> = ({
  documentId,
  organizationView = false,
  userId,
  maxHeight = '600px',
  onEntryClick,
  realtime = false,
  showExport = true,
  className = '',
}) => {
  const [entries, setEntries] = useState<AuditLogEntry[]>([]);
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [expandedEntries, setExpandedEntries] = useState<Set<string>>(new Set());
  const [nextCursor, setNextCursor] = useState<string | null>(null);
  const [hasMore, setHasMore] = useState(false);

  // Filter state
  const [showFilters, setShowFilters] = useState(false);
  const [selectedActions, setSelectedActions] = useState<DocumentAction[]>([]);
  const [dateRange, setDateRange] = useState<{ start: string; end: string }>({
    start: '',
    end: '',
  });
  const [exporting, setExporting] = useState(false);

  // Build filters object
  const filters = useMemo<AuditFilters>(() => {
    const f: AuditFilters = {};
    if (selectedActions.length > 0) {
      f.actions = selectedActions;
    }
    if (dateRange.start) {
      f.startDate = dateRange.start;
    }
    if (dateRange.end) {
      f.endDate = dateRange.end;
    }
    if (userId) {
      f.userId = userId;
    }
    if (documentId) {
      f.documentId = documentId;
    }
    return f;
  }, [selectedActions, dateRange, userId, documentId]);

  // Fetch audit trail
  const fetchAuditTrail = useCallback(async (reset = true) => {
    try {
      if (reset) {
        setLoading(true);
        setError(null);
      } else {
        setLoadingMore(true);
      }

      let result;

      if (documentId) {
        result = await VaultAuditService.getDocumentAuditTrail(documentId, {
          limit: 50,
          startAfter: reset ? undefined : nextCursor || undefined,
          filters,
        });
      } else if (organizationView) {
        result = await VaultAuditService.getOrganizationAuditTrail({
          limit: 50,
          startAfter: reset ? undefined : nextCursor || undefined,
          filters,
        });
      } else if (userId) {
        result = await VaultAuditService.getUserAuditTrail(userId, {
          limit: 50,
          startAfter: reset ? undefined : nextCursor || undefined,
          filters,
        });
      } else {
        // Default to user's own audit trail
        result = await VaultAuditService.getUserAuditTrail(undefined, {
          limit: 50,
          startAfter: reset ? undefined : nextCursor || undefined,
          filters,
        });
      }

      if (result.success) {
        if (reset) {
          setEntries(result.entries);
        } else {
          setEntries(prev => [...prev, ...result.entries]);
        }
        setNextCursor(result.pagination.nextCursor);
        setHasMore(result.pagination.hasMore);
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Erreur lors du chargement');
    } finally {
      setLoading(false);
      setLoadingMore(false);
    }
  }, [documentId, organizationView, userId, filters, nextCursor]);

  // Initial fetch
  useEffect(() => {
    fetchAuditTrail(true);
  }, [fetchAuditTrail]);

  // Real-time updates (polling for simplicity)
  useEffect(() => {
    if (!realtime) return;

    const interval = setInterval(() => {
      fetchAuditTrail(true);
    }, 30000); // Poll every 30 seconds

    return () => clearInterval(interval);
  }, [realtime, fetchAuditTrail]);

  // Toggle entry expansion
  const toggleExpand = (entryId: string) => {
    setExpandedEntries(prev => {
      const next = new Set(prev);
      if (next.has(entryId)) {
        next.delete(entryId);
      } else {
        next.add(entryId);
      }
      return next;
    });
  };

  // Export handler
  const handleExport = async (format: 'csv' | 'json') => {
    try {
      setExporting(true);
      const result = await VaultAuditService.exportAuditTrail(format, filters);
      if (result.success) {
        VaultAuditService.downloadExport(result.data, format, `audit-trail-${Date.now()}.${format}`);
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Erreur lors de l\'export');
    } finally {
      setExporting(false);
    }
  };

  // Get icon component for action
  const getIconComponent = (action: DocumentAction) => {
    const iconName = VaultAuditService.getActionIcon(action);
    return iconMap[iconName] || Activity;
  };

  // Format relative time
  const formatRelativeTime = (timestamp: string | null) => {
    if (!timestamp) return 'N/A';
    try {
      return formatDistanceToNow(new Date(timestamp), { addSuffix: true, locale: fr });
    } catch {
      return timestamp;
    }
  };

  // Format full timestamp
  const formatFullTimestamp = (timestamp: string | null) => {
    if (!timestamp) return 'N/A';
    try {
      return format(new Date(timestamp), 'dd MMM yyyy HH:mm:ss', { locale: fr });
    } catch {
      return timestamp;
    }
  };

  // Clear all filters
  const clearFilters = () => {
    setSelectedActions([]);
    setDateRange({ start: '', end: '' });
  };

  // All available actions
  const allActions = VaultAuditService.getAllActions();

  return (
    <div className={`bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-700 ${className}`}>
      {/* Header */}
      <div className="flex items-center justify-between p-4 border-b border-slate-200 dark:border-slate-700">
        <h3 className="font-semibold text-slate-900 dark:text-white flex items-center gap-2">
          <Activity className="h-5 w-5 text-brand-600" />
          Journal d'Audit
        </h3>
        <div className="flex items-center gap-2">
          <Button
            variant="ghost"
            size="sm"
            onClick={() => fetchAuditTrail(true)}
            disabled={loading}
            className="text-slate-500 hover:text-brand-600"
          >
            <RefreshCw className={`h-4 w-4 ${loading ? 'animate-spin' : ''}`} />
          </Button>
          <Button
            variant="ghost"
            size="sm"
            onClick={() => setShowFilters(!showFilters)}
            className={`text-slate-500 hover:text-brand-600 ${showFilters ? 'bg-brand-50 text-brand-600' : ''}`}
          >
            <Filter className="h-4 w-4" />
          </Button>
          {showExport && (
            <div className="flex items-center gap-1">
              <Button
                variant="ghost"
                size="sm"
                onClick={() => handleExport('csv')}
                disabled={exporting}
                className="text-slate-500 hover:text-brand-600"
                title="Exporter CSV"
              >
                {exporting ? <Loader2 className="h-4 w-4 animate-spin" /> : <FileDown className="h-4 w-4" />}
              </Button>
            </div>
          )}
        </div>
      </div>

      {/* Filters Panel */}
      {showFilters && (
        <div className="p-4 bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-700 space-y-4">
          {/* Action Type Filter */}
          <div>
            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
              Type d'action
            </label>
            <div className="flex flex-wrap gap-2">
              {allActions.map(({ value, label }) => {
                const colors = VaultAuditService.getActionColorClass(value);
                const isSelected = selectedActions.includes(value);
                return (
                  <button
                    key={value}
                    onClick={() => {
                      if (isSelected) {
                        setSelectedActions(prev => prev.filter(a => a !== value));
                      } else {
                        setSelectedActions(prev => [...prev, value]);
                      }
                    }}
                    className={`px-2 py-1 text-xs rounded-full border transition-colors ${isSelected
                      ? `${colors.bg} ${colors.text} ${colors.border}`
                      : 'bg-white dark:bg-slate-700 text-slate-600 dark:text-slate-300 border-slate-200 dark:border-slate-600 hover:border-brand-300'
                      }`}
                  >
                    {label}
                  </button>
                );
              })}
            </div>
          </div>

          {/* Date Range Filter */}
          <div className="flex items-center gap-4">
            <div className="flex-1">
              <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
                <Calendar className="h-3 w-3 inline mr-1" />
                Date debut
              </label>
              <input
                type="date"
                value={dateRange.start}
                onChange={(e) => setDateRange(prev => ({ ...prev, start: e.target.value }))}
                className="w-full px-3 py-2 text-sm border border-slate-200 dark:border-slate-600 rounded-lg bg-white dark:bg-slate-700 text-slate-900 dark:text-white"
              />
            </div>
            <div className="flex-1">
              <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
                <Calendar className="h-3 w-3 inline mr-1" />
                Date fin
              </label>
              <input
                type="date"
                value={dateRange.end}
                onChange={(e) => setDateRange(prev => ({ ...prev, end: e.target.value }))}
                className="w-full px-3 py-2 text-sm border border-slate-200 dark:border-slate-600 rounded-lg bg-white dark:bg-slate-700 text-slate-900 dark:text-white"
              />
            </div>
            {(selectedActions.length > 0 || dateRange.start || dateRange.end) && (
              <Button
                variant="ghost"
                size="sm"
                onClick={clearFilters}
                className="text-slate-500 hover:text-red-600 mt-5"
              >
                <X className="h-4 w-4" />
              </Button>
            )}
          </div>
        </div>
      )}

      {/* Error State */}
      {error && (
        <div className="p-4 bg-red-50 dark:bg-red-950 text-red-600 dark:text-red-400 text-sm">
          {error}
        </div>
      )}

      {/* Loading State */}
      {loading && (
        <div className="flex items-center justify-center py-12">
          <Loader2 className="h-8 w-8 text-brand-600 animate-spin" />
        </div>
      )}

      {/* Empty State */}
      {!loading && entries.length === 0 && (
        <div className="flex flex-col items-center justify-center py-12 text-slate-500">
          <Activity className="h-12 w-12 mb-4 opacity-60" />
          <p className="text-sm">Aucune activite enregistree</p>
          {(selectedActions.length > 0 || dateRange.start || dateRange.end) && (
            <Button variant="ghost" size="sm" onClick={clearFilters} className="mt-2">
              Effacer les filtres
            </Button>
          )}
        </div>
      )}

      {/* Timeline */}
      {!loading && entries.length > 0 && (
        <div className="overflow-y-auto" style={{ maxHeight }}>
          <div className="divide-y divide-slate-100 dark:divide-slate-800">
            {entries.map((entry, index) => {
              const IconComponent = getIconComponent(entry.action);
              const colors = VaultAuditService.getActionColorClass(entry.action);
              const isExpanded = expandedEntries.has(entry.id);

              return (
                <div
                  key={entry.id}
                  className={`p-4 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors ${onEntryClick ? 'cursor-pointer' : ''
                    }`}
                  onClick={() => onEntryClick?.(entry)}
                >
                  <div className="flex items-start gap-4">
                    {/* Timeline connector */}
                    <div className="flex flex-col items-center">
                      <div className={`p-2 rounded-full ${colors.bg} ${colors.border} border`}>
                        <IconComponent className={`h-4 w-4 ${colors.text}`} />
                      </div>
                      {index < entries.length - 1 && (
                        <div className="w-px h-full bg-slate-200 dark:bg-slate-700 mt-2" />
                      )}
                    </div>

                    {/* Content */}
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between gap-2">
                        <div className="flex items-center gap-2">
                          {/* User avatar */}
                          <img
                            src={getUserAvatarUrl(null, 'user')}
                            alt={entry.userEmail}
                            className="w-6 h-6 rounded-full bg-slate-100 dark:bg-slate-800"
                          />
                          <span className="font-medium text-slate-900 dark:text-white text-sm truncate">
                            {entry.userEmail}
                          </span>
                        </div>
                        <span className="text-xs text-slate-500 dark:text-slate-300 whitespace-nowrap" title={formatFullTimestamp(entry.timestamp)}>
                          {formatRelativeTime(entry.timestamp)}
                        </span>
                      </div>

                      <div className="mt-1 flex items-center gap-2">
                        <span className={`inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium ${colors.bg} ${colors.text} ${colors.border} border`}>
                          {VaultAuditService.getActionLabel(entry.action)}
                        </span>
                        {entry.documentId && (
                          <span className="text-xs text-slate-500 dark:text-slate-300 truncate">
                            Document: {entry.documentId.substring(0, 8)}...
                          </span>
                        )}
                      </div>

                      {/* Expandable Details */}
                      {entry.details && Object.keys(entry.details).length > 0 && (
                        <div className="mt-2">
                          <button
                            onClick={(e) => {
                              e.stopPropagation();
                              toggleExpand(entry.id);
                            }}
                            className="text-xs text-brand-600 hover:text-brand-700 flex items-center gap-1"
                          >
                            {isExpanded ? (
                              <>
                                <ChevronUp className="h-3 w-3" />
                                Masquer les details
                              </>
                            ) : (
                              <>
                                <ChevronDown className="h-3 w-3" />
                                Voir les details
                              </>
                            )}
                          </button>

                          {isExpanded && (
                            <div className="mt-2 p-3 bg-slate-50 dark:bg-slate-800 rounded-lg text-xs">
                              <pre className="whitespace-pre-wrap text-slate-600 dark:text-muted-foreground font-mono">
                                {JSON.stringify(entry.details, null, 2)}
                              </pre>
                              {entry.integrity?.hash && (
                                <div className="mt-2 pt-2 border-t border-slate-200 dark:border-slate-700">
                                  <span className="text-slate-500 dark:text-slate-400">Hash d'integrite: </span>
                                  <code className="text-slate-600 dark:text-muted-foreground">
                                    {entry.integrity.hash.substring(0, 16)}...
                                  </code>
                                </div>
                              )}
                              {entry.metadata?.ipAddress && (
                                <div className="mt-1">
                                  <span className="text-slate-500 dark:text-slate-400">IP: </span>
                                  <code className="text-slate-600 dark:text-muted-foreground">
                                    {entry.metadata.ipAddress}
                                  </code>
                                </div>
                              )}
                            </div>
                          )}
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              );
            })}
          </div>

          {/* Load More */}
          {hasMore && (
            <div className="p-4 border-t border-slate-200 dark:border-slate-700">
              <Button
                variant="ghost"
                onClick={() => fetchAuditTrail(false)}
                disabled={loadingMore}
                className="w-full"
              >
                {loadingMore ? (
                  <Loader2 className="h-4 w-4 animate-spin mr-2" />
                ) : null}
                Charger plus
              </Button>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default DocumentAuditTrail;

import React, { useEffect, useState, useCallback } from 'react';
import { useWatch, Controller, FieldErrors } from 'react-hook-form';
import { useZodForm } from '../../hooks/useZodForm';
import { documentSchema, DocumentFormData } from '../../schemas/documentSchema';
import { UserProfile, Control, Asset, Audit, Document, DocumentFolder, Risk } from '../../types';
import { Button } from '../ui/button';
import { FloatingLabelInput } from '../ui/FloatingLabelInput';
import { CustomSelect } from '../ui/CustomSelect';
import { FileUploader } from '../ui/FileUploader';
import { Trash2 } from '../ui/Icons';
import { externalStorageService } from '../../services/externalStorageService';
import { ErrorLogger } from '../../services/errorLogger';
import { useStore } from '../../store';
import { RichTextEditor } from '../ui/RichTextEditor';
import { toast } from '@/lib/toast';
import { useFormPersistence } from '../../hooks/utils/useFormPersistence';

interface DocumentFormProps {
    onSubmit: (data: DocumentFormData & { fileUrl?: string; fileHash?: string; isSecure?: boolean }) => Promise<void>;
    onCancel: () => void;
    initialData?: Document | null;
    users: UserProfile[];
    controls: Control[];
    assets: Asset[];
    audits: Audit[];
    risks: Risk[];
    folders: DocumentFolder[];
    isLoading?: boolean;
    isStorageFull?: boolean;
    onUploadComplete?: (size: number) => void;
}

export const DocumentForm: React.FC<DocumentFormProps> = ({
    onSubmit,
    onCancel,
    initialData,
    users,
    controls,
    assets,
    audits,
    risks,
    folders,
    isLoading = false,
    isStorageFull = false,
    onUploadComplete
}) => {
    const { addToast } = useStore();
    const [uploadedFileUrl, setUploadedFileUrl] = useState<string>(initialData?.url || '');
    const [uploadedFileHash, setUploadedFileHash] = useState<string>(initialData?.hash || '');
    const [uploadedFileSecure, setUploadedFileSecure] = useState<boolean>(initialData?.isSecure || false);

    const { register, handleSubmit, control, setValue, watch, reset, formState: { errors } } = useZodForm<typeof documentSchema>({
        schema: documentSchema,
        mode: 'onChange',
        shouldUnregister: true,
        defaultValues: {
            title: initialData?.title || '',
            type: initialData?.type || 'Politique',
            version: initialData?.version || '1.0',
            status: initialData?.status || 'Brouillon',
            workflowStatus: initialData?.workflowStatus || 'Draft',
            owner: initialData?.owner || '',
            ownerId: initialData?.ownerId || '',
            nextReviewDate: initialData?.nextReviewDate || '',
            expirationDate: initialData?.expirationDate || '',
            readBy: initialData?.readBy || [],
            reviewers: initialData?.reviewers || [],
            approvers: initialData?.approvers || [],
            relatedControlIds: initialData?.relatedControlIds || [],
            relatedAssetIds: initialData?.relatedAssetIds || [],

            relatedAuditIds: initialData?.relatedAuditIds || [],
            relatedRiskIds: initialData?.relatedRiskIds || [],
            storageProvider: initialData?.storageProvider || 'firebase',
            externalUrl: initialData?.externalUrl || '',
            folderId: initialData?.folderId || ''
        }
    });

    // Persistence Hook
    const { clearDraft } = useFormPersistence<DocumentFormData>('sentinel_document_draft_new', {
        watch,
        reset
    }, {
        enabled: !initialData
    });

    const onInvalid = (errors: FieldErrors<DocumentFormData>) => {
        const missingFields = Object.keys(errors).join(', ');
        toast.error(`Formulaire invalide. Champs en erreur : ${missingFields}`);
    };

    const folderId = useWatch({ control, name: 'folderId' });
    const docType = useWatch({ control, name: 'type' });
    const status = useWatch({ control, name: 'status' });

    const ownerId = useWatch({ control, name: 'ownerId' });
    const storageProvider = useWatch({ control, name: 'storageProvider' });

    useEffect(() => {
        if (!ownerId) {
            setValue('owner', '', { shouldDirty: true, shouldValidate: true });
            return;
        }
        const matchedOwner = users.find(u => u.uid === ownerId);
        setValue('owner', matchedOwner ? (matchedOwner.displayName || matchedOwner.email || '') : '', {
            shouldDirty: true,
            shouldValidate: true
        });
    }, [ownerId, users, setValue]);

    const handleFileUploadComplete = async (url: string, fileName: string, hash?: string, isSecure?: boolean, size?: number) => {
        setUploadedFileUrl(url);
        setUploadedFileHash(hash || '');
        setUploadedFileSecure(isSecure || false);
        addToast(`Fichier ${fileName} téléversé avec succès`, 'success');
        if (size && onUploadComplete) {
            onUploadComplete(size);
        }
    };

    const handleConnectProvider = useCallback(async (provider: 'google_drive' | 'onedrive' | 'sharepoint') => {
        try {
            if (provider === 'google_drive') {
                await externalStorageService.connectGoogleDrive();
            } else if (provider === 'onedrive' || provider === 'sharepoint') {
                await externalStorageService.connectOneDrive();
            }
            addToast("Connexion réussie (Simulation)", 'success');
        } catch (e) {
            addToast("Configuration OAuth manquante ou annulée", 'error');
            ErrorLogger.error(e, "DocumentForm.handleConnectProvider");
        }
    }, [addToast]);

    const handleBrowseProvider = useCallback(() => {
        if (storageProvider === 'google_drive' || storageProvider === 'onedrive' || storageProvider === 'sharepoint') {
            void handleConnectProvider(storageProvider);
        }
    }, [storageProvider, handleConnectProvider]);

    const onFormSubmit = async (data: DocumentFormData) => {
        await onSubmit({
            ...data,
            fileUrl: uploadedFileUrl,
            fileHash: uploadedFileHash,
            isSecure: uploadedFileSecure
        });
        clearDraft();
    };

    return (
        <form onSubmit={handleSubmit(onFormSubmit, onInvalid)} className="space-y-6">
            <input type="hidden" {...register('owner', { required: true })} />
            <div className="space-y-6">
                <FloatingLabelInput
                    label="Titre"
                    {...register('title')}
                    error={errors.title?.message}
                    placeholder="Ex: PSSI"
                />

                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <CustomSelect
                        label="Dossier"
                        options={[{ value: '', label: 'Racine' }, ...folders.map(f => ({ value: f.id, label: f.name }))]}
                        value={folderId || ''}
                        onChange={(val) => setValue('folderId', typeof val === 'string' ? val : '')}
                        error={errors.folderId?.message}
                    />
                    <CustomSelect
                        label="Type"
                        options={['Politique', 'Procédure', 'Preuve', 'Rapport', 'Autre'].map(t => ({ value: t, label: t }))}
                        value={docType || 'Politique'}
                        onChange={(val) => setValue('type', (typeof val === 'string' ? val : 'Politique') as DocumentFormData['type'])}
                        error={errors.type?.message}
                    />
                    <FloatingLabelInput
                        label="Version"
                        {...register('version')}
                        error={errors.version?.message}
                    />
                </div>

                <div className="space-y-2">
                    <Controller
                        control={control}
                        name="content"
                        render={({ field }) => (
                            <RichTextEditor
                                label="Contenu (Éditeur Riche)"
                                value={field.value || ''}
                                onChange={field.onChange}
                                error={errors.content?.message}
                            />
                        )}
                    />
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 sm:gap-6">
                    <CustomSelect
                        label="Statut"
                        options={['Brouillon', 'En revue', 'Approuvé', 'Rejeté', 'Publié', 'Obsolète', 'Archivé'].map(s => ({ value: s, label: s }))}
                        value={status || 'Brouillon'}
                        onChange={(val) => setValue('status', (typeof val === 'string' ? val : 'Brouillon') as DocumentFormData['status'])}
                        error={errors.status?.message}
                    />
                    <CustomSelect
                        label="Propriétaire"
                        options={users.map(u => ({ value: u.uid, label: u.displayName || u.email }))}
                        value={ownerId || ''}
                        onChange={(val) => setValue('ownerId', typeof val === 'string' ? val : '', { shouldDirty: true, shouldValidate: true })}
                        error={errors.ownerId?.message}
                    />
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 sm:gap-6">
                    <Controller
                        control={control}
                        name="reviewers"
                        render={({ field }) => (
                            <CustomSelect
                                label="Reviewers"
                                options={users.map(u => ({ value: u.uid, label: u.displayName || u.email }))}
                                value={field.value || []}
                                onChange={field.onChange}
                                multiple
                                error={errors.reviewers?.message}
                            />
                        )}
                    />
                    <Controller
                        control={control}
                        name="approvers"
                        render={({ field }) => (
                            <CustomSelect
                                label="Approbateurs"
                                options={users.map(u => ({ value: u.uid, label: u.displayName || u.email }))}
                                value={field.value || []}
                                onChange={field.onChange}
                                multiple
                                error={errors.approvers?.message}
                            />
                        )}
                    />
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 sm:gap-6">
                    <FloatingLabelInput
                        label="Prochaine révision"
                        type="date"
                        {...register('nextReviewDate')}
                        error={errors.nextReviewDate?.message}
                    />
                    <FloatingLabelInput
                        label="Date d'expiration"
                        type="date"
                        {...register('expirationDate')}
                        error={errors.expirationDate?.message}
                    />
                </div>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <Controller
                        control={control}
                        name="relatedControlIds"
                        render={({ field }) => (
                            <CustomSelect
                                label="Contrôles"
                                options={controls.map(c => ({ value: c.id, label: `${c.code} ${c.name.substring(0, 20)}...` }))}
                                value={field.value || []}
                                onChange={field.onChange}
                                multiple
                                error={errors.relatedControlIds?.message}
                            />
                        )}
                    />
                    <Controller
                        control={control}
                        name="relatedAssetIds"
                        render={({ field }) => (
                            <CustomSelect
                                label="Actifs"
                                options={assets.map(a => ({ value: a.id, label: a.name }))}
                                value={field.value || []}
                                onChange={field.onChange}
                                multiple
                                error={errors.relatedAssetIds?.message}
                            />
                        )}
                    />
                    <Controller
                        control={control}
                        name="relatedAuditIds"
                        render={({ field }) => (
                            <CustomSelect
                                label="Audits"
                                options={audits.map(a => ({ value: a.id, label: a.name }))}
                                value={field.value || []}
                                onChange={field.onChange}
                                multiple
                                error={errors.relatedAuditIds?.message}
                            />
                        )}
                    />
                    <Controller
                        control={control}
                        name="relatedRiskIds"
                        render={({ field }) => (
                            <CustomSelect
                                label="Risques"
                                options={risks.map(r => ({ value: r.id, label: r.threat }))}
                                value={field.value || []}
                                onChange={field.onChange}
                                multiple
                                error={errors.relatedRiskIds?.message}
                            />
                        )}
                    />
                </div>

                <div className="pt-4 border-t border-border">
                    <label className="block text-xs font-bold uppercase tracking-widest text-muted-foreground mb-4">Stockage du Document</label>
                    <div className="mb-6">
                        <CustomSelect
                            label="Fournisseur de stockage"
                            options={[
                                { value: 'firebase', label: 'Interne (Upload)' },
                                { value: 'google_drive', label: 'Google Drive' },
                                { value: 'onedrive', label: 'OneDrive' },
                                { value: 'sharepoint', label: 'SharePoint' }
                            ]}
                            value={storageProvider || 'firebase'}
                            onChange={(val) => {
                                if (typeof val !== 'string') return;
                                if (val === 'firebase' || val === 'google_drive' || val === 'onedrive' || val === 'sharepoint') {
                                    setValue('storageProvider', val);
                                }
                            }}
                            error={errors.storageProvider?.message}
                        />
                    </div>

                    {storageProvider === 'firebase' ? (
                        <div>
                            <FileUploader
                                onUploadComplete={handleFileUploadComplete}
                                category="documents"
                                maxSizeMB={10}
                                allowedTypes={['application/pdf', 'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document', 'image/*']}
                                disabled={isStorageFull}
                                disabledMessage="Espace de stockage plein (1GB max)"
                            />
                            {uploadedFileUrl && (
                                <div className="mt-2 flex items-center justify-between p-2 bg-success/10 rounded-lg">
                                    <span className="text-xs text-success font-medium truncate flex-1">{uploadedFileUrl.split('/').pop()}</span>
                                    <div className="flex items-center gap-2">
                                        <label className="flex items-center gap-1 cursor-pointer">
                                            <input checked={uploadedFileSecure} onChange={e => setUploadedFileSecure(e.target.checked)}
                                                type="checkbox"
                                                className="rounded text-primary focus-visible:ring-primary"
                                            />
                                            <span className="text-[11px] font-bold text-muted-foreground">Sécurisé</span>
                                        </label>
                                        <button type="button" onClick={() => { setUploadedFileUrl(''); setUploadedFileHash(''); }} className="text-destructive hover:text-destructive/80"><Trash2 className="h-4 w-4" /></button>
                                    </div>
                                </div>
                            )}
                        </div>
                    ) : (
                        <div className="space-y-3">
                            <div className="flex gap-2">
                                <FloatingLabelInput
                                    label="URL Externe"
                                    {...register('externalUrl')}
                                    placeholder={storageProvider === 'google_drive' ? "Lien Google Drive..." : "Lien SharePoint/OneDrive..."}
                                    className="flex-1"
                                    error={errors.externalUrl?.message}
                                />
                                <Button
                                    type="button"
                                    variant="secondary"
                                    onClick={handleBrowseProvider}
                                >
                                    Parcourir
                                </Button>
                            </div>
                            <p className="text-xs text-muted-foreground">
                                {storageProvider === 'google_drive' ? 'Le document restera hébergé sur Google Drive.' : 'Le document restera hébergé sur Microsoft 365.'}
                            </p>
                        </div>
                    )}
                </div>
            </div>

            <div className="flex justify-end space-x-4 pt-6 border-t border-border">
                <Button type="button" variant="ghost" onClick={onCancel}>
                    Annuler
                </Button>
                <Button
                    type="submit"
                    isLoading={isLoading}
                    className="px-8 py-3 bg-primary text-primary-foreground hover:bg-primary/90 rounded-xl hover:scale-105 transition-transform shadow-lg shadow-primary/20 font-bold"
                >
                    {initialData ? 'Enregistrer' : 'Créer'}
                </Button>
            </div>
        </form>
    );
};

import React, { useState, useEffect } from 'react';
import { Button } from '../ui/button';
import { Document, Control, UserProfile } from '../../types';
import { Drawer } from '../ui/Drawer';
import { ScrollableTabs } from '../ui/ScrollableTabs';
import { FileText, History, MessageSquare, Eye, ShieldCheck, List, Edit, Trash2 } from '../ui/Icons';
import { WorkflowStatusBadge } from './WorkflowStatusBadge';
import { ApprovalFlow } from './ApprovalFlow';
import { DocumentVersionHistory } from './DocumentVersionHistory';
import { CommentSection } from '../collaboration/CommentSection';
import { TimelineView } from '../shared/TimelineView';
import { DocumentDetails } from './inspector/DocumentDetails';
import { useDocumentVersions } from '../../hooks/documents/useDocumentVersions';
import { getUserAvatarUrl } from '../../utils/avatarUtils';
// FilePreview is imported but intentionally not used via the component tag to avoid auto-modal. 
// However, we should remove the import if we are not using it at all.
// Wait, we replaced the usage with a button.
// BUT, if we want to "Open" the preview, we need to pass a callback or something?
// Current implementation passes 'onSecureView' to Inspector. SecureView opens a Global Viewer or something?
// In `useDocumentWorkflow.ts`, handleSecureView likely sets some state to open the preview?
// If so, we don't need FilePreview directly in Inspector.
// DocumentInspector is independent.

interface DocumentInspectorProps {
    isOpen: boolean;
    onClose: () => void;
    document: Document | null;
    controls: Control[];
    canEdit: boolean;
    users: UserProfile[];
    onEdit: () => void;
    onDelete: () => void;
    onWorkflowAction: (action: 'submit' | 'approve' | 'reject' | 'sign') => void;
    onSecureView: (doc: Document) => void;
}

export const DocumentInspector: React.FC<DocumentInspectorProps> = ({
    isOpen,
    onClose,
    document: selectedDocument,
    controls,
    canEdit,
    users,
    onEdit,
    onDelete,
    onWorkflowAction,
    onSecureView
}) => {
    const [activeTab, setActiveTab] = useState<'details' | 'versions' | 'history' | 'comments'>('details');
    const [isDeleting, setIsDeleting] = useState(false);
    const { versions } = useDocumentVersions(selectedDocument?.id || null, isOpen);

    const handleDelete = async () => {
        if (isDeleting) return;
        setIsDeleting(true);
        try {
            await onDelete();
        } finally {
            setIsDeleting(false);
        }
    };

    useEffect(() => {
        if (!isOpen || !selectedDocument) {
            setActiveTab('details');
        }
    }, [isOpen, selectedDocument]);

    if (!selectedDocument) return null;

    const linkedControls = controls.filter(c => Array.isArray(c.evidenceIds) && c.evidenceIds.includes(selectedDocument.id));

    const ownerUser = users.find(u => u.displayName === selectedDocument.owner);

    return (
        <Drawer
            isOpen={isOpen}
            onClose={onClose}
            title={selectedDocument.title}
            width="max-w-[95vw] md:max-w-6xl"
            actions={
                <div className="flex gap-2">
                    {canEdit && (
                        <>
                            <Button
                                onClick={onEdit}
                                variant="ghost"
                                size="icon"
                                className="text-slate-500 hover:text-brand-600 hover:bg-brand-50 dark:hover:bg-brand-900/30"
                                title="Modifier"
                            >
                                <Edit className="h-5 w-5" />
                            </Button>
                            <Button
                                onClick={handleDelete}
                                disabled={isDeleting}
                                variant="ghost"
                                size="icon"
                                className="text-slate-500 hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-900/30 disabled:bg-slate-200 disabled:text-slate-500 dark:disabled:bg-slate-700 dark:disabled:text-slate-400"
                                title={isDeleting ? "Suppression..." : "Supprimer"}
                                aria-label="Supprimer le document"
                            >
                                <Trash2 className="h-5 w-5" />
                            </Button>
                        </>
                    )}
                </div>
            }
        >
            <div className="p-6 space-y-6 sm:space-y-8">
                {/* Meta Header */}
                <div className="flex flex-wrap items-start justify-between gap-4">
                    <div className="space-y-1">
                        <div className="flex items-center gap-2">
                            <WorkflowStatusBadge status={selectedDocument.status} />
                            {selectedDocument.isSecure && (
                                <span className="bg-success-100 text-success-800 text-xs px-2 py-0.5 rounded-full flex items-center gap-1 border border-success-200 dark:bg-success-900/30 dark:text-success-400 dark:border-success-800">
                                    <ShieldCheck className="h-3 w-3" /> Coffre-fort
                                </span>
                            )}
                            <span className="text-sm text-slate-500 dark:text-slate-300 px-2 py-0.5 bg-slate-100 rounded-lg border border-slate-200 dark:border-slate-700">
                                v{selectedDocument.version}
                            </span>
                        </div>
                        <div className="flex items-center gap-1.5 text-sm text-slate-500">
                            <span className="mr-1">Propriétaire:</span>
                            <img
                                src={getUserAvatarUrl(ownerUser?.photoURL, ownerUser?.role)}
                                alt={selectedDocument.owner}
                                className="w-4 h-4 rounded-full object-cover bg-slate-100 dark:bg-slate-800"
                                onError={(e) => {
                                    const target = e.target as HTMLImageElement;
                                    target.src = getUserAvatarUrl(null, ownerUser?.role);
                                }}
                            />
                            <span>{ownerUser?.displayName || selectedDocument.owner}</span>
                        </div>
                    </div>
                    {/* Action Buttons */}
                    <div className="flex gap-2">
                        {selectedDocument.url && (
                            <Button
                                onClick={() => onSecureView(selectedDocument)}
                                className="flex items-center gap-2 bg-slate-900 dark:bg-slate-800 text-white hover:bg-slate-800 shadow-sm font-medium"
                            >
                                <Eye className="w-4 h-4" />
                                {selectedDocument.isSecure ? "Consultation Sécurisée" : "Visualiser"}
                            </Button>
                        )}
                    </div>
                </div>

                <ApprovalFlow
                    document={selectedDocument}
                    users={users} // Removed currentUser
                    onPublish={() => onWorkflowAction('submit')} // Or adapt? onWorkflowAction takes 'submit'|'approve'... 
                // ApprovalFlow calls submitForReview or publishDocument internally hook. 
                // But here we are passing onAction prop to DocumentInspector which is expected to call handleWorkflowAction from hook.
                // ApprovalFlow implementation uses useDocumentWorkflow internally too (lines 16).
                // So actually DocumentInspector's onWorkflowAction prop might be redundant if ApprovalFlow does it?
                // But DocumentInspector interface wants onWorkflowAction.
                // Let's check ApprovalFlow definition again.
                // It has onPublish prop optional. But it handles actions itself. 
                // DocumentInspector parent (Documenst.tsx) passes handleWorkflowAction.
                // If ApprovalFlow handles it, maybe we don't need to pass anything?
                // But wait, the ApprovalFlow component I verified earlier imported useDocumentWorkflow internally.
                // So it does the logic.
                // However, we can simply not pass anything to ApprovalFlow if not needed, or pass users.
                />

                <ScrollableTabs
                    tabs={[
                        { id: 'details', label: 'Détails', icon: FileText },
                        { id: 'versions', label: 'Versions', icon: List },
                        { id: 'history', label: 'Historique', icon: History },
                        { id: 'comments', label: 'Commentaires', icon: MessageSquare }
                    ]}
                    activeTab={activeTab}
                    onTabChange={(id) => setActiveTab(id as 'details' | 'versions' | 'history' | 'comments')}
                />

                <div className="mt-6">
                    {activeTab === 'details' && (
                        <DocumentDetails
                            document={selectedDocument}
                            controls={linkedControls}
                            onSecureView={onSecureView}
                        />
                    )}

                    {activeTab === 'versions' && (
                        <DocumentVersionHistory versions={versions} />
                    )}

                    {activeTab === 'history' && selectedDocument && (
                        <TimelineView
                            resourceId={selectedDocument.id}
                            resourceType="Document"
                        />
                    )}

                    {activeTab === 'comments' && selectedDocument && (
                        <CommentSection
                            documentId={selectedDocument.id}
                            collectionName="documents"
                        />
                    )}
                </div>
            </div>
        </Drawer>
    );
};

