    { id: 'info', title: 'Informations', icon: FileText },
    { id: 'relations', title: 'Relations', icon: Link },
    { id: 'lifecycle', title: 'Cycle de vie', icon: Users },
    { id: 'review', title: 'Validation', icon: CheckCircle2 }
] as const;

export const DocumentUploadWizard: React.FC<DocumentUploadWizardProps> = ({
    isOpen,
    onClose,
    onSubmit,
    users,
    controls,
    assets,
    risks,
    folders,
    isLoading = false,
    initialFile,
    isStorageFull = false
}) => {
    const { addToast } = useStore();
    const [currentStep, setCurrentStep] = useState(0);
    const [uploadedFileUrl, setUploadedFileUrl] = useState<string>('');
    const [uploadedFileHash, setUploadedFileHash] = useState<string>('');
    const [uploadedFileSecure, setUploadedFileSecure] = useState<boolean>(false);
    const [fileName, setFileName] = useState<string>('');

    const { register, handleSubmit, control, setValue, getValues, trigger, formState: { errors } } = useZodForm({
        schema: documentSchema,
        mode: 'onChange',
        defaultValues: {
            title: '',
            type: 'Politique',
            version: '1.0',
            status: 'Brouillon',
            workflowStatus: 'Draft',
            owner: '',
            ownerId: '',
            nextReviewDate: '',
            readBy: [],
            reviewers: [],
            approvers: [],
            relatedControlIds: [],
            relatedAssetIds: [],
            relatedAuditIds: [],
            relatedRiskIds: [],
            storageProvider: 'firebase',
            externalUrl: '',
            folderId: ''
        }
    });

    const storageProvider = useWatch({ control, name: 'storageProvider' });
    const ownerId = useWatch({ control, name: 'ownerId' });
    const folderId = useWatch({ control, name: 'folderId' });
    const docType = useWatch({ control, name: 'type' });
    const status = useWatch({ control, name: 'status' });

    // Handle initial file drop
    useEffect(() => {
        if (initialFile && isOpen) {
            // We simulate the upload completion if we had a real uploader that accepted a File object directly and returned immediate URL/Hash
            // But FileUploader component handles the upload process.
            // For now, we might need to pass this file to the FileUploader if it supports it, 
            // OR we just use it to pre-fill the name and switch to 'file' step to let user confirm/upload.
            // Since FileUploader usually takes a drop, we might need to refactor it to accept a file prop to start uploading immediately.
            // For this implementation, I will assume the user has to drop it in the uploader OR I'll modify FileUploader later.
            // Let's assume for now we start at step 0.
            if (initialFile.name) {
                // Clean file name
                setValue('title', initialFile.name.split('.').slice(0, -1).join('.'));
            }
        }
    }, [initialFile, isOpen, setValue]);

    // Auto-set owner name
    useEffect(() => {
        if (!ownerId) {
            setValue('owner', '', { shouldDirty: true, shouldValidate: true });
            return;
        }
        const u = users.find(u => u.uid === ownerId);
        setValue('owner', u ? (u.displayName || u.email || '') : '', { shouldDirty: true, shouldValidate: true });
    }, [ownerId, users, setValue]);

    const handleFileUploadComplete = (url: string, fName: string, hash?: string, isSecure?: boolean) => {
        setUploadedFileUrl(url);
        setFileName(fName);
        setUploadedFileHash(hash || '');
        setUploadedFileSecure(isSecure || false);
        if (!getValues('title')) {
            setValue('title', fName.split('.').slice(0, -1).join('.'));
        }
    };

    const nextStep = async () => {
        let valid = false;
        if (currentStep === 0) {
            // Validate file step
            if (storageProvider === 'firebase') {
                if (uploadedFileUrl) valid = true;
                else if (initialFile && !uploadedFileUrl) {
                    // This creates a UX edge case where file is selected but not uploaded yet.
                    // User must wait for upload. FileUploader handles upload automatically on select/drop?
                    // Yes, FileUploader starts upload on selection.
                    addToast("Veuillez attendre la fin du téléversement", "info");
                    valid = false;
                }
                else addToast("Veuillez téléverser un fichier", "error");
            } else {
                if (await trigger('externalUrl')) valid = true;
            }
        } else if (currentStep === 1) {
            // Validate info
            const fields: FieldPath<DocumentFormData>[] = ['title', 'type', 'version', 'status', 'folderId'];
            if (await trigger(fields)) valid = true;
        } else if (currentStep === 2) {
            valid = true; // Relations are optional
        } else if (currentStep === 3) {
            // Validate lifecycle
            const fields: FieldPath<DocumentFormData>[] = ['ownerId', 'nextReviewDate'];
            if (await trigger(fields)) valid = true;
        }

        if (valid) setCurrentStep(prev => Math.min(prev + 1, STEPS.length - 1));
    };

    const prevStep = () => {
        setCurrentStep(prev => Math.max(prev - 1, 0));
    };

    // Fix SubmitHandler type
    const handleFinalSubmit: SubmitHandler<DocumentFormData> = async (data) => {
        await onSubmit({
            ...data,
            fileUrl: uploadedFileUrl,
            fileHash: uploadedFileHash,
            isSecure: uploadedFileSecure
        });
        onClose();
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-modal flex items-center justify-center p-4 sm:p-6">
            <div
                className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm transition-opacity"
                onClick={onClose}
                role="button"
                tabIndex={0}
                aria-label="Fermer"
                onKeyDown={(e) => {
                    if (e.key === 'Enter' || e.key === ' ') {
                        onClose();
                    }
                }}
            />

            <motion.div
                initial={{ opacity: 0, scale: 0.95 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0, scale: 0.95 }}
                className="relative w-full max-w-4xl glass-panel rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh] border border-white/20"
            >
                <div className="absolute inset-0 bg-gradient-to-br from-white/40 to-transparent dark:from-white/5 pointer-events-none" />
                {/* Header */}
                <div className="px-8 py-6 border-b border-white/10 glass-panel backdrop-blur-md relative z-10">
                    <div>
                        <h2 className="text-2xl font-bold text-slate-900 dark:text-white font-display">Nouveau Document</h2>
                        <p className="text-sm text-slate-500 dark:text-muted-foreground mt-1">Assistant d'importation et de classification</p>
                    </div>
                    {/* Progress Steps */}
                    <div className="hidden md:flex items-center gap-2">
                        {STEPS.map((step, idx) => (
                            <div key={step.id} className="flex items-center">
                                <div className={`
                                    flex items-center justify-center w-8 h-8 rounded-full text-xs font-bold transition-all
                                    ${idx === currentStep ? 'bg-brand-600 text-white shadow-lg shadow-brand-500/20 scale-110' :
                                        idx < currentStep ? 'bg-success-500 text-white' : 'bg-slate-100 dark:bg-white/5 text-slate-400'}
                                `}>
                                    {idx < currentStep ? <CheckCircle2 className="w-4 h-4" /> : idx + 1}
                                </div>
                                {idx < STEPS.length - 1 && (
                                    <div className={`w-8 h-0.5 mx-2 rounded-full transition-colors ${idx < currentStep ? 'bg-success-500' : 'bg-slate-100 dark:bg-white/10'}`} />
                                )}
                            </div>
                        ))}
                    </div>
                </div>

                {/* Content */}
                <div className="flex-1 overflow-y-auto p-8 custom-scrollbar relative z-10">
                    <form id="wizard-form" onSubmit={handleSubmit(handleFinalSubmit)}>
                        <input type="hidden" {...register('owner', { required: true })} />

                        {/* Step 1: File */}
                        {currentStep === 0 && (
                            <div className="space-y-6 animate-fade-in-right">
                                <div className="text-center mb-8">
                                    <h3 className="text-lg font-bold text-slate-900 dark:text-white">Téléchargement du fichier</h3>
                                    <p className="text-sm text-slate-500">Choisissez la source de votre document</p>
                                </div>

                                <div className="grid grid-cols-2 gap-4 mb-6">
                                    <button
                                        type="button"
                                        className={`cursor-pointer p-4 rounded-xl border-2 transition-all w-full text-left ${storageProvider === 'firebase' ? 'border-brand-500 bg-brand-50 dark:bg-brand-800' : 'border-slate-200 dark:border-white/10 hover:border-brand-200'}`}
                                        onClick={() => setValue('storageProvider', 'firebase')}
                                    >
                                        <UploadCloud className={`w-6 h-6 mb-2 ${storageProvider === 'firebase' ? 'text-brand-600' : 'text-slate-400'}`} />
                                        <div className="font-bold text-sm">Upload Direct</div>
                                    </button>
                                    <button
                                        type="button"
                                        className={`cursor-pointer p-4 rounded-xl border-2 transition-all w-full text-left ${storageProvider !== 'firebase' ? 'border-brand-500 bg-brand-50 dark:bg-brand-800' : 'border-slate-200 dark:border-white/10 hover:border-brand-200'}`}
                                        onClick={() => setValue('storageProvider', 'google_drive')} // Defaulting to one external
                                    >
                                        <Link className={`w-6 h-6 mb-2 ${storageProvider !== 'firebase' ? 'text-brand-600' : 'text-slate-400'}`} />
                                        <div className="font-bold text-sm">Lien Externe</div>
                                    </button>
                                </div>

                                {storageProvider === 'firebase' ? (
                                    <div>
                                        <FileUploader
                                            onUploadComplete={handleFileUploadComplete}
                                            category="documents"
                                            maxSizeMB={25}
                                            allowedTypes={['application/pdf', 'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document', 'image/*', 'application/vnd.ms-excel', 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet']}
                                            disabled={isStorageFull}
                                            initialFile={initialFile}
                                        />
                                        {uploadedFileUrl && (
                                            <div className="mt-4 flex items-center justify-between p-3 bg-success-50 dark:bg-success-900/20 rounded-xl border border-success-100 dark:border-success-800">
                                                <div className="flex items-center gap-3">
                                                    <div className="p-2 bg-success-100 dark:bg-success-900/40 rounded-lg text-success-600">
                                                        <FileText className="w-5 h-5" />
                                                    </div>
                                                    <div>
                                                        <p className="text-sm font-bold text-success-900 dark:text-success-100">{fileName || 'Fichier téléversé'}</p>
                                                        <p className="text-xs text-success-600 dark:text-success-400 break-all">{uploadedFileUrl.split('/').pop()}</p>
                                                    </div>
                                                </div>
                                                <div className="flex items-center gap-4">
                                                    <label className="flex items-center gap-2 cursor-pointer select-none">
                                                        <input checked={uploadedFileSecure} onChange={e => setUploadedFileSecure(e.target.checked)}
                                                            type="checkbox"
                                                            className="rounded text-brand-600 focus-visible:ring-brand-500"
                                                        />
                                                        <span className="text-xs font-bold text-slate-600 dark:text-slate-300 flex items-center gap-1">
                                                            <Shield className="w-3 h-3" /> Sécurisé
                                                        </span>
                                                    </label>
                                                    <button type="button" onClick={() => { setUploadedFileUrl(''); setFileName(''); }} className="p-2 hover:bg-red-50 dark:hover:bg-red-900/30 text-muted-foreground hover:text-red-500 rounded-lg transition-colors">
                                                        <Trash2 className="h-4 w-4" />
                                                    </button>
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                ) : (
                                    <div className="space-y-4">
                                        <CustomSelect
                                            label="Fournisseur"
                                            options={[
                                                { value: 'google_drive', label: 'Google Drive' },
                                                { value: 'onedrive', label: 'OneDrive / SharePoint' },
                                                { value: 'sharepoint', label: 'SharePoint' }
                                            ]}
                                            value={storageProvider}
                                            onChange={(val) => {
                                                if (typeof val !== 'string') return;
                                                if (val === 'firebase' || val === 'google_drive' || val === 'onedrive' || val === 'sharepoint') {
                                                    setValue('storageProvider', val);
                                                }
                                            }}
                                        />
                                        <FloatingLabelInput
                                            label="URL du document"
                                            {...register('externalUrl')}
                                            placeholder="https://..."
                                        />
                                    </div>
                                )}
                            </div>
                        )}

                        {/* Step 2: Info */}
                        {currentStep === 1 && (
                            <div className="space-y-6 animate-fade-in-right">
                                <div className="text-center mb-8">
                                    <h3 className="text-lg font-bold text-slate-900 dark:text-white">Informations Générales</h3>
                                    <p className="text-sm text-slate-500">Détails et classification</p>
                                </div>
                                <FloatingLabelInput
                                    label="Titre du document"
                                    {...register('title')}
                                    error={errors.title?.message}
                                    autoFocus
                                />
                                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 sm:gap-6">
                                    <CustomSelect
                                        label="Dossier"
                                        options={[{ value: '', label: 'Racine' }, ...folders.map(f => ({ value: f.id, label: f.name }))]}
                                        value={folderId || ''}
                                        onChange={(val) => setValue('folderId', typeof val === 'string' ? val : '')}
                                        error={errors.folderId?.message}
                                    />
                                    <CustomSelect
                                        label="Type"
                                        options={['Politique', 'Procédure', 'Preuve', 'Rapport', 'Contrat', 'Autre'].map(t => ({ value: t, label: t }))}
                                        value={docType || 'Politique'}
                                        onChange={(val) => setValue('type', (typeof val === 'string' ? val : 'Politique') as DocumentFormData['type'])}
                                    />
                                </div>
                                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 sm:gap-6">
                                    <FloatingLabelInput
                                        label="Version"
                                        {...register('version')}
                                        error={errors.version?.message}
                                    />
                                    <div className="space-y-1">
                                        <label className="text-xs font-bold uppercase tracking-widest text-slate-500 dark:text-slate-300 ml-1">Statut</label>
                                        <div className="flex p-1 bg-slate-100 dark:bg-black/20 rounded-xl">
                                            {['Brouillon', 'Publié'].map((s) => (
                                                <button
                                                    key={s}
                                                    type="button"
                                                    onClick={() => setValue('status', s as DocumentFormData['status'])}
                                                    className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all ${status === s ? 'bg-white dark:bg-slate-700 shadow-sm text-brand-600' : 'text-muted-foreground hover:text-foreground'}`}
                                                >
                                                    {s}
                                                </button>
                                            ))}
                                        </div>
                                    </div>
                                </div>
                                <div className="space-y-2">
                                    <label className="text-xs font-bold uppercase tracking-widest text-slate-500 dark:text-slate-300 ml-1">Description / Résumé</label>
                                    <Controller
                                        control={control}
                                        name="content"
                                        render={({ field }) => (
                                            <RichTextEditor
                                                label=""
                                                value={field.value || ''}
                                                onChange={field.onChange}
                                                className="min-h-[150px]"
                                            />
                                        )}
                                    />
                                </div>
                            </div>
                        )}

                        {/* Step 3: Relations */}
                        {currentStep === 2 && (
                            <div className="space-y-6 animate-fade-in-right">
                                <div className="text-center mb-8">
                                    <h3 className="text-lg font-bold text-slate-900 dark:text-white">Relations & Contexte</h3>
                                    <p className="text-sm text-slate-500">Liez ce document aux éléments du GRC</p>
                                </div>
                                <div className="grid grid-cols-1 gap-6">
                                    <Controller
                                        control={control}
                                        name="relatedControlIds"
                                        render={({ field }) => (
                                            <CustomSelect
                                                label="Contrôles ISO 27001 Associés"
                                                options={controls.map(c => ({ value: c.id, label: `${c.code} - ${c.name}` }))}
                                                value={field.value || []}
                                                onChange={field.onChange}
                                                multiple
                                            />
                                        )}
                                    />
                                    <Controller
                                        control={control}
                                        name="relatedAssetIds"
                                        render={({ field }) => (
                                            <CustomSelect
                                                label="Actifs concernés"
                                                options={assets.map(a => ({ value: a.id, label: a.name }))}
                                                value={field.value || []}
                                                onChange={field.onChange}
                                                multiple
                                            />
                                        )}
                                    />
                                    <Controller
                                        control={control}
                                        name="relatedRiskIds"
                                        render={({ field }) => (
                                            <CustomSelect
                                                label="Risques traités"
                                                options={risks.map(r => ({ value: r.id, label: `${r.threat.substring(0, 50)}...` }))}
                                                value={field.value || []}
                                                onChange={field.onChange}
                                                multiple
                                            />
                                        )}
                                    />
                                </div>
                            </div>
                        )}

                        {/* Step 4: Lifecycle */}
                        {currentStep === 3 && (
                            <div className="space-y-6 animate-fade-in-right">
                                <div className="text-center mb-8">
                                </div>
                                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 sm:gap-6">
                                    <Controller
                                        control={control}
                                        name="reviewers"
                                        render={({ field }) => (
                                            <CustomSelect
                                                label="Relecteurs (Reviewers)"
                                                options={users.map(u => ({ value: u.uid, label: u.displayName || u.email }))}
                                                value={field.value || []}
                                                onChange={field.onChange}
                                                multiple
                                            />
                                        )}
                                    />
                                    <Controller
                                        control={control}
                                        name="approvers"
                                        render={({ field }) => (
                                            <CustomSelect
                                                label="Approbateurs Finaux"
                                                options={users.map(u => ({ value: u.uid, label: u.displayName || u.email }))}
                                                value={field.value || []}
                                                onChange={field.onChange}
                                                multiple
                                            />
                                        )}
                                    />
                                </div>
                            </div>
                        )}

                        {/* Step 5: Review */}
                        {currentStep === 4 && (
                            <div className="space-y-8 animate-fade-in-right">
                                <div className="text-center mb-6">
                                    <div className="w-16 h-16 bg-success-100 dark:bg-success-900/30 rounded-full flex items-center justify-center mx-auto mb-4 text-success-600">
                                        <CheckCircle2 className="w-8 h-8" />
                                    </div>
                                    <h3 className="text-xl font-bold text-slate-900 dark:text-white">Prêt à valider ?</h3>
                                    <p className="text-sm text-slate-500">Vérifiez les informations ci-dessous</p>
                                </div>

                                <div className="bg-slate-50 dark:bg-white/5 rounded-2xl p-6 border border-slate-100 dark:border-white/5 space-y-4">
                                    <div className="flex items-start justify-between">
                                        <div>
                                            <p className="text-sm font-bold text-slate-900 dark:text-white">{getValues('title')}</p>
                                            <p className="text-xs text-slate-500">{docType} - v{getValues('version')}</p>
                                        </div>
                                        <span className={`px-2 py-1 rounded text-[11px] font-bold uppercase ${status === 'Publié' ? 'bg-success-100 text-success-700 dark:bg-success-900/30 dark:text-success-400' : 'bg-warning-100 text-warning-700 dark:bg-warning-900/30 dark:text-warning-400'}`}>
                                            {status}
                                        </span>
                                    </div>
                                    <div className="grid grid-cols-2 gap-4 text-xs">
                                        <div>
                                            <span className="text-slate-500 block">Dossier</span>
                                            <span className="font-medium text-slate-700 dark:text-slate-300 dark:text-muted-foreground">
                                                {folders.find(f => f.id === folderId)?.name || 'Racine'}
                                            </span>
                                        </div>
                                        <div>
                                            <span className="text-slate-500 block">Propriétaire</span>
                                            <span className="font-medium text-slate-700 dark:text-slate-300 dark:text-muted-foreground">
                                                {users.find(u => u.uid === ownerId)?.displayName || getValues('owner')}
                                            </span>
                                        </div>
                                        <div>
                                            <span className="text-slate-500 block">Fichier</span>
                                            <span className="font-medium text-slate-700 dark:text-slate-300 truncate block max-w-[150px]">
                                                {fileName || (uploadedFileUrl ? 'Fichier présent' : 'Aucun fichier')}
                                            </span>
                                        </div>
                                        <div>
                                            <span className="text-slate-500 block">Sécurité</span>
                                            <span className="font-medium text-slate-700 dark:text-slate-300 dark:text-muted-foreground">
                                                {uploadedFileSecure ? 'Chiffré / Sécurisé' : 'Standard'}
                                            </span>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        )}
                    </form>
                </div>

                {/* Footer Buttons */}
                <div className="px-8 py-6 border-t border-white/10 glass-panel backdrop-blur-md relative z-10 flex justify-between items-center">
                    <Button
                        type="button"
                        variant="ghost"
                        onClick={currentStep === 0 ? onClose : prevStep}
                        className="text-muted-foreground hover:text-foreground"
                    >
                        {currentStep === 0 ? 'Annuler' : 'Précédent'}
                    </Button>

                    <div className="flex gap-3">
                        {currentStep < STEPS.length - 1 ? (
                            <Button onClick={nextStep} className="bg-slate-900 dark:bg-white text-white dark:text-slate-900 hover:opacity-90">
                                Suivant <ChevronRight className="w-4 h-4 ml-2" />
                            </Button>
                        ) : (
                            <Button onClick={handleSubmit(handleFinalSubmit)} isLoading={isLoading} className="bg-brand-600 hover:bg-brand-700 text-white shadow-lg shadow-brand-500/20">
                                Terminer & Créer <CheckCircle2 className="w-4 h-4 ml-2" />
                            </Button>
                        )}
                    </div>
                </div>

            </motion.div>
        </div>
    );
};

import React from 'react';
import { FileUploader } from '../ui/FileUploader';

interface DocumentUploadZoneProps {
    fileUrl?: string; // Can be string or File mostly in forms, but usually string in Document object
    fileName?: string;
    fileType?: string;
    onUploadSuccess: (url: string, name: string, type: string, size: number, hash?: string) => void;
    onClear: () => void;
    maxSizeMB?: number; // Optional, default to 50
    storagePath?: string;
}

export const DocumentUploadZone: React.FC<DocumentUploadZoneProps> = ({
    fileUrl,
    fileName,
    fileType,
    onUploadSuccess,
    onClear,
    maxSizeMB = 50,
    storagePath = 'documents'
}) => {
    if (fileUrl) {
        return (
            <div className="mb-4">
                <label className="block text-sm font-medium mb-1 dark:text-muted-foreground">Fichier associé</label>
                <div className="flex items-center justify-between p-3 bg-slate-50 dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700">
                    <div className="flex items-center gap-3 overflow-hidden">
                        <div className="h-10 w-10 flex-shrink-0 bg-blue-100 dark:bg-blue-900/30 rounded-lg flex items-center justify-center text-blue-600 dark:text-blue-400 font-bold">
                            {fileType?.includes('pdf') ? 'PDF' : fileType?.includes('image') ? 'IMG' : 'DOC'}
                        </div>
                        <div className="min-w-0">
                            <p className="text-sm font-medium text-slate-700 dark:text-slate-200 truncate">{fileName || 'Document'}</p>
                            <a href={fileUrl} target="_blank" rel="noopener noreferrer" className="text-xs text-blue-500 hover:underline focus:outline-none focus-visible:ring-2 focus-visible:ring-blue-500 rounded">Voir le fichier</a>
                        </div>
                    </div>
                    <button
                        type="button"
                        onClick={onClear}
                        className="text-red-500 hover:text-red-700 p-2 hover:bg-red-50 dark:hover:bg-red-900/30 dark:hover:bg-red-900/20 rounded-lg transition-colors focus:outline-none focus-visible:ring-2 focus-visible:ring-red-500"
                    >
                        Supprimer
                    </button>
                </div>
            </div>
        );
    }

    return (
        <div className="mb-4">
            <label className="block text-sm font-medium mb-1 dark:text-muted-foreground">Fichier (Optionnel)</label>
            <FileUploader
                onUploadComplete={(url, name, hash, _isSecure, size, type) => onUploadSuccess(url, name, type || 'application/octet-stream', size || 0, hash)}
                category={storagePath}
                maxSizeMB={maxSizeMB}
                allowedTypes={[
                    'application/pdf',
                    'application/msword',
                    'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
                    'image/*',
                    'text/plain',
                    'application/vnd.ms-excel',
                    'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
                ]}
            />
            <p className="text-xs text-slate-500 dark:text-slate-300 mt-1">PDF, Word, Excel, Images (Max {maxSizeMB}Mo)</p>
        </div>
    );
};

/**
 * Story 27.4 - eDiscovery Search Component
 *
 * Advanced search interface for legal/compliance teams.
 * Supports boolean operators, date ranges, saved queries, and bulk exports.
 */

import React, { useState, useEffect, useCallback } from 'react';
import {
  Search,
  Calendar,
  User,
  FileText,
  Save,
  Trash2,
  Play,
  Download,
  ChevronDown,
  ChevronUp,
  X,
  History,
  Star,
  Loader2,
  AlertCircle,
} from '../ui/Icons';
import { Button } from '../ui/button';
import { useStore } from '@/store';
import { ErrorLogger } from '@/services/errorLogger';
import { useAuth } from '@/hooks/useAuth';
import {
  EDiscoveryService,
  EDiscoveryQuery,
  SavedSearch,
  SearchResults,
  SearchResultEntry,
  BooleanOperator,
} from '@/services/eDiscoveryService';
import { VaultAuditService, DocumentAction } from '@/services/vaultAuditService';
import { format, formatDistanceToNow } from 'date-fns';
import { fr } from 'date-fns/locale';

interface EDiscoverySearchProps {
  /** Default document ID to filter by */
  defaultDocumentId?: string;
  /** Callback when search is executed */
  onSearchExecuted?: (results: SearchResults) => void;
  /** Callback when a result entry is clicked */
  onResultClick?: (entry: SearchResultEntry) => void;
  /** Custom class name */
  className?: string;
}

export const EDiscoverySearch: React.FC<EDiscoverySearchProps> = ({
  defaultDocumentId,
  onSearchExecuted,
  // onResultClick,
  className = '',
}) => {
  const { user } = useAuth();
  const { organization: currentOrganization } = useStore();

  // Query state
  const [keywords, setKeywords] = useState('');
  const [booleanOperator, setBooleanOperator] = useState<BooleanOperator>('AND');
  const [selectedActions, setSelectedActions] = useState<DocumentAction[]>([]);
  const [dateRange, setDateRange] = useState<{ start: string; end: string }>({
    start: '',
    end: '',
  });
  const [userFilter, setUserFilter] = useState('');
  const [documentIds, setDocumentIds] = useState<string>(defaultDocumentId || '');

  // Results state
  const [results, setResults] = useState<SearchResults | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Saved searches state
  const [savedSearches, setSavedSearches] = useState<SavedSearch[]>([]);
  const [showSavedSearches, setShowSavedSearches] = useState(false);
  const [savingSearch, setSavingSearch] = useState(false);
  const [saveDialogOpen, setSaveDialogOpen] = useState(false);
  const [searchName, setSearchName] = useState('');
  const [searchDescription, setSearchDescription] = useState('');
  const [searchIsPublic, setSearchIsPublic] = useState(false);

  // UI state
  const [showAdvanced, setShowAdvanced] = useState(false);
  const [expandedResults, setExpandedResults] = useState<Set<string>>(new Set());
  const [exporting, setExporting] = useState(false);

  const loadSavedSearches = useCallback(async () => {
    if (!user?.uid || !currentOrganization?.id) return;
    try {
      const searches = await EDiscoveryService.loadSearchQueries(
        currentOrganization.id,
        user.uid
      );
      setSavedSearches(searches);
    } catch (err) {
      ErrorLogger.error(err, 'EDiscoverySearch.loadSavedSearches');
    }
  }, [user?.uid, currentOrganization?.id]);

  // Load saved searches
  useEffect(() => {
    loadSavedSearches();
  }, [loadSavedSearches]);

  // Build query from current state
  const buildQuery = useCallback((): EDiscoveryQuery => {
    const query: EDiscoveryQuery = {
      name: 'Search',
      booleanOperator,
    };

    if (keywords.trim()) {
      query.keywords = keywords.split(/\s+/).filter(k => k.length > 0);
    }

    if (selectedActions.length > 0) {
      query.actions = selectedActions;
    }

    if (dateRange.start || dateRange.end) {
      query.dateRange = {
        startDate: dateRange.start,
        endDate: dateRange.end,
      };
    }

    if (userFilter.trim()) {
      query.userIds = [userFilter.trim()];
    }

    if (documentIds.trim()) {
      query.documentIds = documentIds.split(',').map(id => id.trim()).filter(id => id.length > 0);
    }

    return query;
  }, [keywords, selectedActions, dateRange, userFilter, documentIds, booleanOperator]);

  // Execute search
  const executeSearch = async () => {
    if (!currentOrganization?.id) return;

    const query = buildQuery();
    const validation = EDiscoveryService.validateQuery(query);

    if (!validation.valid) {
      setError(validation.errors.join('. '));
      return;
    }

    try {
      setLoading(true);
      setError(null);

      const searchResults = await EDiscoveryService.executeSearch(
        currentOrganization.id,
        query
      );

      setResults(searchResults);
      onSearchExecuted?.(searchResults);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Erreur lors de la recherche');
    } finally {
      setLoading(false);
    }
  };

  // Apply saved search
  const applySavedSearch = async (savedSearch: SavedSearch) => {
    const query = savedSearch.query;

    // Apply query to UI state
    setKeywords(query.keywords?.join(' ') || '');
    setBooleanOperator(query.booleanOperator || 'AND');
    setSelectedActions(query.actions || []);
    setDateRange({
      start: query.dateRange?.startDate || '',
      end: query.dateRange?.endDate || '',
    });
    setUserFilter(query.userIds?.[0] || '');
    setDocumentIds(query.documentIds?.join(', ') || '');

    setShowSavedSearches(false);

    // Record search execution
    await EDiscoveryService.recordSearchExecution(savedSearch.id);

    // Execute the search
    try {
      setLoading(true);
      setError(null);

      const searchResults = await EDiscoveryService.executeSearch(
        currentOrganization?.id || '',
        query
      );

      setResults(searchResults);
      onSearchExecuted?.(searchResults);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Erreur lors de la recherche');
    } finally {
      setLoading(false);
    }
  };

  // Save current search
  const saveCurrentSearch = async () => {
    if (!searchName.trim() || !currentOrganization?.id || !user?.uid) return;

    try {
      setSavingSearch(true);
      const query = buildQuery();
      query.name = searchName;

      await EDiscoveryService.saveSearchQuery(
        currentOrganization.id,
        user.uid,
        searchName,
        query,
        {
          description: searchDescription,
          isPublic: searchIsPublic,
        }
      );

      await loadSavedSearches();
      setSaveDialogOpen(false);
      setSearchName('');
      setSearchDescription('');
      setSearchIsPublic(false);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Erreur lors de la sauvegarde');
    } finally {
      setSavingSearch(false);
    }
  };

  // Delete saved search
  const deleteSavedSearch = async (searchId: string) => {
    try {
      await EDiscoveryService.deleteSearchQuery(searchId);
      await loadSavedSearches();
    } catch (err) {
      ErrorLogger.error(err, 'EDiscoverySearch.deleteSavedSearch');
    }
  };

  // Export results
  const exportResults = async (format: 'csv' | 'json') => {
    if (!results) return;

    try {
      setExporting(true);
      const exportResult = await EDiscoveryService.exportSearchResults(results, format);
      EDiscoveryService.downloadExport(exportResult, `ediscovery-${Date.now()}.${format}`);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Erreur lors de l\'export');
    } finally {
      setExporting(false);
    }
  };

  // Clear search
  const clearSearch = () => {
    setKeywords('');
    setSelectedActions([]);
    setDateRange({ start: '', end: '' });
    setUserFilter('');
    setDocumentIds(defaultDocumentId || '');
    setResults(null);
    setError(null);
  };

  // Toggle result expansion
  const toggleResultExpand = (id: string) => {
    setExpandedResults(prev => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  };

  // All available actions for filter
  const allActions = VaultAuditService.getAllActions();

  return (
    <div className={`bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-700 ${className}`}>
      {/* Header */}
      <div className="flex items-center justify-between p-4 border-b border-slate-200 dark:border-slate-700">
        <h3 className="font-semibold text-slate-900 dark:text-white flex items-center gap-2">
          <Search className="h-5 w-5 text-brand-600" />
          Recherche eDiscovery
        </h3>
        <div className="flex items-center gap-2">
          <Button
            variant="ghost"
            size="sm"
            onClick={() => setShowSavedSearches(!showSavedSearches)}
            className="text-slate-500 hover:text-brand-600"
          >
            <History className="h-4 w-4 mr-1" />
            Recherches sauvegardees
          </Button>
          <Button
            variant="ghost"
            size="sm"
            onClick={() => setSaveDialogOpen(true)}
            className="text-slate-500 hover:text-brand-600"
            disabled={!keywords && selectedActions.length === 0 && !dateRange.start && !dateRange.end}
          >
            <Save className="h-4 w-4 mr-1" />
            Sauvegarder
          </Button>
        </div>
      </div>

      {/* Saved Searches Panel */}
      {showSavedSearches && savedSearches.length > 0 && (
        <div className="p-4 bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-700">
          <h4 className="text-sm font-medium text-slate-700 dark:text-slate-300 mb-3">
            Recherches sauvegardees ({savedSearches.length})
          </h4>
          <div className="space-y-2 max-h-48 overflow-y-auto">
            {savedSearches.map(search => (
              <div
                key={search.id}
                className="flex items-center justify-between p-3 bg-white dark:bg-slate-800 rounded-lg border border-slate-200 dark:border-slate-700 hover:border-brand-300 transition-colors"
              >
                <div
                  className="flex-1 min-w-0 cursor-pointer"
                  onClick={() => applySavedSearch(search)}
                  onKeyDown={(e) => e.key === 'Enter' && applySavedSearch(search)}
                  role="button"
                  tabIndex={0}
                >
                  <div className="flex items-center gap-2">
                    <span className="font-medium text-slate-900 dark:text-white truncate">
                      {search.name}
                    </span>
                    {search.isPublic && (
                      <Star className="h-3 w-3 text-warning-500" />
                    )}
                  </div>
                  {search.description && (
                    <p className="text-xs text-slate-500 dark:text-slate-300 truncate">{search.description}</p>
                  )}
                  <p className="text-xs text-muted-foreground">
                    Utilisee {search.runCount} fois
                    {search.lastRunAt && ` - Derniere: ${formatDistanceToNow(search.lastRunAt, { addSuffix: true, locale: fr })}`}
                  </p>
                </div>
                <div className="flex items-center gap-1">
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => applySavedSearch(search)}
                    className="text-brand-600 hover:text-brand-700"
                  >
                    <Play className="h-4 w-4" />
                  </Button>
                  {search.createdBy === user?.uid && (
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => deleteSavedSearch(search.id)}
                      className="text-red-500 hover:text-red-600"
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  )}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Search Form */}
      <div className="p-4 space-y-4">
        {/* Keyword Search */}
        <div>
          <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
            Mots-cles
          </label>
          <div className="flex gap-2">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
              <input
                type="text"
                value={keywords}
                onChange={(e) => setKeywords(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && executeSearch()}
                placeholder="Rechercher dans les details..."
                aria-label="Mots-clés de recherche"
                className="w-full pl-10 pr-4 py-2 border border-slate-200 dark:border-slate-600 rounded-lg bg-white dark:bg-slate-800 text-slate-900 dark:text-white placeholder-slate-500 dark:placeholder-slate-400"
              />
            </div>
            <select
              value={booleanOperator}
              onChange={(e) => setBooleanOperator(e.target.value as BooleanOperator)}
              aria-label="Opérateur booléen"
              className="px-3 py-2 border border-slate-200 dark:border-slate-600 rounded-lg bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-sm"
            >
              <option value="AND">ET</option>
              <option value="OR">OU</option>
              <option value="NOT">SAUF</option>
            </select>
          </div>
        </div>

        {/* Action Type Filter */}
        <div>
          <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
            Type d'action
          </label>
          <div className="flex flex-wrap gap-2">
            {allActions.map(({ value, label }) => {
              const colors = VaultAuditService.getActionColorClass(value);
              const isSelected = selectedActions.includes(value);
              return (
                <button
                  key={value}
                  onClick={() => {
                    if (isSelected) {
                      setSelectedActions(prev => prev.filter(a => a !== value));
                    } else {
                      setSelectedActions(prev => [...prev, value]);
                    }
                  }}
                  className={`px-2 py-1 text-xs rounded-full border transition-colors ${isSelected
                    ? `${colors.bg} ${colors.text} ${colors.border}`
                    : 'bg-white dark:bg-slate-700 text-slate-600 dark:text-slate-300 border-slate-200 dark:border-slate-600 hover:border-brand-300'
                    }`}
                >
                  {label}
                </button>
              );
            })}
          </div>
        </div>

        {/* Advanced Filters Toggle */}
        <button
          onClick={() => setShowAdvanced(!showAdvanced)}
          aria-expanded={showAdvanced}
          aria-label={showAdvanced ? "Masquer les filtres avancés" : "Afficher les filtres avancés"}
          className="text-sm text-brand-600 hover:text-brand-700 flex items-center gap-1"
        >
          {showAdvanced ? <ChevronUp className="h-4 w-4" aria-hidden="true" /> : <ChevronDown className="h-4 w-4" aria-hidden="true" />}
          Filtres avances
        </button>

        {/* Advanced Filters */}
        {showAdvanced && (
          <div className="space-y-4 p-4 bg-slate-50 dark:bg-slate-800/50 rounded-lg">
            {/* Date Range */}
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
                  <Calendar className="h-3 w-3 inline mr-1" />
                  Date debut
                </label>
                <input
                  type="date"
                  value={dateRange.start}
                  onChange={(e) => setDateRange(prev => ({ ...prev, start: e.target.value }))}
                  aria-label="Date de début"
                  className="w-full px-3 py-2 text-sm border border-slate-200 dark:border-slate-600 rounded-lg bg-white dark:bg-slate-700 text-slate-900 dark:text-white"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
                  <Calendar className="h-3 w-3 inline mr-1" />
                  Date fin
                </label>
                <input
                  type="date"
                  value={dateRange.end}
                  onChange={(e) => setDateRange(prev => ({ ...prev, end: e.target.value }))}
                  aria-label="Date de fin"
                  className="w-full px-3 py-2 text-sm border border-slate-200 dark:border-slate-600 rounded-lg bg-white dark:bg-slate-700 text-slate-900 dark:text-white"
                />
              </div>
            </div>

            {/* User Filter */}
            <div>
              <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
                <User className="h-3 w-3 inline mr-1" />
                ID Utilisateur
              </label>
              <input
                type="text"
                value={userFilter}
                onChange={(e) => setUserFilter(e.target.value)}
                placeholder="ID de l'utilisateur"
                aria-label="Filtrer par ID utilisateur"
                className="w-full px-3 py-2 text-sm border border-slate-200 dark:border-slate-600 rounded-lg bg-white dark:bg-slate-700 text-slate-900 dark:text-white"
              />
            </div>

            {/* Document IDs Filter */}
            <div>
              <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
                <FileText className="h-3 w-3 inline mr-1" />
                IDs Documents (separes par virgule)
              </label>
              <input
                type="text"
                value={documentIds}
                onChange={(e) => setDocumentIds(e.target.value)}
                placeholder="doc1, doc2, doc3"
                aria-label="IDs des documents"
                className="w-full px-3 py-2 text-sm border border-slate-200 dark:border-slate-600 rounded-lg bg-white dark:bg-slate-700 text-slate-900 dark:text-white"
              />
            </div>
          </div>
        )}

        {/* Error Message */}
        {error && (
          <div className="flex items-center gap-2 p-3 bg-red-50 dark:bg-red-950 text-red-600 dark:text-red-400 rounded-lg text-sm">
            <AlertCircle className="h-4 w-4" />
            {error}
          </div>
        )}

        {/* Action Buttons */}
        <div className="flex items-center justify-between gap-4 pt-2">
          <Button
            variant="ghost"
            onClick={clearSearch}
            className="text-slate-500 hover:text-red-600"
          >
            <X className="h-4 w-4 mr-1" />
            Effacer
          </Button>
          <Button
            onClick={executeSearch}
            disabled={loading}
            className="bg-brand-600 hover:bg-brand-700 text-white"
          >
            {loading ? (
              <Loader2 className="h-4 w-4 animate-spin mr-2" />
            ) : (
              <Search className="h-4 w-4 mr-2" />
            )}
            Rechercher
          </Button>
        </div>
      </div>

      {/* Results */}
      {results && (
        <div className="border-t border-slate-200 dark:border-slate-700">
          {/* Results Header */}
          <div className="flex items-center justify-between p-4 bg-slate-50 dark:bg-slate-800/50">
            <div className="text-sm text-slate-600 dark:text-muted-foreground">
              <span className="font-medium text-slate-900 dark:text-white">{results.totalCount}</span> resultats
              en <span className="font-medium">{results.searchTime}ms</span>
            </div>
            <div className="flex items-center gap-2">
              <Button
                variant="ghost"
                size="sm"
                onClick={() => exportResults('csv')}
                disabled={exporting || results.entries.length === 0}
                className="text-slate-500 hover:text-brand-600"
              >
                {exporting ? <Loader2 className="h-4 w-4 animate-spin" /> : <Download className="h-4 w-4 mr-1" />}
                CSV
              </Button>
              <Button
                variant="ghost"
                size="sm"
                onClick={() => exportResults('json')}
                disabled={exporting || results.entries.length === 0}
                className="text-slate-500 hover:text-brand-600"
              >
                JSON
              </Button>
            </div>
          </div>

          {/* Results List */}
          {results.entries.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-12 text-slate-500">
              <Search className="h-12 w-12 mb-4 opacity-60" />
              <p className="text-sm">Aucun resultat trouve</p>
            </div>
          ) : (
            <div className="divide-y divide-slate-100 dark:divide-slate-800 max-h-96 overflow-y-auto">
              {results.entries.map(entry => {
                const colors = VaultAuditService.getActionColorClass(entry.action);
                const isExpanded = expandedResults.has(entry.id);

                return (
                  <div
                    key={entry.id}
                    className="p-4 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors"
                  >
                    <div className="flex items-start justify-between gap-4">
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 flex-wrap">
                          <span className={`inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium ${colors.bg} ${colors.text} ${colors.border} border`}>
                            {VaultAuditService.getActionLabel(entry.action)}
                          </span>
                          <span className="text-sm text-slate-600 dark:text-slate-300 truncate">
                            {entry.userEmail}
                          </span>
                          {entry.documentName && (
                            <span className="text-xs text-slate-500 dark:text-slate-300 bg-slate-100 dark:bg-slate-700 px-2 py-0.5 rounded">
                              {entry.documentName}
                            </span>
                          )}
                        </div>

                        {/* Highlights */}
                        {entry.highlights && entry.highlights.length > 0 && (
                          <div className="mt-2 space-y-1">
                            {entry.highlights.map((highlight, idx) => (
                              <p key={idx} className="text-xs text-slate-600 dark:text-slate-300 bg-yellow-50 dark:bg-yellow-900/20 px-2 py-1 rounded">
                                {highlight}
                              </p>
                            ))}
                          </div>
                        )}

                        {/* Expandable Details */}
                        <button
                          onClick={() => toggleResultExpand(entry.id)}
                          aria-expanded={isExpanded}
                          aria-label={isExpanded ? "Masquer les détails" : "Afficher les détails"}
                          className="mt-2 text-xs text-brand-600 hover:text-brand-700 flex items-center gap-1"
                        >
                          {isExpanded ? <ChevronUp className="h-3 w-3" aria-hidden="true" /> : <ChevronDown className="h-3 w-3" aria-hidden="true" />}
                          Details
                        </button>

                        {isExpanded && (
                          <div className="mt-2 p-3 bg-slate-50 dark:bg-slate-800 rounded-lg text-xs">
                            <pre className="whitespace-pre-wrap text-slate-600 dark:text-muted-foreground font-mono">
                              {JSON.stringify(entry.details, null, 2)}
                            </pre>
                          </div>
                        )}
                      </div>

                      <div className="text-right">
                        <p className="text-xs text-slate-500">
                          {entry.timestamp ? format(new Date(entry.timestamp), 'dd/MM/yyyy HH:mm', { locale: fr }) : 'N/A'}
                        </p>
                        <p className="text-xs text-muted-foreground font-mono">
                          {entry.documentId.substring(0, 8)}...
                        </p>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      )}

      {/* Save Search Dialog */}
      {saveDialogOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-white dark:bg-slate-900 rounded-xl shadow-xl w-full max-w-md p-6">
            <h3 className="text-lg font-semibold text-slate-900 dark:text-white mb-4">
              Sauvegarder la recherche
            </h3>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
                  Nom *
                </label>
                <input
                  type="text"
                  value={searchName}
                  onChange={(e) => setSearchName(e.target.value)}
                  placeholder="Ma recherche"
                  className="w-full px-3 py-2 border border-slate-200 dark:border-slate-600 rounded-lg bg-white dark:bg-slate-800 text-slate-900 dark:text-white"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
                  Description
                </label>
                <textarea
                  value={searchDescription}
