import React, { useState } from 'react';
import { Button } from '../ui/button';
import { DocumentFolder } from '../../types';
import { Folder, ChevronRight, ChevronDown, Plus, MoreVertical, Edit2, Trash2, FolderOpen, Loader2 } from '../ui/Icons';
import { ConfirmModal } from '../ui/ConfirmModal';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';

const folderSchema = z.object({
    name: z.string().min(1, 'Le nom est requis').max(100, 'Le nom est trop long')
});

type FolderFormData = z.infer<typeof folderSchema>;

interface FolderTreeProps {
    folders: DocumentFolder[];
    selectedFolderId: string | null;
    onSelectFolder: (folderId: string | null) => void;
    onCreateFolder: (name: string, parentId?: string) => Promise<void>;
    onUpdateFolder: (id: string, name: string) => void;
    onDeleteFolder: (id: string) => Promise<void>;
}

export const FolderTree: React.FC<FolderTreeProps> = ({
    folders,
    selectedFolderId,
    onSelectFolder,
    onCreateFolder,
    onUpdateFolder,
    onDeleteFolder
}) => {
    const [expandedFolders, setExpandedFolders] = useState<string[]>([]);
    const [editingFolderId, setEditingFolderId] = useState<string | null>(null);
    const [newFolderName, setNewFolderName] = useState('');
    const [showCreateModal, setShowCreateModal] = useState(false);
    const [createParentId, setCreateParentId] = useState<string | undefined>(undefined);
    const [contextMenu, setContextMenu] = useState<{ id: string, x: number, y: number } | null>(null);
    const [confirmDelete, setConfirmDelete] = useState<{ isOpen: boolean, id: string, loading?: boolean }>({ isOpen: false, id: '' });
    const [isCreatingFolder, setIsCreatingFolder] = useState(false);

    // Form validation for folder creation
    const { register, handleSubmit, formState: { errors }, reset } = useForm<FolderFormData>({
        resolver: zodResolver(folderSchema),
        defaultValues: { name: '' }
    });

    const toggleExpand = React.useCallback((folderId: string, e: React.MouseEvent | React.KeyboardEvent) => {
        e.stopPropagation();
        setExpandedFolders(prev =>
            prev.includes(folderId) ? prev.filter(id => id !== folderId) : [...prev, folderId]
        );
    }, []);

    const onSubmitFolder = React.useCallback(async (data: FolderFormData) => {
        setIsCreatingFolder(true);
        try {
            await onCreateFolder(data.name, createParentId);
            reset();
            setShowCreateModal(false);
        } finally {
            setIsCreatingFolder(false);
        }
    }, [createParentId, onCreateFolder, reset]);

    const handleUpdateSubmit = React.useCallback((id: string) => {
        if (newFolderName.trim()) {
            onUpdateFolder(id, newFolderName.trim());
            setEditingFolderId(null);
            setNewFolderName('');
        }
    }, [newFolderName, onUpdateFolder]);

    const handleBackdropClick = React.useCallback((e: React.MouseEvent) => {
        if (e.target === e.currentTarget) {
            setShowCreateModal(false);
        }
    }, []);

    const handleContextMenuBackdropClick = React.useCallback(() => {
        setContextMenu(null);
    }, []);

    const handleConfirmDeleteClose = React.useCallback(() => {
        setConfirmDelete({ isOpen: false, id: '' });
    }, []);

    const handleConfirmDeleteAction = React.useCallback(async () => {
        setConfirmDelete(prev => ({ ...prev, loading: true }));
        try {
            await onDeleteFolder(confirmDelete.id);
            setConfirmDelete({ isOpen: false, id: '' });
        } finally {
            setConfirmDelete(prev => ({ ...prev, loading: false }));
        }
    }, [confirmDelete.id, onDeleteFolder]);

    const handleCreateRoot = React.useCallback(() => {
        setCreateParentId(undefined);
        setShowCreateModal(true);
    }, []);

    const handleSelectAll = React.useCallback(() => onSelectFolder(null), [onSelectFolder]);
    const handleSelectAllKeyDown = React.useCallback((e: React.KeyboardEvent) => {
        if (e.key === 'Enter') {
            onSelectFolder(null);
        }
    }, [onSelectFolder]);

    const handleContextMenuOpen = React.useCallback((e: React.MouseEvent, id: string) => {
        e.preventDefault();
        setContextMenu({ id, x: e.clientX, y: e.clientY });
    }, []);

    const handleContextMenuCreateSub = React.useCallback(() => {
        if (!contextMenu) return;
        setCreateParentId(contextMenu.id);
        setShowCreateModal(true);
        setContextMenu(null);
    }, [contextMenu]);

    const handleContextMenuRename = React.useCallback(() => {
        if (!contextMenu) return;
        setEditingFolderId(contextMenu.id);
        const folder = folders.find(f => f.id === contextMenu.id);
        if (folder) {
            setNewFolderName(folder.name);
        }
        setContextMenu(null);
    }, [contextMenu, folders]);

    const handleContextMenuDelete = React.useCallback(() => {
        if (!contextMenu) return;
        setConfirmDelete({ isOpen: true, id: contextMenu.id });
        setContextMenu(null);
    }, [contextMenu]);

    const handleCreateModalClose = React.useCallback(() => {
        setShowCreateModal(false);
        reset();
    }, [reset]);
    const handleNewFolderNameChange = React.useCallback((val: string) => setNewFolderName(val), []);

    const rootFolders = React.useMemo(() => folders.filter(f => !f.parentId).sort((a, b) => a.name.localeCompare(b.name)), [folders]);

    return (
        <div className="h-full flex flex-col">
            <div className="p-4 border-b border-slate-100 dark:border-white/5 flex justify-between items-center">
                <h3 className="text-xs font-bold uppercase tracking-widest text-slate-600">Dossiers</h3>
                <Button
                    aria-label="Créer un nouveau dossier racine"
                    onClick={handleCreateRoot}
                    variant="ghost"
                    size="icon"
                    className="h-8 w-8 text-slate-600 dark:text-slate-300 hover:text-brand-600"
                    title="Nouveau dossier racine"
                >
                    <Plus className="h-4 w-4" />
                </Button>
            </div>

            <div className="flex-1 overflow-y-auto p-2 custom-scrollbar">
                <div
                    className={`flex items-center py-2 px-3 rounded-lg cursor-pointer mb-1 focus:outline-none focus-visible:ring-2 focus-visible:ring-brand-500 ${selectedFolderId === null ? 'bg-slate-100 dark:bg-slate-800 text-slate-900 dark:text-white font-bold ring-1 ring-slate-200 dark:ring-slate-700' : 'hover:bg-slate-50 dark:hover:bg-white/5 text-slate-700 dark:text-slate-300'}`}
                    onClick={handleSelectAll}
                    tabIndex={0}
                    onKeyDown={handleSelectAllKeyDown}
                >
                    <div className="w-5 mr-1" /> {/* Spacer for alignment */}
                    <Folder className="h-4 w-4 mr-2 text-slate-500" />
                    <span className="text-sm font-medium">Tous les documents</span>
                </div>
                {rootFolders.map(f => (
                    <FolderNode
                        key={f.id}
                        folder={f}
                        folders={folders}
                        depth={0}
                        expandedFolders={expandedFolders}
                        selectedFolderId={selectedFolderId}
                        editingFolderId={editingFolderId}
                        newFolderName={newFolderName}
                        onSelect={onSelectFolder}
                        onExpand={toggleExpand}
                        onContextMenu={handleContextMenuOpen}
                        onNameChange={handleNewFolderNameChange}
                        onUpdateSubmit={handleUpdateSubmit}
                    />
                ))}
            </div>

            {/* Create Modal */}
            {showCreateModal && (
                <div
                    role="button"
                    tabIndex={0}
                    onKeyDown={(e) => e.key === 'Escape' && setShowCreateModal(false)}
                    className="fixed inset-0 z-modal flex items-center justify-center bg-black/20 backdrop-blur-sm cursor-default"
                    onClick={handleBackdropClick}
                >
                    <div className="glass-premium p-4 sm:p-6 rounded-4xl shadow-2xl w-80 border border-white/20 relative overflow-hidden" onClick={e => e.stopPropagation()} role="presentation">
                        <div className="absolute inset-0 bg-gradient-to-br from-white/40 to-white/0 dark:from-white/10 dark:to-transparent pointer-events-none" />
                        <h3 className="text-lg font-bold mb-4 text-slate-900 dark:text-white relative z-10">Nouveau Dossier</h3>
                        <form onSubmit={handleSubmit(onSubmitFolder)}>
                            <div>
                                <input
                                    {...register('name')}
                                    aria-label="Nom du nouveau dossier"
                                    type="text"
                                    placeholder="Nom du dossier"
                                    className={`w-full px-4 py-2 rounded-xl bg-slate-50 dark:bg-slate-800 border ${errors.name ? 'border-red-500' : 'border-slate-200 dark:border-slate-700'
                                        } mb-1 focus:ring-2 focus-visible:ring-brand-500 outline-none`}
                                    autoFocus
                                />
                                {errors.name && (
                                    <p className="text-red-500 text-xs mb-3">{errors.name.message}</p>
                                )}
                            </div>
                            <div className="flex justify-end gap-2 relative z-10">
                                <Button
                                    aria-label="Annuler la création"
                                    type="button"
                                    onClick={handleCreateModalClose}
                                    variant="ghost"
                                    disabled={isCreatingFolder}
                                >
                                    Annuler
                                </Button>
                                <Button
                                    aria-label="Confirmer la création"
                                    type="submit"
                                    className="bg-gradient-to-r from-brand-600 to-brand-500 hover:from-brand-500 hover:to-brand-400 text-white shadow-lg shadow-brand-500/20 hover:scale-105"
                                    disabled={isCreatingFolder}
                                >
                                    {isCreatingFolder && <Loader2 className="animate-spin mr-2 h-4 w-4" />} Créer
                                </Button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            {/* Context Menu */}
            {contextMenu && (
                <>
                    <div
                        role="button"
                        tabIndex={0}
                        onKeyDown={(e) => e.key === 'Escape' && setContextMenu(null)}
                        className="fixed inset-0 z-header cursor-default"
                        onClick={handleContextMenuBackdropClick}
                    />
                    <div
                        className="fixed z-modal glass-premium rounded-xl shadow-2xl border border-white/20 py-1 w-48 animate-scale-in overflow-hidden backdrop-blur-md"
                        style={{ top: contextMenu.y, left: contextMenu.x }}
                    >
                        <Button
                            aria-label="Nouveau sous-dossier"
                            onClick={handleContextMenuCreateSub}
                            variant="ghost"
                            className="w-full justify-start text-sm font-normal px-4 py-2 text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-white/5"
                        >
                            <Plus className="h-4 w-4 mr-2" /> Nouveau sous-dossier
                        </Button>
                        <Button
                            aria-label="Renommer le dossier"
                            onClick={handleContextMenuRename}
                            variant="ghost"
                            className="w-full justify-start text-sm font-normal px-4 py-2 text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-white/5"
                        >
                            <Edit2 className="h-4 w-4 mr-2" /> Renommer
                        </Button>
                        <div className="h-px bg-slate-100 dark:bg-white/5 my-1" />
                        <Button
                            aria-label="Supprimer le dossier"
                            onClick={handleContextMenuDelete}
                            variant="ghost"
                            className="w-full justify-start text-sm font-normal px-4 py-2 text-red-600 dark:text-red-400 hover:text-red-700 hover:bg-red-50 dark:hover:bg-red-900/30 dark:hover:bg-red-900/20"
                        >
                            <Trash2 className="h-4 w-4 mr-2" /> Supprimer
                        </Button>
                    </div>
                </>
            )}

            <ConfirmModal
                isOpen={confirmDelete.isOpen}
                onClose={handleConfirmDeleteClose}
                onConfirm={handleConfirmDeleteAction}
                title="Supprimer le dossier ?"
                message="Tous les sous-dossiers seront également supprimés. Les documents seront déplacés à la racine."
                loading={confirmDelete.loading}
                closeOnConfirm={false}
            />
        </div>
    );
};

interface FolderNodeProps {
    folder: DocumentFolder;
    folders: DocumentFolder[];
    depth: number;
    expandedFolders: string[];
    selectedFolderId: string | null;
    editingFolderId: string | null;
    newFolderName: string;
    onSelect: (id: string | null) => void;
    onExpand: (id: string, e: React.MouseEvent | React.KeyboardEvent) => void;
    onContextMenu: (e: React.MouseEvent, id: string) => void;
    onNameChange: (name: string) => void;
    onUpdateSubmit: (id: string) => void;
}

const FolderNode = React.memo(({
    folder,
    folders,
    depth,
    expandedFolders,
    selectedFolderId,
    editingFolderId,
    newFolderName,
    onSelect,
    onExpand,
    onContextMenu,
    onNameChange,
    onUpdateSubmit
}: FolderNodeProps) => {
    const children = React.useMemo(() => folders.filter(f => f.parentId === folder.id).sort((a, b) => a.name.localeCompare(b.name)), [folders, folder.id]);
    const isExpanded = expandedFolders.includes(folder.id);
    const isSelected = selectedFolderId === folder.id;
    const isEditing = editingFolderId === folder.id;

    const handleKeyDown = React.useCallback((e: React.KeyboardEvent) => {
        if (e.key === 'Enter') {
            onSelect(folder.id);
        } else if (e.key === 'ArrowRight' && !isExpanded) {
            onExpand(folder.id, e);
        } else if (e.key === 'ArrowLeft' && isExpanded) {
            onExpand(folder.id, e);
        }
    }, [folder.id, isExpanded, onSelect, onExpand]);

    const handleContextMenuFn = React.useCallback((e: React.MouseEvent) => {
        e.preventDefault();
        onContextMenu(e, folder.id);
    }, [folder.id, onContextMenu]);

    const handleExpandClick = React.useCallback((e: React.MouseEvent) => onExpand(folder.id, e), [folder.id, onExpand]);
    const handleSelectClick = React.useCallback(() => onSelect(folder.id), [folder.id, onSelect]);
    const handleUpdateBlur = React.useCallback(() => onUpdateSubmit(folder.id), [folder.id, onUpdateSubmit]);
    const handleUpdateKeyDown = React.useCallback((e: React.KeyboardEvent) => e.key === 'Enter' && onUpdateSubmit(folder.id), [folder.id, onUpdateSubmit]);
    const handleInputChange = React.useCallback((e: React.ChangeEvent<HTMLInputElement>) => onNameChange(e.target.value), [onNameChange]);
    const handleMoreClick = React.useCallback((e: React.MouseEvent) => {
        e.stopPropagation();
        onContextMenu(e, folder.id);
    }, [folder.id, onContextMenu]);

    return (
        <div className="select-none">
            <div
                className={`flex items-center py-2 px-3 rounded-lg cursor-pointer transition-colors group relative focus:outline-none focus-visible:ring-2 focus-visible:ring-brand-500 ${isSelected ? 'bg-slate-100 dark:bg-slate-800 text-slate-900 dark:text-white font-bold' : 'hover:bg-slate-50 dark:hover:bg-white/5 text-slate-700 dark:text-slate-300'}`}
                style={{ paddingLeft: `${depth * 16 + 12}px` }}
                onClick={handleSelectClick}
                tabIndex={0}
                onKeyDown={handleKeyDown}
                onContextMenu={handleContextMenuFn}
            >
                <Button
                    aria-label={isExpanded ? "Replier le dossier" : "Déplier le dossier"}
                    onClick={handleExpandClick}
                    variant="ghost"
                    size="icon"
                    className={`h-6 w-6 rounded mr-1 ${children.length === 0 ? 'invisible' : ''}`}
                >
                    {isExpanded ? <ChevronDown className="h-3 w-3" /> : <ChevronRight className="h-3 w-3" />}
                </Button>

                {isEditing ? (
                    <input value={newFolderName} onChange={handleInputChange} onBlur={handleUpdateBlur} onKeyDown={handleUpdateKeyDown}
                        aria-label="Renommer le dossier"
                        type="text"
                        autoFocus
                        className="flex-1 bg-white dark:bg-slate-800 border border-brand-500 rounded px-2 py-0.5 text-sm focus:outline-none focus:ring-2 focus-visible:ring-brand-500"
                        onClick={(e) => e.stopPropagation()}
                    />
                ) : (
                    <div className="flex items-center flex-1 overflow-hidden">
                        {isExpanded ? <FolderOpen className="h-4 w-4 mr-2 text-brand-500" /> : <Folder className="h-4 w-4 mr-2 text-brand-500" />}
                        <span className="truncate text-sm font-medium">{folder.name}</span>
                    </div>
                )}

                <Button
                    aria-label="Options du dossier"
                    className="opacity-0 group-hover:opacity-70 transition-opacity h-6 w-6 rounded"
                    variant="ghost"
                    size="icon"
                    onClick={handleMoreClick}
                >
                    <MoreVertical className="h-3 w-3" />
                </Button>
            </div>

            {isExpanded && children.map(child => (
                <FolderNode
                    key={child.id}
                    folder={child}
                    folders={folders}
                    depth={depth + 1}
                    expandedFolders={expandedFolders}
                    selectedFolderId={selectedFolderId}
                    editingFolderId={editingFolderId}
                    newFolderName={newFolderName}
                    onSelect={onSelect}
                    onExpand={onExpand}
                    onContextMenu={onContextMenu}
                    onNameChange={onNameChange}
                    onUpdateSubmit={onUpdateSubmit}
                />
            ))}
        </div>
    );
});

/**
 * Story 25.3 - Legal Hold Manager UI Component
 *
 * Provides interface for managing legal holds:
 * - List active and released legal holds
 * - Create new legal holds with document selection
 * - Release legal holds with confirmation
 * - View documents under each hold
 */

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import {
  Shield,
  ShieldOff,
  Plus,
  Search,
  FileText,
  Calendar,
  User,
  AlertTriangle,
  ChevronDown,
  ChevronRight,
  Filter,
  Loader2,
  Scale,
  Trash2,
} from '../ui/Icons';
import { format } from 'date-fns';
import { fr } from 'date-fns/locale';

import { Button } from '@/components/ui/button';
import { Input } from '../ui/input';
import { Badge } from '@/components/ui/Badge';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../ui/card';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '../ui/select';
import { Label } from '../ui/label';
import { Textarea } from '../ui/textarea';
import { Checkbox } from '../ui/checkbox';
import { ScrollArea } from '../ui/scroll-area';
import { Separator } from '../ui/separator';
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from '../ui/collapsible';

import { useStore } from '@/store';
import { useLocale } from '@/hooks/useLocale';
import { useDocumentsData } from '../../hooks/documents/useDocumentsData';
import {
  getLegalHolds,
  createLegalHold,
  releaseLegalHold,
  deleteLegalHold,
  getLegalHoldStats,
} from '@/services/legalHoldService';
import type { LegalHold, LegalHoldStatus } from '@/types/vault';
import type { Document } from '@/types/documents';
import { cn } from '@/lib/utils';
import { toast } from 'sonner';
import { ErrorLogger } from '@/services/errorLogger';

interface LegalHoldManagerProps {
  className?: string;
}

export function LegalHoldManager({ className }: LegalHoldManagerProps) {
  const { t } = useLocale();
  const { user, organization } = useStore();
  const organizationId = organization?.id;
  const { documents } = useDocumentsData(organizationId);

  // State
  const [holds, setHolds] = useState<LegalHold[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<'all' | LegalHoldStatus>('all');
  const [expandedHolds, setExpandedHolds] = useState<Set<string>>(new Set());

  // Stats
  const [stats, setStats] = useState({
    activeHolds: 0,
    releasedHolds: 0,
    documentsUnderHold: 0,
  });

  // Dialog state
  const [createDialogOpen, setCreateDialogOpen] = useState(false);
  const [releaseDialogOpen, setReleaseDialogOpen] = useState(false);
  const [selectedHold, setSelectedHold] = useState<LegalHold | null>(null);

  // Form state
  const [formData, setFormData] = useState({
    name: '',
    reason: '',
    description: '',
    matterNumber: '',
    selectedDocuments: [] as string[],
  });
  const [releaseReason, setReleaseReason] = useState('');
  const [formLoading, setFormLoading] = useState(false);

  const loadHolds = useCallback(async () => {
    if (!organizationId) return;
    setLoading(true);
    try {
      const data = await getLegalHolds(organizationId, { includeReleased: true });
      setHolds(data);
    } catch (error) {
      ErrorLogger.error(error, 'LegalHoldManager.loadHolds');
      toast.error(t('legalHold.error.loadFailed', 'Erreur lors du chargement des legal holds'));
    } finally {
      setLoading(false);
    }
  }, [organizationId, t]);

  const loadStats = useCallback(async () => {
    if (!organizationId) return;
    try {
      const data = await getLegalHoldStats(organizationId);
      setStats(data);
    } catch (error) {
      ErrorLogger.error(error, 'LegalHoldManager.loadStats');
    }
  }, [organizationId]);

  // Load data
  useEffect(() => {
    if (organizationId) {
      loadHolds();
      loadStats();
    }
  }, [organizationId, loadHolds, loadStats]);

  // Filter holds
  const filteredHolds = useMemo(() => {
    return holds.filter((hold) => {
      // Status filter
      if (statusFilter !== 'all' && hold.status !== statusFilter) {
        return false;
      }

      // Search filter
      if (searchTerm) {
        const search = searchTerm.toLowerCase();
        return (
          hold.name.toLowerCase().includes(search) ||
          hold.reason.toLowerCase().includes(search) ||
          hold.matterNumber?.toLowerCase().includes(search)
        );
      }

      return true;
    });
  }, [holds, statusFilter, searchTerm]);

  // Get documents for a hold
  const getDocumentsForHold = (holdId: string): Document[] => {
    const hold = holds.find((h) => h.id === holdId);
    if (!hold) return [];

    return documents.filter((doc) => hold.documentIds.includes(doc.id));
  };

  // Toggle hold expansion
  const toggleHoldExpanded = (holdId: string) => {
    setExpandedHolds((prev) => {
      const next = new Set(prev);
      if (next.has(holdId)) {
        next.delete(holdId);
      } else {
        next.add(holdId);
      }
      return next;
    });
  };

  // Handle create legal hold
  const handleCreate = async () => {
    if (!organizationId || !user) return;
    if (!formData.name.trim() || !formData.reason.trim()) {
      toast.error(t('legalHold.error.requiredFields', 'Veuillez remplir tous les champs obligatoires'));
      return;
    }

    setFormLoading(true);
    try {
      await createLegalHold(
        organizationId,
        formData.name,
        formData.reason,
        user.uid,
        formData.selectedDocuments,
        {
          description: formData.description || undefined,
          matterNumber: formData.matterNumber || undefined,
        }
      );

      toast.success(t('legalHold.success.created', 'Legal hold cree avec succes'));
      setCreateDialogOpen(false);
      resetForm();
      loadHolds();
      loadStats();
    } catch (error) {
      ErrorLogger.error(error, 'LegalHoldManager.createLegalHold');
      toast.error(t('legalHold.error.createFailed', 'Erreur lors de la creation du legal hold'));
    } finally {
      setFormLoading(false);
    }
  };

  // Handle release legal hold
  const handleRelease = async () => {
    if (!selectedHold || !user) return;

    setFormLoading(true);
    try {
      await releaseLegalHold(selectedHold.id, user.uid, releaseReason || undefined);

      toast.success(t('legalHold.success.released', 'Legal hold libere avec succes'));
      setReleaseDialogOpen(false);
      setSelectedHold(null);
      setReleaseReason('');
      loadHolds();
      loadStats();
    } catch (error) {
      ErrorLogger.error(error, 'LegalHoldManager.releaseLegalHold');
      toast.error(t('legalHold.error.releaseFailed', 'Erreur lors de la liberation du legal hold'));
    } finally {
      setFormLoading(false);
    }
  };

  // Handle delete legal hold
  const handleDelete = async (hold: LegalHold) => {
    if (hold.status === 'active' && hold.documentIds.length > 0) {
      toast.error(t('legalHold.error.cannotDelete', 'Impossible de supprimer un legal hold actif avec des documents'));
      return;
    }

    try {
      await deleteLegalHold(hold.id);
      toast.success(t('legalHold.success.deleted', 'Legal hold supprime'));
      loadHolds();
      loadStats();
    } catch (error) {
      ErrorLogger.error(error, 'LegalHoldManager.deleteLegalHold');
      toast.error(t('legalHold.error.deleteFailed', 'Erreur lors de la suppression'));
    }
  };

  // Reset form
  const resetForm = () => {
    setFormData({
      name: '',
      reason: '',
      description: '',
      matterNumber: '',
      selectedDocuments: [],
    });
  };

  // Toggle document selection
  const toggleDocumentSelection = (docId: string) => {
    setFormData((prev) => ({
      ...prev,
      selectedDocuments: prev.selectedDocuments.includes(docId)
        ? prev.selectedDocuments.filter((id) => id !== docId)
        : [...prev.selectedDocuments, docId],
    }));
  };

  const formatDate = (timestamp: { toDate: () => Date } | undefined) => {
    if (!timestamp) return '-';
    return format(timestamp.toDate(), 'dd MMM yyyy HH:mm', { locale: fr });
  };

  const filteredDocuments = useMemo(() => {
    return documents.filter(doc => !doc.isUnderHold);
  }, [documents]);

  return (
    <div className={cn('space-y-6', className)}>
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-semibold tracking-tight">
            {t('legalHold.title', 'Legal Holds')}
          </h2>
          <p className="text-sm text-muted-foreground">
            {t('legalHold.description', 'Gerez les legal holds pour la conformite legale et les litiges')}
          </p>
        </div>
        <Button onClick={() => setCreateDialogOpen(true)}>
          <Plus className="mr-2 h-4 w-4" />
          {t('legalHold.create', 'Nouveau Legal Hold')}
        </Button>
      </div>

      {/* Stats Cards */}
      <div className="grid gap-4 md:grid-cols-3">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">
              {t('legalHold.stats.active', 'Holds Actifs')}
            </CardTitle>
            <Shield className="h-4 w-4 text-warning-500" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats.activeHolds}</div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">
              {t('legalHold.stats.released', 'Holds Liberes')}
            </CardTitle>
            <ShieldOff className="h-4 w-4 text-green-500" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats.releasedHolds}</div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">
              {t('legalHold.stats.documents', 'Documents Proteges')}
            </CardTitle>
            <FileText className="h-4 w-4 text-blue-500" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats.documentsUnderHold}</div>
          </CardContent>
        </Card>
      </div>

      {/* Filters */}
      <div className="flex items-center gap-4">
        <div className="relative flex-1 max-w-sm">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder={t('legalHold.search', 'Rechercher...')}
            value={searchTerm}
            onChange={(e: React.ChangeEvent<HTMLInputElement>) => setSearchTerm(e.target.value)}
            className="pl-9"
          />
        </div>
        <Select
          value={statusFilter}
          onValueChange={(v: string) => setStatusFilter(v as 'all' | LegalHoldStatus)}
        >
          <SelectTrigger className="w-[180px]">
            <Filter className="mr-2 h-4 w-4" />
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">{t('legalHold.filter.all', 'Tous')}</SelectItem>
            <SelectItem value="active">{t('legalHold.filter.active', 'Actifs')}</SelectItem>
            <SelectItem value="released">{t('legalHold.filter.released', 'Liberes')}</SelectItem>
          </SelectContent>
        </Select>
      </div>

      {/* Legal Holds List */}
      {loading ? (
        <div className="flex items-center justify-center py-12">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      ) : filteredHolds.length === 0 ? (
        <Card>
          <CardContent className="flex flex-col items-center justify-center py-12">
            <Scale className="h-12 w-12 text-muted-foreground/50 mb-4" />
            <p className="text-muted-foreground">
              {searchTerm || statusFilter !== 'all'
                ? t('legalHold.noResults', 'Aucun legal hold trouve')
                : t('legalHold.empty', 'Aucun legal hold. Creez-en un pour commencer.')}
            </p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-4">
          {filteredHolds.map((hold) => {
            const isExpanded = expandedHolds.has(hold.id);
            const holdDocs = getDocumentsForHold(hold.id);

            return (
              <Card key={hold.id} className={cn(hold.status === 'released' && 'opacity-75')}>
                <Collapsible open={isExpanded} onOpenChange={() => toggleHoldExpanded(hold.id)}>
                  <CardHeader className="pb-3">
                    <div className="flex items-start justify-between">
                      <div className="flex items-start gap-3">
                        <CollapsibleTrigger className="h-6 w-6 -ml-2 p-0 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full flex items-center justify-center transition-colors">
                          {isExpanded ? (
                            <ChevronDown className="h-4 w-4 text-muted-foreground" />
                          ) : (
                            <ChevronRight className="h-4 w-4 text-muted-foreground" />
                          )}
                        </CollapsibleTrigger>
                        <div>
                          <CardTitle className="flex items-center gap-2">
                            {hold.status === 'active' ? (
                              <Shield className="h-5 w-5 text-warning-500" />
                            ) : (
                              <ShieldOff className="h-5 w-5 text-green-500" />
                            )}
                            {hold.name}
                            <Badge status={hold.status === 'active' ? 'error' : 'neutral'} variant="soft">
                              {hold.status === 'active' ? 'Actif' : 'Libéré'}
                            </Badge>
                          </CardTitle>
                          <CardDescription className="mt-1">
                            {hold.reason}
                          </CardDescription>
                        </div>
                      </div>
                      <div className="flex items-center gap-2">
                        {hold.status === 'active' && (
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => {
                              setSelectedHold(hold);
                              setReleaseDialogOpen(true);
                            }}
                          >
                            <ShieldOff className="mr-2 h-4 w-4" />
                            {t('legalHold.release', 'Liberer')}
                          </Button>
                        )}
                        {(hold.status === 'released' || hold.documentIds.length === 0) && (
                          <Button
                            variant="ghost"
                            size="icon"
                            onClick={() => handleDelete(hold)}
                          >
                            <Trash2 className="h-4 w-4 text-destructive" />
                          </Button>
                        )}
                      </div>
                    </div>
                  </CardHeader>

                  <CollapsibleContent>
                    <CardContent className="pt-0">
                      <Separator className="mb-4" />

                      {/* Hold Details */}
                      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4 mb-4">
                        <div className="flex items-center gap-2 text-sm">
                          <Calendar className="h-4 w-4 text-muted-foreground" />
                          <span className="text-muted-foreground">Cree le:</span>
                          <span>{formatDate(hold.createdAt)}</span>
                        </div>
                        <div className="flex items-center gap-2 text-sm">
                          <User className="h-4 w-4 text-muted-foreground" />
                          <span className="text-muted-foreground">Par:</span>
                          <span>{hold.createdBy}</span>
                        </div>
                        {hold.matterNumber && (
                          <div className="flex items-center gap-2 text-sm">
                            <Scale className="h-4 w-4 text-muted-foreground" />
                            <span className="text-muted-foreground">Reference:</span>
                            <span>{hold.matterNumber}</span>
                          </div>
                        )}
                        <div className="flex items-center gap-2 text-sm">
                          <FileText className="h-4 w-4 text-muted-foreground" />
                          <span className="text-muted-foreground">Documents:</span>
                          <span>{hold.documentIds.length}</span>
                        </div>
                      </div>

                      {hold.status === 'released' && hold.releasedAt && (
                        <div className="p-3 bg-green-50 dark:bg-green-900/20 rounded-lg mb-4">
                          <p className="text-sm">
                            <span className="font-medium">Libere le:</span> {formatDate(hold.releasedAt)}
                            {hold.releasedBy && <span> par {hold.releasedBy}</span>}
                          </p>
                          {hold.releaseReason && (
                            <p className="text-sm text-muted-foreground mt-1">
                              <span className="font-medium">Raison:</span> {hold.releaseReason}
                            </p>
                          )}
                        </div>
                      )}

                      {/* Documents List */}
                      {holdDocs.length > 0 && (
                        <div>
                          <h4 className="text-sm font-medium mb-2">Documents proteges:</h4>
                          <div className="space-y-2">
                            {holdDocs.map((doc) => (
                              <div
                                key={doc.id}
                                className="flex items-center justify-between p-2 rounded-lg bg-muted/50"
                              >
                                <div className="flex items-center gap-2">
                                  <FileText className="h-4 w-4 text-muted-foreground" />
                                  <span className="text-sm">{doc.title}</span>
                                  <Badge variant="outline" className="text-xs">
                                    {doc.type}
                                  </Badge>
                                </div>
                                <span className="text-xs text-muted-foreground">
                                  v{doc.version}
                                </span>
                              </div>
                            ))}
                          </div>
                        </div>
                      )}
                    </CardContent>
                  </CollapsibleContent>
                </Collapsible>
              </Card>
            );
          })}
        </div>
      )}

      {/* Create Dialog */}
      <Dialog open={createDialogOpen} onOpenChange={setCreateDialogOpen}>
        <DialogContent className="max-w-2xl max-h-[90vh] overflow-hidden flex flex-col">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Shield className="h-5 w-5 text-warning-500" />
              {t('legalHold.create', 'Nouveau Legal Hold')}
            </DialogTitle>
            <DialogDescription>
              {t(
                'legalHold.createDescription',
                'Creez un legal hold pour proteger des documents contre la modification ou la suppression.'
              )}
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-4 py-4 overflow-y-auto flex-1">
            <div className="space-y-2">
              <Label htmlFor="name">{t('legalHold.form.name', 'Nom')} *</Label>
              <Input
                id="name"
                value={formData.name}
                onChange={(e) => setFormData((prev) => ({ ...prev, name: e.target.value }))}
                placeholder="Ex: Litige Commercial XYZ"
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="reason">{t('legalHold.form.reason', 'Raison')} *</Label>
              <Textarea
                id="reason"
                value={formData.reason}
                onChange={(e) => setFormData((prev) => ({ ...prev, reason: e.target.value }))}
                placeholder="Expliquez la raison du legal hold..."
                rows={3}
              />
            </div>

            <div className="grid gap-4 md:grid-cols-2">
              <div className="space-y-2">
                <Label htmlFor="matterNumber">
                  {t('legalHold.form.matterNumber', 'Reference du dossier')}
                </Label>
                <Input
                  id="matterNumber"
                  value={formData.matterNumber}
                  onChange={(e) =>
                    setFormData((prev) => ({ ...prev, matterNumber: e.target.value }))
                  }
                  placeholder="Ex: CASE-2024-001"
                />
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="description">
                {t('legalHold.form.description', 'Description')}
              </Label>
              <Textarea
                id="description"
                value={formData.description}
                onChange={(e) =>
                  setFormData((prev) => ({ ...prev, description: e.target.value }))
                }
                placeholder="Description detaillee (optionnel)..."
                rows={2}
              />
            </div>

            <Separator />

            <div className="space-y-2">
              <Label>{t('legalHold.form.selectDocuments', 'Sélectionner les documents')}</Label>
              <p className="text-sm text-muted-foreground">
                {formData.selectedDocuments.length} document(s) sélectionné(s)
              </p>
              <ScrollArea className="h-[200px] border rounded-lg p-2">
                <div className="space-y-2">
                  {filteredDocuments.length === 0 ? (
                    <p className="text-sm text-muted-foreground text-center py-8">
                      Aucun document disponible
                    </p>
                  ) : (
                    filteredDocuments.map((doc: Document) => (
                      <div
                        key={doc.id}
                        className={cn(
                          'flex items-center gap-3 p-2 rounded-lg cursor-pointer transition-colors',
                          formData.selectedDocuments.includes(doc.id)
                            ? 'bg-primary/10'
                            : 'hover:bg-muted'
                        )}
                        onClick={() => toggleDocumentSelection(doc.id)}
                      >
                        <Checkbox
                          checked={formData.selectedDocuments.includes(doc.id)}
                          onCheckedChange={() => toggleDocumentSelection(doc.id)}
                        />
                        <FileText className="h-4 w-4 text-muted-foreground" />
                        <div className="flex-1 min-w-0">
                          <p className="text-sm font-medium truncate">{doc.title}</p>
                          <p className="text-xs text-muted-foreground">
                            {doc.type} - v{doc.version}
                          </p>
                        </div>
                        {doc.isUnderHold && (
                          <Badge variant="outline" className="text-xs">
                            <Shield className="h-3 w-3 mr-1" />
                            Deja sous hold
                          </Badge>
                        )}
                      </div>
                    ))
                  )}
                </div>
              </ScrollArea>
            </div>
          </div>

          <DialogFooter>
            <Button
              variant="outline"
              onClick={() => {
                setCreateDialogOpen(false);
                resetForm();
              }}
            >
              {t('common.cancel', 'Annuler')}
            </Button>
            <Button onClick={handleCreate} disabled={formLoading}>
              {formLoading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              {t('legalHold.create', 'Creer le Legal Hold')}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Release Dialog */}
      <Dialog open={releaseDialogOpen} onOpenChange={setReleaseDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <AlertTriangle className="h-5 w-5 text-warning-500" />
              {t('legalHold.releaseTitle', 'Liberer le Legal Hold')}
            </DialogTitle>
            <DialogDescription>
              {t(
                'legalHold.releaseWarning',
                'Cette action liberera le legal hold et permettra la modification/suppression des documents proteges.'
              )}
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-4 py-4">
            {selectedHold && (
              <div className="p-3 bg-muted rounded-lg">
                <p className="font-medium">{selectedHold.name}</p>
                <p className="text-sm text-muted-foreground mt-1">
                  {selectedHold.documentIds.length} document(s) seront libere(s)
                </p>
              </div>
            )}

            <div className="space-y-2">
              <Label htmlFor="releaseReason">
                {t('legalHold.form.releaseReason', 'Raison de la liberation')}
              </Label>
              <Textarea
                id="releaseReason"
                value={releaseReason}
                onChange={(e) => setReleaseReason(e.target.value)}
                placeholder="Expliquez pourquoi le legal hold est libere..."
                rows={3}
              />
            </div>
          </div>

          <DialogFooter>
            <Button
              variant="outline"
              onClick={() => {
                setReleaseDialogOpen(false);
                setSelectedHold(null);
                setReleaseReason('');
              }}
            >
              {t('common.cancel', 'Annuler')}
            </Button>
            <Button variant="destructive" onClick={handleRelease} disabled={formLoading}>
              {formLoading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              {t('legalHold.confirmRelease', 'Confirmer la liberation')}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

export default LegalHoldManager;

/**
 * Import ICT Providers Modal
 * DORA Art. 28 - Story 35.1
 * CSV import wizard for ICT Providers
 */

import React, { useState, useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import { toast } from '@/lib/toast';
import { Dialog, Transition } from '@headlessui/react';
import { Button } from '../ui/button';
import { Upload, X, FileSpreadsheet, AlertCircle, CheckCircle } from '../ui/Icons';
import { ICTProviderService } from '../../services/ICTProviderService';
import { useStore } from '../../store';
import { useAuth } from '../../hooks/useAuth';
import { ErrorLogger } from '../../services/errorLogger';

interface ImportICTProvidersModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSuccess: () => void;
}

export const ImportICTProvidersModal: React.FC<ImportICTProvidersModalProps> = ({
    isOpen,
    onClose,
    onSuccess
}) => {
    const { t } = useTranslation();
    const { organization } = useStore();
    const { user } = useAuth();

    const [file, setFile] = useState<File | null>(null);
    const [isImporting, setIsImporting] = useState(false);
    const [result, setResult] = useState<{ imported: number; errors: string[] } | null>(null);

    const handleFileChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
        const selectedFile = e.target.files?.[0];
        if (selectedFile) {
            if (!selectedFile.name.endsWith('.csv')) {
                toast.error(t('dora.import.selectCsvFile'));
                return;
            }
            setFile(selectedFile);
            setResult(null);
        }
    }, [t]);

    const handleDrop = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        const droppedFile = e.dataTransfer.files[0];
        if (droppedFile) {
            if (!droppedFile.name.endsWith('.csv')) {
                toast.error(t('dora.import.selectCsvFile'));
                return;
            }
            setFile(droppedFile);
            setResult(null);
        }
    }, [t]);

    const parseCSV = (content: string): Record<string, string>[] => {
        const lines = content.split('\n').filter(line => line.trim());
        if (lines.length < 2) return [];

        const headers = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, ''));
        const rows: Record<string, string>[] = [];

        for (let i = 1; i < lines.length; i++) {
            const values = lines[i].split(',').map(v => v.trim().replace(/^"|"$/g, ''));
            const row: Record<string, string> = {};
            headers.forEach((header, index) => {
                row[header] = values[index] || '';
            });
            rows.push(row);
        }

        return rows;
    };

    const handleImport = async () => {
        if (!file || !organization?.id || !user?.uid) return;

        setIsImporting(true);
        try {
            const content = await file.text();
            const rows = parseCSV(content);

            if (rows.length === 0) {
                toast.error(t('dora.import.emptyOrInvalid'));
                return;
            }

            const importResult = await ICTProviderService.importFromCSV(
                rows,
                organization.id,
                user.uid
            );

            setResult(importResult);

            if (importResult.imported > 0) {
                toast.success(t('dora.import.success', { count: importResult.imported }));
                onSuccess();
            }

            if (importResult.errors.length > 0) {
                toast.error(t('dora.import.errorsFound', { count: importResult.errors.length }));
            }
        } catch (error) {
            ErrorLogger.error(error, 'ImportICTProvidersModal.import');
            toast.error(t('dora.import.error'));
        } finally {
            setIsImporting(false);
        }
    };

    const handleClose = () => {
        setFile(null);
        setResult(null);
        onClose();
    };

    return (
        <Transition.Root show={isOpen} as={React.Fragment}>
            <Dialog as="div" className="relative z-50" onClose={handleClose}>
                <Transition.Child
                    as={React.Fragment}
                    enter="ease-out duration-300"
                    enterFrom="opacity-0"
                    enterTo="opacity-70"
                    leave="ease-in duration-200"
                    leaveFrom="opacity-70"
                    leaveTo="opacity-0"
                >
                    <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm" />
                </Transition.Child>

                <div className="fixed inset-0 z-10 overflow-y-auto">
                    <div className="flex min-h-full items-center justify-center p-4">
                        <Transition.Child
                            as={React.Fragment}
                            enter="ease-out duration-300"
                            enterFrom="opacity-0 scale-95"
                            enterTo="opacity-70 scale-100"
                            leave="ease-in duration-200"
                            leaveFrom="opacity-70 scale-100"
                            leaveTo="opacity-0 scale-95"
                        >
                            <Dialog.Panel className="relative w-full max-w-lg transform rounded-3xl bg-white dark:bg-slate-900 p-6 shadow-2xl transition-all">
                                <div className="absolute right-4 top-4">
                                    <button
                                        onClick={handleClose}
                                        className="text-muted-foreground hover:text-slate-600 dark:hover:text-slate-300"
                                    >
                                        <X className="w-5 h-5" />
                                    </button>
                                </div>

                                <Dialog.Title className="text-xl font-bold text-slate-900 dark:text-white mb-4">
                                    {t('dora.import.title')}
                                </Dialog.Title>

                                {/* Dropzone */}
                                <div
                                    onDrop={handleDrop}
                                    onDragOver={(e) => e.preventDefault()}
                                    className={`
                                        border-2 border-dashed rounded-2xl p-8 text-center transition-colors cursor-pointer
                                        ${file
                                            ? 'border-green-300 bg-green-50 dark:border-green-700 dark:bg-green-900/20'
                                            : 'border-slate-200 hover:border-indigo-300 dark:border-slate-700 dark:hover:border-indigo-600'
                                        }
                                    `}
                                    onClick={() => document.getElementById('csv-upload')?.click()}
                                >
                                    <input
                                        id="csv-upload"
                                        type="file"
                                        accept=".csv"
                                        onChange={handleFileChange}
                                        className="hidden"
                                    />

                                    {file ? (
                                        <div className="flex flex-col items-center">
                                            <FileSpreadsheet className="w-12 h-12 text-green-500 mb-3" />
                                            <p className="font-medium text-slate-900 dark:text-white">{file.name}</p>
                                            <p className="text-sm text-slate-500 dark:text-slate-300 mt-1">
                                                {(file.size / 1024).toFixed(1)} KB
                                            </p>
                                        </div>
                                    ) : (
                                        <div className="flex flex-col items-center">
                                            <Upload className="w-12 h-12 text-muted-foreground mb-3" />
                                            <p className="font-medium text-slate-900 dark:text-white">
                                                {t('dora.import.dropzone')}
                                            </p>
                                            <p className="text-sm text-slate-500 dark:text-slate-300 mt-1">
                                                {t('dora.import.clickToSelect')}
                                            </p>
                                        </div>
                                    )}
                                </div>

                                {/* Expected Format */}
                                <div className="mt-4 p-4 bg-slate-50 dark:bg-slate-800/50 rounded-xl">
                                    <p className="text-xs font-bold uppercase tracking-wider text-slate-500 dark:text-slate-300 mb-2">
                                        {t('dora.import.expectedColumns')}
                                    </p>
                                    <p className="text-sm text-slate-600 dark:text-muted-foreground font-mono">
                                        {t('dora.import.columnsList')}
                                    </p>
                                </div>

                                {/* Result */}
                                {result && (
                                    <div className="mt-4 space-y-2">
                                        <div className="flex items-center gap-2 text-green-600 dark:text-green-400">
                                            <CheckCircle className="w-5 h-5" />
                                            <span>{t('dora.import.providersImported', { count: result.imported })}</span>
                                        </div>
                                        {result.errors.length > 0 && (
                                            <div className="p-3 bg-red-50 dark:bg-red-900/20 rounded-xl">
                                                <div className="flex items-center gap-2 text-red-600 dark:text-red-400 mb-2">
                                                    <AlertCircle className="w-5 h-5" />
                                                    <span>{t('dora.import.errorsCount', { count: result.errors.length })}</span>
                                                </div>
                                                <ul className="text-sm text-red-600 dark:text-red-400 space-y-1 max-h-32 overflow-y-auto">
                                                    {result.errors.map((err, i) => (
                                                        <li key={i}>{err}</li>
                                                    ))}
                                                </ul>
                                            </div>
                                        )}
                                    </div>
                                )}

                                {/* Actions */}
                                <div className="flex justify-end gap-3 mt-6">
                                    <Button variant="ghost" onClick={handleClose}>
                                        {t('common.cancel')}
                                    </Button>
                                    <Button
                                        onClick={handleImport}
                                        disabled={!file || isImporting}
                                        isLoading={isImporting}
                                        className="bg-gradient-to-r from-brand-600 to-indigo-600 text-white"
                                    >
                                        {t('common.import.label')}
                                    </Button>
                                </div>
                            </Dialog.Panel>
                        </Transition.Child>
                    </div>
                </div>
            </Dialog>
        </Transition.Root>
    );
};

import React from 'react';
import { useTranslation } from 'react-i18next';
import { useZodForm } from '../../hooks/useZodForm';
import { Controller } from 'react-hook-form';
import { Drawer } from '../ui/Drawer';
import { Button } from '../ui/button';
import { FloatingLabelInput } from '../ui/FloatingLabelInput';
import { CustomSelect } from '../ui/CustomSelect';
import { createEbiosAnalysisSchema, type CreateEbiosAnalysisFormData } from '../../schemas/ebiosSchema';
import { Shield } from '../ui/Icons';

interface CreateAnalysisDrawerProps {
    isOpen: boolean;
    onClose: () => void;
    onSave: (data: CreateEbiosAnalysisFormData) => Promise<void> | void;
    isLoading?: boolean;
}

export const CreateAnalysisDrawer: React.FC<CreateAnalysisDrawerProps> = ({
    isOpen,
    onClose,
    onSave,
    isLoading = false
}) => {
    const { t } = useTranslation();

    const {
        register,
        handleSubmit,
        formState: { errors },
        reset,
        control
    } = useZodForm({
        schema: createEbiosAnalysisSchema,
        defaultValues: {
            name: '',
            description: '',
            sector: '',
            targetCertificationDate: ''
        },
    });

    // Reset form when opening
    React.useEffect(() => {
        if (isOpen) {
            reset();
        }
    }, [isOpen, reset]);

    const onSubmit = async (data: CreateEbiosAnalysisFormData) => {
        await onSave(data);
    };

    const sectorOptions = [
        { value: 'finance', label: t('ebios.sectors.finance') },
        { value: 'healthcare', label: t('ebios.sectors.healthcare') },
        { value: 'energy', label: t('ebios.sectors.energy') },
        { value: 'transport', label: t('ebios.sectors.transport') },
        { value: 'telecommunications', label: t('ebios.sectors.telecommunications') },
        { value: 'government', label: t('ebios.sectors.government') },
        { value: 'industry', label: t('ebios.sectors.industry') },
        { value: 'retail', label: t('ebios.sectors.retail') },
        { value: 'other', label: t('ebios.sectors.other') },
    ];

    return (
        <Drawer
            isOpen={isOpen}
            onClose={onClose}
            title={
                <div className="flex items-center gap-3">
                    <div className="p-2 bg-slate-100 dark:bg-slate-800 rounded-lg text-slate-600 dark:text-slate-300 shadow-sm border border-slate-200 dark:border-white/5">
                        <Shield className="h-5 w-5" />
                    </div>
                    {t('ebios.createAnalysis')}
                </div>
            }
            subtitle={t('ebios.createAnalysisInfo')}
            width="max-w-xl"
        >
            <form onSubmit={handleSubmit(onSubmit)} className="flex flex-col h-full">
                <div className="flex-1 space-y-6 pt-6 px-1">
                    {/* Name */}
                    <FloatingLabelInput
                        label={t('ebios.analysisName')}
                        placeholder={t('ebios.analysisNamePlaceholder')}
                        error={errors.name?.message}
                        {...register('name')}
                        autoFocus
                    />

                    {/* Description */}
                    <FloatingLabelInput
                        label={t('ebios.analysisDescription')}
                        placeholder={t('ebios.analysisDescriptionPlaceholder')}
                        textarea
                        rows={4}
                        error={errors.description?.message}
                        {...register('description')}
                    />

                    {/* Sector */}
                    <Controller
                        name="sector"
                        control={control}
                        render={({ field }) => (
                            <CustomSelect
                                label={t('ebios.sector')}
                                options={[
                                    { value: "", label: t('ebios.selectSector') },
                                    ...sectorOptions
                                ]}
                                value={field.value || ""}
                                onChange={field.onChange}
                                error={errors.sector?.message}
                            />
                        )}
                    />

                    {/* Target Date */}
                    <FloatingLabelInput
                        type="date"
                        label={t('ebios.targetCertificationDate')}
                        error={errors.targetCertificationDate?.message}
                        {...register('targetCertificationDate')}
                    />
                </div>

                <div className="mt-8 flex justify-end gap-3 pt-6 border-t border-slate-200 dark:border-white/10">
                    <Button
                        type="button"
                        variant="ghost"
                        onClick={onClose}
                        disabled={isLoading}
                    >
                        {t('common.cancel')}
                    </Button>
                    <Button
                        type="submit"
                        isLoading={isLoading}
                    >
                        {t('ebios.startAnalysis')}
                    </Button>
                </div>
            </form>
        </Drawer>
    );
};

export default CreateAnalysisDrawer;

/**
 * Workshop 1: Cadrage et Socle de Sécurité
 * Main content component for EBIOS RM Workshop 1
 *
 * Sections:
 * 1. Scope Definition (Missions, Essential Assets, Supporting Assets)
 * 2. Feared Events (Événements Redoutés)
 * 3. Security Baseline (Socle de Sécurité)
 */

import React, { useState, useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import {
  Building2,
  Box,
  Server,
  AlertTriangle,
  ShieldCheck,
  Plus,
  ChevronDown,
  ChevronUp,
  Link2,
  Download,
} from '../../ui/Icons';
import { cn } from '../../../utils/cn';
import { PremiumCard } from '../../ui/PremiumCard';
import type { Workshop1Data, Mission, EssentialAsset, SupportingAsset, FearedEvent } from '../../../types/ebios';
import { MissionForm } from './forms/MissionForm';
import { EssentialAssetForm } from './forms/EssentialAssetForm';
import { SupportingAssetForm } from './forms/SupportingAssetForm';
import { FearedEventForm } from './forms/FearedEventForm';
import { SecurityBaselinePanel } from './SecurityBaselinePanel';
import { ImportFromInventoryModal } from '../shared/ImportFromInventoryModal';
import { GRAVITY_SCALE } from '../../../data/ebiosLibrary';

interface Workshop1ContentProps {
  data: Workshop1Data;
  onDataChange: (data: Partial<Workshop1Data>) => void;
  readOnly?: boolean;
}

type SectionKey = 'missions' | 'essentialAssets' | 'supportingAssets' | 'fearedEvents' | 'securityBaseline';

export const Workshop1Content: React.FC<Workshop1ContentProps> = ({
  data,
  onDataChange,
  readOnly = false,
}) => {
  const { t, i18n } = useTranslation();
  const locale = i18n.language.startsWith('fr') ? 'fr' : 'en';

  const [expandedSections, setExpandedSections] = useState<Set<SectionKey>>(
    new Set(['missions', 'essentialAssets', 'fearedEvents'])
  );
  const [editingItem, setEditingItem] = useState<{
    type: SectionKey;
    item: Mission | EssentialAsset | SupportingAsset | FearedEvent | null;
  } | null>(null);
  const [showImportModal, setShowImportModal] = useState(false);

  const toggleSection = (section: SectionKey) => {
    setExpandedSections((prev) => {
      const next = new Set(prev);
      if (next.has(section)) {
        next.delete(section);
      } else {
        next.add(section);
      }
      return next;
    });
  };

  // Mission handlers
  const handleAddMission = useCallback(() => {
    setEditingItem({ type: 'missions', item: null });
  }, []);

  const handleEditMission = useCallback((mission: Mission) => {
    setEditingItem({ type: 'missions', item: mission });
  }, []);

  const handleSaveMission = useCallback((mission: Mission) => {
    const existing = data.scope.missions.find((m) => m.id === mission.id);
    const missions = existing
      ? data.scope.missions.map((m) => (m.id === mission.id ? mission : m))
      : [...data.scope.missions, mission];
    onDataChange({ scope: { ...data.scope, missions } });
    setEditingItem(null);
  }, [data.scope, onDataChange]);

  const handleDeleteMission = useCallback((id: string) => {
    const missions = data.scope.missions.filter((m) => m.id !== id);
    onDataChange({ scope: { ...data.scope, missions } });
  }, [data.scope, onDataChange]);

  // Essential Asset handlers
  const handleAddEssentialAsset = useCallback(() => {
    setEditingItem({ type: 'essentialAssets', item: null });
  }, []);

  const handleEditEssentialAsset = useCallback((asset: EssentialAsset) => {
    setEditingItem({ type: 'essentialAssets', item: asset });
  }, []);

  const handleSaveEssentialAsset = useCallback((asset: EssentialAsset) => {
    const existing = data.scope.essentialAssets.find((a) => a.id === asset.id);
    const essentialAssets = existing
      ? data.scope.essentialAssets.map((a) => (a.id === asset.id ? asset : a))
      : [...data.scope.essentialAssets, asset];
    onDataChange({ scope: { ...data.scope, essentialAssets } });
    setEditingItem(null);
  }, [data.scope, onDataChange]);

  const handleDeleteEssentialAsset = useCallback((id: string) => {
    const essentialAssets = data.scope.essentialAssets.filter((a) => a.id !== id);
    onDataChange({ scope: { ...data.scope, essentialAssets } });
  }, [data.scope, onDataChange]);

  // Supporting Asset handlers
  const handleAddSupportingAsset = useCallback(() => {
    setEditingItem({ type: 'supportingAssets', item: null });
  }, []);

  const handleEditSupportingAsset = useCallback((asset: SupportingAsset) => {
    setEditingItem({ type: 'supportingAssets', item: asset });
  }, []);

  const handleSaveSupportingAsset = useCallback((asset: SupportingAsset) => {
    const existing = data.scope.supportingAssets.find((a) => a.id === asset.id);
    const supportingAssets = existing
      ? data.scope.supportingAssets.map((a) => (a.id === asset.id ? asset : a))
      : [...data.scope.supportingAssets, asset];
    onDataChange({ scope: { ...data.scope, supportingAssets } });
    setEditingItem(null);
  }, [data.scope, onDataChange]);

  const handleDeleteSupportingAsset = useCallback((id: string) => {
    const supportingAssets = data.scope.supportingAssets.filter((a) => a.id !== id);
    onDataChange({ scope: { ...data.scope, supportingAssets } });
  }, [data.scope, onDataChange]);

  // Import from inventory handler
  const handleImportFromInventory = useCallback((importedAssets: SupportingAsset[]) => {
    const supportingAssets = [...data.scope.supportingAssets, ...importedAssets];
    onDataChange({ scope: { ...data.scope, supportingAssets } });
    setShowImportModal(false);
  }, [data.scope, onDataChange]);

  // Get existing linked asset IDs for filtering
  const existingLinkedAssetIds = data.scope.supportingAssets
    .filter((a) => a.linkedAssetId)
    .map((a) => a.linkedAssetId as string);

  // Feared Event handlers
  const handleAddFearedEvent = useCallback(() => {
    setEditingItem({ type: 'fearedEvents', item: null });
  }, []);

  const handleEditFearedEvent = useCallback((event: FearedEvent) => {
    setEditingItem({ type: 'fearedEvents', item: event });
  }, []);

  const handleSaveFearedEvent = useCallback((event: FearedEvent) => {
    const existing = data.fearedEvents.find((e) => e.id === event.id);
    const fearedEvents = existing
      ? data.fearedEvents.map((e) => (e.id === event.id ? event : e))
      : [...data.fearedEvents, event];
    onDataChange({ fearedEvents });
    setEditingItem(null);
  }, [data.fearedEvents, onDataChange]);

  const handleDeleteFearedEvent = useCallback((id: string) => {
    const fearedEvents = data.fearedEvents.filter((e) => e.id !== id);
    onDataChange({ fearedEvents });
  }, [data.fearedEvents, onDataChange]);

  // Security Baseline handler
  const handleSecurityBaselineChange = useCallback((baseline: Workshop1Data['securityBaseline']) => {
    onDataChange({ securityBaseline: baseline });
  }, [onDataChange]);

  const getCriticalityColor = (level: number) => {
    const scale = GRAVITY_SCALE.find((s) => s.level === level);
    return scale?.color || 'gray';
  };

  const getCriticalityLabel = (level: number) => {
    const scale = GRAVITY_SCALE.find((s) => s.level === level);
    return scale?.[locale] || '';
  };

  return (
    <div className="space-y-6">
      {/* Missions Section */}
