      </div>

      {/* Edit Modals */}
      {editingItem?.type === 'missions' && (
        <MissionForm
          mission={editingItem.item as Mission | null}
          onSave={handleSaveMission}
          onDelete={editingItem.item ? handleDeleteMission : undefined}
          onClose={() => setEditingItem(null)}
        />
