const TREATMENT_STATUS_OPTIONS = [
  {
    value: 'planned' as const,
    label: { fr: 'Planifié', en: 'Planned' },
    color: 'gray',
  },
  {
    value: 'in_progress' as const,
    label: { fr: 'En cours', en: 'In progress' },
    color: 'blue',
