                    >
                        <Search className="h-4 w-4 text-slate-500 dark:text-slate-300 group-hover:text-brand-500 transition-colors" />
                        <span className="flex-1 text-left font-medium text-xs uppercase tracking-wide">{t('common.search')}</span>
                        <div className="flex items-center gap-1 px-1.5 py-0.5 rounded-md bg-white dark:bg-white/10 border border-slate-200 dark:border-white/5 text-[11px] font-bold text-slate-500 dark:text-slate-300 shadow-sm">
                            <Command className="h-3 w-3" />
                            <span>K</span>
                        </div>
                    </button>

                    {/* Mobile Search Icon */}
                    <button
                        aria-label="Rechercher"
                        onClick={openCommandPalette}
                        className="md:hidden p-2.5 text-slate-500 dark:text-slate-300 hover:text-slate-600 dark:hover:text-white transition-colors rounded-lg hover:bg-slate-100 dark:hover:bg-white/5"
                    >
                        <Search className="h-5 w-5" />
                    </button>
                </div>

                {/* Right: Actions & Profile */}
                <div className="flex items-center gap-2 sm:gap-4">
                    {/* Plan Indicator */}
                    <div>
                        <PlanIndicator />
                    </div>

                    {isSuperAdmin && (
                        <Link
                            to="/admin_management"
                            className="hidden sm:flex items-center gap-2 px-3 py-1.5 bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-400 dark:bg-red-900/30 dark:text-red-300 rounded-lg text-sm font-medium hover:bg-red-200 transition-colors"
