import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { useForm, Controller, Resolver } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { PROJECT_TEMPLATES } from '../../utils/projectTemplates';
import { ProjectTemplate, UserProfile } from '../../types';
import { X, Zap, Calendar } from '../ui/Icons';
import { templateFormSchema, TemplateFormData } from '../../schemas/projectSchema';
import { CustomSelect } from '../ui/CustomSelect';

interface TemplateModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSelectTemplate: (template: ProjectTemplate, projectName: string, startDate: Date, managerId: string) => void;
    managers: UserProfile[];
}

export const TemplateModal: React.FC<TemplateModalProps> = ({ isOpen, onClose, onSelectTemplate, managers }) => {
    const [selectedTemplate, setSelectedTemplate] = useState<ProjectTemplate | null>(null);

    const {
        register,
        handleSubmit,
        control,
        reset,
        formState: { errors }
    } = useForm<TemplateFormData>({
        resolver: zodResolver(templateFormSchema) as Resolver<TemplateFormData>,
        defaultValues: {
            projectName: '',
            startDate: new Date().toISOString().split('T')[0],
            managerId: ''
        }
    });

    useEffect(() => {
        if (isOpen) {
            reset({
                projectName: '',
                startDate: new Date().toISOString().split('T')[0],
                managerId: ''
            });
            // eslint-disable-next-line react-hooks/set-state-in-effect
            setSelectedTemplate(null);
        }
    }, [isOpen, reset]);

    const onFormSubmit = (data: TemplateFormData) => {
        if (selectedTemplate) {
            onSelectTemplate(selectedTemplate, data.projectName, new Date(data.startDate), data.managerId);
            onClose();
        }
    };

    if (!isOpen) return null;

    return createPortal(
        <div className="fixed inset-0 z-max flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fade-in">
            <div className="glass-panel rounded-4xl shadow-2xl max-w-4xl w-full max-h-[90vh] overflow-hidden border border-white/20 animate-scale-in relative">
                <div className="absolute inset-0 bg-gradient-to-br from-white/40 to-white/0 dark:from-white/10 dark:to-transparent pointer-events-none" />
                {/* Header */}
                <div className="flex items-center justify-between p-6 border-b border-white/10 relative z-10 glass-panel backdrop-blur-md">
                    <div>
                        <h2 className="text-2xl font-bold text-slate-900 dark:text-white">
                            Créer depuis un Template
                        </h2>
                        <p className="text-sm text-slate-600 dark:text-muted-foreground mt-1">
                            Démarrez rapidement avec un projet pré-configuré
                        </p>
                    </div>
                    <button
                        aria-label="Fermer la fenêtre"
                        onClick={onClose}
                        className="p-2.5 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-xl transition-colors"
                    >
                        <X className="h-5 w-5" />
                    </button>
                </div>

                <div className="overflow-y-auto max-h-[calc(90vh-200px)] relative z-10">
                    {!selectedTemplate ? (
                        /* Template Selection */
                        <div className="p-6">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                {PROJECT_TEMPLATES.map(template => (
                                    <button
                                        key={template.id}
                                        aria-label={`Sélectionner le modèle ${template.name}`}
                                        onClick={() => setSelectedTemplate(template)}
                                        className="text-left p-6 rounded-xl border-2 border-slate-200 dark:border-white/10 hover:border-brand-500 dark:hover:border-brand-500 transition-all hover:shadow-lg group"
                                    >
                                        <div className="flex items-start gap-4">
                                            <div className="text-4xl">{template.icon}</div>
                                            <div className="flex-1">
                                                <h3 className="font-bold text-lg text-slate-900 dark:text-white group-hover:text-brand-600 dark:group-hover:text-brand-400 transition-colors">
                                                    {template.name}
                                                </h3>
                                                <p className="text-sm text-slate-600 dark:text-muted-foreground mt-1">
                                                    {template.description}
                                                </p>
                                                <div className="flex items-center gap-4 mt-3 text-xs text-slate-600">
                                                    <span className="flex items-center gap-1">
                                                        <Calendar className="h-3 w-3" />
                                                        {template.estimatedDuration} jours
                                                    </span>
                                                    <span className="flex items-center gap-1">
                                                        <Zap className="h-3 w-3" />
                                                        {template.defaultTasks.length} tâches
                                                    </span>
                                                </div>
                                                <div className="mt-3">
                                                    <span className="px-2 py-1 bg-brand-100 dark:bg-brand-800 text-brand-700 dark:text-brand-400 rounded-lg text-xs font-bold">
                                                        {template.category}
                                                    </span>
                                                </div>
                                            </div>
                                        </div>
                                    </button>
                                ))}
                            </div>
                        </div>
                    ) : (
                        /* Template Configuration */
                        <form onSubmit={handleSubmit(onFormSubmit)} className="p-6 space-y-6">
                            <div className="glass-panel p-4 rounded-xl border border-brand-200 dark:border-brand-700 bg-brand-50 dark:bg-brand-900">
                                <div className="flex items-center gap-3">
                                    <span className="text-3xl">{selectedTemplate.icon}</span>
                                    <div>
                                        <h3 className="font-bold text-slate-900 dark:text-white">{selectedTemplate.name}</h3>
                                        <p className="text-sm text-slate-600 dark:text-muted-foreground">{selectedTemplate.description}</p>
                                    </div>
                                </div>
                                <div className="mt-3 flex gap-3 text-xs">
                                    <span className="px-2 py-1 bg-white dark:bg-slate-800 rounded-lg font-bold">
                                        {selectedTemplate.defaultTasks.length} tâches
                                    </span>
                                    <span className="px-2 py-1 bg-white dark:bg-slate-800 rounded-lg font-bold">
                                        {selectedTemplate.defaultMilestones.length} jalons
                                    </span>
                                    <span className="px-2 py-1 bg-white dark:bg-slate-800 rounded-lg font-bold">
                                        ~{selectedTemplate.estimatedDuration} jours
                                    </span>
                                </div>
                            </div>

                            <div>
                                <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">
                                    Nom du Projet *
                                </label>
                                <input {...register('projectName')}
                                    type="text"
                                    placeholder="Ex: Certification ISO 27001 2025"
                                    className="w-full px-4 py-2 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl focus:ring-2 focus-visible:ring-brand-500 focus:border-transparent"
                                />
                                {errors.projectName && <p className="text-red-500 text-xs mt-1">{errors.projectName.message}</p>}
                            </div>

                            <div>
                                <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">
                                    Date de Début *
                                </label>
                                <input {...register('startDate')}
                                    type="date"
                                    className="w-full px-4 py-2 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl focus:ring-2 focus-visible:ring-brand-500 focus:border-transparent"
                                />
                                {errors.startDate && <p className="text-red-500 text-xs mt-1">{errors.startDate.message}</p>}
                            </div>

                            <div>
                                <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">
                                    Chef de Projet *
                                </label>
                                <Controller
                                    name="managerId"
                                    control={control}
                                    render={({ field }) => (
                                        <CustomSelect
                                            options={managers.filter(m => !!m.uid).map(m => ({
                                                value: m.uid,
                                                label: m.displayName || m.email || 'Utilisateur'
                                            }))}
                                            value={field.value}
                                            onChange={field.onChange}
                                            placeholder="Sélectionner..."
                                            label="Chef de Projet"
                                        />
                                    )}
                                />
                                {errors.managerId && <p className="text-red-500 text-xs mt-1">{errors.managerId.message}</p>}
                            </div>

                            <div className="bg-slate-50 dark:bg-slate-800 p-4 rounded-xl">
                                <h4 className="text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">
                                    Ce qui sera créé:
                                </h4>
                                <ul className="space-y-1 text-sm text-slate-600 dark:text-muted-foreground">
                                    <li>✓ {selectedTemplate.defaultTasks.length} tâches pré-configurées</li>
                                    <li>✓ {selectedTemplate.defaultMilestones.length} jalons avec dates calculées</li>
                                    {/* Note: startDate is watched or we can just use a generic message since it's dynamic */}
                                    <li>✓ Durée estimée: {selectedTemplate.estimatedDuration} jours</li>
                                </ul>
                            </div>

                            <div className="flex gap-3">
                                <button
                                    type="button"
                                    aria-label="Retour à la sélection de modèle"
                                    onClick={() => setSelectedTemplate(null)}
                                    className="flex-1 px-4 py-2 bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-300 rounded-xl font-bold hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors"
                                >
                                    Retour
                                </button>
                                <button
                                    type="submit"
                                    aria-label="Créer le projet"
                                    className="flex-1 px-4 py-2 bg-brand-600 text-white rounded-xl font-bold hover:bg-brand-700 transition-colors shadow-lg shadow-brand-500/20"
                                >
                                    Créer le Projet
                                </button>
                            </div>
                        </form>
                    )}
                </div>
            </div>
        </div>,
        document.body
    );
};

// Headless UI handles FocusTrap and keyboard navigation

import React, { useState, useMemo } from 'react';
import { Risk, RiskTreatment, Criticality, Control, TreatmentAction } from '../../types';
import { Calendar, AlertTriangle, CheckCircle2, Clock, User, Shield, Sparkles, Plus, X, Search, Filter } from '../ui/Icons';
import { format, addDays, isAfter, parseISO } from 'date-fns';
import { fr } from 'date-fns/locale';
import { Badge } from '../ui/Badge';
import { Button } from '../ui/button';
import { TreatmentActionsList } from './TreatmentActionsList';

interface RiskTreatmentPlanProps {
    risk: Risk;
    onUpdate: (treatment: RiskTreatment) => void;
    onRiskUpdate?: (updates: Partial<Risk>) => void;
    users: { uid: string; displayName: string }[];
    controls?: Control[];
}

export const RiskTreatmentPlan: React.FC<RiskTreatmentPlanProps> = ({ risk, onUpdate, onRiskUpdate, users, controls = [] }) => {
    // Default SLAs (in days)
    const SLA_DAYS = {
        [Criticality.CRITICAL]: 7,
        [Criticality.HIGH]: 30,
        [Criticality.MEDIUM]: 90,
        [Criticality.LOW]: 180
    };

    // Helper to calculate SLA status
    const calculateSLAStatus = (dueDate: string | undefined, status: string): 'On Track' | 'At Risk' | 'Breached' => {
        if (!dueDate) return 'On Track';

        const today = new Date();
        const due = parseISO(dueDate);

        if (isAfter(today, due) && status !== 'Terminé') {
            return 'Breached';
        } else if (status !== 'Terminé') {
            // Warning if within 3 days
            const warningDate = addDays(today, 3);
            if (isAfter(warningDate, due)) {
                return 'At Risk';
            }
        }
        return 'On Track';
    };

    // Control search and filter state
    const [controlSearch, setControlSearch] = useState('');
    const [frameworkFilter, setFrameworkFilter] = useState<string>('');

    // Get unique frameworks from controls
    const availableFrameworks = useMemo(() => {
        const frameworks = new Set(controls.map(c => c.framework).filter(Boolean));
        return Array.from(frameworks).sort();
    }, [controls]);

    // Filter controls based on search and framework
    const filteredControls = useMemo(() => {
        return controls.filter(c => {
            // Exclude already linked controls
            if (risk.mitigationControlIds?.includes(c.id)) return false;

            // Apply search filter
            const searchLower = controlSearch.toLowerCase();
            const matchesSearch = !controlSearch ||
                c.name.toLowerCase().includes(searchLower) ||
                c.code?.toLowerCase().includes(searchLower) ||
                c.description?.toLowerCase().includes(searchLower);

            // Apply framework filter
            const matchesFramework = !frameworkFilter || c.framework === frameworkFilter;

            return matchesSearch && matchesFramework;
        });
    }, [controls, risk.mitigationControlIds, controlSearch, frameworkFilter]);

    // Get linked controls with details
    const linkedControls = useMemo(() => {
        return (risk.mitigationControlIds || [])
            .map(id => controls.find(c => c.id === id))
            .filter((c): c is Control => c !== undefined);
    }, [risk.mitigationControlIds, controls]);

    // Calculate mitigation coverage based on control implementation status
    const mitigationCoverage = useMemo(() => {
        if (linkedControls.length === 0) return 0;

        const statusWeightMap: Record<string, number> = {
            'Implémenté': 1.0,
            'Actif': 1.0,
            'Partiel': 0.5,
            'En cours': 0.3,
            'En revue': 0.2,
            'Non commencé': 0.1,
            'Non applicable': 0,
            'Exclu': 0,
            'Inactif': 0,
            'Non appliqué': 0
        };

        const effectiveScore = linkedControls.reduce((sum, ctrl) => {
            return sum + (statusWeightMap[ctrl.status] ?? 0);
        }, 0);

        return Math.min(Math.round((effectiveScore / linkedControls.length) * 100), 100);
    }, [linkedControls]);

    const [treatment, setTreatment] = useState<RiskTreatment>(() => {
        const initial: RiskTreatment = risk.treatment ? { ...risk.treatment } : {
            strategy: risk.strategy || 'Atténuer',
            status: 'Planifié',
            description: '',
            ownerId: risk.ownerId
        };

        // Calculate default due date if not present
        if (!initial.dueDate && risk.createdAt) {
            try {
                const days = SLA_DAYS[risk.score >= 15 ? Criticality.CRITICAL :
                    risk.score >= 10 ? Criticality.HIGH :
                        risk.score >= 5 ? Criticality.MEDIUM : Criticality.LOW] || 90;

                const createdAtDate = parseISO(risk.createdAt);
                if (!isNaN(createdAtDate.getTime())) {
                    const suggestedDate = addDays(createdAtDate, days);
                    const formattedDate = format(suggestedDate, 'yyyy-MM-dd');

                    initial.dueDate = formattedDate;
                    initial.slaStatus = calculateSLAStatus(formattedDate, initial.status || 'Planifié');
                }
            } catch {
                // ErrorLogger.error(error, 'RiskTreatmentPlan.parseDate');
                // Keep default date if parsing fails
            }
        }

        return initial;
    });

    const handleChange = (field: keyof RiskTreatment, value: string | number | string[]) => {
        const updated = { ...treatment, [field]: value };

        // Recalculate SLA if relevant fields change
        if ((field === 'dueDate' || field === 'status') && typeof value === 'string') {
            updated.slaStatus = calculateSLAStatus(
                field === 'dueDate' ? value : treatment.dueDate,
                field === 'status' ? value : (treatment.status || 'Planifié')
            );
        }

        setTreatment(updated);
        onUpdate(updated);
    };

    const toggleControl = (controlId: string) => {
        if (!onRiskUpdate) return;
        const currentIds = risk.mitigationControlIds || [];
        const newIds = currentIds.includes(controlId)
            ? currentIds.filter(id => id !== controlId)
            : [...currentIds, controlId];
        onRiskUpdate({ mitigationControlIds: newIds });
    };

    const removeMeasure = (index: number) => {
        const currentMeasures = treatment.measures || [];
        const newMeasures = currentMeasures.filter((_, i) => i !== index);
        handleChange('measures', newMeasures);
        // Actually, let's just do manual update
        const updated = { ...treatment, measures: newMeasures };
        setTreatment(updated);
        onUpdate(updated);
    };

    // Treatment Actions handlers
    const handleAddAction = (actionData: Omit<TreatmentAction, 'id' | 'createdAt'>) => {
        if (!onRiskUpdate) return;
        const newAction: TreatmentAction = {
            ...actionData,
            id: `action-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
            createdAt: new Date().toISOString()
        };
        const currentActions = risk.treatmentActions || [];
        onRiskUpdate({ treatmentActions: [...currentActions, newAction] });
    };

    const handleUpdateAction = (updatedAction: TreatmentAction) => {
        if (!onRiskUpdate) return;
        const currentActions = risk.treatmentActions || [];
        const newActions = currentActions.map(a =>
            a.id === updatedAction.id ? updatedAction : a
        );
        onRiskUpdate({ treatmentActions: newActions });
    };

    const handleDeleteAction = (actionId: string) => {
        if (!onRiskUpdate) return;
        const currentActions = risk.treatmentActions || [];
        onRiskUpdate({ treatmentActions: currentActions.filter(a => a.id !== actionId) });
    };

    return (
        <div className="space-y-6">
            <div className="glass-panel p-4 sm:p-6 rounded-4xl border border-white/60 dark:border-white/10 shadow-sm space-y-6">
                <div className="flex items-center justify-between">
                    <h3 className="text-lg font-bold text-slate-900 dark:text-white flex items-center gap-2">
                        <CheckCircle2 className="h-5 w-5 text-brand-500" />
                        Plan de Traitement
                    </h3>
                    {treatment.slaStatus === 'Breached' && (
                        <span className="px-3 py-1 bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-400 rounded-full text-xs font-bold flex items-center gap-1 border border-red-200">
                            <AlertTriangle className="h-3 w-3" /> SLA Dépassé
                        </span>
                    )}
                    {treatment.slaStatus === 'At Risk' && (
                        <span className="px-3 py-1 bg-warning-bg text-warning-text rounded-full text-xs font-bold flex items-center gap-1 border border-warning-border">
                            <Clock className="h-3 w-3" /> SLA À Risque
                        </span>
                    )}
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 sm:gap-6">
                    {/* Strategy */}
                    <div className="space-y-2">
                        <label className="text-xs font-bold uppercase tracking-wider text-slate-700 dark:text-slate-300 ml-1">Stratégie</label>
                        <div className="relative group">
                            <select
                                value={treatment.strategy}
                                onChange={(e) => handleChange('strategy', e.target.value)}
                                className="w-full appearance-none rounded-xl border-slate-200 dark:border-white/10 bg-white dark:bg-slate-800 text-sm p-3 font-medium transition-all focus:ring-2 focus-visible:ring-brand-300 focus:border-brand-500 outline-none"
                            >
                                <option value="Atténuer">Atténuer (Réduire)</option>
                                <option value="Transférer">Transférer (Assurance/Sous-traitance)</option>
                                <option value="Éviter">Éviter (Supprimer l'activité)</option>
                                <option value="Accepter">Accepter (Risque résiduel)</option>
                            </select>
                            <AlertTriangle className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400 pointer-events-none group-hover:text-brand-500 transition-colors" />
                        </div>
                    </div>

                    {/* Status */}
                    <div className="space-y-2">
                        <label className="text-xs font-bold uppercase tracking-wider text-slate-500 dark:text-slate-300 ml-1">Statut</label>
                        <div className="relative group">
                            <select
                                value={treatment.status}
                                onChange={(e) => handleChange('status', e.target.value)}
                                className="w-full appearance-none rounded-xl border-slate-200 dark:border-white/10 bg-white dark:bg-slate-800 text-sm p-3 font-medium transition-all focus:ring-2 focus-visible:ring-brand-300 focus:border-brand-500 outline-none"
                            >
                                <option value="Planifié">Planifié</option>
                                <option value="En cours">En cours</option>
                                <option value="Terminé">Terminé</option>
                                <option value="Retard">En retard</option>
                            </select>
                            <CheckCircle2 className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400 pointer-events-none group-hover:text-brand-500 transition-colors" />
                        </div>
                    </div>

                    {/* Owner */}
                    <div className="space-y-2">
                        <label className="text-xs font-bold uppercase tracking-wider text-slate-500 dark:text-slate-300 ml-1">Responsable</label>
                        <div className="relative group">
                            <User className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground group-focus-within:text-brand-500 transition-colors" />
                            <select
                                value={treatment.ownerId || ''}
                                onChange={(e) => handleChange('ownerId', e.target.value)}
                                className="w-full pl-10 pr-4 rounded-xl border-slate-200 dark:border-white/10 bg-white dark:bg-slate-800 text-sm p-3 font-medium transition-all focus:ring-2 focus-visible:ring-brand-300 focus:border-brand-500 outline-none appearance-none"
                            >
                                <option value="">Sélectionner un responsable</option>
                                {users.map(u => (
                                    <option key={u.uid} value={u.uid}>{u.displayName}</option>
                                ))}
                            </select>
