                                            <Shield className={`h-4 w-4 ${isImplemented ? 'text-success-text' : isPartial ? 'text-warning-text' : 'text-slate-400'}`} />
                                            <div>
                                                <p className="text-sm font-bold text-slate-900 dark:text-white">{ctrl.code} - {ctrl.name}</p>
                                                <div className="flex items-center gap-2 mt-0.5">
                                                    <span className="text-xs text-slate-500">{ctrl.framework || 'Contrôle'}</span>
                                                    <Badge
                                                        status={isImplemented ? 'success' : isPartial ? 'warning' : 'info'}
                                                        variant="soft"
                                                        size="sm"
                                                    >
                                                        {ctrl.status}
                                                    </Badge>
                                                </div>
                                            </div>
                                        </div>
                                        <Button
                                            variant="ghost"
                                            size="sm"
                                            onClick={() => toggleControl(ctrl.id)}
                                            className="text-red-500 hover:bg-red-50 dark:hover:bg-red-900/30 hover:text-red-600 opacity-0 group-hover:opacity-70 transition-opacity"
                                            aria-label={`Détacher le contrôle ${ctrl.name}`}
                                        >
                                            <X className="h-4 w-4" />
                                        </Button>
                                    </div>
                                );
                            })
                        )}
                    </div>

                    {/* Add Control Section - Enhanced with search and filter */}
                    <div className="pt-4 border-t border-slate-200 dark:border-slate-700 space-y-3">
                        <label className="text-xs font-bold uppercase tracking-wider text-slate-500 dark:text-slate-300 flex items-center gap-2">
                            <Plus className="h-3.5 w-3.5" />
                            Lier un nouveau contrôle
                        </label>

                        {/* Search and Filter Row */}
                        <div className="flex gap-2">
                            <div className="relative flex-1">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                                <input
                                    type="text"
                                    placeholder="Rechercher un contrôle..."
                                    value={controlSearch}
                                    onChange={(e) => setControlSearch(e.target.value)}
                                    className="w-full pl-9 pr-3 py-2 rounded-xl border border-slate-200 dark:border-white/10 bg-white dark:bg-slate-800 text-sm font-medium transition-all focus:ring-2 focus-visible:ring-brand-300 focus:border-brand-500 outline-none placeholder:text-muted-foreground"
                                />
                            </div>
                            {availableFrameworks.length > 1 && (
                                <div className="relative">
                                    <Filter className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                                    <select
                                        value={frameworkFilter}
                                        onChange={(e) => setFrameworkFilter(e.target.value)}
                                        className="pl-9 pr-8 py-2 rounded-xl border border-slate-200 dark:border-white/10 bg-white dark:bg-slate-800 text-sm font-medium transition-all focus:ring-2 focus-visible:ring-brand-300 focus:border-brand-500 outline-none appearance-none cursor-pointer"
                                        aria-label="Filtrer par framework"
                                    >
                                        <option value="">Tous</option>
                                        {availableFrameworks.map(fw => (
                                            <option key={fw} value={fw}>{fw}</option>
                                        ))}
                                    </select>
                                </div>
                            )}
                        </div>

                        {/* Available Controls List */}
                        <div className="max-h-48 overflow-y-auto space-y-1 rounded-xl border border-slate-200 dark:border-white/10 bg-white/30 dark:bg-black/10 p-2">
                            {filteredControls.length === 0 ? (
                                <p className="text-xs text-slate-500 dark:text-slate-300 text-center py-3">
                                    {controlSearch || frameworkFilter
                                        ? 'Aucun contrôle correspondant'
                                        : 'Tous les contrôles sont déjà liés'}
                                </p>
                            ) : (
                                filteredControls.slice(0, 20).map(ctrl => {
                                    const isImplemented = ctrl.status === 'Implémenté' || ctrl.status === 'Actif';
                                    const isPartial = ctrl.status === 'Partiel' || ctrl.status === 'En cours';
                                    return (
                                        <button
                                            key={ctrl.id}
                                            type="button"
                                            onClick={() => toggleControl(ctrl.id)}
                                            className="w-full flex items-center justify-between p-2 rounded-lg hover:bg-white dark:hover:bg-slate-800 transition-colors text-left group"
                                        >
                                            <div className="flex items-center gap-2 min-w-0">
                                                <Shield className="h-3.5 w-3.5 text-muted-foreground flex-shrink-0" />
                                                <span className="text-sm font-medium text-slate-700 dark:text-slate-300 truncate">
                                                    {ctrl.code} - {ctrl.name}
                                                </span>
                                            </div>
                                            <div className="flex items-center gap-2 flex-shrink-0">
                                                <Badge
                                                    status={isImplemented ? 'success' : isPartial ? 'warning' : 'info'}
                                                    variant="soft"
                                                    size="sm"
                                                >
                                                    {ctrl.status}
                                                </Badge>
                                                <Plus className="h-4 w-4 text-brand-500 opacity-0 group-hover:opacity-70 transition-opacity" />
                                            </div>
                                        </button>
                                    );
                                })
                            )}
                            {filteredControls.length > 20 && (
                                <p className="text-xs text-slate-500 dark:text-slate-300 text-center py-1">
                                    +{filteredControls.length - 20} autres contrôles...
                                </p>
                            )}
                        </div>
                    </div>
                </div>
            )}

            {/* Treatment Actions */}
            {onRiskUpdate && (
                <TreatmentActionsList
                    actions={risk.treatmentActions || []}
                    users={users}
                    onAdd={handleAddAction}
                    onUpdate={handleUpdateAction}
                    onDelete={handleDeleteAction}
                />
            )}
        </div>
    );
};

import React from 'react';
import { TreatmentAction } from '../../types';
import { useZodForm } from '../../hooks/useZodForm';
import { treatmentActionSchema, TreatmentActionFormData } from '../../schemas/treatmentActionSchema';
import { Calendar, User, X, Check } from '../ui/Icons';
import { Button } from '../ui/button';
import { useFormPersistence } from '../../hooks/utils/useFormPersistence';

interface TreatmentActionFormProps {
    action?: TreatmentAction; // If provided, editing mode
    users: { uid: string; displayName: string }[];
    onSave: (action: Omit<TreatmentAction, 'id' | 'createdAt'> & { id?: string }) => void;
    onCancel: () => void;
}

export const TreatmentActionForm: React.FC<TreatmentActionFormProps> = ({
    action,
    users,
    onSave,
    onCancel
}) => {
    const { register, handleSubmit, watch, reset, formState: { errors } } = useZodForm<typeof treatmentActionSchema>({
        schema: treatmentActionSchema,
        mode: 'onChange',
        defaultValues: {
            title: action?.title || '',
            description: action?.description || '',
            ownerId: action?.ownerId || '',
            deadline: action?.deadline || '',
            status: action?.status || 'À faire'
        }
    });

    // Persistence Hook
    const { clearDraft } = useFormPersistence<TreatmentActionFormData>('sentinel_treatment_draft_new', {
        watch,
        reset
    }, {
        enabled: !action
    });

    const onSubmit = (data: TreatmentActionFormData) => {
        onSave({
            id: action?.id,
            ...data,
            updatedAt: new Date().toISOString(),
            completedAt: data.status === 'Terminé' ? new Date().toISOString() : action?.completedAt
        });
        clearDraft();
    };

    return (
        <form onSubmit={handleSubmit(onSubmit)} className="space-y-4 p-4 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-slate-200 dark:border-slate-700">
            <div className="flex items-center justify-between">
                <h4 className="text-sm font-bold text-slate-900 dark:text-white">
                    {action ? 'Modifier l\'action' : 'Nouvelle action'}
                </h4>
                <Button
                    type="button"
                    variant="ghost"
                    size="sm"
                    onClick={onCancel}
                    aria-label="Annuler"
                >
                    <X className="h-4 w-4" />
                </Button>
            </div>

            {/* Title */}
            <div className="space-y-1.5">
                <label className="text-xs font-bold uppercase tracking-wider text-slate-500 dark:text-slate-300">
                    Titre <span className="text-red-500">*</span>
                </label>
                <input
                    type="text"
                    {...register('title')}
                    placeholder="Ex: Mettre à jour la politique de sécurité"
                    className={`w-full rounded-xl border ${errors.title ? 'border-red-500' : 'border-slate-200 dark:border-white/10'} bg-white dark:bg-black/20 text-sm p-3 font-medium transition-all focus:ring-2 focus-visible:ring-brand-300 focus:border-brand-500 outline-none placeholder:text-muted-foreground`}
                />
                {errors.title && (
                    <p className="text-xs text-red-500">{errors.title.message}</p>
                )}
            </div>

            {/* Description */}
            <div className="space-y-1.5">
                <label className="text-xs font-bold uppercase tracking-wider text-slate-500 dark:text-slate-300">
                    Description
                </label>
                <textarea
                    {...register('description')}
                    rows={2}
                    placeholder="Décrivez l'action à réaliser..."
                    className="w-full rounded-xl border border-slate-200 dark:border-white/10 bg-white dark:bg-black/20 text-sm p-3 font-medium transition-all focus:ring-2 focus-visible:ring-brand-300 focus:border-brand-500 outline-none placeholder:text-muted-foreground resize-none"
                />
                {errors.description && (
                    <p className="text-xs text-red-500">{errors.description.message}</p>
                )}
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                {/* Owner */}
                <div className="space-y-1.5">
                    <label className="text-xs font-bold uppercase tracking-wider text-slate-500 dark:text-slate-300">
                        Responsable
                    </label>
                    <div className="relative">
                        <User className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                        <select
                            {...register('ownerId')}
                            className="w-full pl-9 pr-4 rounded-xl border border-slate-200 dark:border-white/10 bg-white dark:bg-black/20 text-sm p-3 font-medium transition-all focus:ring-2 focus-visible:ring-brand-300 focus:border-brand-500 outline-none appearance-none"
                        >
                            <option value="">Non assigné</option>
                            {users.map(u => (
                                <option key={u.uid} value={u.uid}>{u.displayName}</option>
                            ))}
                        </select>
                    </div>
                </div>

                {/* Deadline */}
                <div className="space-y-1.5">
                    <label className="text-xs font-bold uppercase tracking-wider text-slate-500 dark:text-slate-300">
                        Échéance
                    </label>
                    <div className="relative">
                        <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                        <input
                            type="date"
                            {...register('deadline')}
                            className="w-full pl-9 pr-4 rounded-xl border border-slate-200 dark:border-white/10 bg-white dark:bg-black/20 text-sm p-3 font-medium transition-all focus:ring-2 focus-visible:ring-brand-300 focus:border-brand-500 outline-none"
                        />
                    </div>
                </div>

                {/* Status */}
                <div className="space-y-1.5">
                    <label className="text-xs font-bold uppercase tracking-wider text-slate-500 dark:text-slate-300">
                        Statut
                    </label>
                    <select
                        {...register('status')}
                        className="w-full rounded-xl border border-slate-200 dark:border-white/10 bg-white dark:bg-black/20 text-sm p-3 font-medium transition-all focus:ring-2 focus-visible:ring-brand-300 focus:border-brand-500 outline-none appearance-none"
                    >
                        <option value="À faire">À faire</option>
                        <option value="En cours">En cours</option>
                        <option value="Terminé">Terminé</option>
                    </select>
                </div>
            </div>

            {/* Actions */}
            <div className="flex justify-end gap-2 pt-2">
                <Button
                    type="button"
                    variant="outline"
                    size="sm"
                    onClick={onCancel}
                >
                    Annuler
                </Button>
                <Button
                    type="submit"
                    variant="default"
                    size="sm"
                    className="gap-1"
                >
                    <Check className="h-4 w-4" />
                    {action ? 'Enregistrer' : 'Ajouter'}
                </Button>
            </div>
        </form>
    );
};

