}

const RegulatoryContextTab: React.FC<RegulatoryContextTabProps> = ({
  data,
  onSave,
  onAddRegulation,
  onRemoveRegulation,
  isSaving
}) => {
  const [description, setDescription] = useState(data.description || '');
