                                                    <span className="text-slate-500 dark:text-slate-400">Uptime</span>
                                                    <span className="font-medium">{formatUptime(agentDetails.uptimeSeconds)}</span>
                                                </div>
                                                <div className="flex justify-between py-2 border-b border-slate-50 dark:border-white/5">
                                                    <span className="text-slate-500 dark:text-slate-400">Dernier Heartbeat</span>
                                                    <span className="font-medium">{new Date(agentDetails.lastHeartbeat).toLocaleString()}</span>
                                                </div>
                                                <div className="flex justify-between py-2 border-b border-slate-50 dark:border-white/5">
                                                    <span className="text-slate-500 dark:text-slate-400">Enrôlé le</span>
                                                    <span className="font-medium">{agentDetails.enrolledAt ? new Date(agentDetails.enrolledAt).toLocaleDateString() : 'N/A'}</span>
                                                </div>
                                                <div className="flex justify-between py-2 border-b border-slate-50 dark:border-white/5">
                                                    <span className="text-slate-500 dark:text-slate-400">Version Config</span>
                                                    <span className="font-mono">v{agentDetails.configVersion}</span>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </motion.div>
                            )}

                            {activeTab === 'compliance' && (
                                <motion.div
                                    initial={{ opacity: 0, y: 10 }}
                                    animate={{ opacity: 1, y: 0 }}
                                    className="space-y-6"
                                >
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                        {/* Compliance Chart */}
                                        <div className="p-6 rounded-2xl border border-slate-200 dark:border-white/10 flex flex-col items-center justify-center">
                                            <h3 className="text-sm font-bold mb-4 w-full text-left">Résumé des Contrôles</h3>
                                            <div className="h-[200px] w-full">
                                                <ResponsiveContainer width="100%" height="100%">
                                                    <PieChart>
                                                        <Pie
                                                            data={[
                                                                { name: 'Pass', value: agentDetails.resultsSummary?.pass || 0, color: SENTINEL_PALETTE.success },
                                                                { name: 'Fail', value: agentDetails.resultsSummary?.fail || 0, color: SENTINEL_PALETTE.danger },
                                                                { name: 'Error', value: agentDetails.resultsSummary?.error || 0, color: SENTINEL_PALETTE.warning },
                                                            ]}
                                                            cx="50%"
                                                            cy="50%"
                                                            innerRadius={60}
                                                            outerRadius={80}
                                                            paddingAngle={5}
                                                            dataKey="value"
                                                        >
                                                            {[
                                                                { name: 'Pass', value: agentDetails.resultsSummary?.pass || 0, color: SENTINEL_PALETTE.success },
                                                                { name: 'Fail', value: agentDetails.resultsSummary?.fail || 0, color: SENTINEL_PALETTE.danger },
                                                                { name: 'Error', value: agentDetails.resultsSummary?.error || 0, color: SENTINEL_PALETTE.warning },
                                                            ].map((entry, index) => (
                                                                <Cell key={`cell-${index}`} fill={entry.color} />
                                                            ))}
                                                        </Pie>
                                                    </PieChart>
                                                </ResponsiveContainer>
                                            </div>
                                            <div className="flex gap-4 mt-4">
                                                <div className="flex items-center gap-2 text-xs">
                                                    <div className="w-3 h-3 rounded-full bg-success-500" />
                                                    <span>Pass ({agentDetails.resultsSummary?.pass || 0})</span>
                                                </div>
                                                <div className="flex items-center gap-2 text-xs">
                                                    <div className="w-3 h-3 rounded-full bg-red-500" />
                                                    <span>Fail ({agentDetails.resultsSummary?.fail || 0})</span>
                                                </div>
                                            </div>
                                        </div>

                                        {/* Compliance Text Stats */}
                                        <div className="space-y-4">
                                            <div className="p-4 rounded-xl bg-slate-50 dark:bg-white/5 border-l-4 border-success-500">
                                                <div className="text-xs text-slate-500 dark:text-slate-300 uppercase font-bold">Conforme</div>
                                                <div className="text-2xl font-black text-slate-900 dark:text-white">
                                                    {agentDetails.complianceScore ?? 0}%
                                                </div>
                                            </div>
                                            <div className="p-4 rounded-xl bg-slate-50 dark:bg-white/5 border-l-4 border-slate-500">
                                                <div className="text-xs text-slate-500 dark:text-slate-300 uppercase font-bold">Total Contrôles</div>
                                                <div className="text-2xl font-black text-slate-900 dark:text-white">
                                                    {agentDetails.resultsSummary?.total ?? 0}
                                                </div>
                                            </div>
                                        </div>
                                    </div>

                                    <div className="p-4 rounded-xl bg-blue-50 dark:bg-blue-900/30 text-blue-800 dark:text-blue-300 text-sm flex items-start gap-3">
                                        <Activity className="w-5 h-5 flex-shrink-0 mt-0.5" />
                                        <div>
                                            <p className="font-bold">Analyse Détaillée</p>
                                            <p className="opacity-80">Pour voir le détail des contrôles échoués, veuillez consulter le rapport de conformité complet dans le module Audit.</p>
                                        </div>
                                    </div>
                                </motion.div>
                            )}

                            {activeTab === 'config' && (
                                <motion.div
                                    initial={{ opacity: 0, y: 10 }}
                                    animate={{ opacity: 1, y: 0 }}
                                    className="space-y-6 max-w-2xl mx-auto"
                                >
                                    <div className="space-y-4">
                                        <div className="space-y-2">
                                            <label className="text-sm font-medium text-slate-700 dark:text-slate-300">Intervalle de vérification (secondes)</label>
                                            <input
                                                type="number"
                                                className="w-full px-4 py-2 rounded-xl border border-slate-200 dark:border-white/10 bg-white dark:bg-white/5 focus:ring-2 focus:ring-brand-500 outline-none transition-all"
                                                value={configForm.check_interval_secs || 900}
                                                onChange={e => setConfigForm({ ...configForm, check_interval_secs: parseInt(e.target.value) })}
                                            />
                                            <p className="text-xs text-slate-500">Fréquence d'exécution des contrôles de conformité.</p>
                                        </div>

                                        <div className="space-y-2">
                                            <label className="text-sm font-medium text-slate-700 dark:text-slate-300">Niveau de Log</label>
                                            <select
                                                className="w-full px-4 py-2 rounded-xl border border-slate-200 dark:border-white/10 bg-white dark:bg-white/5 focus:ring-2 focus:ring-brand-500 outline-none transition-all"
                                                value={configForm.log_level || 'info'}
                                                onChange={e => setConfigForm({ ...configForm, log_level: e.target.value })}
                                            >
                                                <option value="debug">Debug (Verbeux)</option>
                                                <option value="info">Info (Standard)</option>
                                                <option value="warn">Warning (Avertissements)</option>
                                                <option value="error">Error (Critique)</option>
                                            </select>
                                        </div>

                                        <div className="space-y-2">
                                            <label className="text-sm font-medium text-slate-700 dark:text-slate-300">Intervalle Heartbeat (secondes)</label>
                                            <input
                                                type="number"
                                                className="w-full px-4 py-2 rounded-xl border border-slate-200 dark:border-white/10 bg-white dark:bg-white/5 focus:ring-2 focus:ring-brand-500 outline-none transition-all"
                                                value={configForm.heartbeat_interval_secs || 60}
                                                onChange={e => setConfigForm({ ...configForm, heartbeat_interval_secs: parseInt(e.target.value) })}
                                            />
                                        </div>
                                    </div>

                                    <div className="pt-6 flex justify-end">
                                        <Button
                                            onClick={handleSaveConfig}
                                            disabled={updating}
                                            className="bg-brand-500 text-white shadow-lg shadow-brand-500/20"
                                        >
                                            {updating ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <Save className="w-4 h-4 mr-2" />}
                                            Sauvegarder la configuration
                                        </Button>
                                    </div>
                                </motion.div>
                            )}

                            {activeTab === 'logs' && (
                                <motion.div
                                    initial={{ opacity: 0, y: 10 }}
                                    animate={{ opacity: 1, y: 0 }}
                                    className="space-y-4"
                                >
                                    <h3 className="text-sm font-bold flex items-center gap-2">
                                        <FileText className="w-4 h-4 text-brand-500" />
                                        Dernier Self-Check
                                    </h3>

                                    <div className="p-4 bg-slate-900 rounded-xl border border-slate-800 shadow-inner overflow-x-auto">
                                        <pre className="text-xs font-mono text-emerald-400">
                                            {agentDetails.selfCheckResult
                                                ? JSON.stringify(agentDetails.selfCheckResult, null, 2)
                                                : "// Aucun résultat d'autodiagnostic disponible"
                                            }
                                        </pre>
                                    </div>

                                    <h3 className="text-sm font-bold flex items-center gap-2 mt-6">
                                        <Clock className="w-4 h-4 text-brand-500" />
                                        Pending Commands ({agentDetails.pendingCommandsCount})
                                    </h3>
                                    <p className="text-sm text-slate-500">Commandes en attente de récupération par l'agent.</p>
                                </motion.div>
                            )}
                        </AnimatePresence>
                    ) : null}
                </div>
            </div>
        </Modal>
    );
};

/**
 * OT Connector Form Component
 * Story 36-2: OT Connector Configuration
 *
 * Multi-step wizard for creating/editing OT connectors.
 * Step 1: Basic info + type selection
 * Step 2: Type-specific configuration
 * Step 3: Schedule configuration
 * Step 4: Review & test connection
 */

import React, { useState, useCallback, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import {
  FileText,
  Server,
  Cpu,
  Globe,
  ChevronRight,
  ChevronLeft,
  Check,
  Loader2,
  Play,
  AlertCircle,
  CheckCircle,
  Calendar,
  Settings,
  type LucideIcon
} from 'lucide-react';
import { cn } from '../../lib/utils';
import { Card } from '../ui/card';
import { Button } from '../ui/button';
import { Badge } from '../ui/Badge';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '../ui/dialog';
import { useToast } from '../../hooks/useToast';
import { useStore } from '../../store';
import { useAuth } from '../../hooks/useAuth';
import {
  OTConnectorService,
  validateConnector
} from '../../services/OTConnectorService';
import type {
  OTConnector,
  OTConnectorType,
  OTConnectorFormData,
  SyncSchedule,
  CSVConnectorConfig,
  ScheduleType
} from '../../types/otConnector';
import {
  CONNECTOR_TYPE_LABELS,
  CONNECTOR_TYPE_DESCRIPTIONS,
  SYNC_INTERVALS
} from '../../types/otConnector';

// ============================================================================
// Types
// ============================================================================

interface OTConnectorFormProps {
  open: boolean;
  onClose: () => void;
  onSuccess: () => void;
  connector?: OTConnector; // For editing
}

type FormStep = 'type' | 'config' | 'schedule' | 'review';

// ============================================================================
// Constants
// ============================================================================

const STEPS: Array<{ key: FormStep; labelKey: string; icon: LucideIcon }> = [
  { key: 'type', labelKey: 'otConnector.steps.type', icon: Settings },
  { key: 'config', labelKey: 'otConnector.steps.config', icon: FileText },
  { key: 'schedule', labelKey: 'otConnector.steps.schedule', icon: Calendar },
  { key: 'review', labelKey: 'otConnector.steps.review', icon: Check }
];

const TYPE_ICONS: Record<OTConnectorType, LucideIcon> = {
  csv: FileText,
  opcua: Server,
  modbus: Cpu,
  api: Globe
};

// ============================================================================
// Component
// ============================================================================

export const OTConnectorForm: React.FC<OTConnectorFormProps> = ({
  open,
  onClose,
  onSuccess,
  connector
}) => {
  const { t, i18n } = useTranslation();
  const { toast } = useToast();
  const { organization } = useStore();
  const { user } = useAuth();
  const isEnglish = i18n.language === 'en';
  const isEditing = !!connector;

  // Form state
  const [currentStep, setCurrentStep] = useState<FormStep>('type');
  const [saving, setSaving] = useState(false);
  const [testing, setTesting] = useState(false);
  const [testResult, setTestResult] = useState<{ success: boolean; message: string } | null>(null);

  // Form data
  const [formData, setFormData] = useState<OTConnectorFormData>(() => ({
    name: connector?.name || '',
    description: connector?.description || '',
    type: connector?.type || 'csv',
    config: connector?.config || {},
    schedule: connector?.schedule || { type: 'manual' },
    enabled: connector?.enabled ?? true,
    tags: connector?.tags || []
  }));

  // Update form field
  const updateField = useCallback(<K extends keyof OTConnectorFormData>(
    field: K,
    value: OTConnectorFormData[K]
  ) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  }, []);

  // Update config field
  const updateConfig = useCallback(<K extends string>(
    field: K,
    value: unknown
  ) => {
    setFormData(prev => ({
      ...prev,
      config: { ...prev.config, [field]: value }
    }));
  }, []);

  // Update schedule field
  const updateSchedule = useCallback(<K extends keyof SyncSchedule>(
    field: K,
    value: SyncSchedule[K]
  ) => {
    setFormData(prev => ({
      ...prev,
      schedule: { ...prev.schedule, [field]: value }
    }));
  }, []);

  // Validation
  const validationResult = useMemo(() =>
    validateConnector(formData),
    [formData]
  );

  // Test connection
  const handleTestConnection = useCallback(async () => {
    if (!organization?.id) return;

    setTesting(true);
    setTestResult(null);

    try {
      const result = await OTConnectorService.testConnection(organization.id, formData);
      setTestResult(result);
    } catch (error) {
      setTestResult({
        success: false,
        message: error instanceof Error ? error.message : 'Test failed'
      });
    } finally {
      setTesting(false);
    }
  }, [organization?.id, formData]);

  // Save connector
  const handleSave = useCallback(async () => {
    if (!organization?.id || !user?.uid) return;

    if (!validationResult.valid) {
      toast({
        variant: 'destructive',
        title: t('otConnector.errors.validation', 'Validation errors'),
        description: validationResult.errors.map(e => e.message).join(', ')
      });
      return;
    }

    setSaving(true);

    try {
      if (isEditing && connector) {
        await OTConnectorService.updateConnector(organization.id, connector.id, formData);
        toast({
          title: t('otConnector.updated', 'Connector updated'),
          description: formData.name
        });
      } else {
        await OTConnectorService.createConnector(organization.id, user.uid, formData);
        toast({
          title: t('otConnector.created', 'Connector created'),
          description: formData.name
        });
      }
      onSuccess();
      onClose();
    } catch (error) {
      toast({
        variant: 'destructive',
        title: t('otConnector.errors.saveFailed', 'Save failed'),
        description: error instanceof Error ? error.message : 'Unknown error'
      });
    } finally {
      setSaving(false);
    }
  }, [organization?.id, user?.uid, formData, isEditing, connector, validationResult, onSuccess, onClose, t, toast]);

  // Navigation
  const canProceed = useMemo(() => {
    switch (currentStep) {
      case 'type':
        return formData.name.trim().length > 0 && formData.type;
      case 'config':
        if (formData.type === 'csv') {
          const csvConfig = formData.config as Partial<CSVConnectorConfig>;
          return csvConfig.filePattern && csvConfig.filePattern.length > 0;
        }
        return true;
      case 'schedule':
        return true;
      case 'review':
        return validationResult.valid;
      default:
        return false;
    }
  }, [currentStep, formData, validationResult]);

  const handleNext = useCallback(() => {
    const stepIndex = STEPS.findIndex(s => s.key === currentStep);
    if (stepIndex < STEPS.length - 1) {
      setCurrentStep(STEPS[stepIndex + 1].key);
    }
  }, [currentStep]);

  const handleBack = useCallback(() => {
    const stepIndex = STEPS.findIndex(s => s.key === currentStep);
    if (stepIndex > 0) {
      setCurrentStep(STEPS[stepIndex - 1].key);
    }
  }, [currentStep]);

  // Render step indicator
  const renderStepIndicator = () => (
    <div className="flex items-center justify-center mb-6">
      {STEPS.map((step, index) => {
        const isActive = step.key === currentStep;
        const isPast = STEPS.findIndex(s => s.key === currentStep) > index;
        const Icon = step.icon;

        return (
          <React.Fragment key={step.key}>
            {index > 0 && (
              <div className={cn(
                'w-12 h-0.5 mx-2',
                isPast ? 'bg-green-500' : 'bg-slate-200'
              )} />
            )}
            <div className={cn(
              'flex items-center gap-2 px-3 py-1.5 rounded-full text-sm font-medium transition-colors',
              isActive && 'bg-blue-100 text-blue-700',
              isPast && 'bg-green-100 text-green-700',
              !isActive && !isPast && 'bg-slate-100 dark:bg-slate-800 text-slate-500'
            )}>
              {isPast ? (
                <Check className="h-4 w-4" />
              ) : (
                <Icon className="h-4 w-4" />
              )}
              <span className="hidden sm:inline">
                {t(step.labelKey, step.key)}
              </span>
            </div>
          </React.Fragment>
        );
      })}
    </div>
  );

  // Step 1: Type selection
  const renderTypeStep = () => (
    <div className="space-y-6">
      {/* Name */}
      <div>
        <label className="block text-sm font-medium mb-2">
          {t('otConnector.fields.name', 'Connector Name')} *
        </label>
        <input
          type="text"
          value={formData.name}
          onChange={e => updateField('name', e.target.value)}
          placeholder={t('otConnector.placeholders.name', 'e.g., Production SCADA Sync')}
          className="w-full px-4 py-2 border rounded-lg focus:outline-none focus-visible:ring-2 focus-visible:ring-brand-500"
        />
      </div>

      {/* Description */}
      <div>
        <label className="block text-sm font-medium mb-2">
          {t('otConnector.fields.description', 'Description')}
        </label>
        <textarea
          value={formData.description || ''}
          onChange={e => updateField('description', e.target.value)}
          placeholder={t('otConnector.placeholders.description', 'Optional description...')}
          rows={2}
          className="w-full px-4 py-2 border rounded-lg focus:outline-none focus-visible:ring-2 focus-visible:ring-brand-500"
        />
      </div>

      {/* Type selection */}
      <div>
        <label className="block text-sm font-medium mb-3">
          {t('otConnector.fields.type', 'Connector Type')} *
        </label>
        <div className="grid grid-cols-2 gap-3">
          {(['csv', 'opcua', 'modbus', 'api'] as OTConnectorType[]).map(type => {
            const Icon = TYPE_ICONS[type];
            const isSelected = formData.type === type;
            const label = isEnglish
              ? CONNECTOR_TYPE_LABELS[type].en
              : CONNECTOR_TYPE_LABELS[type].fr;
            const desc = isEnglish
              ? CONNECTOR_TYPE_DESCRIPTIONS[type].en
              : CONNECTOR_TYPE_DESCRIPTIONS[type].fr;
            const isDisabled = type !== 'csv'; // Only CSV implemented for now

            return (
              <button
                key={type}
                type="button"
                onClick={() => !isDisabled && updateField('type', type)}
                disabled={isDisabled}
                className={cn(
                  'p-4 rounded-xl border-2 text-left transition-all',
                  isSelected && 'border-blue-500 bg-blue-50',
                  !isSelected && !isDisabled && 'border-slate-200 dark:border-slate-700 hover:border-slate-300 dark:hover:border-slate-600',
                  isDisabled && 'opacity-70 cursor-not-allowed border-slate-200 dark:border-slate-700'
                )}
              >
                <div className="flex items-center gap-3 mb-2">
                  <div className={cn(
                    'p-2 rounded-lg',
                    isSelected ? 'bg-blue-100' : 'bg-slate-100'
                  )}>
                    <Icon className={cn(
                      'h-5 w-5',
                      isSelected ? 'text-blue-600' : 'text-slate-500'
                    )} />
                  </div>
                  <span className="font-medium">{label}</span>
                  {isDisabled && (
                    <Badge variant="outline" className="ml-auto text-xs">
                      {t('common.comingSoon', 'Coming soon')}
                    </Badge>
                  )}
                </div>
                <p className="text-sm text-slate-500">{desc}</p>
              </button>
            );
          })}
        </div>
      </div>
    </div>
  );

  // Step 2: Type-specific configuration
  const renderConfigStep = () => {
    if (formData.type === 'csv') {
      return renderCSVConfig();
    }
    return (
      <div className="text-center py-12 text-slate-500">
        {t('otConnector.configNotImplemented', 'Configuration for this connector type is not yet available')}
      </div>
    );
  };

  const renderCSVConfig = () => {
    const config = formData.config as Partial<CSVConnectorConfig>;

    return (
      <div className="space-y-6">
        {/* File pattern */}
        <div>
          <label className="block text-sm font-medium mb-2">
            {t('otConnector.csv.filePattern', 'File Pattern (Regex)')} *
          </label>
          <input
            type="text"
            value={config.filePattern || ''}
            onChange={e => updateConfig('filePattern', e.target.value)}
            placeholder=".*\.csv$"
            className="w-full px-4 py-2 border rounded-lg font-mono text-sm focus:outline-none focus-visible:ring-2 focus-visible:ring-brand-500"
          />
          <p className="text-xs text-slate-500 dark:text-slate-300 mt-1">
            {t('otConnector.csv.filePatternHelp', 'Regular expression to match CSV files')}
          </p>
        </div>

        {/* Encoding */}
        <div>
          <label className="block text-sm font-medium mb-2">
            {t('otConnector.csv.encoding', 'File Encoding')}
          </label>
          <select
            value={config.encoding || 'utf-8'}
            onChange={e => updateConfig('encoding', e.target.value)}
            className="w-full px-4 py-2 border rounded-lg focus:outline-none focus-visible:ring-2 focus-visible:ring-brand-500"
          >
            <option value="utf-8">UTF-8</option>
            <option value="iso-8859-1">ISO-8859-1 (Latin-1)</option>
            <option value="windows-1252">Windows-1252</option>
          </select>
        </div>

        {/* Archive processed */}
        <div className="flex items-center gap-3">
          <input
            type="checkbox"
            id="archiveProcessed"
            checked={config.archiveProcessed ?? true}
            onChange={e => updateConfig('archiveProcessed', e.target.checked)}
            className="h-4 w-4 rounded border-slate-300 text-blue-600 dark:text-blue-400 focus-visible:ring-brand-500"
          />
          <label htmlFor="archiveProcessed" className="text-sm">
            {t('otConnector.csv.archiveProcessed', 'Archive processed files')}
          </label>
        </div>

        {/* Default network segment */}
        <div>
          <label className="block text-sm font-medium mb-2">
            {t('otConnector.csv.defaultSegment', 'Default Network Segment')}
          </label>
          <select
            value={config.defaultNetworkSegment || 'OT'}
            onChange={e => updateConfig('defaultNetworkSegment', e.target.value)}
            className="w-full px-4 py-2 border rounded-lg focus:outline-none focus-visible:ring-2 focus-visible:ring-brand-500"
          >
            <option value="IT">IT</option>
            <option value="OT">OT</option>
            <option value="DMZ">DMZ</option>
          </select>
        </div>

        {/* Default criticality */}
        <div>
          <label className="block text-sm font-medium mb-2">
            {t('otConnector.csv.defaultCriticality', 'Default OT Criticality')}
          </label>
          <select
            value={config.defaultOTCriticality || 'monitoring'}
            onChange={e => updateConfig('defaultOTCriticality', e.target.value)}
            className="w-full px-4 py-2 border rounded-lg focus:outline-none focus-visible:ring-2 focus-visible:ring-brand-500"
          >
            <option value="safety">{t('otCriticality.safety', 'Safety')}</option>
            <option value="production">{t('otCriticality.production', 'Production')}</option>
            <option value="operations">{t('otCriticality.operations', 'Operations')}</option>
            <option value="monitoring">{t('otCriticality.monitoring', 'Monitoring')}</option>
          </select>
        </div>
      </div>
    );
  };

  // Step 3: Schedule
  const renderScheduleStep = () => (
    <div className="space-y-6">
      {/* Schedule type */}
      <div>
        <label className="block text-sm font-medium mb-3">
          {t('otConnector.schedule.type', 'Sync Schedule')}
        </label>
        <div className="space-y-2">
          {(['manual', 'interval', 'cron'] as ScheduleType[]).map(type => (
            <label
              key={type}
              className={cn(
                'flex items-center gap-3 p-4 rounded-lg border-2 cursor-pointer transition-colors',
                formData.schedule.type === type
                  ? 'border-blue-500 bg-blue-50'
                  : 'border-slate-200 dark:border-slate-700 hover:border-slate-300 dark:hover:border-slate-600'
              )}
            >
              <input
                type="radio"
                name="scheduleType"
                value={type}
                checked={formData.schedule.type === type}
                onChange={() => updateSchedule('type', type)}
                className="h-4 w-4 text-blue-600"
              />
              <div>
                <span className="font-medium">
                  {type === 'manual' && t('otConnector.schedule.manual', 'Manual only')}
                  {type === 'interval' && t('otConnector.schedule.interval', 'Fixed interval')}
                  {type === 'cron' && t('otConnector.schedule.cron', 'Custom schedule (Cron)')}
                </span>
                <p className="text-sm text-slate-500">
                  {type === 'manual' && t('otConnector.schedule.manualDesc', 'Trigger syncs manually')}
                  {type === 'interval' && t('otConnector.schedule.intervalDesc', 'Run at regular intervals')}
                  {type === 'cron' && t('otConnector.schedule.cronDesc', 'Advanced scheduling with cron expression')}
                </p>
              </div>
            </label>
          ))}
        </div>
      </div>

      {/* Interval selection */}
      {formData.schedule.type === 'interval' && (
        <div>
          <label className="block text-sm font-medium mb-2">
            {t('otConnector.schedule.selectInterval', 'Select Interval')}
          </label>
          <select
            value={formData.schedule.interval || 1440}
            onChange={e => updateSchedule('interval', parseInt(e.target.value))}
            className="w-full px-4 py-2 border rounded-lg focus:outline-none focus-visible:ring-2 focus-visible:ring-brand-500"
          >
            {SYNC_INTERVALS.map(opt => (
              <option key={opt.value} value={opt.value}>
                {opt.label}
              </option>
            ))}
          </select>
        </div>
      )}

      {/* Cron expression */}
      {formData.schedule.type === 'cron' && (
        <div>
          <label className="block text-sm font-medium mb-2">
            {t('otConnector.schedule.cronExpression', 'Cron Expression')}
          </label>
          <input
            type="text"
            value={formData.schedule.cronExpression || ''}
            onChange={e => updateSchedule('cronExpression', e.target.value)}
            placeholder="0 2 * * *"
            className="w-full px-4 py-2 border rounded-lg font-mono text-sm focus:outline-none focus-visible:ring-2 focus-visible:ring-brand-500"
          />
          <p className="text-xs text-slate-500 dark:text-slate-300 mt-1">
            {t('otConnector.schedule.cronHelp', 'Format: minute hour day month weekday (e.g., "0 2 * * *" for 2 AM daily)')}
          </p>
        </div>
      )}

      {/* Enabled toggle */}
      <div className="flex items-center gap-3 pt-4 border-t">
        <input
          type="checkbox"
          id="enabled"
          checked={formData.enabled}
          onChange={e => updateField('enabled', e.target.checked)}
          className="h-4 w-4 rounded border-slate-300 text-blue-600 dark:text-blue-400 focus-visible:ring-brand-500"
        />
        <label htmlFor="enabled" className="text-sm">
          {t('otConnector.enabled', 'Enable connector immediately after creation')}
        </label>
      </div>
    </div>
  );

  // Step 4: Review
  const renderReviewStep = () => (
    <div className="space-y-6">
      {/* Summary card */}
      <Card className="p-4">
        <h4 className="font-medium mb-3">{t('otConnector.review.summary', 'Configuration Summary')}</h4>
        <dl className="space-y-2 text-sm">
          <div className="flex justify-between">
            <dt className="text-slate-500 dark:text-slate-400">{t('otConnector.fields.name', 'Name')}:</dt>
            <dd className="font-medium">{formData.name}</dd>
          </div>
          <div className="flex justify-between">
            <dt className="text-slate-500 dark:text-slate-400">{t('otConnector.fields.type', 'Type')}:</dt>
            <dd className="font-medium">
              {isEnglish
                ? CONNECTOR_TYPE_LABELS[formData.type].en
                : CONNECTOR_TYPE_LABELS[formData.type].fr}
            </dd>
          </div>
          <div className="flex justify-between">
            <dt className="text-slate-500 dark:text-slate-400">{t('otConnector.schedule.type', 'Schedule')}:</dt>
            <dd className="font-medium capitalize">{formData.schedule.type}</dd>
          </div>
          <div className="flex justify-between">
            <dt className="text-slate-500 dark:text-slate-400">{t('otConnector.enabled', 'Enabled')}:</dt>
            <dd>
              <Badge variant={formData.enabled ? 'default' : 'outline'} status={formData.enabled ? 'success' : 'neutral'}>
                {formData.enabled ? t('common.yes', 'Yes') : t('common.no', 'No')}
              </Badge>
            </dd>
          </div>
        </dl>
      </Card>

      {/* Test connection */}
      <Card className="p-4">
        <div className="flex items-center justify-between mb-3">
          <h4 className="font-medium">{t('otConnector.review.testConnection', 'Test Connection')}</h4>
          <Button
            variant="outline"
            size="sm"
            onClick={handleTestConnection}
            disabled={testing}
          >
            {testing ? (
              <Loader2 className="h-4 w-4 mr-2 animate-spin" />
            ) : (
              <Play className="h-4 w-4 mr-2" />
            )}
            {t('otConnector.review.runTest', 'Run Test')}
          </Button>
        </div>

        {testResult && (
          <div className={cn(
            'flex items-center gap-2 p-3 rounded-lg',
            testResult.success ? 'bg-green-50 dark:bg-green-900/20 text-green-700 dark:text-green-400' : 'bg-red-50 dark:bg-red-900/20 text-red-700 dark:text-red-400'
          )}>
            {testResult.success ? (
              <CheckCircle className="h-5 w-5" />
            ) : (
              <AlertCircle className="h-5 w-5" />
            )}
            <span>{testResult.message}</span>
          </div>
        )}
      </Card>

      {/* Validation errors */}
      {!validationResult.valid && (
        <Card className="p-4 border-red-200 dark:border-red-800 bg-red-50">
          <h4 className="font-medium text-red-700 dark:text-red-400 mb-2">
            {t('otConnector.review.validationErrors', 'Validation Errors')}
          </h4>
          <ul className="list-disc list-inside text-sm text-red-600">
            {validationResult.errors.map((err, i) => (
              <li key={i}>{err.message}</li>
            ))}
          </ul>
        </Card>
      )}
    </div>
  );

  // Render current step content
  const renderStepContent = () => {
    switch (currentStep) {
      case 'type':
        return renderTypeStep();
      case 'config':
        return renderConfigStep();
      case 'schedule':
        return renderScheduleStep();
      case 'review':
        return renderReviewStep();
      default:
        return null;
    }
  };

  return (
    <Dialog open={open} onOpenChange={onClose}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Settings className="h-5 w-5 text-blue-600" />
            {isEditing
              ? t('otConnector.editTitle', 'Edit Connector')
              : t('otConnector.createTitle', 'Create Connector')}
          </DialogTitle>
        </DialogHeader>

        {/* Step indicator */}
        {renderStepIndicator()}

        {/* Step content */}
        <div className="min-h-[300px]">
          {renderStepContent()}
        </div>

        {/* Navigation buttons */}
        <div className="flex justify-between pt-4 border-t">
          <div>
            {currentStep !== 'type' && (
              <Button variant="outline" onClick={handleBack}>
                <ChevronLeft className="h-4 w-4 mr-1" />
                {t('common.back', 'Back')}
              </Button>
            )}
          </div>
          <div className="flex gap-2">
            <Button variant="outline" onClick={onClose}>
              {t('common.cancel', 'Cancel')}
            </Button>
            {currentStep === 'review' ? (
              <Button
                onClick={handleSave}
                disabled={saving || !validationResult.valid}
              >
                {saving && <Loader2 className="h-4 w-4 mr-1 animate-spin" />}
                {isEditing
                  ? t('common.save', 'Save')
                  : t('otConnector.create', 'Create Connector')}
              </Button>
            ) : (
              <Button onClick={handleNext} disabled={!canProceed}>
                {t('common.next', 'Next')}
                <ChevronRight className="h-4 w-4 ml-1" />
              </Button>
            )}
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
};

export default OTConnectorForm;

import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { collection, query, where, onSnapshot, deleteDoc, doc } from 'firebase/firestore';
import { httpsCallable } from 'firebase/functions';
import { db, functions } from '../../firebase';
import { useStore } from '../../store';
import { Handshake, Plus, Mail, Loader2, Building2, Clock, Trash2, AlertTriangle, ShieldCheck } from '../ui/Icons';
import { toast } from '@/lib/toast';
import { ErrorLogger } from '../../services/errorLogger';
import { ConfirmModal } from '../ui/ConfirmModal';
import { AnimatePresence, motion } from 'framer-motion';
import { hasPermission } from '../../utils/permissions';

interface Partner {
    id: string;
    contactEmail: string;
    status: 'PENDING' | 'ACTIVE';
    certifierId?: string;
    invitedAt: string;
    tenantId: string;
    tenantName?: string;
}

export const PartnerManagement: React.FC = () => {
    const { t } = useTranslation();
    const { user } = useStore();
    const [partners, setPartners] = useState<Partner[]>([]);
    const [loading, setLoading] = useState(true);
    const [isInviteOpen, setIsInviteOpen] = useState(false);
    const [inviting, setInviting] = useState(false);
    const [permissionError, setPermissionError] = useState(false);

    // Revoke/Delete state
    const [partnerToDelete, setPartnerToDelete] = useState<Partner | null>(null);

    useEffect(() => {
        if (!user?.organizationId) {
            setLoading(false);
            return;
        }

        const q = query(collection(db, 'partnerships'), where('tenantId', '==', user.organizationId));

        const unsubscribe = onSnapshot(q,
            (snapshot) => {
                const parts = snapshot.docs.map(d => ({ id: d.id, ...d.data() } as Partner));
                setPartners(parts);
                setLoading(false);
                setPermissionError(false);
            },
            (error) => {
                if (error.code === 'permission-denied') {
                    setPermissionError(true);
                } else {
                    ErrorLogger.handleErrorWithToast(error, 'PartnerManagement.fetch');
                }
                setLoading(false);
            }
        );

        return () => unsubscribe();
    }, [user?.organizationId]);

    const handleInvite = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        const formData = new FormData(e.currentTarget);
        const email = formData.get('email') as string;

        if (!email) return;

        setInviting(true);
        try {
            const inviteFn = httpsCallable(functions, 'inviteCertifier');
            await inviteFn({ email, message: 'Nous souhaitons vous ajouter comme partenaire de certification sur Sentinel GRC.' });
            toast.success('Invitation envoyée avec succès !');
            setIsInviteOpen(false);
        } catch (error) {
            ErrorLogger.handleErrorWithToast(error, 'PartnerManagement.invite');
        } finally {
            setInviting(false);
        }
    };

    const confirmDelete = async () => {
        if (!partnerToDelete) return;

        // SECURITY: Check authorization - only admin/rssi can manage partners
        if (!hasPermission(user, 'Partner', 'delete')) {
            ErrorLogger.warn('Unauthorized partner deletion attempt', 'PartnerManagement.delete', {
                metadata: { attemptedBy: user?.uid, targetPartnerId: partnerToDelete.id }
            });
            toast.error("Vous n'avez pas les droits pour retirer ce partenaire");
            setPartnerToDelete(null);
            return;
        }

        // SECURITY: Verify partner belongs to user's organization (IDOR protection)
        if (partnerToDelete.tenantId !== user?.organizationId) {
            ErrorLogger.warn('IDOR attempt: partner deletion across organizations', 'PartnerManagement.delete', {
                metadata: { attemptedBy: user?.uid, targetPartnerId: partnerToDelete.id, targetOrg: partnerToDelete.tenantId, callerOrg: user?.organizationId }
            });
            toast.error("Partenaire non trouvé");
            setPartnerToDelete(null);
            return;
        }

        try {
            // If it's just a doc within the partnerships collection, we can delete it directly if rules allow.
            // Otherwise, we might need a cloud function 'revokePartner'.
            // Assuming direct delete per rules for 'manage' permissions.
            await deleteDoc(doc(db, 'partnerships', partnerToDelete.id));
            toast.success('Partenaire retiré avec succès');
            setPartnerToDelete(null);
        } catch (error) {
            ErrorLogger.handleErrorWithToast(error, 'PartnerManagement.delete');
        }
    };

    if (permissionError) {
        return (
            <div className="flex flex-col items-center justify-center p-12 text-center bg-red-50 dark:bg-red-50 dark:bg-red-900 rounded-2xl border border-red-100 dark:border-red-900/30">
                <div className="w-16 h-16 bg-red-100 dark:bg-red-900/30 dark:bg-red-900/20 rounded-full flex items-center justify-center mb-4">
                    <AlertTriangle className="w-8 h-8 text-red-600 dark:text-red-400" />
                </div>
                <h3 className="text-xl font-bold text-red-900 dark:text-red-300 mb-2">Accès restreint</h3>
                <p className="text-red-700 dark:text-red-400 max-w-md">
                    Vous n'avez pas les permissions nécessaires pour gérer les partenaires. Veuillez contacter votre administrateur ou le support pour vérifier votre plan et vos accès.
                </p>
            </div>
        );
    }

    if (loading) {
        return (
            <div className="p-12 flex justify-center">
                <Loader2 className="w-8 h-8 animate-spin text-brand-600" />
            </div>
        );
    }

    return (
        <div className="max-w-5xl mx-auto space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
            {/* Header Section */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 p-6 glass-panel rounded-2xl border border-slate-200 dark:border-white/10 shadow-sm">
                <div>
                    <h2 className="text-2xl font-bold bg-gradient-to-r from-slate-900 to-slate-700 dark:from-white dark:to-slate-300 bg-clip-text text-transparent flex items-center gap-3">
                        <Handshake className="w-8 h-8 text-brand-500" />
                        {t('certifier.partners.title') || "Partenaires Certifiés"}
                    </h2>
                    <p className="text-slate-500 dark:text-slate-300 mt-2 max-w-2xl">
                        {t('certifier.partners.description') || "Connectez votre organisation avec des auditeurs certifiés pour faciliter vos audits externes et certifications."}
                    </p>
                </div>
                <button
                    onClick={() => setIsInviteOpen(true)}
                    className="btn-primary flex items-center gap-2 shadow-lg shadow-brand-500/20 hover:shadow-brand-500/30 transition-all active:scale-95"
                >
                    <Plus className="w-5 h-5" />
                    {t('certifier.partners.inviteButton') || "Inviter un partenaire"}
                </button>
            </div>

            {/* Partners List */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 sm:gap-6">
                <AnimatePresence>
                    {partners.length === 0 ? (
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            className="col-span-full"
                        >
                            <div className="text-center py-16 bg-white dark:bg-slate-900 rounded-3xl border border-dashed border-slate-300 dark:border-white/10 flex flex-col items-center">
                                <div className="w-20 h-20 bg-slate-50 dark:bg-slate-800 rounded-full flex items-center justify-center mb-6 shadow-inner">
                                    <Building2 className="w-10 h-10 text-muted-foreground" />
                                </div>
                                <h3 className="text-xl font-bold text-slate-900 dark:text-white mb-2">
                                    {t('certifier.partners.noPartners') || "Aucun partenaire connectée"}
                                </h3>
                                <p className="text-slate-500 max-w-sm mx-auto mb-8">
                                    {t('certifier.partners.noPartnersDesc') || "Invitez votre premier auditeur ou cabinet de conseil pour commencer la collaboration."}
                                </p>
                                <button
                                    onClick={() => setIsInviteOpen(true)}
                                    className="px-6 py-2 bg-slate-100 hover:bg-slate-200 dark:bg-slate-800 dark:hover:bg-slate-700 text-slate-700 dark:text-slate-300 rounded-xl font-medium transition-colors"
                                >
                                    Inviter maintenant
                                </button>
                            </div>
                        </motion.div>
                    ) : (
                        partners.map((partner, index) => (
                            <motion.div
                                key={partner.id}
                                initial={{ opacity: 0, y: 20 }}
                                animate={{ opacity: 1, y: 0 }}
                                transition={{ delay: index * 0.1 }}
                                className="group bg-white dark:bg-slate-900 p-6 rounded-2xl border border-slate-200 dark:border-white/5 hover:border-brand-300 dark:hover:border-brand-300 shadow-sm hover:shadow-xl hover:shadow-brand-900/25 transition-all duration-300 relative overflow-hidden"
                            >
                                <div className="absolute top-0 right-0 p-4 opacity-0 group-hover:opacity-70 transition-opacity z-10">
                                    <button
                                        onClick={() => setPartnerToDelete(partner)}
                                        className="p-2 text-muted-foreground hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/30 dark:hover:bg-red-900/20 rounded-lg transition-colors"
                                        title="Retirer ce partenaire"
                                    >
                                        <Trash2 className="w-4 h-4" />
                                    </button>
                                </div>

                                <div className="flex items-start gap-4 mb-4">
                                    <div className={`w-12 h-12 rounded-xl flex items-center justify-center flex-shrink-0 ${partner.status === 'ACTIVE'
                                        ? 'bg-gradient-to-br from-success-500 to-success-600 text-white shadow-lg shadow-success-500/20'
                                        : 'bg-gradient-to-br from-warning-400 to-warning-500 text-white shadow-lg shadow-warning-500/20'
                                        }`}>
                                        {partner.status === 'ACTIVE' ? <ShieldCheck className="w-6 h-6" /> : <Clock className="w-6 h-6" />}
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <h4 className="font-bold text-slate-900 dark:text-white truncate" title={partner.contactEmail}>
                                            {partner.tenantName || partner.contactEmail}
                                        </h4>
                                        <div className="flex items-center gap-2 mt-1">
                                            <span className={`text-[11px] uppercase font-bold px-2 py-0.5 rounded-full ${partner.status === 'ACTIVE'
                                                ? 'bg-success-100 text-success-700 dark:bg-success-900/30 dark:text-success-400'
                                                : 'bg-warning-100 text-warning-700 dark:bg-warning-900/30 dark:text-warning-400'
                                                }`}>
                                                {partner.status === 'ACTIVE' ? "Partenaire Actif" : "Invitation envoyée"}
                                            </span>
                                        </div>
                                    </div>
                                </div>

                                <div className="space-y-3">
                                    <div className="flex items-center gap-2 text-sm text-slate-600 dark:text-muted-foreground">
                                        <Mail className="w-4 h-4 text-muted-foreground" />
                                        <span className="truncate">{partner.contactEmail}</span>
                                    </div>

                                    {partner.status === 'ACTIVE' && (
                                        <div className="p-3 bg-slate-50 dark:bg-slate-800/50 rounded-xl text-xs text-slate-500 dark:text-slate-300 border border-slate-100 dark:border-white/5">
                                            <span className="font-medium text-slate-700 dark:text-slate-300 dark:text-muted-foreground">ID Certifieur:</span>
                                            <code className="ml-2 px-1 py-0.5 bg-white dark:bg-black/20 rounded border border-slate-200 dark:border-white/10 font-mono">
                                                {partner.certifierId?.substring(0, 12)}...
                                            </code>
                                        </div>
                                    )}

                                    {partner.status === 'PENDING' && (
                                        <button className="w-full mt-2 py-2 text-sm text-brand-600 hover:text-brand-700 hover:bg-brand-50 dark:hover:bg-brand-800 rounded-lg transition-colors border border-dashed border-brand-200 dark:border-brand-600">
                                            {t('certifier.partners.resendInvite') || "Renvoyer l'invitation"}
                                        </button>
                                    )}
                                </div>
                            </motion.div>
                        ))
                    )}
                </AnimatePresence>
            </div>

            {/* Invite Modal */}
            <AnimatePresence>
                {isInviteOpen && (
                    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            className="absolute inset-0 bg-black/40 backdrop-blur-sm"
                            onClick={() => setIsInviteOpen(false)}
                        />
                        <motion.div
                            initial={{ scale: 0.95, opacity: 0, y: 20 }}
                            animate={{ scale: 1, opacity: 1, y: 0 }}
                            exit={{ scale: 0.95, opacity: 0, y: 20 }}
                            className="bg-white dark:bg-slate-900 rounded-2xl w-full max-w-md p-6 shadow-2xl border border-slate-200 dark:border-white/10 relative z-10"
                        >
                            <h3 className="text-xl font-bold mb-2 text-slate-900 dark:text-white">
                                {t('certifier.partners.modalTitle') || "Inviter un partenaire"}
                            </h3>
                            <p className="text-sm text-slate-500 dark:text-slate-300 mb-6">
                                Le partenaire recevra un email pour rejoindre votre espace. Il devra posséder un compte Sentinel GRC "Certifieur".
                            </p>

                            <form onSubmit={handleInvite} className="space-y-4">
                                <div>
                                    <label className="block text-sm font-medium mb-1.5 text-slate-700 dark:text-slate-300 dark:text-muted-foreground">
                                        {t('certifier.partners.emailLabel') || "Email du contact principal"}
                                    </label>
                                    <div className="relative group">
                                        <Mail className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground group-focus-within:text-brand-500 transition-colors" />
                                        <input
                                            name="email"
                                            type="email"
                                            required
                                            autoFocus
                                            placeholder="contact@cabinet-audit.com"
                                            className="w-full pl-10 pr-4 py-2.5 bg-slate-50 dark:bg-slate-800/50 border border-slate-200 dark:border-white/10 rounded-xl focus:ring-2 focus-visible:ring-brand-500 focus:border-transparent outline-none transition-all"
                                        />
                                    </div>
                                </div>

                                <div className="flex justify-end gap-3 mt-8 pt-4 border-t border-slate-100 dark:border-white/5">
                                    <button
                                        type="button"
                                        onClick={() => setIsInviteOpen(false)}
                                        className="px-4 py-2 text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-800 dark:text-slate-300 dark:hover:bg-slate-700 rounded-xl transition-colors text-sm font-medium"
                                    >
                                        {t('certifier.partners.cancel') || "Annuler"}
                                    </button>
                                    <button
                                        type="submit"
                                        disabled={inviting}
                                        className="btn-primary flex items-center gap-2"
                                    >
                                        {inviting ? <Loader2 className="w-4 h-4 animate-spin" /> : <Mail className="w-4 h-4" />}
                                        {t('certifier.partners.send') || "Envoyer l'invitation"}
                                    </button>
                                </div>
                            </form>
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>

            <ConfirmModal
                isOpen={!!partnerToDelete}
                onClose={() => setPartnerToDelete(null)}
                onConfirm={confirmDelete}
                title="Retirer ce partenaire ?"
                message={`Êtes-vous sûr de vouloir retirer l'accès à ${partnerToDelete?.contactEmail} ? Cette action révoquera immédiatement tous les accès aux audits partagés.`}
                confirmText="Retirer l'accès"
                type="danger"
            />
        </div>
    );
};

import React, { useRef, useState } from 'react';
import { ShieldCheck } from '../ui/Icons';

import { useStore } from '../../store';
import { Camera, ShieldAlert, Trash2, AlertTriangle } from '../ui/Icons';
import { SubmitHandler, Controller } from 'react-hook-form';
import { useZodForm } from '../../hooks/useZodForm';
import { profileSchema, ProfileFormData } from '../../schemas/settingsSchema';
import { CustomSelect } from '../ui/CustomSelect';
import { FloatingLabelInput } from '../ui/FloatingLabelInput';
import { Switch } from '../ui/Switch';
import { Button } from '../ui/button';
import { ref, uploadBytes, getDownloadURL } from 'firebase/storage';
import { storage, auth } from '../../firebase';
import { useTeamData } from '../../hooks/team/useTeamData';
import { getFunctions, httpsCallable } from 'firebase/functions';
import { AccountService } from '../../services/accountService';
import { ConfirmModal } from '../ui/ConfirmModal';
import { ErrorLogger } from '../../services/errorLogger';
import { sanitizeData } from '../../utils/dataSanitizer';
import { hasPermission } from '../../utils/permissions';
import { UserProfile } from '../../types';
import { getDefaultAvatarUrl } from '../../utils/avatarUtils';

export const ProfileSettings: React.FC = () => {
    const { user, setUser, addToast, t, language, setLanguage, demoMode, toggleDemoMode } = useStore();
    const { updateUser } = useTeamData();
    const [savingProfile, setSavingProfile] = useState(false);
    const [uploadingPhoto, setUploadingPhoto] = useState(false);
    const [breachCheckLoading, setBreachCheckLoading] = useState(false);
    const [isDeleting, setIsDeleting] = useState(false);
    const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Mock MFA Toggle
    const handleToggleMfa = async () => {
        if (!user) return;
        // In real impl, this would trigger a flow (QR Code scan, etc.)
        // For now, simply toggle the boolean in the user profile via updateUser
        const newStatus = !user.mfaEnabled;
        try {
            await updateUser(user.uid, { mfaEnabled: newStatus });
            setUser({ ...user, mfaEnabled: newStatus });
            addToast(newStatus ? "MFA activé avec succès" : "MFA désactivé", "success");
        } catch (error) {
            ErrorLogger.handleErrorWithToast(error, 'ProfileSettings.handleToggleMfa', 'UPDATE_FAILED');
        }
    };

    const profileForm = useZodForm<typeof profileSchema>({
        schema: profileSchema,
        mode: 'onChange',
        defaultValues: {
            displayName: user?.displayName || '',
            department: user?.department || '',
            role: user?.role || 'user',
            shodanApiKey: '',
            hibpApiKey: '',
            safeBrowsingApiKey: '',
            notificationPreferences: user?.notificationPreferences || {
                risks: { email: true, push: true, inApp: true },
                audits: { email: true, push: true, inApp: true },
                tasks: { email: true, push: true, inApp: true },
                system: { email: true, push: true, inApp: true }
            }
        }
    });

    const handlePhotoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        if (!user || !e.target.files || e.target.files.length === 0) return;
        const file = e.target.files[0];
        setUploadingPhoto(true);

        try {
            const storageRef = ref(storage, `avatars/${user.uid}/${file.name}`);
            const snapshot = await uploadBytes(storageRef, file);
            const downloadURL = await getDownloadURL(snapshot.ref);

            // Use updateUser hook instead of direct Firebase call
            await updateUser(user.uid, { photoURL: downloadURL });
            setUser({ ...user, photoURL: downloadURL });
            addToast(t('settings.photoUpdated'), "success");
        } catch (error) {
            ErrorLogger.handleErrorWithToast(error, 'ProfileSettings.handlePhotoUpload', 'FILE_UPLOAD_FAILED');
        } finally {
            setUploadingPhoto(false);
        }
    };

    const handleCheckBreach = async () => {
        if (!user?.email) return;
        if (!user.hasHibpKey) {
            addToast(t('settings.hibpKeyRequired'), "info");
            return;
        }

        setBreachCheckLoading(true);
        try {
            const functions = getFunctions();
            const checkBreachWithHIBP = httpsCallable(functions, 'checkBreachWithHIBP');
            const { data } = await checkBreachWithHIBP({ email: user.email });
            const breaches = (data as { breaches?: unknown[] } | undefined)?.breaches || [];
            if (breaches.length === 0) {
                addToast(t('settings.noBreachesFound'), "success");
            } else {
                addToast(t('settings.breachesFound').replace('{count}', breaches.length.toString()), "error");
            }
        } catch (err) {
            addToast(t('settings.hibpError'), "error");
            ErrorLogger.handleErrorWithToast(err, 'ProfileSettings.handleCheckBreach', 'HIBP_FAILED');
        } finally {
            setBreachCheckLoading(false);
        }
    };

    const handleUpdateProfile: SubmitHandler<ProfileFormData> = async (data) => {
        if (!user) return;
        setSavingProfile(true);
        try {
            const updatedRole = hasPermission(user, 'User', 'manage') ? data.role : user.role;

            // Use updateUser hook instead of direct Firebase call
            await updateUser(user.uid, sanitizeData({
                displayName: data.displayName,
                department: data.department || '',
                role: updatedRole,
                notificationPreferences: data.notificationPreferences
            }));

            const functions = getFunctions();
            const saveUserApiKeys = httpsCallable(functions, 'saveUserApiKeys');
            const payload: Record<string, string> = {};
            if (data.shodanApiKey !== undefined) payload.shodanApiKey = data.shodanApiKey || '';
            if (data.hibpApiKey !== undefined) payload.hibpApiKey = data.hibpApiKey || '';
            if (data.safeBrowsingApiKey !== undefined) payload.safeBrowsingApiKey = data.safeBrowsingApiKey || '';

            await saveUserApiKeys(payload);

            const userData: UserProfile = {
                ...user,
                displayName: data.displayName,
                department: data.department || '',
                role: updatedRole,
                hasShodanKey: data.shodanApiKey ? true : user.hasShodanKey,
                hasHibpKey: data.hibpApiKey ? true : user.hasHibpKey,
                hasSafeBrowsingKey: data.safeBrowsingApiKey ? true : user.hasSafeBrowsingKey,
                notificationPreferences: data.notificationPreferences
            };

            setUser(userData);
            addToast(t('settings.profileUpdated'), "success");
        } catch (err) {
            ErrorLogger.handleErrorWithToast(err, 'ProfileSettings.handleUpdateProfile', 'UPDATE_FAILED');
        } finally {
            setSavingProfile(false);
        }
    };

    const handleDeleteAccount = async () => {
        if (!user || !auth.currentUser) return;
        setIsDeleting(true);
        try {
            await AccountService.deleteAccount(user, auth.currentUser);
            addToast(t('settings.accountDeleted'), "success");
            // Intentional: full page reload after account deletion to clear all state
            window.location.href = '/login';
        } catch (error) {
            ErrorLogger.handleErrorWithToast(error, 'ProfileSettings.handleDeleteAccount', 'DELETE_ACCOUNT_FAILED');
        } finally {
            setIsDeleting(false);
            setShowDeleteConfirm(false);
        }
    };

    return (
        <div className="space-y-8 animate-fade-in-up">
            <div className="glass-premium p-8 rounded-3xl border border-border/50 shadow-apple relative overflow-hidden">
                <div className="absolute inset-0 bg-gradient-to-br from-white/40 to-transparent dark:from-white/5 pointer-events-none" />
                <div className="relative z-10 flex flex-col md:flex-row gap-8 items-start">
                    {/* Avatar Section */}
                    <div className="flex-shrink-0 w-full md:w-auto flex flex-col items-center space-y-4">
                        <div className="relative group mx-auto">
                            <div className="w-32 h-32 rounded-full overflow-hidden shadow-2xl ring-1 ring-black/5 dark:ring-white/20 bg-white dark:bg-slate-900">
                                <img
                                    src={getDefaultAvatarUrl(user?.role)}
                                    alt={user?.displayName || 'User'}
                                    className="w-full h-full object-cover"
                                    onError={(e) => {
                                        const target = e.target as HTMLImageElement;
                                        target.src = getDefaultAvatarUrl(user?.role);
                                    }}
                                />
                                <div
                                    className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm backdrop-blur-[2px] opacity-0 group-hover:opacity-70 transition-all duration-300 flex items-center justify-center cursor-pointer"
                                    onClick={() => fileInputRef.current?.click()}
                                    onKeyDown={(e) => {
                                        if (e.key === 'Enter' || e.key === ' ') {
                                            e.preventDefault();
                                            fileInputRef.current?.click();
                                        }
                                    }}
                                    role="button"
                                    tabIndex={0}
                                    aria-label="Modifier la photo de profil"
                                >
                                    <Camera className="w-8 h-8 text-white drop-shadow-md transform group-hover:scale-110 transition-transform duration-300" />
                                </div>
                            </div>
                            <input
                                type="file"
                                ref={fileInputRef}
                                className="hidden"
                                accept="image/*"
                                onChange={handlePhotoUpload}
                                aria-label="Sélectionner une photo de profil"
