                                    <p className="text-xs text-slate-500 dark:text-muted-foreground">
                                        {user?.mfaEnabled
                                            ? "Votre compte est protégé par une authentification à deux facteurs."
                                            : "Ajoutez une couche de sécurité supplémentaire à votre compte."}
