/**
 * MilestoneFormDrawer.tsx
 * Drawer form for creating and editing SMSI milestones
 *
 * Story 20.2: Définition des Jalons
 * Story 20.4: Attribution des Responsables
 */

import React, { useEffect } from 'react';
import { useStore } from '../../store';
import { Drawer } from '../ui/Drawer';
import { Button } from '../ui/button';
import { FloatingLabelInput } from '../ui/FloatingLabelInput';
import { FloatingLabelTextarea } from '../ui/FloatingLabelTextarea';
import { useZodForm } from '../../hooks/useZodForm';
import { z } from 'zod';
import { FieldValues } from 'react-hook-form';
import { Milestone, PDCAPhase } from '../../types/ebios';
import { PHASE_CONFIG, PHASE_STYLES } from './constants';
import { cn } from '../../utils/cn';
import { Users } from '../ui/Icons';

const milestoneSchema = z.object({
  name: z.string().min(3, 'Le nom doit contenir au moins 3 caractères'),
  description: z.string().optional(),
  phase: z.enum(['plan', 'do', 'check', 'act']),
  dueDate: z.string().min(1, 'La date d\'échéance est requise'),
  responsibleId: z.string().optional(),
});

type MilestoneFormData = z.infer<typeof milestoneSchema>;

interface MilestoneFormDrawerProps {
  isOpen: boolean;
  onClose: () => void;
  milestone?: Milestone | null;
  onSubmit: (data: MilestoneFormData) => Promise<void>;
  isLoading?: boolean;
  defaultPhase?: PDCAPhase;
  teamMembers?: Array<{ id: string; displayName: string; email: string }>;
}

export const MilestoneFormDrawer: React.FC<MilestoneFormDrawerProps> = ({
  isOpen,
  onClose,
  milestone,
  onSubmit,
  isLoading = false,
  defaultPhase = 'plan',
  teamMembers = [],
}) => {
  const { t } = useStore();

  const {
    register,
    handleSubmit,
    formState: { errors },
    reset,
    watch,
    setValue,
  } = useZodForm({
    schema: milestoneSchema,
    defaultValues: {
      name: milestone?.name || '',
      description: milestone?.description || '',
      phase: milestone?.phase || defaultPhase,
      dueDate: milestone?.dueDate
        ? new Date(milestone.dueDate).toISOString().split('T')[0]
        : '',
      responsibleId: milestone?.responsibleId || '',
    },
  });

  const selectedPhase = watch('phase') as PDCAPhase;

  useEffect(() => {
    if (isOpen) {
      reset({
        name: milestone?.name || '',
        description: milestone?.description || '',
        phase: milestone?.phase || defaultPhase,
        dueDate: milestone?.dueDate
          ? new Date(milestone.dueDate).toISOString().split('T')[0]
          : '',
        responsibleId: milestone?.responsibleId || '',
      });
    }
  }, [isOpen, milestone, defaultPhase, reset]);

  const handleFormSubmit = async (data: FieldValues) => {
    await onSubmit(data as MilestoneFormData);
  };

  const title = milestone ? 'Modifier le jalon' : 'Nouveau jalon';
  const subtitle = 'Définissez les détails du jalon SMSI';

  return (
    <Drawer
      isOpen={isOpen}
      onClose={onClose}
      title={title}
      subtitle={subtitle}
      width="max-w-xl"
    >
      <form
        id="milestone-form"
        onSubmit={handleSubmit(handleFormSubmit)}
        className="flex flex-col h-full"
      >
        <div className="flex-1 space-y-6 pt-6 px-1">
          {/* Name */}
          <FloatingLabelInput
            label="Nom du jalon"
            placeholder="Ex: Rédaction de la politique SMSI"
            required
            error={errors.name?.message}
            {...register('name')}
          />

          {/* Description */}
          <FloatingLabelTextarea
            label="Description"
            placeholder="Décrivez les objectifs et livrables attendus..."
            rows={3}
            error={errors.description?.message}
            {...register('description')}
          />

          {/* Phase Selection - Story 20.2 */}
          <div className="space-y-2">
            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 dark:text-muted-foreground">
              Phase PDCA *
            </label>
            <div className="grid grid-cols-2 gap-3">
              {(Object.keys(PHASE_CONFIG) as PDCAPhase[]).map((phase) => {
                const config = PHASE_CONFIG[phase];
                const style = PHASE_STYLES[phase];
                const isSelected = selectedPhase === phase;
                const PhaseIcon = config.icon as React.ComponentType<{ className?: string }>;

                return (
                  <button
                    key={phase}
                    type="button"
                    onClick={() => setValue('phase', phase)}
                    className={cn(
                      'flex items-center gap-3 p-3 rounded-xl border-2 transition-all text-left',
                      isSelected
                        ? `${style.borderActive} ${style.bgActive}`
                        : 'border-slate-200 dark:border-slate-700 hover:border-slate-300 dark:hover:border-slate-600'
                    )}
                  >
                    <div
                      className={cn(
                        'w-10 h-10 rounded-lg flex items-center justify-center',
                        style.iconBg
                      )}
                    >
                      <PhaseIcon className={cn('w-5 h-5', style.iconText)} />
                    </div>
                    <div>
                      <p
                        className={cn(
                          'font-medium',
                          isSelected
                            ? style.textActive
                            : 'text-slate-700 dark:text-slate-300'
                        )}
                      >
                        {config.label}
                      </p>
                      <p className="text-xs text-slate-500 dark:text-slate-300 line-clamp-1">
                        {config.description.substring(0, 30)}...
                      </p>
                    </div>
                  </button>
                );
              })}
            </div>
            <input type="hidden" {...register('phase')} />
            {errors.phase && (
              <p className="text-sm text-red-500">{errors.phase.message}</p>
            )}
          </div>

          {/* Due Date */}
          <FloatingLabelInput
            type="date"
            label="Date d'échéance"
            required
            error={errors.dueDate?.message}
            {...register('dueDate')}
          />

          {/* Responsible Person - Story 20.4 */}
          <div className="space-y-2">
            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 flex items-center gap-2">
              <Users className="w-4 h-4" />
              Responsable
            </label>
            <select
              {...register('responsibleId')}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus-visible:ring-2 focus-visible:ring-brand-400 focus:border-blue-500"
            >
              <option value="">Non assigné</option>
              {teamMembers.map((member) => (
                <option key={member.id} value={member.id}>
                  {member.displayName || member.email}
                </option>
              ))}
            </select>
            {errors.responsibleId && (
              <p className="text-sm text-red-500">
                {errors.responsibleId.message}
              </p>
            )}
          </div>

          {/* Quick Tips */}
          <div className="p-4 rounded-xl bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800 dark:border-blue-800">
            <p className="text-sm text-blue-700 dark:text-blue-400">
              <strong>Conseil :</strong> Définissez des jalons SMART (Spécifiques,
              Mesurables, Atteignables, Réalistes, Temporellement définis) pour
              un suivi efficace.
            </p>
          </div>
        </div>

        <div className="mt-8 flex justify-end gap-3 pt-6 border-t border-slate-200 dark:border-white/10">
          <Button
            type="button"
            variant="ghost"
            onClick={onClose}
            disabled={isLoading}
          >
            {t('common.cancel')}
          </Button>
          <Button type="submit" isLoading={isLoading}>
            {milestone ? t('common.save') : t('common.create')}
          </Button>
        </div>
      </form>
    </Drawer>
  );
};

export default MilestoneFormDrawer;

import React, { useEffect } from 'react';
import { useStore } from '../../store';
import { Drawer } from '../ui/Drawer';
import { Button } from '../ui/button';
import { FloatingLabelInput } from '../ui/FloatingLabelInput';
import { FloatingLabelTextarea } from '../ui/FloatingLabelTextarea';
import { useZodForm } from '../../hooks/useZodForm';
import { z } from 'zod';
import { Shield, Clock, Settings, CheckCircle2 } from '../ui/Icons';
import { cn } from '../../utils/cn';
import { FieldValues } from 'react-hook-form';
import { SMSIProgram } from '../../types/ebios';

const smsiSchema = z.object({
    name: z.string().min(1, 'Le nom est requis'),
    description: z.string().optional(),
    targetCertificationDate: z.string().optional(),
    isCertified: z.boolean().optional(),
    template: z.enum(['standard', 'fast-track', 'maintenance']).default('standard'),
});

const PROGRAM_TEMPLATES = [
    {
        id: 'standard',
        name: 'Implémentation Standard ISO 27001',
        description: 'Cycle complet PDCA avec tous les jalons classiques.',
        icon: Shield
    },
    {
        id: 'fast-track',
        name: 'Fast Track (Startup/PME)',
        description: 'Focus sur les risques critiques et contrôles essentiels.',
        icon: Clock
    },
    {
        id: 'maintenance',
        name: 'Maintien & Amélioration',
        description: 'Pour les organisations déjà certifiées (Cycle annuel).',
        icon: Settings
    }
] as const;

type SMSIFormData = z.infer<typeof smsiSchema>;

interface SMSIDrawerProps {
    isOpen: boolean;
    onClose: () => void;
    program?: SMSIProgram | null;
    onSubmit: (data: SMSIFormData) => Promise<void>;
    isLoading?: boolean;
}

export const SMSIDrawer: React.FC<SMSIDrawerProps> = ({
    isOpen,
    onClose,
    program,
    onSubmit,
    isLoading = false
}) => {
    const { t } = useStore();
    const isEditing = !!program;

    const { register, handleSubmit, formState: { errors }, reset, watch, setValue } = useZodForm({
        schema: smsiSchema,
        defaultValues: {
            name: program?.name || '',
            description: program?.description || '',
            targetCertificationDate: program?.targetCertificationDate ? new Date(program.targetCertificationDate).toISOString().split('T')[0] : '',
            isCertified: false,
            template: 'standard'
        }
    });

    const selectedTemplate = watch('template');

    useEffect(() => {
        if (isOpen) {
            reset({
                name: program?.name || '',
                description: program?.description || '',
                targetCertificationDate: program?.targetCertificationDate ? new Date(program.targetCertificationDate).toISOString().split('T')[0] : '',
                isCertified: false,
                template: 'standard'
            });
        }
    }, [isOpen, program, reset]);

    const handleFormSubmit = async (data: FieldValues) => {
        await onSubmit(data as SMSIFormData);
    };

    const title = program ? t('smsi.editProgram') : t('smsi.newProgram');
    const subtitle = t('smsi.programDetails');

    return (
        <Drawer
            isOpen={isOpen}
            onClose={onClose}
            title={title}
            subtitle={subtitle}
            width="max-w-xl"
        >
            <form id="smsi-form" onSubmit={handleSubmit(handleFormSubmit)} className="flex flex-col h-full">
                <div className="flex-1 space-y-6 pt-6 px-1">
                    <FloatingLabelInput
                        label={t('common.name')}
                        placeholder="Ex: Certification ISO 27001 - 2025"
                        required
                        error={errors.name?.message}
                        {...register('name')}
                    />

                    <FloatingLabelTextarea
                        label={t('common.description')}
                        placeholder="Description du périmètre et des objectifs..."
                        rows={4}
                        error={errors.description?.message}
                        {...register('description')}
                    />

                    <FloatingLabelInput
                        type="date"
                        label={t('smsi.targetDate')}
                        error={errors.targetCertificationDate?.message}
                        {...register('targetCertificationDate')}
                    />

                    {!isEditing && (
                        <div className="pt-4">
                            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-3">
                                Modèle de programme
                            </label>
                            <div className="grid gap-3">
                                {PROGRAM_TEMPLATES.map((template) => (
                                    <div
                                        key={template.id}
                                        onClick={() => setValue('template', template.id)}
                                        className={cn(
                                            "relative flex items-start gap-3 p-3 rounded-xl border cursor-pointer transition-all",
                                            selectedTemplate === template.id
                                                ? "border-brand-500 bg-brand-50 dark:bg-brand-800 ring-1 ring-brand-500"
                                                : "border-slate-200 dark:border-white/10 hover:border-slate-300 dark:hover:border-white/20 bg-white dark:bg-slate-900"
                                        )}
                                    >
                                        <div className={cn(
                                            "p-2 rounded-lg",
                                            selectedTemplate === template.id ? "bg-brand-100 text-brand-600 dark:bg-brand-900 dark:text-brand-400" : "bg-slate-100 dark:bg-slate-800 text-slate-500 dark:bg-slate-800 dark:text-slate-300"
                                        )}>
                                            <template.icon className="w-5 h-5" />
                                        </div>
                                        <div className="flex-1">
                                            <h4 className={cn(
                                                "text-sm font-medium mb-0.5",
                                                selectedTemplate === template.id ? "text-brand-900 dark:text-brand-100" : "text-slate-900 dark:text-white"
                                            )}>
                                                {template.name}
                                            </h4>
                                            <p className="text-xs text-slate-500 dark:text-muted-foreground">
                                                {template.description}
                                            </p>
                                        </div>
                                        {selectedTemplate === template.id && (
                                            <div className="absolute top-3 right-3 text-brand-500">
                                                <CheckCircle2 className="w-5 h-5 fill-current" />
                                            </div>
                                        )}
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}
                </div>

                <div className="mt-8 flex justify-end gap-3 pt-6 border-t border-slate-200 dark:border-white/10">
                    <Button
                        type="button"
                        variant="ghost"
                        onClick={onClose}
                        disabled={isLoading}
                    >
                        {t('common.cancel')}
                    </Button>
                    <Button
                        type="submit"
                        isLoading={isLoading}
                    >
                        {program ? t('common.save') : t('common.create')}
                    </Button>
                </div>
            </form>
        </Drawer>
    );
};

/**
 * SMSIInspector.tsx
 * Inspector panel for viewing and managing SMSI milestones
 *
 * Story 20.2: Définition des Jalons
 * Story 20.4: Attribution des Responsables
 */

import React, { useMemo } from 'react';
import { InspectorLayout } from '../ui/InspectorLayout';
import { Milestone } from '../../types/ebios';
import { Badge } from '../ui/Badge';
import { PHASE_CONFIG, MILESTONE_STATUS_CONFIG, PHASE_STYLES, MILESTONE_STATUS_STYLES } from './constants';
import { PremiumCard } from '../ui/PremiumCard';
import { Calendar, Users, Pencil, Trash2, Link, FileText, AlertTriangle } from '../ui/Icons';
import { Button } from '../ui/button';
import { cn } from '../../utils/cn';
import { ConfirmModal } from '../ui/ConfirmModal';
import { useState } from 'react';

interface TeamMember {
    id: string;
    displayName: string;
    email: string;
}

interface LinkedItem {
    id: string;
    title: string;
    type: 'document' | 'control' | 'risk';
}

interface SMSIInspectorProps {
    isOpen: boolean;
    onClose: () => void;
    milestone: Milestone | null;
    onStatusChange?: (id: string, status: Milestone['status']) => void;
    onEdit?: (milestone: Milestone) => void;
    onDelete?: (id: string) => Promise<void>;
    teamMembers?: TeamMember[];
    linkedItems?: LinkedItem[];
}

export const SMSIInspector: React.FC<SMSIInspectorProps> = ({
    isOpen,
    onClose,
    milestone,
    onStatusChange,
    onEdit,
    onDelete,
    teamMembers = [],
    linkedItems = []
}) => {
    const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
    const [isDeleting, setIsDeleting] = useState(false);

    // Get responsible person's display name - Story 20.4
    const responsibleName = useMemo(() => {
        if (!milestone?.responsibleId) return 'Non assigné';
        const member = teamMembers.find(m => m.id === milestone.responsibleId);
        return member?.displayName || member?.email || milestone.responsibleId;
    }, [milestone, teamMembers]);

    const handleDelete = async () => {
        if (!milestone || !onDelete) return;
        setIsDeleting(true);
        try {
            await onDelete(milestone.id);
            setShowDeleteConfirm(false);
            onClose();
        } finally {
            setIsDeleting(false);
        }
    };

    const isOverdue = milestone && milestone.status !== 'completed' && new Date(milestone.dueDate) < new Date();

    if (!milestone) return null;

    const phaseConfig = PHASE_CONFIG[milestone.phase];
    const statusConfig = MILESTONE_STATUS_CONFIG[milestone.status];
    const statusStyle = MILESTONE_STATUS_STYLES[milestone.status];
    const phaseStyle = PHASE_STYLES[milestone.phase];
    const StatusIcon = statusConfig.icon;

    return (
        <InspectorLayout
            isOpen={isOpen}
            onClose={onClose}
            title={milestone.name}
            subtitle={milestone.phase ? `Phase ${phaseConfig.label}` : 'Programme SMSI'}
            width="max-w-2xl"
            statusBadge={
                <Badge
                    className={cn(
                        statusStyle.bg,
                        statusStyle.text
                    )}
                >
                    <div className="flex items-center gap-1.5">
                        <StatusIcon className="w-3.5 h-3.5" />
                        {statusConfig.label}
                    </div>
                </Badge>
            }
        >
            <div className="p-6 space-y-6">
                <PremiumCard glass className="p-6">
                    <h3 className="text-lg font-semibold mb-4">Informations</h3>
                    <div className="space-y-4">
                        <div>
                            <label className="text-sm font-medium text-slate-500 dark:text-slate-300 block mb-1">Description</label>
                            <p className="text-slate-900 dark:text-white">{milestone.description || 'Aucune description'}</p>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="text-sm font-medium text-slate-500 dark:text-slate-300 block mb-1">Échéance</label>
                                <div className="flex items-center gap-2 text-slate-900 dark:text-white">
                                    <Calendar className="w-4 h-4 text-muted-foreground" />
                                    {new Date(milestone.dueDate).toLocaleDateString()}
                                </div>
                            </div>
                            <div>
                                <label className="text-sm font-medium text-slate-500 dark:text-slate-300 block mb-1">Responsable</label>
                                <div className="flex items-center gap-2 text-slate-900 dark:text-white">
                                    <Users className="w-4 h-4 text-muted-foreground" />
                                    {responsibleName}
                                </div>
                            </div>
                        </div>

                        <div>
                            <label className="text-sm font-medium text-slate-500 dark:text-slate-300 block mb-1">Phase PDCA</label>
                            <div className="flex items-center gap-2">
                                {(() => {
                                    const PhaseIcon = phaseConfig.icon as React.ComponentType<{ className?: string }>;
                                    return <PhaseIcon className={cn("w-4 h-4", phaseStyle.text)} />;
                                })()}
                                <span className="text-slate-900 dark:text-white">{phaseConfig.label} - {phaseConfig.description}</span>
                            </div>
                        </div>
                    </div>
                </PremiumCard>

                {/* Overdue Warning */}
                {isOverdue && (
                    <PremiumCard glass className="p-4 border-red-200 dark:border-red-800 dark:border-red-900 bg-red-500 dark:bg-red-50 dark:bg-red-900">
                        <div className="flex items-center gap-3">
                            <AlertTriangle className="w-5 h-5 text-red-500 flex-shrink-0" />
                            <div>
                                <p className="font-medium text-red-700 dark:text-red-400">Jalon en retard</p>
                                <p className="text-sm text-red-600/80 dark:text-red-400/80">
                                    Échéance dépassée depuis le {new Date(milestone.dueDate).toLocaleDateString('fr-FR')}
                                </p>
                            </div>
                        </div>
                    </PremiumCard>
                )}

                {/* Linked Items */}
                {linkedItems.length > 0 && (
                    <PremiumCard glass className="p-6">
                        <h3 className="text-lg font-semibold mb-4 flex items-center gap-2">
                            <Link className="w-5 h-5" />
                            Éléments liés
                        </h3>
                        <div className="space-y-2">
                            {linkedItems.map(item => (
                                <div key={item.id} className="flex items-center gap-3 p-3 rounded-lg bg-slate-50 dark:bg-slate-800/50">
                                    <FileText className="w-4 h-4 text-muted-foreground" />
                                    <span className="text-sm text-slate-700 dark:text-slate-300 dark:text-muted-foreground">{item.title}</span>
                                    <Badge variant="outline" size="sm" className="ml-auto capitalize">{item.type}</Badge>
                                </div>
                            ))}
                        </div>
                    </PremiumCard>
                )}

                {(onStatusChange || onEdit || onDelete) && (
                    <PremiumCard glass className="p-6">
                        <h3 className="text-lg font-semibold mb-4">Actions</h3>
                        <div className="space-y-4">
                            <div className="flex gap-2">
                                {onEdit && (
                                    <Button
                                        variant="outline"
                                        size="sm"
                                        onClick={() => onEdit(milestone)}
                                        className="flex-1 justify-center"
                                    >
                                        <Pencil className="w-4 h-4 mr-2" />
                                        Modifier
                                    </Button>
                                )}
                                {onDelete && (
                                    <Button
                                        variant="outline"
                                        size="sm"
                                        onClick={() => setShowDeleteConfirm(true)}
                                        className="text-red-600 hover:bg-red-50 dark:hover:bg-red-900/30 dark:hover:bg-red-900/20 border-red-200 dark:border-red-800 dark:border-red-800"
                                    >
                                        <Trash2 className="w-4 h-4" />
                                    </Button>
                                )}
                            </div>

                            {onStatusChange && (
                                <div>
                                    <label className="text-sm font-medium text-slate-500 dark:text-slate-300 block mb-2">Changer le statut</label>
                                    <div className="flex flex-wrap gap-2">
                                        {Object.entries(MILESTONE_STATUS_CONFIG).map(([status, config]) => {
                                            if (status === 'overdue') return null; // Don't allow manual setting to 'overdue'
                                            const isActive = milestone.status === status;
                                            const ConfigIcon = config.icon;
                                            const style = MILESTONE_STATUS_STYLES[status as Milestone['status']];
                                            return (
                                                <Button
                                                    key={status}
                                                    variant={isActive ? 'default' : 'outline'}
                                                    size="sm"
                                                    onClick={() => onStatusChange(milestone.id, status as Milestone['status'])}
                                                    className={cn(
                                                        isActive && style.button
                                                    )}
                                                    disabled={isActive}
                                                >
                                                    <ConfigIcon className="w-4 h-4 mr-2" />
                                                    {config.label}
                                                </Button>
                                            );
                                        })}
                                    </div>
                                </div>
                            )}
                        </div>
                    </PremiumCard>
                )}
            </div>

            {/* Delete Confirmation Dialog */}
            <ConfirmModal
                isOpen={showDeleteConfirm}
                onClose={() => setShowDeleteConfirm(false)}
                onConfirm={handleDelete}
                title="Supprimer le jalon"
                message={`Êtes-vous sûr de vouloir supprimer le jalon "${milestone.name}" ? Cette action est irréversible.`}
                confirmText="Supprimer"
                cancelText="Annuler"
                type="danger"
                loading={isDeleting}
            />
        </InspectorLayout>
    );
};

import React, { memo } from 'react';
import { Supplier, Criticality, UserProfile } from '../../types';
import { Building, Truck, ShieldAlert } from '../ui/Icons';
import { getUserAvatarUrl } from '../../utils/avatarUtils';
// Focus indicators: focus-visible:ring-2 applied globally via CSS

const getCriticalityColor = (c: Criticality) => {
    switch (c) {
        case Criticality.CRITICAL: return 'bg-red-100 text-red-700 dark:text-red-400 border-red-200 dark:border-red-800 dark:bg-red-900/20 dark:text-red-400 dark:border-red-800';
        case Criticality.HIGH: return 'bg-orange-100 text-orange-700 dark:text-orange-400 border-orange-200 dark:border-orange-800 dark:bg-orange-900/20 dark:text-orange-400 dark:border-orange-800';
        case Criticality.MEDIUM: return 'bg-yellow-100 text-yellow-700 border-yellow-200 dark:bg-yellow-900/20 dark:text-yellow-400 dark:border-yellow-800';
        default: return 'bg-green-100 text-green-700 dark:text-green-400 border-green-200 dark:border-green-800 dark:bg-green-900/20 dark:text-green-400 dark:border-green-800';
    }
};

const getScoreColor = (score: number) => {
    if (score >= 80) return 'bg-emerald-500';
    if (score >= 50) return 'bg-amber-500';
    return 'bg-red-500';
};

interface SupplierCardProps {
    supplier: Supplier;
    onClick: (supplier: Supplier) => void;
    onDelete?: () => void;
    users?: UserProfile[]; // Optional to avoid breaking if not passed yet
}

export const SupplierCard = memo(({ supplier, onClick, users }: SupplierCardProps) => {
    const isExpired = supplier.contractEnd && new Date(supplier.contractEnd) < new Date();

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter' || e.key === ' ') {
            e.preventDefault();
            onClick(supplier);
        }
    };

    return (
        <div
            onClick={() => onClick(supplier)}
