import React, { useState, useCallback, useMemo } from 'react';
import { Controller } from 'react-hook-form';
import { useZodForm } from '../../hooks/useZodForm';
import { batchAssignmentSchema, BatchAssignmentFormData } from '../../schemas/trainingSchema';
import { Button } from '../ui/button';
import { FloatingLabelInput } from '../ui/FloatingLabelInput';
import { CustomSelect } from '../ui/CustomSelect';
import {
  Users,
  Calendar,
  GraduationCap,
  AlertCircle,
  CheckCircle,
  Clock,
  Shield,
  Award,
  FileText,
  ChevronRight,
} from '../ui/Icons';
import { useStore } from '../../store';
import { useTrainingAssignment } from '../../hooks/training/useTrainingAssignment';
import { motion, AnimatePresence } from 'framer-motion';
import { appleEasing } from '../../utils/microInteractions';
import type { UserProfile } from '../../types';
import type { TrainingCategory } from '../../types/training';

// ============================================================================
// Types
// ============================================================================

interface TrainingAssignmentFormProps {
  onSuccess: (assignmentIds: string[]) => void;
  onCancel: () => void;
  users: UserProfile[];
  preselectedCourseId?: string;
  preselectedUserIds?: string[];
  campaignId?: string;
}

// ============================================================================
// Helpers
// ============================================================================

const getCategoryIcon = (category: TrainingCategory) => {
  const icons = {
    security: Shield,
    compliance: Award,
    awareness: Users,
    technical: FileText,
  };
  return icons[category] || GraduationCap;
};

const formatDuration = (minutes: number): string => {
  if (minutes < 60) return `${minutes} min`;
  const hours = Math.floor(minutes / 60);
  const mins = minutes % 60;
  return mins > 0 ? `${hours}h ${mins}min` : `${hours}h`;
};

// ============================================================================
// Component
// ============================================================================

export const TrainingAssignmentForm: React.FC<TrainingAssignmentFormProps> = ({
  onSuccess,
  onCancel,
  users,
  preselectedCourseId,
  preselectedUserIds,
  campaignId,
}) => {
  const { t } = useStore();
  const {
    isLoading,
    courses,
    preview,
    generatePreview,
    clearPreview,
    assignTraining,
  } = useTrainingAssignment();

  // Step state: 'select' | 'preview' | 'confirm'
  const [step, setStep] = useState<'select' | 'preview' | 'confirm'>('select');

  // Form setup
  const {
    control,
    handleSubmit,
    watch,
    formState: { errors, isValid },
  } = useZodForm<typeof batchAssignmentSchema>({
    schema: batchAssignmentSchema,
    mode: 'onChange',
    defaultValues: {
      courseId: preselectedCourseId || '',
      userIds: preselectedUserIds || [],
      dueDate: new Date(Date.now() + 14 * 24 * 60 * 60 * 1000), // 2 weeks default
    },
  });

  // Watched values
  const selectedCourseId = watch('courseId');
  const selectedUserIds = watch('userIds');
  const selectedDueDate = watch('dueDate');

  // Selected course details
  const selectedCourse = useMemo(() => {
    return courses.find((c) => c.id === selectedCourseId);
  }, [courses, selectedCourseId]);

  // Selected users details
  const selectedUsers = useMemo(() => {
    return users.filter((u) => selectedUserIds.includes(u.uid));
  }, [users, selectedUserIds]);

  // Course options for select
  const courseOptions = useMemo(() => {
    return courses
      .filter((c) => !c.isArchived)
      .map((c) => ({
        value: c.id,
        label: `${c.title} (${formatDuration(c.duration)})`,
      }));
  }, [courses]);

  // User options for select
  const userOptions = useMemo(() => {
    return users.map((u) => ({
      value: u.uid,
      label: u.displayName || u.email || u.uid,
    }));
  }, [users]);

  // Generate preview when moving to preview step
  const handlePreview = useCallback(() => {
    if (selectedCourse && selectedUsers.length > 0 && selectedDueDate) {
      generatePreview(selectedCourseId, selectedUsers, selectedDueDate);
      setStep('preview');
    }
  }, [selectedCourse, selectedUsers, selectedDueDate, selectedCourseId, generatePreview]);

  // Handle form submission
  const onFormSubmit = useCallback(async (data: BatchAssignmentFormData) => {
    try {
      const assignmentIds = await assignTraining(
        data.courseId,
        data.userIds,
        data.dueDate,
        campaignId
      );
      onSuccess(assignmentIds);
    } catch {
      // Error handled in hook
    }
  }, [assignTraining, campaignId, onSuccess]);

  // Reset preview when going back
  const handleBack = useCallback(() => {
    clearPreview();
    setStep('select');
  }, [clearPreview]);

  // Minimum date for deadline (tomorrow)
  const minDate = useMemo(() => {
    const tomorrow = new Date();
    tomorrow.setDate(tomorrow.getDate() + 1);
    return tomorrow.toISOString().split('T')[0];
  }, []);

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.3, ease: appleEasing }}
      className="space-y-6"
    >
      {/* Progress Steps */}
      <div className="flex items-center justify-center gap-2">
        {['select', 'preview', 'confirm'].map((s, i) => (
          <React.Fragment key={s}>
            <div
              className={`flex items-center justify-center w-8 h-8 rounded-full text-sm font-bold transition-colors ${
                step === s
                  ? 'bg-primary text-primary-foreground'
                  : i < ['select', 'preview', 'confirm'].indexOf(step)
                  ? 'bg-success-bg text-success-text'
                  : 'bg-muted text-muted-foreground'
              }`}
            >
              {i < ['select', 'preview', 'confirm'].indexOf(step) ? (
                <CheckCircle className="w-4 h-4" />
              ) : (
                i + 1
              )}
            </div>
            {i < 2 && (
              <div
                className={`w-12 h-0.5 transition-colors ${
                  i < ['select', 'preview', 'confirm'].indexOf(step)
                    ? 'bg-success-bg'
                    : 'bg-muted'
                }`}
              />
            )}
          </React.Fragment>
        ))}
      </div>

      <AnimatePresence mode="wait">
        {/* Step 1: Select */}
        {step === 'select' && (
          <motion.div
            key="select"
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: 20 }}
            transition={{ duration: 0.2 }}
            className="space-y-6"
          >
            <h3 className="text-lg font-bold text-foreground">
              {t('training.assignment.selectDetails')}
            </h3>

            {/* Course Selection */}
            <Controller
              control={control}
              name="courseId"
              render={({ field }) => (
                <CustomSelect
                  label={t('training.assignment.selectCourse')}
                  options={courseOptions}
                  value={field.value}
                  onChange={field.onChange}
                  error={errors.courseId?.message}
                />
              )}
            />

            {/* Selected Course Preview */}
            {selectedCourse && (
              <motion.div
                initial={{ opacity: 0, height: 0 }}
                animate={{ opacity: 1, height: 'auto' }}
                className="p-4 rounded-2xl bg-muted/30 border border-muted"
              >
                <div className="flex items-start gap-3">
                  {(() => {
                    const CategoryIcon = getCategoryIcon(selectedCourse.category);
                    return (
                      <div className="p-2 rounded-xl bg-primary/10">
                        <CategoryIcon className="w-5 h-5 text-primary" />
                      </div>
                    );
                  })()}
                  <div className="flex-1">
                    <h4 className="font-semibold text-foreground">
                      {selectedCourse.title}
                    </h4>
                    <p className="text-sm text-muted-foreground line-clamp-2">
                      {selectedCourse.description}
                    </p>
                    <div className="flex items-center gap-4 mt-2">
                      <span className="flex items-center gap-1 text-xs text-muted-foreground">
                        <Clock className="w-3 h-3" />
                        {formatDuration(selectedCourse.duration)}
                      </span>
                      {selectedCourse.isRequired && (
                        <span className="px-2 py-0.5 rounded-full bg-error-bg text-error-text text-[11px] font-bold uppercase">
                          {t('common.required')}
                        </span>
                      )}
                    </div>
                  </div>
                </div>
              </motion.div>
            )}

            {/* User Selection */}
            <Controller
              control={control}
              name="userIds"
              render={({ field }) => (
                <CustomSelect
                  label={t('training.assignment.selectUsers')}
                  options={userOptions}
                  value={field.value}
                  onChange={field.onChange}
                  multiple
                  error={errors.userIds?.message}
                />
              )}
            />

            {/* Selected Users Count */}
            {selectedUsers.length > 0 && (
              <div className="flex items-center gap-2 text-sm text-muted-foreground">
                <Users className="w-4 h-4" />
                <span>
                  {selectedUsers.length} {t('training.assignment.usersSelected')}
                </span>
              </div>
            )}

            {/* Due Date */}
            <Controller
              control={control}
              name="dueDate"
              render={({ field }) => (
                <FloatingLabelInput
                  label={t('training.assignment.dueDate')}
                  type="date"
                  value={field.value instanceof Date ? field.value.toISOString().split('T')[0] : ''}
                  onChange={(e) => field.onChange(new Date(e.target.value))}
                  error={errors.dueDate?.message}
                  min={minDate}
                />
              )}
            />

            {/* Actions */}
            <div className="flex justify-end gap-4 pt-4 border-t border-muted">
              <Button type="button" variant="ghost" onClick={onCancel}>
                {t('common.cancel')}
              </Button>
              <Button
                type="button"
                onClick={handlePreview}
                disabled={!isValid || selectedUsers.length === 0}
                className="gap-2"
              >
                {t('training.assignment.preview')}
                <ChevronRight className="w-4 h-4" />
              </Button>
            </div>
          </motion.div>
        )}

        {/* Step 2: Preview */}
        {step === 'preview' && preview && (
          <motion.div
            key="preview"
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -20 }}
            transition={{ duration: 0.2 }}
            className="space-y-6"
          >
            <h3 className="text-lg font-bold text-foreground">
              {t('training.assignment.previewTitle')}
            </h3>

            {/* Assignment Summary Card */}
            <div className="p-6 rounded-3xl bg-gradient-to-br from-primary/10 to-primary/5 border border-primary/20">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-3">
                  <div className="p-3 rounded-2xl bg-primary/20">
                    <GraduationCap className="w-6 h-6 text-primary" />
                  </div>
                  <div>
                    <h4 className="font-bold text-foreground">
                      {preview.course.title}
                    </h4>
                    <p className="text-sm text-muted-foreground">
                      {formatDuration(preview.course.duration)}
                    </p>
                  </div>
                </div>
                {preview.course.isRequired && (
                  <span className="px-3 py-1 rounded-full bg-error-bg text-error-text text-xs font-bold uppercase">
                    {t('common.required')}
                  </span>
                )}
              </div>

              {/* Stats Grid */}
              <div className="grid grid-cols-3 gap-4">
                <div className="p-4 rounded-2xl bg-background/50 text-center">
                  <div className="text-2xl font-bold text-primary">
                    {preview.totalAssignments}
                  </div>
                  <div className="text-xs text-muted-foreground uppercase tracking-wider">
                    {t('training.assignment.totalAssignments')}
                  </div>
                </div>
                <div className="p-4 rounded-2xl bg-background/50 text-center">
                  <div className="text-2xl font-bold text-foreground">
                    <Calendar className="w-6 h-6 mx-auto" />
                  </div>
                  <div className="text-xs text-muted-foreground uppercase tracking-wider mt-1">
                    {preview.dueDate.toLocaleDateString()}
                  </div>
                </div>
                <div className="p-4 rounded-2xl bg-background/50 text-center">
                  <div className="text-2xl font-bold text-foreground">
                    <Users className="w-6 h-6 mx-auto" />
                  </div>
                  <div className="text-xs text-muted-foreground uppercase tracking-wider mt-1">
                    {preview.users.length} {t('training.assignment.users')}
                  </div>
                </div>
              </div>
            </div>

            {/* Users List */}
            <div className="space-y-2">
              <h4 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">
                {t('training.assignment.assignees')}
              </h4>
              <div className="max-h-48 overflow-y-auto space-y-2 p-1">
                {preview.users.map((user) => (
                  <div
                    key={user.uid}
                    className="flex items-center gap-3 p-3 rounded-xl bg-muted/30 border border-muted"
                  >
                    <div className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center text-sm font-bold text-primary">
                      {(user.displayName || user.email || '?')[0].toUpperCase()}
                    </div>
                    <div className="flex-1">
                      <div className="text-sm font-medium text-foreground">
                        {user.displayName || user.email}
                      </div>
                      {user.role && (
                        <div className="text-xs text-muted-foreground">
                          {user.role}
                        </div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Warning for required training */}
            {preview.course.isRequired && (
              <div className="flex items-start gap-3 p-4 rounded-xl bg-warning-bg/50 border border-warning-border/30">
                <AlertCircle className="w-5 h-5 text-warning-text shrink-0 mt-0.5" />
                <div>
                  <p className="text-sm font-medium text-warning-text">
                    {t('training.assignment.requiredWarningTitle')}
                  </p>
                  <p className="text-xs text-warning-text/80">
                    {t('training.assignment.requiredWarningDesc')}
                  </p>
                </div>
              </div>
            )}

            {/* Actions */}
            <div className="flex justify-between gap-4 pt-4 border-t border-muted">
              <Button type="button" variant="ghost" onClick={handleBack}>
                {t('common.back')}
              </Button>
              <div className="flex gap-2">
                <Button type="button" variant="outline" onClick={onCancel}>
                  {t('common.cancel')}
                </Button>
                <Button
                  type="button"
                  onClick={() => setStep('confirm')}
                  className="gap-2"
                >
                  {t('training.assignment.confirmAndAssign')}
                  <ChevronRight className="w-4 h-4" />
                </Button>
              </div>
            </div>
          </motion.div>
        )}

        {/* Step 3: Confirm */}
        {step === 'confirm' && preview && (
          <motion.div
            key="confirm"
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0, scale: 0.95 }}
            transition={{ duration: 0.2 }}
            className="space-y-6 text-center"
          >
            <div className="p-6 rounded-3xl bg-muted/30 border border-muted">
              <div className="w-16 h-16 mx-auto mb-4 rounded-full bg-primary/10 flex items-center justify-center">
                <GraduationCap className="w-8 h-8 text-primary" />
              </div>
              <h3 className="text-xl font-bold text-foreground mb-2">
                {t('training.assignment.confirmTitle')}
              </h3>
              <p className="text-muted-foreground">
                {t('training.assignment.confirmDesc', {
                  count: preview.totalAssignments,
                  course: preview.course.title,
                })}
              </p>
            </div>

            {/* Final confirmation */}
            <div className="flex justify-center gap-4 pt-4">
              <Button
                type="button"
                variant="outline"
                onClick={() => setStep('preview')}
              >
                {t('common.back')}
              </Button>
              <Button
                type="button"
                onClick={handleSubmit(onFormSubmit)}
                isLoading={isLoading}
                className="px-8 shadow-sm shadow-primary"
              >
                {t('training.assignment.assign')}
              </Button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

TrainingAssignmentForm.displayName = 'TrainingAssignmentForm';

/**
 * TrainingCampaignForm Component
 *
 * Multi-step wizard for creating training campaigns.
 * Part of the Training & Awareness module (NIS2 Art. 21.2g).
 *
 * @module TrainingCampaignForm
 */

import React, { useState, useCallback, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useForm, Controller } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import {
  Megaphone,
  Users,
  Building2,
  Shield,
  CheckCircle,
  ChevronLeft,
  ChevronRight,
  RefreshCcw,
  GraduationCap,
  AlertCircle,
  X,
} from '../ui/Icons';
import { Button } from '../ui/button';
import { Input } from '../ui/input';
import { Label } from '../ui/label';
import { Checkbox } from '../ui/checkbox';
import { useStore } from '../../store';
import { useAuth } from '../../hooks/useAuth';
import { useCourses } from '../../stores/trainingStore';
import { TrainingService } from '../../services/TrainingService';
import { trainingCampaignSchema } from '../../schemas/trainingSchema';
import { toast } from '@/lib/toast';
import { appleEasing } from '../../utils/microInteractions';
import type {
  TrainingCampaignFormData,
  CampaignScope,
  RecurrenceFrequency,
  TrainingCourse,
} from '../../types/training';

// ============================================================================
// Types
// ============================================================================

interface TrainingCampaignFormProps {
  onSuccess: (campaignId: string) => void;
  onCancel: () => void;
}

type WizardStep = 'info' | 'courses' | 'scope' | 'review';

interface StepConfig {
  id: WizardStep;
  title: string;
  description: string;
  icon: React.ElementType<{ className?: string }>;
}

// ============================================================================
// Constants
// ============================================================================

const SCOPE_OPTIONS: { value: CampaignScope; label: string; icon: React.ElementType<{ className?: string }>; description: string }[] = [
  {
    value: 'all',
    label: 'training.campaign.scope.all',
    icon: Users,
    description: 'training.campaign.scopeDesc.all',
  },
  {
    value: 'department',
    label: 'training.campaign.scope.department',
    icon: Building2,
    description: 'training.campaign.scopeDesc.department',
  },
  {
    value: 'role',
    label: 'training.campaign.scope.role',
    icon: Shield,
    description: 'training.campaign.scopeDesc.role',
  },
];

const FREQUENCY_OPTIONS: { value: RecurrenceFrequency; label: string }[] = [
  { value: 'monthly', label: 'training.campaign.frequency.monthly' },
  { value: 'quarterly', label: 'training.campaign.frequency.quarterly' },
  { value: 'yearly', label: 'training.campaign.frequency.yearly' },
];

const STEPS: StepConfig[] = [
  {
    id: 'info',
    title: 'training.campaign.steps.info',
    description: 'training.campaign.steps.infoDesc',
    icon: Megaphone,
  },
  {
    id: 'courses',
    title: 'training.campaign.steps.courses',
    description: 'training.campaign.steps.coursesDesc',
    icon: GraduationCap,
  },
  {
    id: 'scope',
    title: 'training.campaign.steps.scope',
    description: 'training.campaign.steps.scopeDesc',
    icon: Users,
  },
  {
    id: 'review',
    title: 'training.campaign.steps.review',
    description: 'training.campaign.steps.reviewDesc',
    icon: CheckCircle,
  },
];

// ============================================================================
// Helper Components
// ============================================================================

interface CourseSelectCardProps {
  course: TrainingCourse;
  selected: boolean;
  onToggle: () => void;
  t: (key: string) => string;
}

const CourseSelectCard: React.FC<CourseSelectCardProps> = ({
  course,
  selected,
  onToggle,
  t,
}) => (
  <div
    onClick={onToggle}
    className={`p-4 rounded-xl border cursor-pointer transition-all ${
      selected
        ? 'border-primary bg-primary/5 ring-2 ring-primary/20'
        : 'border-white/10 hover:border-white/20 hover:bg-muted/30'
    }`}
  >
    <div className="flex items-start gap-3">
      <Checkbox checked={selected} onCheckedChange={onToggle} />
      <div className="flex-1 min-w-0">
        <div className="font-medium text-foreground">{course.title}</div>
        <div className="text-sm text-muted-foreground line-clamp-2 mt-1">
          {course.description}
        </div>
        <div className="flex items-center gap-2 mt-2 text-xs text-muted-foreground">
          <span className="px-2 py-0.5 rounded-full bg-muted">
            {t(`training.category.${course.category}`)}
          </span>
          <span>{course.duration} min</span>
          {course.isRequired && (
            <span className="px-2 py-0.5 rounded-full bg-error-bg text-error-text">
              {t('common.required')}
            </span>
          )}
        </div>
      </div>
    </div>
  </div>
);

// ============================================================================
// Main Component
// ============================================================================

export const TrainingCampaignForm: React.FC<TrainingCampaignFormProps> = ({
  onSuccess,
  onCancel,
}) => {
  const { t } = useStore();
  const { user } = useAuth();
  const courses = useCourses();

  // Wizard state
  const [currentStep, setCurrentStep] = useState<WizardStep>('info');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Form
  const {
    register,
    control,
    handleSubmit,
    watch,
    setValue,
    formState: { errors },
  } = useForm({
    resolver: zodResolver(trainingCampaignSchema),
    defaultValues: {
      name: '',
      description: '',
      startDate: new Date(),
      endDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000), // 30 days from now
      scope: 'all' as const,
      scopeFilter: [] as string[],
      courseIds: [] as string[],
      recurrence: {
        enabled: false,
        frequency: 'quarterly' as const,
      },
    },
  });

  const watchedValues = watch();
  const selectedCourseIds = watchedValues.courseIds || [];

  // Navigation
  const currentStepIndex = STEPS.findIndex((s) => s.id === currentStep);

  const canGoNext = useMemo(() => {
    switch (currentStep) {
      case 'info':
        return watchedValues.name && watchedValues.startDate && watchedValues.endDate;
      case 'courses':
        return selectedCourseIds.length > 0;
      case 'scope':
        return true;
      case 'review':
        return true;
      default:
        return false;
    }
  }, [currentStep, watchedValues, selectedCourseIds]);

  const goNext = useCallback(() => {
    const nextIndex = currentStepIndex + 1;
    if (nextIndex < STEPS.length) {
      setCurrentStep(STEPS[nextIndex].id);
    }
  }, [currentStepIndex]);

  const goBack = useCallback(() => {
    const prevIndex = currentStepIndex - 1;
    if (prevIndex >= 0) {
      setCurrentStep(STEPS[prevIndex].id);
    }
  }, [currentStepIndex]);

  // Course selection
  const toggleCourse = useCallback((courseId: string) => {
    const current = selectedCourseIds;
    if (current.includes(courseId)) {
      setValue('courseIds', current.filter((id) => id !== courseId));
    } else {
      setValue('courseIds', [...current, courseId]);
    }
  }, [selectedCourseIds, setValue]);

  // Submit
  const onSubmit = useCallback(async (formData: Record<string, unknown>) => {
    if (!user) return;

    const data = formData as unknown as TrainingCampaignFormData;
    setIsSubmitting(true);
    try {
      const campaignId = await TrainingService.createCampaign(data, user);
      toast.success(t('training.campaign.createSuccess'));
      onSuccess(campaignId);
    } catch (error) {
      toast.error(t('training.errors.createFailed'));
    } finally {
      setIsSubmitting(false);
    }
  }, [user, t, onSuccess]);

  // Get selected courses for review
  const selectedCourses = useMemo(() => {
    return courses.filter((c) => selectedCourseIds.includes(c.id));
  }, [courses, selectedCourseIds]);

  return (
    <div className="max-w-3xl mx-auto">
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <div className="flex items-center gap-3">
          <div className="p-3 rounded-2xl bg-primary/10">
            <Megaphone className="w-6 h-6 text-primary" />
          </div>
          <div>
            <h1 className="text-2xl font-bold text-foreground">
              {t('training.campaign.createTitle')}
            </h1>
            <p className="text-muted-foreground">
              {t('training.campaign.createDesc')}
            </p>
          </div>
        </div>
        <Button variant="ghost" size="sm" onClick={onCancel}>
          <X className="w-4 h-4" />
        </Button>
      </div>

      {/* Progress Steps */}
      <div className="flex items-center justify-between mb-8">
        {STEPS.map((step, index) => {
          const StepIcon = step.icon;
          const isActive = step.id === currentStep;
          const isCompleted = index < currentStepIndex;

          return (
            <React.Fragment key={step.id}>
              <div className="flex flex-col items-center">
                <div
                  className={`w-10 h-10 rounded-full flex items-center justify-center transition-all ${
                    isActive
                      ? 'bg-primary text-primary-foreground'
                      : isCompleted
                      ? 'bg-success text-white'
                      : 'bg-muted text-muted-foreground'
                  }`}
                >
                  {isCompleted ? (
                    <CheckCircle className="w-5 h-5" />
                  ) : (
                    <StepIcon className="w-5 h-5" />
                  )}
                </div>
                <span className={`text-xs mt-2 ${isActive ? 'text-foreground font-medium' : 'text-muted-foreground'}`}>
                  {t(step.title)}
                </span>
              </div>
              {index < STEPS.length - 1 && (
                <div className={`flex-1 h-0.5 mx-2 ${index < currentStepIndex ? 'bg-success' : 'bg-muted'}`} />
              )}
            </React.Fragment>
          );
        })}
      </div>

      {/* Step Content */}
      <form onSubmit={handleSubmit(onSubmit)}>
        <AnimatePresence mode="wait">
          <motion.div
            key={currentStep}
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -20 }}
            transition={{ duration: 0.2, ease: appleEasing }}
            className="glass-panel p-6 rounded-2xl border border-white/10 min-h-[400px]"
          >
            {/* Step: Info */}
            {currentStep === 'info' && (
              <div className="space-y-6">
                <div>
                  <Label htmlFor="name">{t('training.campaign.name')} *</Label>
                  <Input
                    id="name"
                    {...register('name')}
                    placeholder={t('training.campaign.namePlaceholder')}
                    className="mt-2"
                  />
                  {errors.name && (
                    <p className="text-sm text-error-text mt-1">{errors.name.message}</p>
                  )}
                </div>

                <div>
                  <Label htmlFor="description">{t('common.description')}</Label>
                  <textarea
                    id="description"
                    {...register('description')}
                    placeholder={t('training.campaign.descriptionPlaceholder')}
                    className="mt-2 w-full min-h-[100px] px-3 py-2 rounded-xl border border-input bg-background text-sm resize-none focus:outline-none focus:ring-2 focus:ring-primary"
                  />
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <Label htmlFor="startDate">{t('training.campaign.startDate')} *</Label>
                    <Controller
                      name="startDate"
                      control={control}
                      render={({ field }) => (
                        <Input
                          id="startDate"
                          type="date"
                          value={field.value ? new Date(field.value as Date).toISOString().split('T')[0] : ''}
                          onChange={(e) => field.onChange(new Date(e.target.value))}
                          className="mt-2"
                        />
                      )}
                    />
                  </div>
                  <div>
                    <Label htmlFor="endDate">{t('training.campaign.endDate')} *</Label>
                    <Controller
                      name="endDate"
                      control={control}
                      render={({ field }) => (
                        <Input
                          id="endDate"
                          type="date"
                          value={field.value ? new Date(field.value as Date).toISOString().split('T')[0] : ''}
                          onChange={(e) => field.onChange(new Date(e.target.value))}
                          className="mt-2"
                        />
                      )}
                    />
                  </div>
                </div>

                {/* Recurrence */}
                <div className="p-4 rounded-xl border border-white/10 bg-muted/20">
                  <div className="flex items-center gap-3 mb-4">
                    <Controller
                      name="recurrence.enabled"
                      control={control}
                      render={({ field }) => (
                        <Checkbox
                          checked={field.value}
                          onCheckedChange={(checked) => field.onChange(checked)}
                        />
                      )}
                    />
                    <div>
                      <div className="flex items-center gap-2 font-medium text-foreground">
                        <RefreshCcw className="w-4 h-4" />
                        {t('training.campaign.recurrence')}
                      </div>
                      <div className="text-xs text-muted-foreground">
                        {t('training.campaign.recurrenceDesc')}
                      </div>
                    </div>
                  </div>

                  {watchedValues.recurrence?.enabled && (
                    <div className="flex gap-2 mt-3">
                      {FREQUENCY_OPTIONS.map((opt) => (
                        <Controller
                          key={opt.value}
                          name="recurrence.frequency"
                          control={control}
                          render={({ field }) => (
                            <button
                              type="button"
                              onClick={() => field.onChange(opt.value)}
                              className={`px-3 py-2 rounded-xl text-sm font-medium transition-all ${
                                field.value === opt.value
                                  ? 'bg-primary text-primary-foreground'
                                  : 'bg-muted/50 text-muted-foreground hover:bg-muted'
                              }`}
                            >
                              {t(opt.label)}
                            </button>
                          )}
                        />
                      ))}
                    </div>
                  )}
                </div>
              </div>
            )}

            {/* Step: Courses */}
            {currentStep === 'courses' && (
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <div>
                    <h3 className="font-bold text-foreground">{t('training.campaign.selectCourses')}</h3>
                    <p className="text-sm text-muted-foreground">
                      {selectedCourseIds.length} {t('training.campaign.coursesSelected')}
                    </p>
                  </div>
                </div>

                {courses.length === 0 ? (
                  <div className="text-center py-8">
                    <AlertCircle className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
                    <p className="text-muted-foreground">{t('training.campaign.noCourses')}</p>
                  </div>
                ) : (
                  <div className="space-y-3 max-h-[350px] overflow-y-auto pr-2">
                    {courses.map((course) => (
                      <CourseSelectCard
                        key={course.id}
                        course={course}
                        selected={selectedCourseIds.includes(course.id)}
                        onToggle={() => toggleCourse(course.id)}
                        t={t}
                      />
                    ))}
                  </div>
                )}
              </div>
            )}

            {/* Step: Scope */}
            {currentStep === 'scope' && (
              <div className="space-y-6">
                <div>
                  <h3 className="font-bold text-foreground mb-4">{t('training.campaign.selectScope')}</h3>
                  <div className="grid grid-cols-1 gap-3">
                    {SCOPE_OPTIONS.map((opt) => {
                      const ScopeIcon = opt.icon;
                      const isSelected = watchedValues.scope === opt.value;

                      return (
                        <Controller
                          key={opt.value}
                          name="scope"
                          control={control}
                          render={({ field }) => (
                            <div
                              onClick={() => field.onChange(opt.value)}
                              className={`p-4 rounded-xl border cursor-pointer transition-all ${
                                isSelected
                                  ? 'border-primary bg-primary/5 ring-2 ring-primary/20'
                                  : 'border-white/10 hover:border-white/20 hover:bg-muted/30'
                              }`}
                            >
                              <div className="flex items-center gap-3">
                                <div className={`p-2 rounded-xl ${isSelected ? 'bg-primary/10' : 'bg-muted'}`}>
                                  <ScopeIcon className={`w-5 h-5 ${isSelected ? 'text-primary' : 'text-muted-foreground'}`} />
                                </div>
                                <div>
                                  <div className="font-medium text-foreground">{t(opt.label)}</div>
                                  <div className="text-sm text-muted-foreground">{t(opt.description)}</div>
                                </div>
                              </div>
                            </div>
                          )}
                        />
                      );
                    })}
                  </div>
                </div>

                {/* TODO: Add department/role filter when scope is not 'all' */}
              </div>
            )}

            {/* Step: Review */}
            {currentStep === 'review' && (
              <div className="space-y-6">
                <h3 className="font-bold text-foreground">{t('training.campaign.reviewTitle')}</h3>

                {/* Campaign Info */}
                <div className="p-4 rounded-xl border border-white/10 bg-muted/20">
                  <h4 className="text-sm font-bold text-muted-foreground uppercase tracking-wider mb-3">
                    {t('training.campaign.steps.info')}
                  </h4>
                  <div className="space-y-2">
                    <div className="flex justify-between">
                      <span className="text-muted-foreground">{t('training.campaign.name')}</span>
                      <span className="font-medium text-foreground">{watchedValues.name}</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-muted-foreground">{t('training.campaign.dates')}</span>
                      <span className="font-medium text-foreground">
                        {(watchedValues.startDate as Date)?.toLocaleDateString()} - {(watchedValues.endDate as Date)?.toLocaleDateString()}
                      </span>
                    </div>
                    {watchedValues.recurrence?.enabled && (
                      <div className="flex justify-between">
                        <span className="text-muted-foreground">{t('training.campaign.recurrence')}</span>
                        <span className="font-medium text-foreground">
                          {t(`training.campaign.frequency.${watchedValues.recurrence.frequency}`)}
                        </span>
                      </div>
                    )}
                  </div>
                </div>

                {/* Courses */}
                <div className="p-4 rounded-xl border border-white/10 bg-muted/20">
                  <h4 className="text-sm font-bold text-muted-foreground uppercase tracking-wider mb-3">
                    {t('training.campaign.steps.courses')} ({selectedCourses.length})
                  </h4>
                  <div className="space-y-2">
                    {selectedCourses.map((course) => (
                      <div key={course.id} className="flex items-center gap-2">
                        <GraduationCap className="w-4 h-4 text-primary" />
                        <span className="text-foreground">{course.title}</span>
                      </div>
                    ))}
                  </div>
                </div>

                {/* Scope */}
                <div className="p-4 rounded-xl border border-white/10 bg-muted/20">
                  <h4 className="text-sm font-bold text-muted-foreground uppercase tracking-wider mb-3">
                    {t('training.campaign.steps.scope')}
                  </h4>
                  <div className="flex items-center gap-2">
                    {(() => {
                      const scopeOpt = SCOPE_OPTIONS.find((s) => s.value === watchedValues.scope);
                      const ScopeIcon = scopeOpt?.icon || Users;
                      return (
                        <>
                          <ScopeIcon className="w-4 h-4 text-primary" />
                          <span className="text-foreground">{t(scopeOpt?.label || '')}</span>
                        </>
                      );
                    })()}
                  </div>
                </div>
              </div>
            )}
          </motion.div>
        </AnimatePresence>

        {/* Navigation */}
        <div className="flex items-center justify-between mt-6">
          <Button
            type="button"
            variant="outline"
            onClick={currentStepIndex === 0 ? onCancel : goBack}
          >
            <ChevronLeft className="w-4 h-4 mr-2" />
            {currentStepIndex === 0 ? t('common.cancel') : t('common.back')}
          </Button>

          {currentStep === 'review' ? (
            <Button type="submit" disabled={isSubmitting}>
              {isSubmitting ? (
                <span className="animate-pulse">{t('common.saving')}</span>
              ) : (
                <>
                  <CheckCircle className="w-4 h-4 mr-2" />
                  {t('training.campaign.create')}
                </>
              )}
            </Button>
          ) : (
            <Button
              type="button"
              onClick={goNext}
              disabled={!canGoNext}
            >
              {t('common.next')}
              <ChevronRight className="w-4 h-4 ml-2" />
            </Button>
          )}
        </div>
      </form>
    </div>
  );
};

