              >
                <Menu.Items className="absolute right-0 mt-2 w-48 origin-top-right glass-panel rounded-2xl p-1 shadow-lg z-50 border border-white/10">
                  {onAssign && (
                    <Menu.Item>
                      {({ active }) => (
                        <button
                          onClick={(e) => {
                            e.stopPropagation();
                            onAssign(course);
                          }}
                          className={`${active ? 'bg-primary/10 text-primary' : 'text-foreground'
