import {
  Clock,
  Play,
  CheckCircle,
  AlertTriangle,
  ExternalLink,
  Download,
  Calendar,
  Shield,
  Award,
  Users,
  FileText,
  PlayCircle,
  HelpCircle,
} from '../ui/Icons';
import { Button } from '../ui/button';
