import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { appleEasing } from '../../utils/microInteractions';

/**
 * Composant Button avec animation de feedback au clic
 * Fournit un retour visuel immédiat à l'utilisateur
 */
interface AnimatedButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  children: React.ReactNode;
  variant?: 'primary' | 'secondary' | 'danger' | 'success';
  size?: 'sm' | 'md' | 'lg';
  loading?: boolean;
}

export const AnimatedButton: React.FC<AnimatedButtonProps> = ({
  children,
  variant = 'primary',
  size = 'md',
  loading = false,
  className = '',
  onClick,
  ...props
}) => {
  const [isPressed, setIsPressed] = useState(false);

  const baseClasses = 'font-bold rounded-xl transition-all duration-200 focus:outline-none focus-visible:ring-2 focus-visible:ring-offset-2';

  const variantClasses = {
    primary: 'bg-brand-600 hover:bg-brand-700 text-white focus-visible:ring-brand-500 shadow-lg shadow-brand-500/20',
    secondary: 'bg-white dark:bg-slate-800 border border-slate-200 dark:border-white/10 text-slate-700 dark:text-white hover:bg-slate-50 dark:hover:bg-slate-700 focus-visible:ring-brand-500',
    danger: 'bg-red-600 hover:bg-red-700 text-white focus:ring-red-500 shadow-lg shadow-red-500/20',
    success: 'bg-success-600 hover:bg-success-700 text-white focus:ring-success-500 shadow-lg shadow-success-500/20'
  };

  const sizeClasses = {
    sm: 'px-3 py-1.5 text-xs',
    md: 'px-5 py-2.5 text-sm',
    lg: 'px-6 py-3 text-base'
  };

  const handleClick = (e: React.MouseEvent<HTMLButtonElement>) => {
    setIsPressed(true);
    setTimeout(() => setIsPressed(false), 200);

    // Créer effet ripple
    const button = e.currentTarget;
    const rect = button.getBoundingClientRect();
    const ripple = document.createElement('span');
    const diameter = Math.max(rect.width, rect.height);
    const radius = diameter / 2;

    ripple.style.width = ripple.style.height = `${diameter}px`;
    ripple.style.left = `${e.clientX - rect.left - radius}px`;
    ripple.style.top = `${e.clientY - rect.top - radius}px`;
    ripple.className = 'ripple';

    button.appendChild(ripple);
    setTimeout(() => ripple.remove(), 600);

    onClick?.(e);
  };

  return (
    <button
      className={`
        ${baseClasses}
        ${variantClasses[variant]}
        ${sizeClasses[size]}
        ${isPressed ? 'scale-95' : 'hover:scale-105'}
        ${loading ? 'opacity-75 cursor-not-allowed' : ''}
        ${className}
        relative overflow-hidden
      `}
      onClick={handleClick}
      disabled={loading}
      {...props}
    >
      {loading && (
        <span className="absolute inset-0 flex items-center justify-center">
          <span className="animate-spin h-4 w-4 border-2 border-white border-t-transparent rounded-full"></span>
        </span>
      )}
      <span className={loading ? 'opacity-0' : ''}>{children}</span>

      <style>{`
        .ripple {
          position: absolute;
          border-radius: 50%;
          background-color: rgba(255, 255, 255, 0.6);
          transform: scale(0);
          animation: ripple-animation 600ms ease-out;
          pointer-events: none;
        }

        @keyframes ripple-animation {
          to {
            transform: scale(4);
            opacity: 0;
          }
        }
      `}</style>
    </button>
  );
};

/**
 * Composant Card avec animation au hover
 */
interface AnimatedCardProps {
  children: React.ReactNode;
  onClick?: () => void;
  className?: string;
  interactive?: boolean;
}

export const AnimatedCard: React.FC<AnimatedCardProps> = ({
  children,
  onClick,
  className = '',
  interactive = false
}) => {
  return (
    <div
      onClick={onClick}
      className={`
        glass-panel rounded-4xl border border-white/50 dark:border-white/5
        transition-all duration-300
        ${interactive ? 'cursor-pointer hover:scale-[1.02] hover:shadow-xl' : ''}
        ${interactive ? 'hover:-translate-y-1' : ''}
        ${className}
      `}
    >
      {children}
    </div>
  );
};

/**
 * Skeleton avec pulse amélioré
 */
interface PulseSkeletonProps {
  className?: string;
  count?: number;
  variant?: 'text' | 'circular' | 'rectangular';
}

export const PulseSkeleton: React.FC<PulseSkeletonProps> = ({
  className = '',
  count = 1,
  variant = 'rectangular'
}) => {
  const baseClasses = 'bg-slate-200 dark:bg-slate-700 animate-pulse';

  const variantClasses = {
    text: 'h-4 rounded-md',
    circular: 'rounded-full',
    rectangular: 'rounded-xl'
  };

  return (
    <>
      {Array.from({ length: count }).map((_, i) => (
        <div
          key={`pulse-${i}`}
          className={`${baseClasses} ${variantClasses[variant]} ${className}`}
          style={{ animationDelay: `${i * 100}ms` }}
        />
      ))}
    </>
  );
};

/**
 * Badge avec animation de notification
 */
interface NotificationBadgeProps {
  count: number;
  max?: number;
  showZero?: boolean;
  className?: string;
}

export const NotificationBadge: React.FC<NotificationBadgeProps> = ({
  count,
  max = 99,
  showZero = false,
  className = ''
}) => {
  if (!showZero && count === 0) return null;

  const displayCount = count > max ? `${max}+` : count;

  return (
    <span
      className={`
        inline-flex items-center justify-center
        min-w-[20px] h-5 px-1.5
        bg-red-500 text-white
        text-[11px] font-bold
        rounded-full
        animate-bounce
        ${className}
      `}
      style={{
        animation: count > 0 ? 'bounce 1s ease-in-out 2' : 'none'
      }}
    >
      {displayCount}
    </span>
  );
};

/**
 * Progress bar animée avec Framer Motion
 */
interface AnimatedProgressProps {
  value: number;
  max?: number;
  color?: 'brand' | 'success' | 'warning' | 'danger';
  size?: 'sm' | 'md' | 'lg';
  showLabel?: boolean;
  /** Show pulse glow effect */
  showGlow?: boolean;
  /** Indeterminate mode (loading animation) */
  indeterminate?: boolean;
}

export const AnimatedProgress: React.FC<AnimatedProgressProps> = ({
  value,
  max = 100,
  color = 'brand',
  size = 'md',
  showLabel = false,
  showGlow = false,
  indeterminate = false
}) => {
  const percentage = Math.min((value / max) * 100, 100);

  const colorClasses = {
    brand: 'bg-brand-500',
    success: 'bg-success-500',
    warning: 'bg-warning-500',
    danger: 'bg-error-500'
  };

  const glowClasses = {
    brand: 'shadow-brand-500/250',
    success: 'shadow-success-500/50',
    warning: 'shadow-warning-500/50',
    danger: 'shadow-error-500/50'
  };

  const sizeClasses = {
    sm: 'h-1',
    md: 'h-2',
    lg: 'h-3'
  };

  return (
    <div className="w-full">
      {showLabel && (
        <motion.div
          className="flex justify-between items-center mb-2"
          initial={{ opacity: 0, y: -10 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ ease: appleEasing }}
        >
          <span className="text-sm font-medium text-slate-700 dark:text-slate-300 dark:text-muted-foreground">
            Progression
          </span>
          <motion.span
            className="text-sm font-bold text-slate-900 dark:text-white tabular-nums"
            key={Math.round(percentage)}
            initial={{ scale: 1.2, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            transition={{ type: 'spring', stiffness: 300 }}
          >
            {Math.round(percentage)}%
          </motion.span>
        </motion.div>
      )}
      <div className={`w-full bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden ${sizeClasses[size]}`}>
        {indeterminate ? (
          <motion.div
            className={`${colorClasses[color]} ${sizeClasses[size]} rounded-full w-1/3`}
            animate={{ x: ['0%', '200%', '0%'] }}
            transition={{ duration: 1.5, repeat: Infinity, ease: 'easeInOut' }}
          />
        ) : (
          <motion.div
            className={`${colorClasses[color]} ${sizeClasses[size]} rounded-full ${showGlow ? `shadow-lg ${glowClasses[color]}` : ''}`}
            initial={{ width: 0 }}
            animate={{ width: `${percentage}%` }}
            transition={{ duration: 0.8, ease: appleEasing }}
          />
        )}
      </div>
    </div>
  );
};

/**
 * Circular progress indicator
 */
interface CircularProgressProps {
  value: number;
  max?: number;
  size?: number;
  strokeWidth?: number;
  color?: 'brand' | 'success' | 'warning' | 'danger';
  showValue?: boolean;
}

export const CircularProgress: React.FC<CircularProgressProps> = ({
  value,
  max = 100,
  size = 60,
  strokeWidth = 6,
  color = 'brand',
  showValue = true
}) => {
  const percentage = Math.min((value / max) * 100, 100);
  const radius = (size - strokeWidth) / 2;
  const circumference = 2 * Math.PI * radius;
  const strokeDashoffset = circumference - (percentage / 100) * circumference;

  const colorClasses = {
    brand: 'stroke-brand-500',
    success: 'stroke-success-500',
    warning: 'stroke-warning-500',
    danger: 'stroke-error-500'
  };

  const textColorClasses = {
    brand: 'text-brand-600',
    success: 'text-success-600',
    warning: 'text-warning-600',
    danger: 'text-error-600'
  };

  return (
    <div className="relative inline-flex items-center justify-center">
      <svg width={size} height={size} className="transform -rotate-90">
        {/* Background circle */}
        <circle
          cx={size / 2}
          cy={size / 2}
          r={radius}
          fill="none"
          stroke="currentColor"
          strokeWidth={strokeWidth}
          className="text-slate-200 dark:text-slate-700"
        />
        {/* Progress circle */}
        <motion.circle
          cx={size / 2}
          cy={size / 2}
          r={radius}
          fill="none"
          strokeWidth={strokeWidth}
          strokeLinecap="round"
          className={colorClasses[color]}
          initial={{ strokeDashoffset: circumference }}
          animate={{ strokeDashoffset }}
          transition={{ duration: 1, ease: appleEasing }}
          style={{ strokeDasharray: circumference }}
        />
      </svg>
      {showValue && (
        <motion.span
          className={`absolute text-sm font-bold ${textColorClasses[color]}`}
          initial={{ opacity: 0, scale: 0.5 }}
          animate={{ opacity: 1, scale: 1 }}
          transition={{ delay: 0.5, ease: appleEasing }}
        >
          {Math.round(percentage)}%
        </motion.span>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { X, MessageSquare, Bug, Lightbulb, Star, Send } from './Icons';
import { Button } from './button';
import { FormError } from './FormError';
import { useStore } from '../../store';
import { ErrorLogger } from '../../services/errorLogger';
import { useForm, useWatch } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { useFeedbackActions } from '../../hooks/feedback/useFeedbackActions';

interface FeedbackModalProps {
    isOpen: boolean;
    onClose: () => void;
}

type FeedbackType = 'bug' | 'feature' | 'improvement' | 'other';

const feedbackSchema = z.object({
    type: z.enum(['bug', 'feature', 'improvement', 'other']),
    title: z.string().min(3, 'Le titre doit faire au moins 3 caractères').max(200, 'Titre trop long'),
    description: z.string().min(10, 'Description trop courte (min 10 caractères)').max(2000, 'Description trop longue'),
    priority: z.enum(['low', 'medium', 'high'])
});

type FeedbackFormData = z.infer<typeof feedbackSchema>;

export const FeedbackModal: React.FC<FeedbackModalProps> = ({ isOpen, onClose }) => {
    const { user, addToast } = useStore();
    const { addFeedback } = useFeedbackActions();
    const [mounted, setMounted] = useState(false);

    const { register, handleSubmit, reset, control, setValue, formState: { errors, isSubmitting } } = useForm<FeedbackFormData>({
        resolver: zodResolver(feedbackSchema),
        defaultValues: {
            type: 'feature',
            title: '',
            description: '',
            priority: 'medium'
        }
    });

    const [type, priority] = useWatch({
        control,
        name: ['type', 'priority']
    });
    const formValues = { type, priority };

    useEffect(() => {
        setTimeout(() => setMounted(true), 0);
        return () => setMounted(false);
    }, []);

    if (!isOpen || !mounted) return null;

    const onSubmit = async (data: FeedbackFormData) => {
        try {
            await addFeedback({
                ...data,
                userId: user?.uid || 'anonymous',
                userEmail: user?.email || 'anonymous',
                organizationId: user?.organizationId || 'unknown',
                status: 'new',
                userAgent: navigator.userAgent,
                url: window.location.href // Intentional: reading current URL for feedback context
            });

            addToast('Merci ! Votre retour a bien été envoyé.', 'success');
            onClose();
            reset();
        } catch (error) {
            ErrorLogger.error(error, 'FeedbackModal.onSubmit');
            addToast("Une erreur est survenue lors de l'envoi.", 'error');
        }
    };

    const getTypeIcon = (t: FeedbackType) => {
        switch (t) {
            case 'bug': return <Bug className="w-4 h-4" />;
            case 'feature': return <Star className="w-4 h-4" />;
            case 'improvement': return <Lightbulb className="w-4 h-4" />;
            default: return <MessageSquare className="w-4 h-4" />;
        }
    };

    const getTypeLabel = (t: FeedbackType) => {
        switch (t) {
            case 'bug': return 'Signaler un Bug';
            case 'feature': return 'Nouvelle Fonctionnalité';
            case 'improvement': return 'Amélioration';
            default: return 'Autre';
        }
    };

    const modalContent = (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fade-in">
            <div className="bg-white dark:bg-slate-900 rounded-3xl w-full max-w-lg flex flex-col max-h-[90vh] shadow-2xl shadow-black/20 dark:shadow-black/50 animate-scale-in border border-slate-200/80 dark:border-slate-700/50">
                {/* Header - Solid background for clarity */}
                <div className="p-6 border-b border-slate-200 dark:border-slate-700/50 flex items-center justify-between shrink-0 bg-slate-50/80 dark:bg-slate-800/50 rounded-t-3xl">
                    <h2 className="text-xl font-bold text-slate-900 dark:text-white flex items-center gap-3">
                        <div className="w-10 h-10 rounded-xl bg-blue-100 dark:bg-blue-900/30 dark:bg-blue-900/50 flex items-center justify-center">
                            <MessageSquare className="w-5 h-5 text-blue-600 dark:text-blue-400" />
                        </div>
                        Votre Avis Compte
                    </h2>
                    <Button variant="ghost" size="icon" aria-label="Fermer la fenêtre" onClick={onClose} className="text-slate-500 hover:text-slate-700 dark:text-slate-300 dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors rounded-xl">
                        <X className="w-5 h-5" />
                    </Button>
                </div>

                <form id="feedback-form" onSubmit={handleSubmit(onSubmit)} className="p-6 overflow-y-auto custom-scrollbar space-y-6 bg-white dark:bg-slate-900">
                    {/* Type Selection */}
                    <div className="grid grid-cols-2 gap-3">
                        {(['feature', 'bug', 'improvement', 'other'] as FeedbackType[]).map((t) => (
                            <button
                                key={t}
                                type="button"
                                aria-label={`Type de retour : ${getTypeLabel(t)}`}
                                aria-pressed={formValues.type === t}
                                onClick={() => setValue('type', t)}
                                className={`flex items-center gap-2 p-3 rounded-xl border text-sm font-semibold transition-all ${formValues.type === t
                                    ? 'bg-blue-50 dark:bg-blue-900/40 border-blue-500 text-blue-700 dark:text-blue-300 ring-2 ring-blue-500/30 shadow-sm'
                                    : 'bg-slate-50 dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700 hover:border-slate-300 dark:hover:border-slate-600'
                                    }`}
                            >
                                {getTypeIcon(t)}
                                {getTypeLabel(t)}
                            </button>
                        ))}
                    </div>
                    <FormError message={errors.type?.message} />

                    {/* Priority (only for bugs/features) */}
                    {(formValues.type === 'bug' || formValues.type === 'feature') && (
                        <div className="animate-fade-in">
                            <label className="block text-sm font-semibold text-slate-900 dark:text-white mb-2">
                                Priorité / Importance
                            </label>
                            <div className="flex gap-1 p-1 bg-slate-100 dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 w-fit">
                                {(['low', 'medium', 'high'] as const).map((p) => (
                                    <label key={p} className={`flex items-center gap-2 cursor-pointer px-4 py-2 rounded-lg transition-all ${formValues.priority === p ? 'bg-brand-500 text-white shadow-md' : 'text-slate-600 dark:text-slate-300 hover:bg-slate-200 dark:hover:bg-slate-700'}`}>
                                        <input {...register('priority')}
                                            checked={formValues.priority === p}
                                            type="radio"
                                            value={p}
                                            className="hidden"
                                        />
                                        <span className={`text-sm capitalize font-semibold ${formValues.priority === p ? 'text-white' : ''}`}>
                                            {p === 'low' ? 'Faible' : p === 'medium' ? 'Moyenne' : 'Haute'}
                                        </span>
                                    </label>
                                ))}
                            </div>
                            <FormError message={errors.priority?.message} />
                        </div>
                    )}

                    {/* Title */}
                    <div>
                        <label className="block text-sm font-semibold text-slate-900 dark:text-white mb-2">
                            Sujet
                        </label>
                        <input {...register('title')}
                            type="text"
                            placeholder="Ex: Ajout d'un filtre par date..."
                            className="w-full px-4 py-3 bg-white dark:bg-slate-800 border border-slate-300 dark:border-slate-600 rounded-xl text-slate-900 dark:text-white placeholder:text-slate-400 dark:placeholder:text-slate-500 focus:ring-2 focus:ring-brand-300 focus:border-brand-500 outline-none transition-all"
                        />
                        <FormError message={errors.title?.message} />
                    </div>

                    {/* Description */}
                    <div>
                        <label className="block text-sm font-semibold text-slate-900 dark:text-white mb-2">
                            Description détaillée
                        </label>
                        <textarea {...register('description')}
                            placeholder="Dites-nous en plus..."
                            rows={5}
                            className="w-full px-4 py-3 bg-white dark:bg-slate-800 border border-slate-300 dark:border-slate-600 rounded-xl text-slate-900 dark:text-white placeholder:text-slate-400 dark:placeholder:text-slate-500 focus:ring-2 focus:ring-brand-300 focus:border-brand-500 outline-none transition-all resize-none"
                        />
                        <FormError message={errors.description?.message} />
                    </div>
                </form>

                {/* Footer - Solid background */}
                <div className="p-6 border-t border-slate-200 dark:border-slate-700/50 bg-slate-50/80 dark:bg-slate-800/50 flex justify-end gap-3 shrink-0 rounded-b-3xl">
                    <Button
                        type="button"
                        variant="ghost"
                        aria-label="Annuler le retour"
                        onClick={onClose}
                        className="px-5 py-2.5 text-slate-700 dark:text-slate-300 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-xl transition-colors font-semibold"
                    >
                        Annuler
                    </Button>
                    <Button
                        type="submit"
                        form="feedback-form"
                        aria-label="Envoyer le retour"
                        disabled={isSubmitting}
                        isLoading={isSubmitting}
                        className="px-6 py-2.5 bg-brand-600 hover:bg-brand-700 text-white rounded-xl shadow-lg shadow-brand-500/25 hover:shadow-xl hover:shadow-brand-500/30 transition-all flex items-center gap-2 font-bold"
                    >
                        <Send className="w-4 h-4" />
                        Envoyer
                    </Button>
                </div>
            </div>
        </div>
    );

    return createPortal(modalContent, document.body);
};

