  );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Search, Command, Clock, TrendingUp, FileText, Users, Shield, Database } from './Icons';
import { cn } from '../../lib/utils';
import { useNavigate } from 'react-router-dom';
import { useDebounce } from '../../hooks/utils/useDebounce';

interface SearchResult {
  id: string;
  title: string;
  type: 'page' | 'project' | 'risk' | 'asset' | 'user' | 'document';
  url: string;
  description?: string;
  icon: React.ReactNode;
  category?: string;
}

const mockResults: SearchResult[] = [
  { id: '1', title: 'Tableau de Bord', type: 'page', url: '/', icon: <TrendingUp className="w-4 h-4" />, category: 'Navigation' },
  { id: '2', title: 'Projets', type: 'page', url: '/projects', icon: <FileText className="w-4 h-4" />, category: 'Navigation' },
  { id: '3', title: 'Risques', type: 'page', url: '/risks', icon: <Shield className="w-4 h-4" />, category: 'Navigation' },
  { id: '4', title: 'Actifs', type: 'page', url: '/assets', icon: <Database className="w-4 h-4" />, category: 'Navigation' },
  { id: '5', title: 'Équipe', type: 'page', url: '/team', icon: <Users className="w-4 h-4" />, category: 'Navigation' },
];

export const UniversalSearch: React.FC<{ className?: string }> = ({ className = '' }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [query, setQuery] = useState('');
  const [selectedIndex, setSelectedIndex] = useState(0);
  const navigate = useNavigate();
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        setIsOpen(true);
        inputRef.current?.focus();
      }
      if (e.key === 'Escape') {
        setIsOpen(false);
      }
    };

    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, []);

  const debouncedQuery = useDebounce(query, 300);

  const filteredResults = useMemo(() => {
    if (debouncedQuery.length > 0) {
      return mockResults.filter(result =>
        result.title.toLowerCase().includes(debouncedQuery.toLowerCase()) ||
        result.category?.toLowerCase().includes(debouncedQuery.toLowerCase())
      );
    } else {
      return mockResults.slice(0, 5);
    }
  }, [debouncedQuery]);

  // Track previous results to reset index when they change
  const [prevFilteredResults, setPrevFilteredResults] = useState(filteredResults);
  if (filteredResults !== prevFilteredResults) {
    setPrevFilteredResults(filteredResults);
    setSelectedIndex(0);
  }

  // Note: useEffect removed as state update happens during render

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setSelectedIndex(prev => (prev + 1) % filteredResults.length);
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setSelectedIndex(prev => (prev - 1 + filteredResults.length) % filteredResults.length);
    } else if (e.key === 'Enter') {
      e.preventDefault();
      if (filteredResults[selectedIndex]) {
        navigate(filteredResults[selectedIndex].url);
        setIsOpen(false);
        setQuery('');
      }
    }
  };

  const getTypeColor = (type: SearchResult['type']) => {
    switch (type) {
      case 'page': return 'text-brand-500';
      case 'project': return 'text-success-500';
      case 'risk': return 'text-error-500';
      case 'asset': return 'text-violet-500';
      case 'user': return 'text-warning-500';
      case 'document': return 'text-info-500';
      default: return 'text-slate-500';
    }
  };

  return (
    <div className={cn("relative", className)}>
      <div className="relative">
        <motion.button
          onClick={() => setIsOpen(true)}
          className="flex items-center gap-2 px-3 py-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors w-64"
          whileHover={{ scale: 1.02 }}
          whileTap={{ scale: 0.98 }}
        >
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-muted-foreground" />
          <span className="text-sm text-slate-500 dark:text-muted-foreground">Rechercher...</span>
          <kbd className="ml-auto hidden sm:flex items-center gap-1 px-2 py-1 bg-slate-100 dark:bg-slate-700 rounded text-xs text-slate-600 dark:text-muted-foreground">
            <Command className="w-3 h-3" />
            K
          </kbd>
        </motion.button>
      </div>

      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: -10, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: -10, scale: 0.95 }}
            transition={{ duration: 0.2 }}
            className="absolute top-full left-0 right-0 mt-2 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl shadow-2xl shadow-slate-200/25 dark:shadow-slate-900/25 z-50 overflow-hidden"
          >
            <div className="p-4">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-muted-foreground" />
                <input
                  ref={inputRef}
                  type="text"
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  onKeyDown={handleKeyDown}
                  placeholder="Rechercher des pages, projets, risques..."
                  className="w-full pl-10 pr-4 py-2 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg focus:outline-none focus:ring-2 focus-visible:ring-brand-500 focus:border-transparent"
                  autoFocus
                />
              </div>

              <div className="mt-4 space-y-1 max-h-96 overflow-y-auto">
                {filteredResults.length > 0 ? (
                  filteredResults.map((result, index) => (
                    <motion.button
                      key={result.id}
                      initial={{ opacity: 0, x: -10 }}
                      animate={{ opacity: 1, x: 0 }}
                      transition={{ delay: index * 0.05 }}
                      onClick={() => {
                        navigate(result.url);
                        setIsOpen(false);
                        setQuery('');
                      }}
                      className={cn(
                        "w-full flex items-center gap-3 px-3 py-2 rounded-lg hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors text-left",
                        index === selectedIndex && "bg-slate-50 dark:bg-slate-800"
                      )}
                    >
                      <div className={cn("flex items-center justify-center w-8 h-8 rounded-lg", getTypeColor(result.type))}>
                        {result.icon}
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="font-medium text-slate-900 dark:text-white truncate">
                          {result.title}
                        </div>
                        {result.category && (
                          <div className="text-xs text-slate-500 dark:text-muted-foreground">
                            {result.category}
                          </div>
                        )}
                      </div>
                    </motion.button>
                  ))
                ) : (
                  <div className="text-center py-8 text-slate-500 dark:text-muted-foreground">
                    Aucun résultat trouvé pour "{query}"
                  </div>
                )}
              </div>

              <div className="mt-4 pt-4 border-t border-slate-200 dark:border-slate-700 flex items-center gap-2 text-xs text-slate-500 dark:text-muted-foreground">
                <Clock className="w-3 h-3" />
                <span>Utilisez ↑↓ pour naviguer, Entrée pour sélectionner</span>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

/**
 * Unit tests for RowActionsMenu component (Story 1.6)
 *
 * Tests menu rendering, keyboard navigation, and action callbacks.
 */

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { render, screen, fireEvent, waitFor } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { RowActionsMenu, RowActionItem } from '../RowActionsMenu';
import { Edit, Copy, Trash2 } from '../Icons';

// Mock Headless UI to eliminate async transition state updates and "ot" warnings
vi.mock('@headlessui/react', async (importOriginal) => {
  const actual = await importOriginal<typeof import('@headlessui/react')>();
  return {
    ...actual,
    Transition: ({ children }: { children: React.ReactNode }) => <>{children}</>,
  };
});

describe('RowActionsMenu', () => {
  const mockOnEdit = vi.fn();
  const mockOnDuplicate = vi.fn();
  const mockOnDelete = vi.fn();

  const defaultItems: RowActionItem[] = [
    { label: 'Modifier', icon: Edit, onClick: mockOnEdit },
    { label: 'Dupliquer', icon: Copy, onClick: mockOnDuplicate },
    { label: 'Supprimer', icon: Trash2, onClick: mockOnDelete, variant: 'danger' },
  ];

  beforeEach(() => {
    vi.clearAllMocks();
    // Suppress specific Headless UI warnings
    const originalError = console.error;
    vi.spyOn(console, 'error').mockImplementation((...args) => {
      const msg = args.join(' ');
      if (typeof msg === 'string' && msg.includes('An update to')) return;
      originalError(...args);
    });
  });

  afterEach(() => {
    vi.clearAllMocks();
  });

  describe('rendering', () => {
    it('renders menu trigger button', () => {
      render(<RowActionsMenu items={defaultItems} />);

      expect(screen.getByRole('button', { name: 'Actions' })).toBeInTheDocument();
    });

    it('renders with custom aria-label', () => {
      render(<RowActionsMenu items={defaultItems} aria-label="Actions pour le risque" />);

      expect(screen.getByRole('button', { name: 'Actions pour le risque' })).toBeInTheDocument();
    });

    it('returns null when items array is empty', () => {
      const { container } = render(<RowActionsMenu items={[]} />);

      expect(container.firstChild).toBeNull();
    });

    it('renders all menu items when opened', async () => {
      render(<RowActionsMenu items={defaultItems} />);

      const trigger = screen.getByRole('button', { name: 'Actions' });
      await userEvent.click(trigger);

      await waitFor(() => {
        expect(screen.getByText('Modifier')).toBeInTheDocument();
        expect(screen.getByText('Dupliquer')).toBeInTheDocument();
        expect(screen.getByText('Supprimer')).toBeInTheDocument();
      });
    });

    it('applies glass-premium styling to dropdown', async () => {
      render(<RowActionsMenu items={defaultItems} />);

      const trigger = screen.getByRole('button', { name: 'Actions' });
      await userEvent.click(trigger);

      await waitFor(() => {
        const menuItems = screen.getByRole('menu');
        expect(menuItems).toHaveClass('rounded-xl');
        expect(menuItems).toHaveClass('shadow-lg');
      });
    });
  });

  describe('variant styling', () => {
    it('applies danger styling to delete action', async () => {
      render(<RowActionsMenu items={defaultItems} />);

      const trigger = screen.getByRole('button', { name: 'Actions' });
      await userEvent.click(trigger);

      await waitFor(() => {
        const deleteButton = screen.getByText('Supprimer').closest('button');
        expect(deleteButton).toHaveClass('text-error-600');
      });
    });

    it('applies default styling to regular actions', async () => {
      render(<RowActionsMenu items={defaultItems} />);

      const trigger = screen.getByRole('button', { name: 'Actions' });
      await userEvent.click(trigger);

      await waitFor(() => {
        const editButton = screen.getByText('Modifier').closest('button');
        expect(editButton).toHaveClass('text-slate-700');
      });
    });
  });

  describe('disabled state', () => {
    it('disables item when disabled prop is true', async () => {
      const itemsWithDisabled: RowActionItem[] = [
        { label: 'Modifier', icon: Edit, onClick: mockOnEdit },
        { label: 'Dupliquer', icon: Copy, onClick: mockOnDuplicate, disabled: true },
      ];

      render(<RowActionsMenu items={itemsWithDisabled} />);

      const trigger = screen.getByRole('button', { name: 'Actions' });
      await userEvent.click(trigger);

      await waitFor(() => {
        const duplicateButton = screen.getByText('Dupliquer').closest('button');
        expect(duplicateButton).toBeDisabled();
        expect(duplicateButton).toHaveClass('cursor-not-allowed');
      });
    });

    it('does not call onClick when item is disabled', async () => {
      const itemsWithDisabled: RowActionItem[] = [
        { label: 'Dupliquer', icon: Copy, onClick: mockOnDuplicate, disabled: true },
      ];

      render(<RowActionsMenu items={itemsWithDisabled} />);

      const trigger = screen.getByRole('button', { name: 'Actions' });
      await userEvent.click(trigger);

      await waitFor(() => {
        const duplicateButton = screen.getByText('Dupliquer').closest('button');
        fireEvent.click(duplicateButton!);
      });

      expect(mockOnDuplicate).not.toHaveBeenCalled();
    });
  });

  describe('click handlers', () => {
    it('calls onClick when menu item is clicked', async () => {
      render(<RowActionsMenu items={defaultItems} />);

      const trigger = screen.getByRole('button', { name: 'Actions' });
      await userEvent.click(trigger);

      await waitFor(() => {
        fireEvent.click(screen.getByText('Modifier'));
      });

      expect(mockOnEdit).toHaveBeenCalledTimes(1);
    });

    it('calls correct handler for each action', async () => {
      render(<RowActionsMenu items={defaultItems} />);

      const trigger = screen.getByRole('button', { name: 'Actions' });

      // Test Edit
      await userEvent.click(trigger);
      await waitFor(() => {
        fireEvent.click(screen.getByText('Modifier'));
      });
      expect(mockOnEdit).toHaveBeenCalled();

      // Test Duplicate
      await userEvent.click(trigger);
      await waitFor(() => {
        fireEvent.click(screen.getByText('Dupliquer'));
      });
      expect(mockOnDuplicate).toHaveBeenCalled();

      // Test Delete
      await userEvent.click(trigger);
      await waitFor(() => {
        fireEvent.click(screen.getByText('Supprimer'));
      });
      expect(mockOnDelete).toHaveBeenCalled();
    });

    it('stops event propagation on container click', async () => {
      const parentClick = vi.fn();

      render(
        <div onClick={parentClick}>
          <RowActionsMenu items={defaultItems} />
        </div>
      );

      const trigger = screen.getByRole('button', { name: 'Actions' });
      await userEvent.click(trigger);

      // The parent click should not be triggered
      expect(parentClick).not.toHaveBeenCalled();
    });
  });

  describe('keyboard navigation', () => {
    it('opens menu on Enter key', async () => {
      render(<RowActionsMenu items={defaultItems} />);

      const trigger = screen.getByRole('button', { name: 'Actions' });
      trigger.focus();
      await userEvent.keyboard('{Enter}');

      await waitFor(() => {
        expect(screen.getByText('Modifier')).toBeInTheDocument();
      });
    });

    it('opens menu on Space key', async () => {
      render(<RowActionsMenu items={defaultItems} />);

      const trigger = screen.getByRole('button', { name: 'Actions' });
      trigger.focus();
      await userEvent.keyboard(' ');

      await waitFor(() => {
        expect(screen.getByText('Modifier')).toBeInTheDocument();
      }, { timeout: 1000 }); // Headless UI animations might take a moment
    });

    it('closes menu on Escape key', async () => {
      render(<RowActionsMenu items={defaultItems} />);

      const trigger = screen.getByRole('button', { name: 'Actions' });
      await userEvent.click(trigger);

      await waitFor(() => {
        expect(screen.getByText('Modifier')).toBeInTheDocument();
      });

      await userEvent.keyboard('{Escape}');

      await waitFor(() => {
        expect(screen.queryByText('Modifier')).not.toBeInTheDocument();
      });
    });

    it('navigates through items with arrow keys', async () => {
      render(<RowActionsMenu items={defaultItems} />);

      const trigger = screen.getByRole('button', { name: 'Actions' });
      await userEvent.click(trigger);

      await waitFor(() => {
        expect(screen.getByText('Modifier')).toBeInTheDocument();
      });

      // Arrow down should move focus
      await userEvent.keyboard('{ArrowDown}');
      await userEvent.keyboard('{ArrowDown}');

      // The focus should have moved (Headless UI handles this internally)
      // We can verify the menu is still open and items are present
      expect(screen.getByText('Dupliquer')).toBeInTheDocument();
    });
  });

  describe('click outside', () => {
    it('closes menu when clicking outside', async () => {
      render(
        <div>
          <RowActionsMenu items={defaultItems} />
          <button>Outside button</button>
        </div>
      );

      const trigger = screen.getByRole('button', { name: 'Actions' });
      await userEvent.click(trigger);

      await waitFor(() => {
        expect(screen.getByText('Modifier')).toBeInTheDocument();
      });

      // Click outside the menu
      await userEvent.click(screen.getByText('Outside button'));

      await waitFor(() => {
        expect(screen.queryByText('Modifier')).not.toBeInTheDocument();
      });
    });
  });

  describe('accessibility', () => {
    it('has aria-haspopup attribute on trigger', () => {
      render(<RowActionsMenu items={defaultItems} />);

      const trigger = screen.getByRole('button', { name: 'Actions' });
      expect(trigger).toHaveAttribute('aria-haspopup', 'menu');
    });

    it('menu has role="menu"', async () => {
      render(<RowActionsMenu items={defaultItems} />);

      const trigger = screen.getByRole('button', { name: 'Actions' });
      await userEvent.click(trigger);

      await waitFor(() => {
        expect(screen.getByRole('menu')).toBeInTheDocument();
      });
    });

    it('menu items have role="menuitem"', async () => {
      render(<RowActionsMenu items={defaultItems} />);

      const trigger = screen.getByRole('button', { name: 'Actions' });
      await userEvent.click(trigger);

      await waitFor(() => {
        const menuItems = screen.getAllByRole('menuitem');
        expect(menuItems).toHaveLength(3);
      });
    });
  });
});

