import * as React from "react"
import { ChevronDown } from './Icons'
import { cn } from "@/lib/utils"

// Simplified Context-based Select to mock the Radix API structure
const SelectContext = React.createContext<{
    value?: string
    onValueChange?: (value: string) => void
    open?: boolean
    setOpen?: (open: boolean) => void
} | null>(null)

interface SelectProps {
    children?: React.ReactNode
    value?: string
    onValueChange?: (value: string) => void
    defaultValue?: string
    open?: boolean
    onOpenChange?: (open: boolean) => void
}

const Select: React.FC<SelectProps> = ({ children, value, onValueChange, defaultValue, open, onOpenChange }) => {
    const [internalValue, setInternalValue] = React.useState(defaultValue || "")
    const [internalOpen, setInternalOpen] = React.useState(false)

    const isControlled = value !== undefined
    const currentValue = isControlled ? value : internalValue
    const currentOpen = open !== undefined ? open : internalOpen

    const handleValueChange = (v: string) => {
        if (!isControlled) setInternalValue(v)
        onValueChange?.(v)
    }

    const handleOpenChange = (o: boolean) => {
        if (onOpenChange === undefined) setInternalOpen(o)
        onOpenChange?.(o)
    }

    return (
        <SelectContext.Provider value={{ value: currentValue, onValueChange: handleValueChange, open: currentOpen, setOpen: handleOpenChange }}>
            <div className="relative inline-block w-full text-left">
                {children}
            </div>
        </SelectContext.Provider>
    )
}

const SelectTrigger = React.forwardRef<
    HTMLButtonElement,
    React.ButtonHTMLAttributes<HTMLButtonElement>
>(({ className, children, ...props }, ref) => {
    const { open, setOpen } = React.useContext(SelectContext)!
    return (
        <button
            onClick={() => setOpen?.(!open)}
            ref={ref}
            className={cn(
                "flex h-10 w-full items-center justify-between rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background placeholder:text-muted-foreground focus:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:bg-slate-200 disabled:text-slate-500 dark:disabled:bg-slate-700 dark:disabled:text-slate-400",
                className
            )}
            {...props}
        >
            {children}
            <ChevronDown className="h-4 w-4 opacity-60" />
        </button>
    )
})
SelectTrigger.displayName = "SelectTrigger"

const SelectValue = React.forwardRef<
    HTMLSpanElement,
    React.HTMLAttributes<HTMLSpanElement> & { placeholder?: string }
>(({ className, placeholder, ...props }, ref) => {
    const { value } = React.useContext(SelectContext)!
    return (
        <span ref={ref} className={cn("block truncate", className)} {...props}>
            {value || placeholder}
        </span>
    )
})
SelectValue.displayName = "SelectValue"

const SelectContent = React.forwardRef<
    HTMLDivElement,
    React.HTMLAttributes<HTMLDivElement> & { position?: "popper" | "item-aligned" }
>(({ className, children, position = "popper", ...props }, ref) => {
    const { open } = React.useContext(SelectContext)!
    if (!open) return null
    return (
        <div
            ref={ref}
            className={cn(
                "absolute z-50 min-w-[8rem] overflow-hidden rounded-md border bg-popover text-popover-foreground shadow-md animate-in fade-in-0 zoom-in-95",
                position === "popper" && "translate-y-1",
                className
            )}
            style={{ top: "100%", left: 0, width: "100%" }}
            {...props}
        >
            <div className="p-1">{children}</div>
        </div>
    )
})
SelectContent.displayName = "SelectContent"

const SelectItem = React.forwardRef<
    HTMLDivElement,
    React.HTMLAttributes<HTMLDivElement> & { value: string }
>(({ className, children, value, onClick, ...props }, ref) => {
    const { onValueChange, setOpen } = React.useContext(SelectContext)!
    return (
        <div
            ref={ref}
            className={cn(
                "relative flex w-full cursor-default select-none items-center rounded-sm py-1.5 pl-8 pr-2 text-sm outline-none focus:bg-accent focus:text-accent-foreground data-[disabled]:pointer-events-none data-[disabled]:opacity-60 hover:bg-accent hover:text-accent-foreground cursor-pointer",
                className
            )}
            onClick={(e) => {
                onValueChange?.(value)
                setOpen?.(false)
                onClick?.(e)
            }}
            {...props}
