  AlertThreshold,
  AlertChannelConfig,
  VoxelAnomalyType,
  VoxelAnomalySeverity,
} from '../../types/voxel';
import { DEFAULT_ALERT_CONFIG } from '../../types/voxel';

// ============================================================================
// Constants
// ============================================================================

const ANOMALY_TYPE_INFO: Record<
  VoxelAnomalyType,
  { label: string; description: string }
> = {
  orphan_control: {
    label: 'Controle orphelin',
    description: 'Controles non lies a des risques',
