    description: 'Evolution negative detectee',
  },
};

const SEVERITY_LEVELS: VoxelAnomalySeverity[] = ['critical', 'high', 'medium', 'low'];

const SEVERITY_COLORS: Record<VoxelAnomalySeverity, string> = {
  critical: 'text-error',
  high: 'text-warning',
  medium: 'text-yellow-500',
  low: 'text-info',
};

const SEVERITY_BG: Record<VoxelAnomalySeverity, string> = {
  critical: 'bg-error',
  high: 'bg-warning',
  medium: 'bg-yellow-500',
  low: 'bg-info',
};

// ============================================================================
// Component Props
// ============================================================================

interface AlertConfigModalProps {
  isOpen: boolean;
  onClose: () => void;
  config: VoxelAlertConfig | null;
  onSave: (config: Partial<VoxelAlertConfig>) => Promise<void>;
  isLoading?: boolean;
}

// ============================================================================
// ThresholdRow Component
// ============================================================================

interface ThresholdRowProps {
  threshold: AlertThreshold;
  onChange: (updated: AlertThreshold) => void;
}

const ThresholdRow: React.FC<ThresholdRowProps> = ({ threshold, onChange }) => {
  const info = ANOMALY_TYPE_INFO[threshold.anomalyType];

  const handleToggle = () => {
    onChange({ ...threshold, enabled: !threshold.enabled });
  };

  const handleSeverityChange = (severity: VoxelAnomalySeverity) => {
    onChange({ ...threshold, minSeverity: severity });
  };

  return (
    <div
      className={`
        p-4 rounded-xl border transition-all
        ${threshold.enabled
          ? 'bg-white/5 border-white/10'
          : 'bg-white/[0.02] border-white/5 opacity-60'}
      `}
    >
      <div className="flex items-start gap-4">
        {/* Toggle */}
        <button
          onClick={handleToggle}
          className={`
            mt-0.5 w-10 h-6 rounded-full relative transition-colors
            ${threshold.enabled ? 'bg-brand-500' : 'bg-white/10'}
          `}
        >
          <span
            className={`
              absolute top-1 w-4 h-4 rounded-full bg-white shadow transition-transform
              ${threshold.enabled ? 'left-5' : 'left-1'}
            `}
          />
        </button>

        {/* Info */}
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2">
            <span className="text-sm font-medium text-white">
              {info?.label || threshold.anomalyType}
            </span>
          </div>
          <p className="text-xs text-white/50 mt-0.5">
            {info?.description || 'Aucune description'}
          </p>

          {/* Severity Selector */}
          {threshold.enabled && (
            <div className="mt-3">
              <span className="text-[11px] text-white/40 uppercase tracking-wider">
                Severite minimum
              </span>
              <div className="flex gap-1 mt-1.5">
                {SEVERITY_LEVELS.map((severity) => {
                  const isSelected = threshold.minSeverity === severity;
                  const isAtOrAbove =
                    SEVERITY_LEVELS.indexOf(severity) <=
                    SEVERITY_LEVELS.indexOf(threshold.minSeverity);

                  return (
                    <button
                      key={severity}
                      onClick={() => handleSeverityChange(severity)}
                      className={`
                        px-2.5 py-1 rounded text-[11px] font-medium uppercase transition-all
                        ${isSelected ? `${SEVERITY_BG[severity]} text-white` : ''}
                        ${isAtOrAbove && !isSelected ? `${SEVERITY_COLORS[severity]} bg-white/5` : ''}
                        ${!isAtOrAbove ? 'text-white/20 bg-white/[0.02]' : ''}
                      `}
                    >
                      {severity}
                    </button>
                  );
                })}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

// ============================================================================
// Main AlertConfigModal Component
// ============================================================================

export const AlertConfigModal: React.FC<AlertConfigModalProps> = ({
  isOpen,
  onClose,
  config,
  onSave,
  isLoading = false,
}) => {
  // Local state for editing
  const [thresholds, setThresholds] = useState<AlertThreshold[]>([]);
  const [channels, setChannels] = useState<AlertChannelConfig>({
    inApp: true,
    email: false,
  });
  const [maxAlertsPerHour, setMaxAlertsPerHour] = useState(10);
  const [cooldownMinutes, setCooldownMinutes] = useState(30);
  const [isSaving, setIsSaving] = useState(false);
  const [hasChanges, setHasChanges] = useState(false);

  // Accessibility: Handle keyboard escape to close modal
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape' && isOpen) {
        onClose();
      }
    };
    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [isOpen, onClose]);

  // Initialize from config
  useEffect(() => {
    if (config) {
      setThresholds(config.thresholds);
      setChannels(config.channels);
      setMaxAlertsPerHour(config.maxAlertsPerHour);
      setCooldownMinutes(config.cooldownMinutes);
    } else {
      setThresholds(DEFAULT_ALERT_CONFIG.thresholds);
      setChannels(DEFAULT_ALERT_CONFIG.channels);
      setMaxAlertsPerHour(DEFAULT_ALERT_CONFIG.maxAlertsPerHour);
      setCooldownMinutes(DEFAULT_ALERT_CONFIG.cooldownMinutes);
    }
    setHasChanges(false);
  }, [config, isOpen]);

  // Track changes
  const markChanged = useCallback(() => setHasChanges(true), []);

  const handleThresholdChange = (index: number, updated: AlertThreshold) => {
    setThresholds((prev) => {
      const next = [...prev];
      next[index] = updated;
      return next;
    });
    markChanged();
  };

  const handleChannelToggle = (channel: keyof AlertChannelConfig) => {
    setChannels((prev) => ({
      ...prev,
      [channel]: !prev[channel],
    }));
    markChanged();
  };

  const handleReset = () => {
    setThresholds(DEFAULT_ALERT_CONFIG.thresholds);
    setChannels(DEFAULT_ALERT_CONFIG.channels);
    setMaxAlertsPerHour(DEFAULT_ALERT_CONFIG.maxAlertsPerHour);
    setCooldownMinutes(DEFAULT_ALERT_CONFIG.cooldownMinutes);
    markChanged();
  };

  const handleSave = async () => {
    setIsSaving(true);
    try {
      await onSave({
        thresholds,
        channels,
        maxAlertsPerHour,
        cooldownMinutes,
      });
      setHasChanges(false);
      onClose();
    } catch (error) {
      ErrorLogger.error(error, 'AlertConfigModal.handleSave');
    } finally {
      setIsSaving(false);
    }
  };

  if (!isOpen) return null;

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          {/* Backdrop */}
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50"
          />

          {/* Modal */}
          <motion.div
            role="dialog"
            aria-modal="true"
            aria-labelledby="alert-config-title"
            initial={{ opacity: 0, scale: 0.95, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: 20 }}
            className="fixed inset-4 md:inset-auto md:left-1/2 md:top-1/2 md:-translate-x-1/2 md:-translate-y-1/2 md:w-[600px] md:max-h-[80vh] bg-slate-900 rounded-2xl border border-white/10 shadow-2xl z-50 flex flex-col overflow-hidden"
          >
            {/* Header */}
            <div className="p-6 border-b border-white/10 shrink-0">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-brand-500 to-purple-600 flex items-center justify-center shadow-lg shadow-brand-500/20">
                    <Bell className="h-5 w-5 text-white" aria-hidden="true" />
                  </div>
                  <div>
                    <h2 id="alert-config-title" className="text-lg font-bold text-white">
                      Configuration des Alertes
                    </h2>
                    <p className="text-xs text-white/50">
                      Gerez les notifications d'anomalies
                    </p>
                  </div>
                </div>
                <button
                  onClick={onClose}
                  aria-label="Fermer la configuration des alertes"
                  className="p-2 rounded-full hover:bg-white/10 text-white/60 hover:text-white transition-colors"
                >
                  <X className="h-5 w-5" aria-hidden="true" />
                </button>
              </div>
            </div>

            {/* Content */}
            <div className="flex-1 overflow-y-auto p-6 space-y-6">
              {/* Notification Channels */}
              <section>
                <h3 className="text-sm font-semibold text-white mb-3 flex items-center gap-2">
                  <MessageSquare className="h-4 w-4 text-white/50" />
                  Canaux de notification
                </h3>
                <div className="grid grid-cols-2 gap-3">
                  {/* In-App */}
                  <button
                    onClick={() => handleChannelToggle('inApp')}
                    className={`
                      p-4 rounded-xl border transition-all text-left
                      ${channels.inApp
                        ? 'bg-brand-50 border-brand-300'
                        : 'bg-white/[0.02] border-white/5'}
                    `}
                  >
                    <div className="flex items-center gap-3">
                      {channels.inApp ? (
                        <Bell className="h-5 w-5 text-brand-400" />
                      ) : (
                        <BellOff className="h-5 w-5 text-white/30" />
                      )}
                      <div>
                        <span className="text-sm font-medium text-white">
                          In-App
                        </span>
                        <p className="text-[11px] text-white/50">
                          Notifications dans l'application
                        </p>
                      </div>
                    </div>
                  </button>

                  {/* Email */}
                  <button
                    onClick={() => handleChannelToggle('email')}
                    className={`
                      p-4 rounded-xl border transition-all text-left
                      ${channels.email
                        ? 'bg-brand-50 border-brand-300'
                        : 'bg-white/[0.02] border-white/5'}
                    `}
                  >
                    <div className="flex items-center gap-3">
                      <Mail
                        className={`h-5 w-5 ${channels.email ? 'text-brand-400' : 'text-white/30'}`}
                      />
                      <div>
                        <span className="text-sm font-medium text-white">
                          Email
                        </span>
                        <p className="text-[11px] text-white/50">
                          Alertes par courriel
                        </p>
                      </div>
                    </div>
                  </button>
                </div>
              </section>

              {/* Rate Limiting */}
              <section>
                <h3 className="text-sm font-semibold text-white mb-3 flex items-center gap-2">
                  <Shield className="h-4 w-4 text-white/50" />
                  Limitation des alertes
                </h3>
                <div className="grid grid-cols-2 gap-4">
                  <div className="p-4 rounded-xl bg-white/5 border border-white/10">
                    <label className="flex items-center gap-2 text-xs text-white/60 mb-2">
                      <Clock className="h-3 w-3" />
                      Max alertes / heure
                    </label>
                    <input
                      type="number"
                      min={1}
                      max={100}
                      value={maxAlertsPerHour}
                      onChange={(e) => {
                        setMaxAlertsPerHour(parseInt(e.target.value) || 10);
                        markChanged();
                      }}
                      className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-brand-500"
                    />
                  </div>
                  <div className="p-4 rounded-xl bg-white/5 border border-white/10">
                    <label className="flex items-center gap-2 text-xs text-white/60 mb-2">
                      <Clock className="h-3 w-3" />
                      Cooldown (minutes)
                    </label>
                    <input
                      type="number"
                      min={5}
                      max={1440}
                      value={cooldownMinutes}
                      onChange={(e) => {
                        setCooldownMinutes(parseInt(e.target.value) || 30);
                        markChanged();
                      }}
                      className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-brand-500"
                    />
                  </div>
                </div>
              </section>

              {/* Anomaly Type Thresholds */}
              <section>
                <div className="flex items-center justify-between mb-3">
                  <h3 className="text-sm font-semibold text-white flex items-center gap-2">
                    <AlertTriangle className="h-4 w-4 text-white/50" />
                    Types d'anomalies
                  </h3>
                  <button
                    onClick={handleReset}
                    className="flex items-center gap-1 text-[11px] text-white/40 hover:text-white/60 transition-colors"
                  >
                    <RotateCcw className="h-3 w-3" />
                    Reinitialiser
                  </button>
                </div>
                <div className="space-y-3">
                  {thresholds.map((threshold, index) => (
                    <ThresholdRow
                      key={threshold.anomalyType}
                      threshold={threshold}
                      onChange={(updated) => handleThresholdChange(index, updated)}
                    />
                  ))}
                </div>
              </section>
            </div>

            {/* Footer */}
            <div className="p-6 border-t border-white/10 shrink-0">
              <div className="flex items-center justify-between">
                <p className="text-xs text-white/40">
                  {hasChanges ? 'Modifications non sauvegardees' : 'Aucune modification'}
                </p>
                <div className="flex gap-3">
                  <button
                    onClick={onClose}
                    className="px-4 py-2 text-sm text-white/60 hover:text-white transition-colors"
                  >
                    Annuler
                  </button>
                  <button
                    onClick={handleSave}
                    disabled={!hasChanges || isSaving || isLoading}
                    className="flex items-center gap-2 px-4 py-2 bg-brand-500 text-white text-sm font-medium rounded-lg hover:bg-brand-600 transition-colors disabled:bg-slate-200 disabled:text-slate-500 disabled:border-slate-300 disabled:cursor-not-allowed dark:disabled:bg-slate-700 dark:disabled:text-slate-400 dark:disabled:border-slate-600"
                  >
                    <Save className="h-4 w-4" />
                    {isSaving ? 'Sauvegarde...' : 'Sauvegarder'}
                  </button>
                </div>
              </div>
            </div>
          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
};

export default AlertConfigModal;

/**
 * Epic 33: Story 33.2 - Annotation Creation UI
 *
 * A floating panel for creating and editing annotations in the Voxel scene.
 * Features:
 * - Click on 3D space to place annotation
 * - Rich text content editor
 * - Type/color/visibility selectors
 * - Drag to reposition
 * - Keyboard shortcut (A) to start annotation mode
 */

import React, { useState, useCallback, useEffect, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  X,
  StickyNote,
  HelpCircle,
  AlertTriangle,
  Highlighter,
  Globe,
  Lock,
  Users,
  Paperclip,
  Check,
  GripVertical,
} from '../ui/Icons';
import type {
  Position3D,
  AnnotationType,
  AnnotationVisibility,
  CreateAnnotationDTO,
  UpdateAnnotationDTO,
  VoxelAnnotation,
  AnnotationAuthor,
} from '../../types/voxelAnnotation';
import {
  ANNOTATION_TYPE_COLORS,
  ANNOTATION_TYPE_LABELS,
  ANNOTATION_VISIBILITY_LABELS,
} from '../../types/voxelAnnotation';
import { AnnotationService } from '../../services/annotationService';
import { useAuth } from '../../hooks/useAuth';

// ============================================================================
// Types
// ============================================================================

interface AnnotationCreatorProps {
  /** Whether the creator is visible */
  isOpen: boolean;

  /** Callback when creator is closed */
  onClose: () => void;

  /** Organization ID */
  organizationId: string;

  /** Position in 3D space (required for new annotations) */
  position?: Position3D;

  /** Node ID to attach annotation to (optional) */
  nodeId?: string;

  /** Existing annotation for editing */
  editingAnnotation?: VoxelAnnotation;

  /** Callback after successful save */
  onSave?: (annotation: VoxelAnnotation) => void;

  /** Panel offset position (for dragging) */
  initialOffset?: { x: number; y: number };
}

// ============================================================================
// Constants
// ============================================================================

const TYPE_OPTIONS: { value: AnnotationType; icon: React.ReactNode; label: string }[] = [
  { value: 'note', icon: <StickyNote className="w-4 h-4" />, label: ANNOTATION_TYPE_LABELS.note },
  { value: 'question', icon: <HelpCircle className="w-4 h-4" />, label: ANNOTATION_TYPE_LABELS.question },
  { value: 'issue', icon: <AlertTriangle className="w-4 h-4" />, label: ANNOTATION_TYPE_LABELS.issue },
  { value: 'highlight', icon: <Highlighter className="w-4 h-4" />, label: ANNOTATION_TYPE_LABELS.highlight },
];

const VISIBILITY_OPTIONS: { value: AnnotationVisibility; icon: React.ReactNode; label: string }[] = [
  { value: 'public', icon: <Globe className="w-4 h-4" />, label: ANNOTATION_VISIBILITY_LABELS.public },
  { value: 'private', icon: <Lock className="w-4 h-4" />, label: ANNOTATION_VISIBILITY_LABELS.private },
  { value: 'team', icon: <Users className="w-4 h-4" />, label: ANNOTATION_VISIBILITY_LABELS.team },
];

const COLOR_PRESETS = [
  '#3b82f6', // Blue
  '#8b5cf6', // Purple
  '#ef4444', // Red
  '#f59e0b', // Amber
  '#22c55e', // Green
  '#06b6d4', // Cyan
  '#ec4899', // Pink
  '#6b7280', // Gray
];

// ============================================================================
// Component
// ============================================================================

export const AnnotationCreator: React.FC<AnnotationCreatorProps> = ({
  isOpen,
  onClose,
  organizationId,
  position,
  nodeId,
  editingAnnotation,
  onSave,
  initialOffset = { x: 0, y: 0 },
}) => {
  const { user } = useAuth();

  // Form state
  const [content, setContent] = useState('');
  const [type, setType] = useState<AnnotationType>('note');
  const [color, setColor] = useState(ANNOTATION_TYPE_COLORS.note);
  const [visibility, setVisibility] = useState<AnnotationVisibility>('public');
  const [teamId, setTeamId] = useState<string>('');

  // UI state
  const [isSaving, setIsSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [panelOffset, setPanelOffset] = useState(initialOffset);
  // const [isDragging, setIsDragging] = useState(false);

  // Initialize form with editing annotation data
  useEffect(() => {
    if (editingAnnotation) {
      setContent(editingAnnotation.content);
      setType(editingAnnotation.type);
      setColor(editingAnnotation.color);
      setVisibility(editingAnnotation.visibility);
      setTeamId(editingAnnotation.teamId || '');
    } else {
      // Reset form for new annotation
      setContent('');
      setType('note');
      setColor(ANNOTATION_TYPE_COLORS.note);
      setVisibility('public');
      setTeamId('');
    }
  }, [editingAnnotation, isOpen]);

  // Update color when type changes (only for new annotations)
  useEffect(() => {
    if (!editingAnnotation) {
      setColor(ANNOTATION_TYPE_COLORS[type]);
    }
  }, [type, editingAnnotation]);

  // Create author object from current user
  const author = useMemo<AnnotationAuthor | null>(() => {
    if (!user) return null;
    return {
      id: user.uid,
      displayName: user.displayName || user.email || 'Anonymous',
      email: user.email || undefined,
      avatarUrl: user.photoURL || undefined,
    };
  }, [user]);

  // Handle save
  const handleSave = useCallback(async () => {
    if (!content.trim()) {
      setError('Le contenu est requis');
      return;
    }

    if (!author) {
      setError('Vous devez etre connecte');
      return;
    }

    if (!editingAnnotation && !position) {
      setError('Position requise pour une nouvelle annotation');
      return;
    }

    setIsSaving(true);
    setError(null);

    try {
      let savedAnnotation: VoxelAnnotation | null;

      if (editingAnnotation) {
        // Update existing annotation
        const dto: UpdateAnnotationDTO = {
          content,
          type,
          color,
          visibility,
          teamId: visibility === 'team' ? teamId : undefined,
        };

        savedAnnotation = await AnnotationService.updateAnnotation(
          editingAnnotation.id,
          dto,
          author
        );
      } else {
        // Create new annotation
        const dto: CreateAnnotationDTO = {
          nodeId,
          position: position!,
          content,
          type,
          color,
          visibility,
          teamId: visibility === 'team' ? teamId : undefined,
        };

        savedAnnotation = await AnnotationService.createAnnotation(
          organizationId,
          author,
          dto
        );
      }

      if (savedAnnotation) {
        onSave?.(savedAnnotation);
        onClose();
      } else {
        setError('Erreur lors de la sauvegarde');
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Erreur inconnue');
    } finally {
      setIsSaving(false);
    }
  }, [content, type, color, visibility, teamId, author, editingAnnotation, position, nodeId, organizationId, onSave, onClose]);

  // Handle keyboard shortcut (Escape to close)
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape' && isOpen) {
        onClose();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isOpen, onClose]);

  // Handle drag
  const handleDragStart = useCallback((e: React.MouseEvent) => {
    e.preventDefault();
    // setIsDragging(true);

    const startX = e.clientX - panelOffset.x;
    const startY = e.clientY - panelOffset.y;

    const handleMouseMove = (moveEvent: MouseEvent) => {
      setPanelOffset({
        x: moveEvent.clientX - startX,
        y: moveEvent.clientY - startY,
      });
    };

    const handleMouseUp = () => {
      // setIsDragging(false);
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
  }, [panelOffset]);

  if (!isOpen) return null;

  return (
    <AnimatePresence>
      <motion.div
        initial={{ opacity: 0, scale: 0.9, y: 20 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.9, y: 20 }}
        transition={{ type: 'spring', damping: 25, stiffness: 300 }}
        className="fixed z-50 pointer-events-auto"
        style={{
          left: `calc(50% + ${panelOffset.x}px)`,
          top: `calc(50% + ${panelOffset.y}px)`,
          transform: 'translate(-50%, -50%)',
        }}
      >
        <div className="w-[400px] glass-panel rounded-3xl shadow-apple-xl overflow-hidden">
          {/* Header */}
          <div
            className="flex items-center justify-between px-5 py-4 bg-gradient-to-r from-slate-800/80 to-slate-900/80 cursor-move"
            onMouseDown={handleDragStart}
          >
            <div className="flex items-center gap-3">
              <GripVertical className="w-4 h-4 text-muted-foreground" />
              <h3 className="text-base font-semibold text-white">
                {editingAnnotation ? 'Modifier l\'annotation' : 'Nouvelle annotation'}
              </h3>
            </div>
            <button
              onClick={onClose}
              className="p-2 rounded-xl hover:bg-slate-700/50 transition-colors"
            >
              <X className="w-4 h-4 text-muted-foreground" />
            </button>
          </div>

          {/* Content */}
          <div className="p-5 space-y-5 bg-slate-900/60">
            {/* Position indicator */}
            {position && (
              <div className="flex items-center gap-2 text-xs text-muted-foreground font-mono">
                <span className="px-2 py-1 bg-slate-800/50 rounded">
                  X: {position.x.toFixed(2)}
                </span>
                <span className="px-2 py-1 bg-slate-800/50 rounded">
                  Y: {position.y.toFixed(2)}
                </span>
                <span className="px-2 py-1 bg-slate-800/50 rounded">
                  Z: {position.z.toFixed(2)}
                </span>
              </div>
            )}

            {/* Type selector */}
            <div className="space-y-2">
              <label className="text-sm font-medium text-muted-foreground">Type</label>
              <div className="flex gap-2">
                {TYPE_OPTIONS.map((option) => (
                  <button
                    key={option.value}
                    onClick={() => setType(option.value)}
                    className={`flex-1 flex items-center justify-center gap-2 px-3 py-2.5 rounded-xl transition-all ${type === option.value
                      ? 'bg-brand-100 border-2 border-brand-500 text-brand-400'
                      : 'bg-slate-800/50 border-2 border-transparent text-slate-400 hover:bg-slate-700/50'
                      }`}
                  >
                    {option.icon}
                    <span className="text-xs font-medium">{option.label}</span>
                  </button>
                ))}
              </div>
            </div>

            {/* Content textarea */}
            <div className="space-y-2">
              <label className="text-sm font-medium text-muted-foreground">Contenu</label>
              <textarea
                value={content}
                onChange={(e) => setContent(e.target.value)}
                placeholder="Écrivez votre annotation... (Utilisez @nom pour mentionner quelqu'un)"
                rows={4}
                className="w-full px-4 py-3 bg-slate-800/50 border border-slate-700 rounded-xl text-white placeholder-slate-500 focus:outline-none focus-visible:ring-2 focus-visible:ring-brand-500 focus:border-transparent resize-none text-sm"
              />
              <p className="text-xs text-slate-500">
                Supporte Markdown. Utilisez @username pour mentionner des collègues.
              </p>
            </div>

            {/* Color picker */}
            <div className="space-y-2">
              <label className="text-sm font-medium text-muted-foreground">Couleur</label>
              <div className="flex gap-2">
                {COLOR_PRESETS.map((presetColor) => (
                  <button
                    key={presetColor}
                    onClick={() => setColor(presetColor)}
                    className={`w-8 h-8 rounded-full transition-transform hover:scale-110 ${color === presetColor ? 'ring-2 ring-white ring-offset-2 ring-offset-slate-900' : ''
                      }`}
                    style={{ backgroundColor: presetColor }}
                  />
                ))}
              </div>
            </div>

            {/* Visibility selector */}
            <div className="space-y-2">
              <label className="text-sm font-medium text-muted-foreground">Visibilite</label>
              <div className="flex gap-2">
                {VISIBILITY_OPTIONS.map((option) => (
                  <button
                    key={option.value}
                    onClick={() => setVisibility(option.value)}
                    className={`flex-1 flex items-center justify-center gap-2 px-3 py-2.5 rounded-xl transition-all ${visibility === option.value
                      ? 'bg-brand-100 border-2 border-brand-500 text-brand-400'
                      : 'bg-slate-800/50 border-2 border-transparent text-slate-400 hover:bg-slate-700/50'
                      }`}
                  >
                    {option.icon}
                    <span className="text-xs font-medium">{option.label}</span>
                  </button>
                ))}
              </div>
            </div>

            {/* Team selector (shown only when visibility is 'team') */}
            {visibility === 'team' && (
              <div className="space-y-2">
                <label className="text-sm font-medium text-muted-foreground">Équipe</label>
                <input
                  type="text"
                  value={teamId}
                  onChange={(e) => setTeamId(e.target.value)}
                  placeholder="ID de l'équipe"
                  className="w-full px-4 py-3 bg-slate-800/50 border border-slate-700 rounded-xl text-white placeholder-slate-500 focus:outline-none focus-visible:ring-2 focus-visible:ring-brand-500 focus:border-transparent text-sm"
                />
              </div>
            )}

            {/* Error message */}
            {error && (
              <div className="px-4 py-3 bg-red-50 dark:bg-red-900/30 border border-red-500/30 rounded-xl text-red-400 text-sm">
                {error}
              </div>
            )}
          </div>

          {/* Footer */}
          <div className="flex items-center justify-between px-5 py-4 bg-slate-800/50 border-t border-slate-700/50">
            <button
              onClick={onClose}
              className="px-4 py-2 text-sm font-medium text-muted-foreground hover:text-white transition-colors"
              disabled={isSaving}
            >
              Annuler
            </button>

            <div className="flex gap-2">
              <button
                disabled
                className="p-2 rounded-xl bg-slate-700/50 text-slate-500 dark:text-slate-300 cursor-not-allowed"
                title="Ajouter une piece jointe (bientot)"
              >
                <Paperclip className="w-4 h-4" />
              </button>

              <button
                onClick={handleSave}
                disabled={isSaving || !content.trim()}
                className={`flex items-center gap-2 px-5 py-2 rounded-xl text-sm font-semibold transition-all ${isSaving || !content.trim()
                  ? 'bg-brand-100 text-brand-400 cursor-not-allowed'
                  : 'bg-brand-500 text-white hover:bg-brand-600 shadow-lg shadow-brand-500/25'
                  }`}
              >
                {isSaving ? (
                  <>
                    <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                    <span>Sauvegarde...</span>
                  </>
                ) : (
                  <>
                    <Check className="w-4 h-4" />
                    <span>{editingAnnotation ? 'Mettre a jour' : 'Creer'}</span>
                  </>
                )}
              </button>
            </div>
          </div>
        </div>
      </motion.div>
    </AnimatePresence>
  );
};

export default AnnotationCreator;

/**
 * Epic 30: Story 30.4, 30.5 & 30.8 - Blast Radius Stats Panel
 *
 * Sidebar panel showing simulation results:
 * - Total affected nodes, max depth, total impact score
 * - List of affected nodes sorted by impact
 * - Breakdown by node type
 * - What-If simulation controls
 * - Export results functionality
 *
 * Enhanced with micro-interactions for "aha moments"
 */

import React, { useState, useMemo } from 'react';
import {
  Activity,
  AlertTriangle,
  Info,
  Target,
  Layers,
  TrendingUp,
  TrendingDown,
  ChevronDown,
  ChevronUp,
  Search,

  X,

  Eye,
  Download,
  FileText,

  GitBranch,
  Shield,
  Server,
  Briefcase,
  Users,
  ClipboardCheck,
  Bell,
  Sliders,
  BarChart3,
  Check,
} from '../ui/Icons';
import { motion, AnimatePresence } from 'framer-motion';
import type { VoxelNode, VoxelNodeType } from '@/types/voxel';
import type {
  AffectedNode,
  WhatIfScenario,
  WhatIfComparison,
  ExtendedBlastRadiusConfig,
} from '@/services/blastRadiusService';
import type { SimulationMode } from '@/hooks/voxel/useBlastRadius';
import { appleEasing } from '@/utils/microInteractions';

// ============================================================================
// Constants
// ============================================================================

const IMPACT_COLORS = {
  critical: { bg: 'bg-red-50', border: 'border-red-500/30', text: 'text-red-500' },
  high: { bg: 'bg-orange-500/10', border: 'border-orange-500/30', text: 'text-orange-500' },
  medium: { bg: 'bg-yellow-50', border: 'border-yellow-500/30', text: 'text-yellow-500' },
  low: { bg: 'bg-green-50', border: 'border-green-500/30', text: 'text-green-500' },
};

const NODE_TYPE_ICONS: Record<VoxelNodeType, React.FC<{ className?: string }>> = {
  asset: Server,
  risk: AlertTriangle,
  control: Shield,
  incident: Bell,
  supplier: Users,
  project: Briefcase,
  audit: ClipboardCheck,
};

const NODE_TYPE_LABELS: Record<VoxelNodeType, string> = {
  asset: 'Actifs',
  risk: 'Risques',
  control: 'Controles',
  incident: 'Incidents',
  supplier: 'Fournisseurs',
  project: 'Projets',
  audit: 'Audits',
};

// ============================================================================
// Types
// ============================================================================

interface BlastRadiusPanelProps {
  isOpen: boolean;
  onClose: () => void;
  // Simulation state
  sourceNodeId: string | null;
  sourceNode: VoxelNode | null;
  mode: SimulationMode;
  isSimulating: boolean;
  // Results
  affectedNodes: AffectedNode[];
  stats: {
    totalAffected: number;
    totalImpact: number;
    maxDepth: number;
    criticalCount: number;
    highCount: number;
    mediumCount: number;
    lowCount: number;
    byType: Record<VoxelNodeType, number>;
  };
  businessImpact: 'low' | 'medium' | 'high' | 'critical';
  // What-If
  whatIfResult: WhatIfComparison | null;
  whatIfScenario: WhatIfScenario | null;
  // Configuration
  config: ExtendedBlastRadiusConfig;
  // Actions
  onStartSimulation: (nodeId: string) => void;
  onStopSimulation: () => void;
  onSetConfig: (config: Partial<ExtendedBlastRadiusConfig>) => void;
  onApplyWhatIf: (scenario: WhatIfScenario) => void;
  onClearWhatIf: () => void;
  onFocusNode: (nodeId: string) => void;
  onClearResults: () => void;
  onSetMode: (mode: SimulationMode) => void;
  onExportPdf?: () => void;
  onExportCsv?: () => void;
}

// ============================================================================
// Sub-Components
// ============================================================================

/**
 * Impact level badge
 */
const ImpactBadge: React.FC<{ impact: number; className?: string }> = ({ impact, className }) => {
  const level = impact >= 0.75 ? 'critical' : impact >= 0.5 ? 'high' : impact >= 0.25 ? 'medium' : 'low';
  const colors = IMPACT_COLORS[level];

  return (
    <span className={`px-2 py-0.5 rounded-full text-[11px] font-medium ${colors.bg} ${colors.text} ${className}`}>
      {Math.round(impact * 100)}%
    </span>
  );
};

/**
 * Stats card component with animations
 */
const StatsCard: React.FC<{
  label: string;
  value: string | number;
  icon: React.FC<{ className?: string }>;
  color?: string;
  delta?: number;
  delay?: number;
}> = ({ label, value, icon: Icon, color = 'text-white', delta, delay = 0 }) => (
  <motion.div
    initial={{ opacity: 0, y: 20, scale: 0.9 }}
    animate={{ opacity: 1, y: 0, scale: 1 }}
    transition={{ delay, duration: 0.4, ease: appleEasing }}
    className="bg-white/5 rounded-xl p-3 border border-white/10"
  >
    <div className="flex items-center gap-2 mb-1">
      <motion.div
        initial={{ scale: 0, rotate: -180 }}
        animate={{ scale: 1, rotate: 0 }}
        transition={{ delay: delay + 0.2, type: 'spring', stiffness: 200 }}
      >
        <Icon className={`h-4 w-4 ${color}`} />
      </motion.div>
      <span className="text-xs text-white/50">{label}</span>
    </div>
    <div className="flex items-baseline gap-2">
      <motion.span
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: delay + 0.3 }}
        className={`text-xl font-bold tabular-nums ${color}`}
      >
        {value}
      </motion.span>
      {delta !== undefined && delta !== 0 && (
        <motion.span
          initial={{ scale: 0, x: -10 }}
          animate={{ scale: 1, x: 0 }}
          transition={{ delay: delay + 0.5, type: 'spring', stiffness: 300 }}
          className={`text-xs flex items-center gap-0.5 ${delta > 0 ? 'text-red-400' : 'text-green-400'}`}
        >
          {delta > 0 ? <TrendingUp className="h-3 w-3" /> : <TrendingDown className="h-3 w-3" />}
          {delta > 0 ? '+' : ''}{delta}
        </motion.span>
      )}
    </div>
  </motion.div>
);

/**
 * Affected node list item
 */
const AffectedNodeItem: React.FC<{
  node: AffectedNode;
  isSelected: boolean;
  onSelect: () => void;
  onFocus: () => void;
}> = ({ node, isSelected, onSelect, onFocus }) => {
  const Icon = NODE_TYPE_ICONS[node.node.type];
  const typeLabel = NODE_TYPE_LABELS[node.node.type];

  return (
    <motion.div
      initial={{ opacity: 0, x: 10 }}
      animate={{ opacity: 1, x: 0 }}
      exit={{ opacity: 0, x: -10 }}
      className={`
        p-3 rounded-xl border cursor-pointer transition-all
        ${isSelected ? 'ring-2 ring-brand-500 bg-brand-50' : 'bg-white/5 hover:bg-white/10'}
        border-white/10 hover:border-white/20
      `}
      onClick={onSelect}
    >
      <div className="flex items-start gap-3">
        <div className="w-8 h-8 rounded-lg bg-white/10 flex items-center justify-center shrink-0">
          <Icon className="h-4 w-4 text-white/70" />
        </div>

        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2">
            <span className="text-sm font-medium text-white truncate">
              {node.node.label || node.nodeId.substring(0, 12)}
            </span>
            <ImpactBadge impact={node.impact} />
          </div>

          <div className="flex items-center gap-2 mt-1">
            <span className="text-[11px] text-white/40">{typeLabel}</span>
            <span className="text-[11px] text-white/30">|</span>
            <span className="text-[11px] text-white/40">Profondeur: {node.depth}</span>
          </div>
        </div>

        <button
          onClick={(e) => {
            e.stopPropagation();
            onFocus();
          }}
          className="p-1.5 rounded-lg hover:bg-white/10 text-white/50 hover:text-white transition-colors"
          title="Voir dans la vue 3D"
        >
          <Eye className="h-4 w-4" />
        </button>
      </div>
    </motion.div>
  );
};

/**
 * What-If scenario builder
 */
const WhatIfBuilder: React.FC<{
  onApply: (scenario: WhatIfScenario) => void;
  nodes: Map<string, VoxelNode>;
}> = ({ onApply, nodes }) => {
  const [scenarioType, setScenarioType] = useState<WhatIfScenario['type']>('remove_node');
  const [selectedNodeId, setSelectedNodeId] = useState('');

  const controlNodes = useMemo(() => {
    return Array.from(nodes.values()).filter((n) => n.type === 'control');
  }, [nodes]);

  const handleApply = () => {
    if (!selectedNodeId) return;

    switch (scenarioType) {
      case 'remove_node':
        onApply({ type: 'remove_node', nodeId: selectedNodeId });
        break;
      // Add more cases as needed
    }
  };

  return (
    <div className="space-y-3 p-3 bg-white/5 rounded-xl border border-white/10">
      <div className="text-xs text-white/70 font-medium">Scenario What-If</div>

      <div className="space-y-2">
        <select
          value={scenarioType}
          onChange={(e) => setScenarioType(e.target.value as WhatIfScenario['type'])}
          className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-brand-500"
        >
          <option value="remove_node">Supprimer un controle</option>
          <option value="add_node">Ajouter un controle</option>
          <option value="modify_weight">Modifier poids connexion</option>
        </select>

        {scenarioType === 'remove_node' && (
          <select
            value={selectedNodeId}
            onChange={(e) => setSelectedNodeId(e.target.value)}
            className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-brand-500"
          >
            <option value="">Sélectionner un contrôle...</option>
            {controlNodes.map((node) => (
              <option key={node.id} value={node.id}>
                {node.label || node.id.substring(0, 20)}
              </option>
            ))}
          </select>
        )}

        <button
          onClick={handleApply}
          disabled={!selectedNodeId}
          className="w-full px-4 py-2 bg-brand-500 hover:bg-brand-600 disabled:bg-white/10 disabled:text-white/30 text-white text-sm font-medium rounded-lg transition-colors"
        >
          Appliquer le scenario
        </button>
      </div>
    </div>
  );
};

