export const VoxelFrameworkOverlay: React.FC<VoxelFrameworkOverlayProps> = ({
  visible = true,
  frameworks = DEFAULT_FRAMEWORKS,
  selectedFrameworkId,
  onFrameworkSelect,
  onFrameworkHover,
  showBreakdown = true,
  className = '',
}) => {
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [isMinimized, setIsMinimized] = useState(false);

  // Calculate overall compliance
  const overallStats = useMemo(() => {
    if (frameworks.length === 0) {
      return { avgScore: 0, totalMapped: 0, totalControls: 0 };
    }
    const totalControls = frameworks.reduce((sum, f) => sum + f.totalControls, 0);
    const totalMapped = frameworks.reduce((sum, f) => sum + f.mappedControls, 0);
    const avgScore = Math.round(
      frameworks.reduce((sum, f) => sum + f.complianceScore, 0) / frameworks.length
    );
    return { avgScore, totalMapped, totalControls };
  }, [frameworks]);

  const handleSelect = useCallback(
    (frameworkId: string) => {
      if (onFrameworkSelect) {
        onFrameworkSelect(selectedFrameworkId === frameworkId ? null : frameworkId);
      }
    },
    [selectedFrameworkId, onFrameworkSelect]
  );

  const handleToggleExpand = useCallback((frameworkId: string) => {
    setExpandedId((prev) => (prev === frameworkId ? null : frameworkId));
  }, []);

  const handleHover = useCallback(
    (frameworkId: string, hovering: boolean) => {
      if (onFrameworkHover) {
        onFrameworkHover(hovering ? frameworkId : null);
      }
    },
    [onFrameworkHover]
  );

  if (!visible) return null;

  return (
    <div className={`fixed top-20 right-4 z-40 ${className}`}>
      <div
        className="rounded-xl overflow-hidden transition-all duration-300"
        style={{
          width: isMinimized ? '56px' : '280px',
          background: 'rgba(15, 23, 42, 0.95)',
          backdropFilter: 'blur(20px)',
          WebkitBackdropFilter: 'blur(20px)',
          border: '1px solid rgba(148, 163, 184, 0.1)',
          boxShadow: '0 8px 32px rgba(0, 0, 0, 0.4)',
        }}
      >
        {/* Header */}
        <div className="p-3 border-b border-slate-700/50">
          <div className="flex items-center justify-between">
            {!isMinimized && (
              <div className="flex items-center gap-2">
                <Layers className="w-4 h-4 text-blue-400" />
                <span className="text-sm font-medium text-white">Frameworks</span>
              </div>
            )}
            <button
              onClick={() => setIsMinimized(!isMinimized)}
              className="p-1.5 hover:bg-slate-700/50 rounded-lg transition-colors"
              aria-label={isMinimized ? 'Expand panel' : 'Minimize panel'}
            >
              <Layers className={`w-4 h-4 text-slate-400 ${isMinimized ? '' : 'hidden'}`} />
              {!isMinimized &&
                (isMinimized ? (
                  <ChevronDown className="w-4 h-4 text-muted-foreground" />
                ) : (
                  <ChevronUp className="w-4 h-4 text-muted-foreground" />
                ))}
            </button>
          </div>

          {!isMinimized && (
            <div className="mt-2 flex items-center justify-between text-xs">
              <span className="text-muted-foreground">Overall Coverage</span>
              <span
                className="font-bold"
                style={{
                  color:
                    overallStats.avgScore >= 80
                      ? '#10B981'
                      : overallStats.avgScore >= 60
                        ? '#F59E0B'
                        : '#EF4444',
                }}
              >
                {overallStats.avgScore}%
              </span>
            </div>
          )}
        </div>

        {/* Framework list */}
        {!isMinimized && (
          <div className="p-2 space-y-2 max-h-[60vh] overflow-y-auto">
            {frameworks.map((framework) => (
              <FrameworkCard
                key={framework.id}
                framework={framework}
                isSelected={selectedFrameworkId === framework.id}
                isExpanded={showBreakdown && expandedId === framework.id}
                onSelect={() => handleSelect(framework.id)}
                onToggleExpand={() => handleToggleExpand(framework.id)}
                onHover={(hovering) => handleHover(framework.id, hovering)}
              />
            ))}

            {frameworks.length === 0 && (
              <div className="p-4 text-center text-slate-500 dark:text-slate-300 text-sm">
                No frameworks configured
              </div>
            )}
          </div>
        )}

        {/* Minimized icons */}
        {isMinimized && (
          <div className="p-2 space-y-2">
            {frameworks.slice(0, 4).map((framework) => (
              <button
                key={framework.id}
                onClick={() => handleSelect(framework.id)}
                className={`w-10 h-10 rounded-lg flex items-center justify-center transition-all ${
                  selectedFrameworkId === framework.id ? 'ring-2' : 'hover:bg-slate-700/50'
                }`}
                style={{
                  background:
                    selectedFrameworkId === framework.id
                      ? `${framework.color}20`
                      : 'transparent',
                  ['--tw-ring-color' as string]: framework.color,
                }}
                title={framework.name}
                aria-label={`Select ${framework.name}`}
              >
                <span
                  className="text-xs font-bold"
                  style={{ color: framework.color }}
                >
                  {framework.code.slice(0, 3)}
                </span>
              </button>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default VoxelFrameworkOverlay;

/**
 * VoxelMinimap - 2D minimap overlay for spatial orientation
 *
 * Displays a simplified 2D view of the 3D scene showing:
 * - Node positions as colored dots
 * - Current camera viewport indicator
 * - Click-to-navigate functionality
 *
 * @see Story VOX-9.5: Minimap Navigation
 * @see FR49: Users can see a minimap for orientation
 */

import React, { useMemo, useCallback, useState, useRef, useEffect } from 'react';
import { X, Map, Maximize2, Minimize2 } from 'lucide-react';
import { useVoxelStore } from '@/stores/voxelStore';
import type { VoxelNode } from '@/types/voxel';

// ============================================================================
// Types
// ============================================================================

export interface VoxelMinimapProps {
  /** Width of the minimap in pixels */
  width?: number;
  /** Height of the minimap in pixels */
  height?: number;
  /** Camera position [x, y, z] for viewport indicator */
  cameraPosition?: [number, number, number];
  /** Camera target/look-at point for viewport direction */
  cameraTarget?: [number, number, number];
  /** Callback when user clicks on minimap to navigate */
  onNavigate?: (position: { x: number; y: number; z: number }) => void;
  /** Whether minimap is visible */
  visible?: boolean;
  /** Callback to toggle visibility */
  onToggle?: () => void;
  /** Custom class name */
  className?: string;
}

interface MinimapNode {
  id: string;
  x: number;
  y: number;
  color: string;
  size: number;
  type: string;
  status: string;
}

// ============================================================================
// Constants
// ============================================================================

const NODE_TYPE_COLORS: Record<string, string> = {
  asset: '#3B82F6',
  risk: '#EF4444',
  control: '#8B5CF6',
  audit: '#F59E0B',
  project: '#10B981',
  incident: '#F97316',
  supplier: '#6366F1',
};

const DEFAULT_WIDTH = 160;
const DEFAULT_HEIGHT = 120;
const PADDING = 10;
const DOT_SIZE_BASE = 3;
const VIEWPORT_COLOR = 'rgba(255, 255, 255, 0.3)';

// ============================================================================
// Helper Functions
// ============================================================================

/**
 * Calculate bounds of all nodes
 */
function calculateBounds(nodes: VoxelNode[]): {
  minX: number;
  maxX: number;
  minZ: number;
  maxZ: number;
  width: number;
  height: number;
} {
  if (nodes.length === 0) {
    return { minX: -100, maxX: 100, minZ: -100, maxZ: 100, width: 200, height: 200 };
  }

  let minX = Infinity,
    maxX = -Infinity;
  let minZ = Infinity,
    maxZ = -Infinity;

  nodes.forEach((node) => {
    minX = Math.min(minX, node.position.x);
    maxX = Math.max(maxX, node.position.x);
    minZ = Math.min(minZ, node.position.z);
    maxZ = Math.max(maxZ, node.position.z);
  });

  // Add padding
  const padding = Math.max(maxX - minX, maxZ - minZ) * 0.1;
  minX -= padding;
  maxX += padding;
  minZ -= padding;
  maxZ += padding;

  return {
    minX,
    maxX,
    minZ,
    maxZ,
    width: maxX - minX,
    height: maxZ - minZ,
  };
}

/**
 * Convert 3D position to 2D minimap coordinates
 */
function worldToMinimap(
  worldX: number,
  worldZ: number,
  bounds: ReturnType<typeof calculateBounds>,
  mapWidth: number,
  mapHeight: number
): { x: number; y: number } {
  const normalizedX = (worldX - bounds.minX) / bounds.width;
  const normalizedZ = (worldZ - bounds.minZ) / bounds.height;

  return {
    x: PADDING + normalizedX * (mapWidth - 2 * PADDING),
    y: PADDING + normalizedZ * (mapHeight - 2 * PADDING),
  };
}

/**
 * Convert minimap click to 3D world position
 */
function minimapToWorld(
  clickX: number,
  clickY: number,
  bounds: ReturnType<typeof calculateBounds>,
  mapWidth: number,
  mapHeight: number
): { x: number; y: number; z: number } {
  const normalizedX = (clickX - PADDING) / (mapWidth - 2 * PADDING);
  const normalizedZ = (clickY - PADDING) / (mapHeight - 2 * PADDING);

  return {
    x: bounds.minX + normalizedX * bounds.width,
    y: 50, // Default camera height
    z: bounds.minZ + normalizedZ * bounds.height,
  };
}

// ============================================================================
// Component
// ============================================================================

export const VoxelMinimap: React.FC<VoxelMinimapProps> = ({
  width = DEFAULT_WIDTH,
  height = DEFAULT_HEIGHT,
  cameraPosition,
  cameraTarget,
  onNavigate,
  visible = true,
  onToggle,
  className = '',
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isExpanded, setIsExpanded] = useState(false);
  const [isHovered, setIsHovered] = useState(false);

  // Get nodes from store
  const nodes = useVoxelStore((state) => Array.from(state.nodes.values()));
  const selectedNodeId = useVoxelStore((state) => state.ui.selectedNodeId);

  // Calculate bounds
  const bounds = useMemo(() => calculateBounds(nodes), [nodes]);

  // Prepare minimap nodes
  const minimapNodes = useMemo((): MinimapNode[] => {
    return nodes.map((node) => {
      const pos = worldToMinimap(node.position.x, node.position.z, bounds, width, height);
      return {
        id: node.id,
        x: pos.x,
        y: pos.y,
        color: NODE_TYPE_COLORS[node.type] || '#6B7280',
        size: node.id === selectedNodeId ? DOT_SIZE_BASE + 2 : DOT_SIZE_BASE,
        type: node.type,
        status: node.status,
      };
    });
  }, [nodes, bounds, width, height, selectedNodeId]);

  // Camera viewport position
  const viewportPosition = useMemo(() => {
    if (!cameraPosition) return null;
    return worldToMinimap(cameraPosition[0], cameraPosition[2], bounds, width, height);
  }, [cameraPosition, bounds, width, height]);

  // Draw minimap
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Clear canvas
    ctx.clearRect(0, 0, width, height);

    // Background
    ctx.fillStyle = 'rgba(15, 23, 42, 0.9)';
    ctx.fillRect(0, 0, width, height);

    // Draw grid
    ctx.strokeStyle = 'rgba(148, 163, 184, 0.1)';
    ctx.lineWidth = 1;
    const gridSize = 20;
    for (let x = PADDING; x < width - PADDING; x += gridSize) {
      ctx.beginPath();
      ctx.moveTo(x, PADDING);
      ctx.lineTo(x, height - PADDING);
      ctx.stroke();
    }
    for (let y = PADDING; y < height - PADDING; y += gridSize) {
      ctx.beginPath();
      ctx.moveTo(PADDING, y);
      ctx.lineTo(width - PADDING, y);
      ctx.stroke();
    }

    // Draw nodes
    minimapNodes.forEach((node) => {
      ctx.beginPath();
      ctx.arc(node.x, node.y, node.size, 0, Math.PI * 2);
      ctx.fillStyle = node.color;
      ctx.fill();

      // Add glow for critical status
      if (node.status === 'critical') {
        ctx.beginPath();
        ctx.arc(node.x, node.y, node.size + 2, 0, Math.PI * 2);
        ctx.strokeStyle = node.color;
        ctx.lineWidth = 1;
        ctx.stroke();
      }
    });

    // Draw viewport indicator
    if (viewportPosition) {
      ctx.beginPath();
      ctx.arc(viewportPosition.x, viewportPosition.y, 8, 0, Math.PI * 2);
      ctx.fillStyle = VIEWPORT_COLOR;
      ctx.fill();
      ctx.strokeStyle = 'rgba(255, 255, 255, 0.6)';
      ctx.lineWidth = 2;
      ctx.stroke();

      // Draw direction indicator if we have a target
      if (cameraTarget) {
        const targetPos = worldToMinimap(cameraTarget[0], cameraTarget[2], bounds, width, height);
        const dx = targetPos.x - viewportPosition.x;
        const dy = targetPos.y - viewportPosition.y;
        const angle = Math.atan2(dy, dx);
        const length = 12;

        ctx.beginPath();
        ctx.moveTo(viewportPosition.x, viewportPosition.y);
        ctx.lineTo(
          viewportPosition.x + Math.cos(angle) * length,
          viewportPosition.y + Math.sin(angle) * length
        );
        ctx.strokeStyle = 'rgba(255, 255, 255, 0.8)';
        ctx.lineWidth = 2;
        ctx.stroke();
      }
    }

    // Border
    ctx.strokeStyle = 'rgba(148, 163, 184, 0.2)';
    ctx.lineWidth = 1;
    ctx.strokeRect(0, 0, width, height);
  }, [minimapNodes, viewportPosition, width, height, cameraTarget, bounds]);

  // Handle click to navigate
  const handleClick = useCallback(
    (event: React.MouseEvent<HTMLCanvasElement>) => {
      if (!onNavigate) return;

      const canvas = canvasRef.current;
      if (!canvas) return;

      const rect = canvas.getBoundingClientRect();
      const x = event.clientX - rect.left;
      const y = event.clientY - rect.top;

      const worldPos = minimapToWorld(x, y, bounds, width, height);
      onNavigate(worldPos);
    },
    [onNavigate, bounds, width, height]
  );

  if (!visible) {
    return (
      <button
        onClick={onToggle}
        className="fixed bottom-4 left-4 z-40 p-2 rounded-lg transition-colors"
        style={{
          background: 'rgba(15, 23, 42, 0.9)',
          border: '1px solid rgba(148, 163, 184, 0.2)',
        }}
        aria-label="Show minimap"
      >
        <Map className="w-5 h-5 text-muted-foreground" />
      </button>
    );
  }

  const displayWidth = isExpanded ? width * 1.5 : width;
  const displayHeight = isExpanded ? height * 1.5 : height;

  return (
    <div
      className={`fixed bottom-4 left-4 z-40 ${className}`}
      style={{
        width: displayWidth,
        height: displayHeight + 32,
      }}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      <div
        style={{
          background: 'rgba(15, 23, 42, 0.95)',
          backdropFilter: 'blur(20px)',
          WebkitBackdropFilter: 'blur(20px)',
          border: '1px solid rgba(148, 163, 184, 0.1)',
          boxShadow: '0 4px 24px rgba(0, 0, 0, 0.3)',
        }}
        className="rounded-xl overflow-hidden"
      >
        {/* Header */}
        <div className="flex items-center justify-between px-2 py-1.5 border-b border-slate-700/50">
          <div className="flex items-center gap-1.5 text-muted-foreground">
            <Map className="w-3.5 h-3.5" />
            <span className="text-xs font-medium">Minimap</span>
          </div>
          <div className="flex items-center gap-1">
            <button
              onClick={() => setIsExpanded(!isExpanded)}
              className="p-1 hover:bg-slate-700/50 rounded transition-colors"
              aria-label={isExpanded ? 'Minimize minimap' : 'Expand minimap'}
            >
              {isExpanded ? (
                <Minimize2 className="w-3.5 h-3.5 text-slate-500" />
              ) : (
                <Maximize2 className="w-3.5 h-3.5 text-slate-500" />
              )}
            </button>
            {onToggle && (
              <button
                onClick={onToggle}
                className="p-1 hover:bg-slate-700/50 rounded transition-colors"
                aria-label="Hide minimap"
              >
                <X className="w-3.5 h-3.5 text-slate-500" />
              </button>
            )}
          </div>
        </div>

        {/* Canvas */}
        <canvas
          ref={canvasRef}
          width={displayWidth}
          height={displayHeight}
          onClick={handleClick}
          className={`cursor-${onNavigate ? 'pointer' : 'default'}`}
          style={{
            display: 'block',
            transition: 'all 0.2s ease',
          }}
          aria-label="3D scene minimap"
        />

        {/* Hover info */}
        {isHovered && (
          <div className="absolute bottom-1 left-1 right-1 text-center">
            <span className="text-[11px] text-slate-500">
              {nodes.length} nodes
              {onNavigate && ' | Click to navigate'}
            </span>
          </div>
        )}
      </div>
    </div>
  );
};

