// CVSS Score Gauge
const CvssGauge: React.FC<{ score: number; size?: 'sm' | 'md' | 'lg' }> = ({
    score,
    size = 'md'
}) => {
    const severity = getCvssSeverity(score);
    const sizeClasses = {
        sm: 'w-10 h-10',
        md: 'w-14 h-14',
        lg: 'w-20 h-20',
    };

    const strokeWidth = size === 'sm' ? 3 : size === 'md' ? 4 : 5;
    const radius = size === 'sm' ? 14 : size === 'md' ? 20 : 28;
    const circumference = 2 * Math.PI * radius;
    const strokeDashoffset = circumference - (score / 10) * circumference;

    const getStrokeColor = () => {
        switch (severity) {
            case 'critical': return 'stroke-destructive';
            case 'high': return 'stroke-orange-500';
            case 'medium': return 'stroke-warning';
            case 'low': return 'stroke-success';
            default: return 'stroke-muted-foreground';
        }
    };

    return (
        <div className={cn('relative', sizeClasses[size])}>
            <svg className="w-full h-full -rotate-90" viewBox="0 0 56 56">
                <circle
                    cx="28"
                    cy="28"
                    r={radius}
                    fill="none"
                    stroke="currentColor"
                    strokeWidth={strokeWidth}
                    className="text-muted/30"
                />
                <circle
                    cx="28"
                    cy="28"
                    r={radius}
                    fill="none"
                    strokeWidth={strokeWidth}
                    strokeLinecap="round"
                    strokeDasharray={circumference}
                    strokeDashoffset={strokeDashoffset}
                    className={cn('transition-all duration-700', getStrokeColor())}
                />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center">
                <span className={cn(
                    'font-bold',
                    size === 'sm' ? 'text-xs' : size === 'md' ? 'text-sm' : 'text-lg',
                    getSeverityColor(severity)
                )}>
                    {score.toFixed(1)}
                </span>
                {size !== 'sm' && (
                    <span className="text-[11px] uppercase text-muted-foreground">
                        CVSS
                    </span>
                )}
            </div>
        </div>
    );
};

// EPSS Probability Bar
const EpssBar: React.FC<{ probability: number; percentile: number }> = ({
    probability,
    percentile
}) => {
    const getRiskLevel = () => {
        if (probability >= 0.1) return { color: 'bg-destructive', label: 'Critique' };
        if (probability >= 0.01) return { color: 'bg-orange-500', label: 'Élevé' };
        if (probability >= 0.001) return { color: 'bg-warning', label: 'Moyen' };
        return { color: 'bg-success', label: 'Bas' };
    };

    const risk = getRiskLevel();

    return (
        <div className="space-y-1">
            <div className="flex items-center justify-between text-xs">
                <span className="text-muted-foreground">EPSS</span>
                <span className="font-medium">{(probability * 100).toFixed(2)}%</span>
            </div>
            <div className="h-1.5 bg-muted/30 rounded-full overflow-hidden">
                <motion.div
                    initial={{ width: 0 }}
                    animate={{ width: `${probability * 100}%` }}
                    transition={{ duration: 0.5 }}
                    className={cn('h-full rounded-full', risk.color)}
                />
            </div>
            <div className="flex items-center justify-between text-[11px] text-muted-foreground">
                <span>Top {percentile.toFixed(0)}%</span>
                <Badge status={
                    probability >= 0.1 ? 'error' :
                    probability >= 0.01 ? 'warning' :
                    probability >= 0.001 ? 'neutral' : 'success'
                } className="text-[11px] px-1 py-0">
                    {risk.label}
                </Badge>
            </div>
        </div>
    );
};

