// Main Panel Component
export const AgentVulnerabilityPanel: React.FC<AgentVulnerabilityPanelProps> = ({
    className,
    maxItems = 10,
    onVulnerabilityClick
}) => {
    const { user } = useStore();
    const [vulnerabilities, setVulnerabilities] = useState<AgentVulnerability[]>([]);
    const [stats, setStats] = useState<AgentVulnerabilityStats | null>(null);
    const [loading, setLoading] = useState(true);
    const [expandedId, setExpandedId] = useState<string | null>(null);

    // Filter state
    const [severityFilter, setSeverityFilter] = useState<CvssSeverity | 'all'>('all');
    const [showKevOnly, setShowKevOnly] = useState(false);

    // Load vulnerabilities
    useEffect(() => {
        const organizationId = user?.organizationId;
        if (!organizationId) return;

        // Note: loading is initialized to true, no need to set it here

        const unsubscribe = AgentVulnerabilityService.subscribeToAgentVulnerabilities(
            organizationId,
            (vulns) => {
                setVulnerabilities(vulns);
                setLoading(false);
            },
            () => setLoading(false)
        );

        // Load stats
        AgentVulnerabilityService.getVulnerabilityStats(organizationId)
            .then(setStats)
            .catch(() => {});

        return unsubscribe;
    }, [user?.organizationId]);

    // Filtered vulnerabilities
    const filteredVulnerabilities = useMemo(() => {
        let filtered = vulnerabilities;

        if (severityFilter !== 'all') {
            filtered = filtered.filter(v => {
                const sev = v.nvdData?.cvssV3?.baseSeverity ||
                    getCvssSeverity(v.nvdData?.cvssV3?.baseScore ?? 0);
                return sev === severityFilter;
            });
        }

        if (showKevOnly) {
            filtered = filtered.filter(v => v.nvdData?.isKnownExploited);
        }

        return filtered.slice(0, maxItems);
    }, [vulnerabilities, severityFilter, showKevOnly, maxItems]);

    const handleToggleExpand = (id: string) => {
        setExpandedId(prev => prev === id ? null : id);
    };

    return (
        <motion.div
            variants={staggerContainerVariants}
            initial="initial"
            animate="visible"
            className={cn('space-y-4', className)}
        >
            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <h3 className="font-semibold">Vulnérabilités Agent</h3>
                    <p className="text-sm text-muted-foreground">
                        Découvertes automatiques via Sentinel Agent
                    </p>
                </div>
                <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => setLoading(true)}
                    className="h-8 gap-2"
                >
                    <RefreshCw className={cn('h-4 w-4', loading && 'animate-spin')} />
                </Button>
            </div>

            {/* Stats */}
            <StatsSummary stats={stats} loading={loading} />

            {/* Filters */}
            <div className="flex items-center gap-2 flex-wrap">
                <Filter className="h-4 w-4 text-muted-foreground" />
                <div className="flex gap-1">
                    {(['all', 'critical', 'high', 'medium', 'low'] as const).map(sev => (
                        <Button
                            key={sev}
                            variant={severityFilter === sev ? 'default' : 'ghost'}
                            size="sm"
                            onClick={() => setSeverityFilter(sev)}
                            className={cn(
                                'h-7 px-2 text-xs',
                                sev === 'critical' && severityFilter === sev && 'bg-destructive hover:bg-destructive/90',
                                sev === 'high' && severityFilter === sev && 'bg-orange-500 hover:bg-orange-500/90'
                            )}
                        >
                            {sev === 'all' ? 'Toutes' :
                             sev === 'critical' ? 'Critiques' :
                             sev === 'high' ? 'Élevées' :
                             sev === 'medium' ? 'Moyennes' : 'Basses'}
                        </Button>
                    ))}
                </div>
                <div className="w-px h-6 bg-border" />
                <Button
                    variant={showKevOnly ? 'default' : 'ghost'}
                    size="sm"
                    onClick={() => setShowKevOnly(!showKevOnly)}
                    className="h-7 px-2 text-xs gap-1"
                >
                    <Zap className="h-3 w-3" />
                    KEV uniquement
                </Button>
            </div>

            {/* Vulnerabilities list */}
            {loading ? (
                <div className="space-y-3 animate-pulse">
                    {[1, 2, 3].map(i => (
                        <div key={i} className="h-24 rounded-xl bg-muted/50" />
                    ))}
                </div>
            ) : filteredVulnerabilities.length === 0 ? (
                <Card className="p-8 text-center">
                    <Shield className="h-12 w-12 text-success mx-auto mb-3" />
                    <h4 className="font-medium mb-1">Aucune vulnérabilité</h4>
                    <p className="text-sm text-muted-foreground">
                        {severityFilter !== 'all' || showKevOnly
                            ? 'Aucune vulnérabilité ne correspond aux filtres.'
                            : 'Aucune vulnérabilité détectée par les agents.'}
                    </p>
                </Card>
            ) : (
                <motion.div
                    variants={staggerContainerVariants}
                    className="space-y-3"
                >
                    {filteredVulnerabilities.map(vuln => (
                        <VulnerabilityCard
                            key={vuln.id}
                            vulnerability={vuln}
                            isExpanded={expandedId === vuln.id}
                            onToggle={() => handleToggleExpand(vuln.id!)}
                            onClick={() => onVulnerabilityClick?.(vuln)}
                        />
                    ))}
                </motion.div>
            )}

            {/* Show more link */}
            {vulnerabilities.length > maxItems && (
                <div className="text-center pt-2">
                    <Button variant="ghost" size="sm" className="gap-2">
                        Voir les {vulnerabilities.length - maxItems} autres
                        <ChevronRight className="h-4 w-4" />
                    </Button>
                </div>
            )}
        </motion.div>
    );
};

