import React, { useState, useMemo, useCallback } from 'react';
import { Vulnerability } from '../../types';
import { DataTable } from '../ui/DataTable';
import { ColumnDef } from '@tanstack/react-table';
import { Badge } from '../ui/Badge';
import { Button } from '../ui/button';
import { Edit2, Trash2, Bug, Copy, Bot } from '../ui/Icons';
import { RowActionsMenu, RowActionItem } from '../ui/RowActionsMenu';
import { format } from 'date-fns';
import { fr } from 'date-fns/locale';
import { cn } from '../../lib/utils';
import { VulnerabilityEmptyState } from './VulnerabilityEmptyState';

interface VulnerabilityListProps {
    vulnerabilities: Vulnerability[];
    viewMode: 'list' | 'grid' | 'kanban';
    onSelect: (v: Vulnerability) => void;
    onDelete: (id: string) => void;
    onDuplicate?: (v: Vulnerability) => void;
    loading: boolean;
    onImportClick?: () => void;
    onCreateClick?: () => void;
    duplicatingIds?: Set<string>;
}

// Define a type with required ID for the DataTable
type VulnerabilityWithId = Vulnerability & { id: string };

export const VulnerabilityList: React.FC<VulnerabilityListProps> = ({
    vulnerabilities,
    onSelect,
    onDelete,
    onDuplicate,
    loading,
    viewMode,
    onImportClick,
    onCreateClick,
    duplicatingIds = new Set(),
}) => {
    const [deletingIds, setDeletingIds] = useState<Set<string>>(new Set());

    // Filter out vulnerabilities without ID for the table view to satisfy type requirements
    const safeVulnerabilities = useMemo(() => {
        return vulnerabilities.filter((v): v is VulnerabilityWithId => !!v.id);
    }, [vulnerabilities]);

    const handleDelete = useCallback(async (id: string, e?: React.MouseEvent) => {
        e?.stopPropagation();
        if (deletingIds.has(id)) return;
        setDeletingIds(prev => new Set(prev).add(id));
        try {
            await onDelete(id);
        } finally {
            setDeletingIds(prev => {
                const next = new Set(prev);
                next.delete(id);
                return next;
            });
        }
    }, [deletingIds, onDelete]);

    const columns = useMemo<ColumnDef<VulnerabilityWithId>[]>(() => [
        {
            accessorKey: 'severity',
            header: 'Sévérité',
            cell: ({ row }) => {
                const severity = row.original.severity;
                const getSeverityStyle = (s: string) => {
                    switch (s) {
                        case 'Critical': return { status: 'error' as const, label: 'Critique' };
                        case 'High': return { status: 'warning' as const, label: 'Élevée' };
                        case 'Medium': return { status: 'brand' as const, label: 'Moyenne' };
                        default: return { status: 'info' as const, label: 'Faible' };
                    }
                };
                const style = getSeverityStyle(severity);
                return (
                    <Badge status={style.status} variant="soft" size="sm">
                        {style.label}
                    </Badge>
                );
            },
            size: 100
        },
        {
            accessorKey: 'cveId',
            header: 'CVE / ID',
            cell: ({ row }) => (
                <span className="font-mono text-xs bg-slate-100 dark:bg-slate-800 px-2 py-1 rounded text-slate-600 dark:text-muted-foreground">
                    {row.original.cveId}
                </span>
            ),
            size: 120
        },
        {
            accessorKey: 'title',
            header: 'Vulnérabilité',
            cell: ({ row }) => (
                <div className="flex flex-col">
                    <span className="font-bold text-slate-900 dark:text-white truncate max-w-[300px]" title={row.original.title}>
                        {row.original.title || 'Sans titre'}
                    </span>
                    {row.original.assetName && (
                        <span className="text-xs text-slate-500 dark:text-slate-300 flex items-center gap-1 mt-0.5">
                            <ServerIcon className="w-3 h-3" /> {row.original.assetName}
                        </span>
                    )}
                </div>
            )
        },
        {
            accessorKey: 'status',
            header: 'Statut',
            cell: ({ row }) => {
                const status = row.original.status || 'Open';
                const getStatusConfig = (s: string) => {
                    switch (s) {
                        case 'Resolved':
                        case 'Patch Applied':
                            return { status: 'success' as const, label: 'Corrigée' };
                        case 'Risk Accepted':
                            return { status: 'warning' as const, label: 'Acceptée' };
                        case 'False Positive':
                            return { status: 'neutral' as const, label: 'Faux Positif' };
                        default:
                            return { status: 'error' as const, label: 'Ouverte' };
                    }
                };
                const config = getStatusConfig(status);
                return (
                    <Badge status={config.status} variant="outline" size="sm">
                        {config.label}
                    </Badge>
                );
            },
            size: 100
        },
        {
            accessorKey: 'source',
            header: 'Source',
            cell: ({ row }) => {
                const source = row.original.source;
                if (source === 'agent') {
                    return (
                        <Badge variant="soft" status="brand" className="gap-1">
                            <Bot className="w-3 h-3" />
                            Agent
                        </Badge>
                    );
                }
                if (source === 'nvd' || source === 'cisa') {
                    return (
                        <Badge variant="outline" className="text-slate-500 dark:text-slate-300 border-slate-300 dark:border-slate-600">
                            {source.toUpperCase()}
                        </Badge>
                    );
                }
                return (
                    <span className="text-xs text-muted-foreground">
                        {source || 'Manuel'}
                    </span>
                );
            },
            size: 90
        },
        {
            accessorKey: 'publishedDate',
            header: 'Date',
            cell: ({ row }) => {
                try {
                    return row.original.publishedDate ? format(new Date(row.original.publishedDate), 'dd MMM yyyy', { locale: fr }) : '-';
                } catch {
                    return '-';
                }
            },
            size: 120
        },
        {
            id: 'actions',
            header: '',
            cell: ({ row }) => {
                const isDuplicating = duplicatingIds.has(row.original.id);
                const isDeleting = deletingIds.has(row.original.id);
                const menuItems: RowActionItem[] = [
                    {
                        label: 'Modifier',
                        icon: Edit2,
                        onClick: () => onSelect(row.original),
                    },
                    ...(onDuplicate ? [{
                        label: 'Dupliquer',
                        icon: Copy,
                        onClick: () => onDuplicate(row.original),
                        disabled: isDuplicating,
                    }] : []),
                    {
                        label: 'Supprimer',
                        icon: Trash2,
                        onClick: () => handleDelete(row.original.id),
                        variant: 'danger' as const,
                        disabled: isDeleting,
                    },
                ];

                return (
                    <div className="flex justify-end">
                        <RowActionsMenu
                            items={menuItems}
                            aria-label={`Actions pour ${row.original.title || row.original.cveId}`}
                        />
                    </div>
                );
            },
            size: 80
        }
    ], [deletingIds, onSelect, handleDelete, onDuplicate, duplicatingIds]);

    if (loading) {
        return (
            <div className="space-y-4">
                {[1, 2, 3].map(i => (
                    <div key={i} className="h-16 bg-slate-100 dark:bg-slate-800 animate-pulse rounded-xl" />
                ))}
            </div>
        );
    }

    if (viewMode === 'grid') {
        return (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 sm:gap-6 animate-in fade-in duration-500">
                {safeVulnerabilities.map(v => (
                    <div
                        key={v.id}
                        onClick={() => onSelect(v)}
                        className="group relative bg-white dark:bg-slate-900/50 rounded-2xl p-6 border border-slate-200/50 dark:border-white/5 hover:border-brand-400 transition-all cursor-pointer overflow-hidden shadow-sm hover:shadow-md"
                    >
                        <div className="absolute top-0 right-0 w-24 h-24 bg-gradient-to-br from-brand-500/5 to-transparent rounded-bl-[4rem]" />

                        <div className="flex items-start justify-between mb-4 relative z-10">
                            <div className={cn(
                                "p-3 rounded-xl",
                                v.severity === 'Critical' ? "bg-red-100 dark:bg-red-900/20 text-red-600 dark:text-red-400" :
                                    v.severity === 'High' ? "bg-orange-100 dark:bg-orange-900/20 text-orange-600 dark:text-orange-400" :
                                        v.severity === 'Medium' ? "bg-amber-100 dark:bg-amber-900/20 text-amber-600 dark:text-amber-400" :
                                            "bg-blue-100 dark:bg-blue-900/20 text-blue-700 dark:text-blue-400"
                            )}>
                                <Bug className="h-6 w-6" />
                            </div>
                            <Badge
                                variant="soft"
                                status={
                                    v.status === 'Resolved' ? 'success' :
                                        v.status === 'Risk Accepted' ? 'warning' :
                                            'error'
                                }
                            >
                                {v.status || 'Open'}
                            </Badge>
                        </div>

                        <h3 className="font-bold text-lg text-slate-900 dark:text-white mb-2 line-clamp-2 min-h-[3.5rem]" title={v.title}>
                            {v.title || 'Vulnérabilité sans titre'}
                        </h3>

                        <div className="flex items-center gap-2 mb-4 flex-wrap">
                            <span className="font-mono text-xs bg-slate-100 dark:bg-slate-800 px-2 py-1 rounded text-slate-500">
                                {v.cveId}
                            </span>
                            <span className="text-xs text-muted-foreground">•</span>
                            <span className="text-xs text-slate-500">
                                {v.publishedDate ? format(new Date(v.publishedDate), 'dd MMM yyyy', { locale: fr }) : 'N/A'}
                            </span>
                            {v.source === 'agent' && (
                                <>
                                    <span className="text-xs text-muted-foreground">•</span>
                                    <Badge variant="soft" className="bg-brand-50 text-brand-600 dark:text-brand-400 border-brand-200 gap-1 text-[11px] py-0">
                                        <Bot className="w-2.5 h-2.5" />
                                        Agent
                                    </Badge>
                                </>
                            )}
                        </div>

                        <div className="flex items-center justify-between pt-4 border-t border-slate-100 dark:border-white/5">
                            <div className="flex items-center text-xs text-slate-500">
                                {v.severity} Severity
                            </div>
                            <Button
                                variant="ghost"
                                size="sm"
                                onClick={(e) => handleDelete(v.id, e)}
                                className="text-muted-foreground hover:text-red-500 transition-colors"
                            >
                                <Trash2 className="h-4 w-4" />
                            </Button>
                        </div>
                    </div>
                ))}
                {safeVulnerabilities.length === 0 && (
                    <VulnerabilityEmptyState
                        viewMode={viewMode}
                        onImportClick={onImportClick}
                        onCreateClick={onCreateClick}
                    />
                )}
            </div>
        );
    }

    return (
        <DataTable
            columns={columns}
            data={safeVulnerabilities}
            onRowClick={onSelect}
            searchable={false} // Managed by parent
            pageSize={10}
            emptyState={safeVulnerabilities.length === 0 ? (
                <VulnerabilityEmptyState
                    viewMode="list"
                    onImportClick={onImportClick}
                    onCreateClick={onCreateClick}
                />
            ) : undefined}
        />
    );
};

// Helper Icon
const ServerIcon = ({ className }: { className?: string }) => (
    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={className}>
        <rect width="20" height="8" x="2" y="2" rx="2" ry="2" />
        <rect width="20" height="8" x="2" y="14" rx="2" ry="2" />
        <line x1="6" y1="6" x2="6.01" y2="6" />
        <line x1="6" y1="18" x2="6.01" y2="18" />
    </svg>
);

/**
 * VulnerabilityOverview - Premium advanced dashboard for vulnerability management
 * Features: Animated gauges, glowing charts, RadialBarChart, ComposedChart, interactive elements
 */
import React, { useMemo, useState } from 'react';
import {
    ResponsiveContainer,
    PieChart,
    Pie,
    Cell,
    BarChart,
    Bar,
    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    Area,
    Legend,
    RadialBarChart,
    RadialBar,
    ComposedChart,
    Line,
    Sector
} from 'recharts';
import { Vulnerability } from '../../types';
import { ChartTooltip } from '../ui/ChartTooltip';
import { EmptyChartState } from '../ui/EmptyChartState';
import {
    DONUT_COLORS,
    SEVERITY_COLORS,
    CHART_AXIS_COLORS,
    SENTINEL_PALETTE
} from '../../theme/chartTheme';
import {
    ShieldAlert,
    Bug,
    CheckCircle2,
    AlertTriangle,
    TrendingUp,
    TrendingDown,
    Target,
    Activity,
    Zap,
    FileText,
    ExternalLink,
    Shield,
    Flame
} from '../ui/Icons';

interface VulnerabilityOverviewProps {
    vulnerabilities: Vulnerability[];
}

const STATUS_COLORS: Record<string, string> = {
    'Open': SEVERITY_COLORS.critical,
    'In Progress': SENTINEL_PALETTE.primary,
    'Resolved': SENTINEL_PALETTE.success,
    'Patch Applied': SENTINEL_PALETTE.success,
    'False Positive': '#94a3b8',
    'Risk Accepted': SENTINEL_PALETTE.warning
};

const SOURCE_ICONS: Record<string, string> = {
    'Nessus': '🔬',
    'Qualys': '🛡️',
    'CrowdStrike': '🦅',
    'SentinelOne': '🎯',
    'Manuel': '✋',
    'SIEM': '📊',
    'EDR': '🔍'
};

export const VulnerabilityOverview: React.FC<VulnerabilityOverviewProps> = ({ vulnerabilities }) => {
    const [activeIndex, setActiveIndex] = useState<number | null>(null);
    const [hoveredSource, setHoveredSource] = useState<string | null>(null);
    const [selectedCVE, setSelectedCVE] = useState<string | null>(null);

    // ========== STATS CALCULATION ==========
    const stats = useMemo(() => {
        const total = vulnerabilities.length;
        const open = vulnerabilities.filter(v => v.status === 'Open' || v.status === 'In Progress').length;
        const critical = vulnerabilities.filter(v => v.severity === 'Critical' && (v.status === 'Open' || v.status === 'In Progress')).length;
        const high = vulnerabilities.filter(v => v.severity === 'High' && (v.status === 'Open' || v.status === 'In Progress')).length;
        const resolved = vulnerabilities.filter(v => v.status === 'Resolved' || v.status === 'Patch Applied').length;
        const remediationRate = total > 0 ? Math.round((resolved / total) * 100) : 100;

        // Critical ratio
        const criticalRatio = total > 0 ? Math.round((critical / total) * 100) : 0;

        // Average CVSS Score
        const vulnsWithScore = vulnerabilities.filter(v => v.score && v.score > 0);
        const avgScore = vulnsWithScore.length > 0
            ? (vulnsWithScore.reduce((acc, v) => acc + (v.score || 0), 0) / vulnsWithScore.length).toFixed(1)
            : null;

        // MTTR Calculation
        let totalResolutionHours = 0;
        let resolvedWithTimes = 0;
        vulnerabilities.forEach(v => {
            if ((v.status === 'Resolved' || v.status === 'Patch Applied') && v.remediatedAt) {
                const startStr = v.detectedAt || v.publishedDate || v.createdAt;
                if (startStr) {
                    const start = new Date(startStr).getTime();
                    const end = new Date(v.remediatedAt).getTime();
                    if (!Number.isNaN(start) && !Number.isNaN(end) && end > start) {
                        totalResolutionHours += (end - start) / (1000 * 60 * 60);
                        resolvedWithTimes++;
                    }
                }
            }
        });
        const mttrHours = resolvedWithTimes > 0 ? Math.round(totalResolutionHours / resolvedWithTimes) : null;

        // Trend (compare last 7 days vs previous 7 days)
        const now = new Date();
        const last7Days = vulnerabilities.filter(v => {
            const dateStr = v.detectedAt || v.publishedDate || v.createdAt;
            if (!dateStr) return false;
            const d = new Date(dateStr);
            if (Number.isNaN(d.getTime())) return false;
            return (now.getTime() - d.getTime()) <= 7 * 24 * 60 * 60 * 1000;
        }).length;
        const prev7Days = vulnerabilities.filter(v => {
            const dateStr = v.detectedAt || v.publishedDate || v.createdAt;
            if (!dateStr) return false;
            const d = new Date(dateStr);
            if (Number.isNaN(d.getTime())) return false;
            const diff = now.getTime() - d.getTime();
            return diff > 7 * 24 * 60 * 60 * 1000 && diff <= 14 * 24 * 60 * 60 * 1000;
        }).length;
        const trend = prev7Days > 0 ? Math.round(((last7Days - prev7Days) / prev7Days) * 100) : 0;

        // Exploit available count
        const exploitAvailable = vulnerabilities.filter(v => v.exploitAvailable && (v.status === 'Open' || v.status === 'In Progress')).length;

        return { total, open, critical, high, resolved, remediationRate, criticalRatio, avgScore, mttrHours, trend, last7Days, exploitAvailable };
    }, [vulnerabilities]);

    // ========== CHART DATA ==========
    // Severity Distribution
    const severityData = useMemo(() => {
        const counts = {
            'Critique': vulnerabilities.filter(v => v.severity === 'Critical').length,
            'Élevée': vulnerabilities.filter(v => v.severity === 'High').length,
            'Moyenne': vulnerabilities.filter(v => v.severity === 'Medium').length,
            'Faible': vulnerabilities.filter(v => v.severity === 'Low').length
        };
        return Object.entries(counts)
            .filter(([_, v]) => v > 0)
            .map(([name, value], i) => ({ name, value, color: DONUT_COLORS.severity[i] }));
    }, [vulnerabilities]);

    // Status Distribution
    const statusData = useMemo(() => {
        const data = vulnerabilities.reduce((acc, v) => {
            const status = v.status || 'Open';
            acc[status] = (acc[status] || 0) + 1;
            return acc;
        }, {} as Record<string, number>);
        return Object.entries(data).map(([name, value]) => ({
            name,
            value,
            fill: STATUS_COLORS[name] || SENTINEL_PALETTE.tertiary
        }));
    }, [vulnerabilities]);

    // Source Distribution with icons
    const sourceData = useMemo(() => {
        const data = vulnerabilities.reduce((acc, v) => {
            const source = v.source || 'Manuel';
            acc[source] = (acc[source] || 0) + 1;
            return acc;
        }, {} as Record<string, number>);
        return Object.entries(data)
            .map(([name, value], i) => ({
                name,
                value,
                color: DONUT_COLORS.category[i % DONUT_COLORS.category.length],
                icon: SOURCE_ICONS[name] || '📋'
            }))
            .sort((a, b) => b.value - a.value)
            .slice(0, 6);
    }, [vulnerabilities]);

    // Radial gauge data for remediation rate
    const gaugeData = useMemo(() => [
        { name: 'Remédiation', value: stats.remediationRate, fill: stats.remediationRate >= 70 ? SENTINEL_PALETTE.success : stats.remediationRate >= 40 ? SENTINEL_PALETTE.warning : SEVERITY_COLORS.critical }
    ], [stats.remediationRate]);

    // CVSS Score distribution
    const cvssDistribution = useMemo(() => {
        const ranges = [
            { name: '9.0-10.0', min: 9, max: 10, color: SEVERITY_COLORS.critical },
            { name: '7.0-8.9', min: 7, max: 8.9, color: SEVERITY_COLORS.high },
            { name: '4.0-6.9', min: 4, max: 6.9, color: SEVERITY_COLORS.medium },
            { name: '0.0-3.9', min: 0, max: 3.9, color: SEVERITY_COLORS.low }
        ];
        return ranges.map(r => ({
            ...r,
            value: vulnerabilities.filter(v => v.score !== undefined && v.score >= r.min && v.score <= r.max).length
        })).filter(r => r.value > 0);
    }, [vulnerabilities]);

    // Timeline (Last 30 days) with cumulative
    const timelineData = useMemo(() => {
        const days = 30;
        const data = [];
        const now = new Date();
        let cumulative = stats.open;

        // First calculate starting cumulative by going backwards
        for (let i = 0; i < days; i++) {
            const d = new Date(now.getTime() - i * 24 * 60 * 60 * 1000);
            const dateStr = d.toISOString().split('T')[0];

            const discovered = vulnerabilities.filter(v => {
                const vDate = (v.detectedAt || v.publishedDate || v.createdAt || '').split('T')[0];
                return vDate === dateStr;
            }).length;

            const remediated = vulnerabilities.filter(v => {
                if (!v.remediatedAt) return false;
                const remDateObj = new Date(v.remediatedAt);
                if (Number.isNaN(remDateObj.getTime())) return false;
                return remDateObj.toISOString().split('T')[0] === dateStr;
            }).length;

            cumulative = cumulative - discovered + remediated;
        }

        // Now build forward
        cumulative = Math.max(0, cumulative);
        for (let i = days - 1; i >= 0; i--) {
            const d = new Date(now.getTime() - i * 24 * 60 * 60 * 1000);
            const dateStr = d.toISOString().split('T')[0];

            const discovered = vulnerabilities.filter(v => {
                const vDate = (v.detectedAt || v.publishedDate || v.createdAt || '').split('T')[0];
                return vDate === dateStr;
            }).length;

            const remediated = vulnerabilities.filter(v => {
                if (!v.remediatedAt) return false;
                const remDateObj = new Date(v.remediatedAt);
                if (Number.isNaN(remDateObj.getTime())) return false;
                return remDateObj.toISOString().split('T')[0] === dateStr;
            }).length;

            cumulative += discovered - remediated;

            data.push({
                date: i === 0 ? 'Auj.' : i <= 6 ? `J-${i}` : d.toLocaleDateString('fr-FR', { day: '2-digit', month: 'short' }),
                decouvertes: discovered,
                remediees: remediated,
                cumul: Math.max(0, cumulative)
            });
        }
        return data;
    }, [vulnerabilities, stats.open]);

    // Top CVEs by Score
    const topCVEs = useMemo(() => {
        return vulnerabilities
            .filter(v => v.score && v.score > 0 && (v.status === 'Open' || v.status === 'In Progress'))
            .sort((a, b) => (b.score || 0) - (a.score || 0))
            .slice(0, 6)
            .map(v => ({
                cve: v.cveId,
                score: v.score || 0,
                severity: v.severity,
                asset: v.assetName || '-',
                exploitAvailable: v.exploitAvailable
            }));
    }, [vulnerabilities]);

    const getScoreColor = (score: number) => {
        if (score >= 9) return 'text-red-600 dark:text-red-400 bg-gradient-to-r from-red-50 to-red-100/50 dark:from-red-900/40 dark:to-red-800/20 border-red-200 dark:border-red-800/30';
        if (score >= 7) return 'text-amber-600 dark:text-amber-400 bg-gradient-to-r from-amber-50 to-amber-100/50 dark:from-amber-900/40 dark:to-amber-800/20 border-amber-200 dark:border-amber-800/30';
        if (score >= 4) return 'text-yellow-600 dark:text-yellow-400 bg-gradient-to-r from-yellow-50 to-yellow-100/50 dark:from-yellow-900/40 dark:to-yellow-800/20 border-yellow-200/50 dark:border-yellow-800/30';
        return 'text-emerald-600 dark:text-emerald-400 bg-gradient-to-r from-emerald-50 to-emerald-100/50 dark:from-emerald-900/40 dark:to-emerald-800/20 border-emerald-200/50 dark:border-emerald-800/30';
    };

    // Custom active shape for pie
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const renderActiveShape = (props: any) => {
        const { cx, cy, innerRadius, outerRadius, startAngle, endAngle, fill, payload } = props;
        return (
            <g>
                <text x={cx} y={cy - 8} textAnchor="middle" fill="currentColor" className="text-slate-900 dark:text-white text-lg font-black">
                    {payload.value}
                </text>
                <text x={cx} y={cy + 12} textAnchor="middle" className="text-[11px] fill-slate-500 font-bold uppercase">
                    {payload.name}
                </text>
                <Sector
                    cx={cx}
                    cy={cy}
                    innerRadius={innerRadius}
                    outerRadius={outerRadius + 8}
                    startAngle={startAngle}
                    endAngle={endAngle}
                    fill={fill}
                    style={{ filter: 'url(#glowVuln)', transition: 'all 0.3s ease' }}
                />
                <Sector
                    cx={cx}
                    cy={cy}
                    startAngle={startAngle}
                    endAngle={endAngle}
                    innerRadius={innerRadius}
                    outerRadius={outerRadius}
                    fill={fill}
                    stroke="none"
                />
            </g>
        );
    };

    return (
        <div className="space-y-6 animate-fade-in pb-10">
            {/* ========== SVG DEFS FOR EFFECTS ========== */}
            <svg className="absolute w-0 h-0">
                <defs>
                    <filter id="glowVuln" x="-50%" y="-50%" width="200%" height="200%">
                        <feGaussianBlur stdDeviation="4" result="coloredBlur" />
                        <feMerge>
                            <feMergeNode in="coloredBlur" />
                            <feMergeNode in="SourceGraphic" />
                        </feMerge>
                    </filter>
                    <filter id="glowGaugeVuln" x="-50%" y="-50%" width="200%" height="200%">
                        <feGaussianBlur stdDeviation="6" result="coloredBlur" />
                        <feMerge>
                            <feMergeNode in="coloredBlur" />
                            <feMergeNode in="SourceGraphic" />
                        </feMerge>
                    </filter>
                    <linearGradient id="vulnAnimatedGradient" x1="0%" y1="0%" x2="100%" y2="0%">
                        <stop offset="0%" stopColor="#8B5CF6">
                            <animate attributeName="stop-color" values="#8B5CF6;#EC4899;#8B5CF6" dur="4s" repeatCount="indefinite" />
                        </stop>
                        <stop offset="100%" stopColor="#EC4899">
                            <animate attributeName="stop-color" values="#EC4899;#8B5CF6;#EC4899" dur="4s" repeatCount="indefinite" />
                        </stop>
                    </linearGradient>
                </defs>
            </svg>

            {/* ========== HERO KPI SECTION ========== */}
            <div className="glass-premium p-6 md:p-8 rounded-3xl flex flex-col xl:flex-row xl:items-center xl:justify-between gap-8 relative overflow-hidden group shadow-apple">
                {/* Background Decorations */}
                <div className="absolute inset-0 bg-gradient-to-br from-white/40 via-transparent to-purple-500/5 dark:from-white/5 dark:to-purple-500/10 pointer-events-none" />
                <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-gradient-radial from-purple-500/20 via-transparent to-transparent -mr-48 -mt-48 pointer-events-none opacity-70 blur-2xl" />
                <div className="absolute bottom-0 left-0 w-[300px] h-[300px] bg-gradient-radial from-fuchsia-500/10 via-transparent to-transparent -ml-24 -mb-24 pointer-events-none opacity-60" />

                {/* Animated corner accents */}
