/**
 * Get the complete locale configuration for a given locale
 *
 * @param locale - The locale to get configuration for ('fr' or 'en')
 * @returns The complete locale configuration
 *
 * @example
 * const config = getLocaleConfig('fr');
 * console.log(config.dateFormat); // 'dd/MM/yyyy'
 */
export function getLocaleConfig(locale: SupportedLocale): LocaleConfig {
  return localeConfig[locale];
}

/**
 * Get the date-fns locale object for a given locale
 *
 * @param locale - The locale to get date-fns locale for
 * @returns The date-fns Locale object
 *
 * @example
 * const dfLocale = getDateFnsLocale('fr');
 * format(new Date(), 'PPP', { locale: dfLocale });
 */
export function getDateFnsLocale(locale: SupportedLocale): Locale {
  return localeConfig[locale].dateFnsLocale;
}

/**
 * Format a date according to the specified locale
 *
 * @param date - The date to format
 * @param locale - The locale to use for formatting
 * @param includeTime - Whether to include time in the output
 * @returns Formatted date string
 *
 * @example
 * formatDate(new Date(2026, 0, 15), 'fr'); // '15/01/2026'
 * formatDate(new Date(2026, 0, 15), 'en'); // '01/15/2026'
 * formatDate(new Date(2026, 0, 15, 14, 30), 'fr', true); // '15/01/2026 14:30'
 */
export function formatDate(
  date: Date,
  locale: SupportedLocale,
  includeTime = false
): string {
  const config = localeConfig[locale];
  const formatStr = includeTime ? config.dateTimeFormat : config.dateFormat;
  return format(date, formatStr, { locale: config.dateFnsLocale });
}

/**
 * Parse a localized date string into a Date object
 *
 * @param dateString - The date string to parse
 * @param locale - The locale of the date string
 * @returns Parsed Date object or null if invalid
 *
 * @example
 * parseLocalizedDate('15/01/2026', 'fr'); // Date object for Jan 15, 2026
 * parseLocalizedDate('01/15/2026', 'en'); // Date object for Jan 15, 2026
 * parseLocalizedDate('invalid', 'fr'); // null
 */
export function parseLocalizedDate(
  dateString: string,
  locale: SupportedLocale
): Date | null {
  const config = localeConfig[locale];
  try {
    const parsed = parse(dateString, config.dateFormat, new Date(), {
      locale: config.dateFnsLocale,
    });
    return isValid(parsed) ? parsed : null;
  } catch {
    return null;
  }
}

/**
 * Format a localized date for display
 *
 * @param date - The date to format (Date object or ISO string)
 * @param locale - The locale to use for formatting
 * @param includeTime - Whether to include time
 * @returns Formatted date string, or empty string if invalid
 *
 * @example
 * formatLocalizedDate('2026-01-15T14:30:00Z', 'fr', true); // '15/01/2026 14:30'
 */
export function formatLocalizedDate(
  date: Date | string | null | undefined,
  locale: SupportedLocale,
  includeTime = false
): string {
  if (!date) return '';

  const dateObj = typeof date === 'string' ? new Date(date) : date;

  if (!isValid(dateObj)) return '';

  return formatDate(dateObj, locale, includeTime);
}

/**
 * Format a number according to the specified locale
 *
 * @param value - The number to format
 * @param locale - The locale to use for formatting
 * @param options - Optional Intl.NumberFormat options
 * @returns Formatted number string
 *
 * @example
 * formatNumber(1234.56, 'fr'); // '1 234,56'
 * formatNumber(1234.56, 'en'); // '1,234.56'
 * formatNumber(1234.56, 'fr', { minimumFractionDigits: 2 }); // '1 234,56'
 */
export function formatNumber(
  value: number,
  locale: SupportedLocale,
  options?: Intl.NumberFormatOptions
): string {
  const config = localeConfig[locale];
  return new Intl.NumberFormat(config.intlLocale, options).format(value);
}

/**
 * Format a number as currency according to the specified locale
 *
 * @param value - The number to format
 * @param locale - The locale to use for formatting
 * @param currency - The currency code (default: EUR for FR, USD for EN)
 * @returns Formatted currency string
 *
 * @example
 * formatCurrency(1234.56, 'fr'); // '1 234,56 €'
 * formatCurrency(1234.56, 'en'); // '$1,234.56'
 */
export function formatCurrency(
  value: number,
  locale: SupportedLocale,
  currency?: string
): string {
  const config = localeConfig[locale];
  const defaultCurrency = locale === 'en' ? 'USD' : 'EUR';
  return new Intl.NumberFormat(config.intlLocale, {
    style: 'currency',
    currency: currency ?? defaultCurrency,
  }).format(value);
}

/**
 * Format a percentage according to the specified locale
 *
 * @param value - The decimal value to format as percentage (0.5 = 50%)
 * @param locale - The locale to use for formatting
 * @param decimals - Number of decimal places (default: 0)
 * @returns Formatted percentage string
 *
 * @example
 * formatPercentage(0.756, 'fr'); // '76 %'
 * formatPercentage(0.756, 'en', 1); // '75.6%'
 */
export function formatPercentage(
  value: number,
  locale: SupportedLocale,
  decimals = 0
): string {
  const config = localeConfig[locale];
  return new Intl.NumberFormat(config.intlLocale, {
    style: 'percent',
    minimumFractionDigits: decimals,
    maximumFractionDigits: decimals,
  }).format(value);
}

/**
 * Get Zod error messages for a given locale
 *
 * @param locale - The locale to get messages for
 * @returns ZodMessages object
 *
 * @example
 * const messages = getZodMessages('fr');
 * console.log(messages.required); // 'Ce champ est requis'
 */
export function getZodMessages(locale: SupportedLocale): ZodMessages {
  return localeConfig[locale].zodMessages;
}

// ============================================================================
// ZOD SCHEMA FACTORIES (Task 3: Locale-aware validation)
// ============================================================================

/**
 * Create a locale-aware date schema that validates and parses dates
 *
 * @param locale - The locale to use for parsing
 * @param options - Optional configuration
 * @returns Zod schema that validates localized date strings
 *
 * @example
 * const schema = createLocalizedDateSchema('fr');
 * schema.parse('15/01/2026'); // Valid
 * schema.parse('01/15/2026'); // Invalid for FR locale
 */
export function createLocalizedDateSchema(
  locale: SupportedLocale,
  options?: { required?: boolean; message?: string }
) {
  const config = localeConfig[locale];
  const isRequired = options?.required ?? true;
  const errorMessage = options?.message ?? config.zodMessages.invalidDate;

  const baseSchema = z.string().transform((val, ctx) => {
    if (!val || val.trim() === '') {
      if (isRequired) {
        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          message: config.zodMessages.required,
        });
        return z.NEVER;
      }
      return null;
    }

    const parsed = parseLocalizedDate(val, locale);
    if (!parsed) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: errorMessage,
      });
      return z.NEVER;
    }

    return parsed;
  });

  return baseSchema;
}

/**
 * Create a locale-aware optional date schema
 *
 * @param locale - The locale to use for parsing
 * @returns Zod schema that validates optional localized date strings
 */
export function createOptionalLocalizedDateSchema(locale: SupportedLocale) {
  return createLocalizedDateSchema(locale, { required: false });
}

/**
 * Predefined locale-aware date schemas for common use cases
 * These are factory functions that return schemas for the specified locale
 */
export const zodDateSchemas = {
  /**
   * Required date schema for FR locale
   */
  requiredFr: () => createLocalizedDateSchema('fr'),

  /**
   * Required date schema for EN locale
   */
  requiredEn: () => createLocalizedDateSchema('en'),

  /**
   * Optional date schema for FR locale
   */
  optionalFr: () => createOptionalLocalizedDateSchema('fr'),

  /**
   * Optional date schema for EN locale
   */
  optionalEn: () => createOptionalLocalizedDateSchema('en'),

  /**
   * Create a date schema for any locale
   */
  forLocale: (locale: SupportedLocale, required = true) =>
    createLocalizedDateSchema(locale, { required }),
} as const;

/**
 * Create a locale-aware number schema that validates number inputs
 *
 * @param locale - The locale to use for parsing
 * @param options - Optional configuration
 * @returns Zod schema that validates numbers
 */
export function createLocalizedNumberSchema(
  locale: SupportedLocale,
  options?: {
    required?: boolean;
    min?: number;
    max?: number;
    integer?: boolean;
  }
) {
  const config = localeConfig[locale];
  const { required = true, min, max, integer = false } = options ?? {};


  let schema = z.number({
    required_error: config.zodMessages.required,
    invalid_type_error: config.zodMessages.invalidNumber,
  } as any);

  if (integer) {
    schema = schema.int();
  }

  if (min !== undefined) {
    schema = schema.min(min);
  }

  if (max !== undefined) {
    schema = schema.max(max);
  }

  if (!required) {
    return schema.optional();
  }

  return schema;
}

import { useState, useMemo, useEffect, useCallback } from 'react';
import { useStore } from '../../store';
import { useFirestoreCollection } from '../../hooks/useFirestore';
import { where, doc, updateDoc, addDoc, collection, writeBatch, limit, serverTimestamp, getCountFromServer, query } from 'firebase/firestore';
import { db } from '../../firebase';
import { Project, ProjectTask, ProjectMilestone } from '../../types';
import { ErrorLogger } from '../../services/errorLogger';
import { ProjectService } from '../../services/projectService';
import { AuditLogService } from '../../services/auditLogService';
import { projectSchema } from '../../schemas/projectSchema';
import { sanitizeData } from '../../utils/dataSanitizer';
import { z } from 'zod';
import { SubscriptionService } from '../../services/subscriptionService';
import { canEditResource, canDeleteResource } from '../../utils/permissions';
import { usePlanLimits } from '../usePlanLimits';
import { ImportService } from '../../services/ImportService';
import { MockDataService } from '../../services/mockDataService';

export const useProjectLogic = () => {
    const { user, addToast, organization, demoMode } = useStore();
    const role = user?.role || 'user';
    const canEdit = canEditResource(user, 'Project');
    const { limits } = usePlanLimits();

    // Mock Data State
    const [mockData, setMockData] = useState<{
        projects: Project[];
    } | null>(null);

    // Data Fetching
    // Data Fetching
    // Data Fetching
    const organizationId = user?.organizationId;
    const constraints = useMemo(() => {
        return organizationId ? [where('organizationId', '==', organizationId), limit(500)] : undefined;
    }, [organizationId]);

    const { data: rawProjects, loading: loadingProjects } = useFirestoreCollection<Project>(
        'projects',
        constraints,
        { logError: true, realtime: true, enabled: !!organizationId && !demoMode }
    );

    // Mock Data Effect
    useEffect(() => {
        if (demoMode && !mockData) {
            setMockData({
                projects: MockDataService.getCollection('projects') as Project[]
            });
        }
    }, [demoMode, mockData]);

    // Derived State
    const projects = useMemo(() => {
        const source = demoMode && mockData ? mockData.projects : rawProjects;
        return [...source].sort((a, b) => new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime());
    }, [rawProjects, mockData, demoMode]);

    const loading = demoMode ? !mockData : loadingProjects;

    // Actions
    const [isSubmitting, setIsSubmitting] = useState(false);

    const handleProjectFormSubmit = async (
        projectData: Omit<Project, 'id' | 'organizationId' | 'tasks' | 'progress' | 'createdAt'>,
        editingProject: Project | null,
        preSelectedContext?: { type: 'risk' | 'control' | 'asset' | 'audit', id: string } | null
    ) => {
        if (!canEdit || !user?.organizationId) return;
        setIsSubmitting(true);
        try {
            const validatedData = projectSchema.parse(projectData);
            const cleanData = sanitizeData(validatedData);
            const batch = writeBatch(db); // Note: batch operations < 500 limit for typical project relationships

            if (editingProject) {
                // Update
                const projectRef = doc(db, 'projects', editingProject.id);
                batch.update(projectRef, { ...cleanData });

                // Use ProjectService to sync relationship links
                ProjectService.syncProjectLinks(batch, {
                    projectId: editingProject.id,
                    relatedRiskIds: validatedData.relatedRiskIds,
                    relatedControlIds: validatedData.relatedControlIds,
                    relatedAssetIds: validatedData.relatedAssetIds,
                    relatedAuditIds: validatedData.relatedAuditIds,
                    oldRiskIds: editingProject.relatedRiskIds,
                    oldControlIds: editingProject.relatedControlIds,
                    oldAssetIds: editingProject.relatedAssetIds,
                    oldAuditIds: editingProject.relatedAuditIds
                });

                await batch.commit();

                // Audit Log
                await AuditLogService.logUpdate(
                    user.organizationId,
                    { id: user.uid, name: user.displayName || user.email || '', email: user.email || '' },
                    'project',
                    editingProject.id,
                    editingProject as unknown as Record<string, unknown>,
                    cleanData as Record<string, unknown>,
                    editingProject.name
                );

            } else {
                // Create
                const countSnap = await getCountFromServer(query(collection(db, 'projects'), where('organizationId', '==', user.organizationId)));
                const currentCount = countSnap.data().count;

                const canAddProject = await SubscriptionService.checkLimit(user.organizationId, 'projects', currentCount);
                if (!canAddProject) {
                    addToast(`Nombre maximum de projets atteint pour votre plan (${projects.length}/${limits?.maxProjects ?? '…'}).`, "error");
                    setIsSubmitting(false);
                    return;
                }
                const finalData = { ...cleanData };
                if (preSelectedContext) {
                    if (preSelectedContext.type === 'risk') finalData.relatedRiskIds = [...(finalData.relatedRiskIds || []), preSelectedContext.id];
                    if (preSelectedContext.type === 'control') finalData.relatedControlIds = [...(finalData.relatedControlIds || []), preSelectedContext.id];
                    if (preSelectedContext.type === 'asset') finalData.relatedAssetIds = [...(finalData.relatedAssetIds || []), preSelectedContext.id];
                    if (preSelectedContext.type === 'audit') finalData.relatedAuditIds = [...(finalData.relatedAuditIds || []), preSelectedContext.id];
                }

                const newProjectRef = doc(collection(db, 'projects'));
                const newProjectData = {
                    ...finalData,
                    organizationId: user.organizationId,
                    progress: 0,
                    tasks: [],
                    createdAt: serverTimestamp()
                };

                batch.set(newProjectRef, newProjectData);

                // Use ProjectService to sync new project links
                ProjectService.syncNewProjectLinks(
                    batch,
                    newProjectRef.id,
                    finalData.relatedRiskIds,
                    finalData.relatedControlIds,
                    finalData.relatedAssetIds,
                    finalData.relatedAuditIds
                );

                await batch.commit();

                // Audit Log
                await AuditLogService.logCreate(
                    user.organizationId,
                    { id: user.uid, name: user.displayName || user.email || '', email: user.email || '' },
                    'project',
                    newProjectRef.id,
                    newProjectData as unknown as Record<string, unknown>,
                    validatedData.name
                );

                addToast("Projet créé avec succès", "success");
            }
        } catch (e) {
            if (e instanceof z.ZodError) {
                addToast((e as z.ZodError).issues[0].message, "error");
            } else {
                ErrorLogger.handleErrorWithToast(e, 'useProjectLogic.submit', 'UPDATE_FAILED');
            }
            throw e;
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleDuplicate = async (project: Project) => {
        if (!canEdit || !user?.organizationId) return;

        const countSnap = await getCountFromServer(query(collection(db, 'projects'), where('organizationId', '==', user.organizationId)));
        const canAdd = await SubscriptionService.checkLimit(user.organizationId, 'projects', countSnap.data().count);

        if (!canAdd) return 'LIMIT_REACHED';

        setIsSubmitting(true);
        try {
            const newProjData = {
                ...project,
                name: `${project.name} (Copie)`,
                createdAt: serverTimestamp(),
                organizationId: user.organizationId,
                progress: 0,
                tasks: project.tasks.map(t => ({ ...t, status: 'A faire', id: Date.now() + Math.random().toString() }))
            };
            // @ts-expect-error - Timestamp type mismatch with external library
            delete newProjData.id;

            const docRef = await addDoc(collection(db, 'projects'), sanitizeData(newProjData));

            await AuditLogService.logCreate(
                user.organizationId,
                { id: user.uid, name: user.displayName || user.email || '', email: user.email || '' },
                'project',
                docRef.id,
                sanitizeData(newProjData) as Record<string, unknown>,
                `Duplication: ${newProjData.name}`
            );

            addToast("Projet dupliqué", "success");
            return 'SUCCESS';
        } catch (e) {
            ErrorLogger.handleErrorWithToast(e, 'Projects.handleDuplicate', 'CREATE_FAILED');
            return 'ERROR';
        } finally {
            setIsSubmitting(false);
        }
    };

    const checkDependencies = async (projectId: string) => {
        if (!user?.organizationId) return { hasDependencies: false, dependencies: [] };
        // Use ProjectService to check dependencies
        return await ProjectService.checkDependencies(projectId, user.organizationId);
    };

    const deleteProject = async (id: string, name?: string) => {
        if (!canDeleteResource(user, 'Project') || !user?.organizationId) return;
        try {
            // Fetch project text details for log fallback if name not provided
            // ideally we pass the object, but here we only have id/name

            // Use ProjectService for cascade deletion with dependency cleanup
            await ProjectService.deleteProjectWithCascade(id, user.organizationId);

            await AuditLogService.logDelete(
                user.organizationId,
                { id: user.uid, name: user.displayName || user.email || '', email: user.email || '' },
                'project',
                id,
                { id, name }, // Limited before data
                name || 'Projet'
            );

            addToast("Projet supprimé", "info");
        } catch (e) {
            ErrorLogger.handleErrorWithToast(e, 'Projects.deleteProject', 'DELETE_FAILED');
        }
    };

    const updateProjectTasks = async (project: Project, tasks: ProjectTask[]) => {
        if (!canEdit || !user?.organizationId) return; // Added organization check
        const completed = tasks.filter(t => t.status === 'Terminé').length;
        const progress = tasks.length > 0 ? Math.round((completed / tasks.length) * 100) : 0;

        try {
            await updateDoc(doc(db, 'projects', project.id), { tasks, progress });

            // Not logging every task update to avoid spam, but could if critical
            // AuditLogService.logUpdate(...) 

            return { tasks, progress };
        } catch (e) {
            ErrorLogger.handleErrorWithToast(e, 'Projects.updateTasks', 'UPDATE_FAILED');
            throw e;
        }
    };

    const importProjects = useCallback(async (csvContent: string) => {
        if (!user?.organizationId) return;
        if (!canEditResource(user, 'Project')) {
            addToast("Permission refusée", "error");
            return;
        }

        try {
            const lines = ImportService.parseCSV(csvContent);
            if (lines.length === 0) {
                addToast("Fichier vide ou invalide", "error");
                return;
            }

            const count = await ProjectService.importProjectsFromCSV(
                lines,
                user.organizationId,
                user.uid,
                user.displayName || 'Utilisateur'
            );

            await AuditLogService.logImport(
                user.organizationId,
                { id: user.uid, name: user.displayName || user.email || '', email: user.email || '' },
                'project',
                count,
                'CSV Upload'
            );

            addToast(`Import de ${count} projets réussi`, "success");
        } catch (error) {
            ErrorLogger.handleErrorWithToast(error, 'useProjectLogic.importProjects');
        } finally {
            setIsSubmitting(false);
        }
    }, [user, addToast, canEdit]); // Added canEdit to deps

    const createProjectFromTemplateData = async (
        projectData: Omit<Project, 'id'>,
        milestones: Omit<ProjectMilestone, 'id'>[]
    ) => {
        if (!canEdit || !user?.organizationId) return;

        const canAddProject = await SubscriptionService.checkLimit(user.organizationId, 'projects', projects.length);
        if (!canAddProject) {
            addToast(`Nombre maximum de projets atteint pour votre plan (${projects.length}/${limits?.maxProjects ?? '…'}).`, "error");
            return;
        }

        setIsSubmitting(true);
        try {
            const batch = writeBatch(db);

            // 1. Create Project
            const newProjectRef = doc(collection(db, 'projects'));
            const finalProjectData = sanitizeData({
                ...projectData,
                organizationId: user.organizationId,
                createdAt: serverTimestamp(),
                // Ensure tasks have unique IDs if not already
                tasks: projectData.tasks.map((t, i) => ({
                    ...t,
                    id: t.id || `task-${Date.now()}-${i}`
                }))
            });

            batch.set(newProjectRef, finalProjectData);

            // 2. Create Milestones
            milestones.forEach((m) => {
                const newMilestoneRef = doc(collection(db, 'project_milestones'));
                batch.set(newMilestoneRef, sanitizeData({
                    ...m,
                    projectId: newProjectRef.id,
                    organizationId: user.organizationId,
                    createdAt: serverTimestamp()
                }));
            });

            await batch.commit();

            await AuditLogService.logCreate(
                user.organizationId,
                { id: user.uid, name: user.displayName || user.email || '', email: user.email || '' },
                'project',
                newProjectRef.id,
                finalProjectData as Record<string, unknown>,
                `Template: ${projectData.name}`
            );

            addToast("Projet et jalons créés avec succès", "success");

            return newProjectRef.id;

        } catch (e) {
            ErrorLogger.handleErrorWithToast(e, 'useProjectLogic.createFromTemplate', 'CREATE_FAILED');
            throw e;
        } finally {
            setIsSubmitting(false);
        }
    };

    return {
        projects, loading,
        handleProjectFormSubmit, handleDuplicate, deleteProject, updateProjectTasks, checkDependencies, importProjects, createProjectFromTemplateData,
        isSubmitting, role, canEdit, user, organization
    };
};

